#[cfg_attr(feature = "serde", derive(Serialize, Deserialize))]
#[derive(Debug, Error)]
pub enum InteriorPointSolveError {
    #[error("invalid NLIP input: {0}")]
    InvalidInput(String),
    #[error("NLIP linear solve failed using {solver:?}")]
    LinearSolve {
        solver: InteriorPointLinearSolver,
        context: Box<InteriorPointFailureContext>,
    },
    #[error(
        "NLIP line search failed (residual merit {merit}, mu {mu}, step inf-norm {step_inf_norm})"
    )]
    LineSearchFailed {
        merit: f64,
        mu: f64,
        step_inf_norm: f64,
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP restoration failed ({status:?})")]
    RestorationFailed {
        status: InteriorPointRestorationFailureStatus,
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP detected local infeasibility")]
    LocalInfeasibility {
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP iterates are diverging (max |x| {max_abs_x}, threshold {threshold})")]
    DivergingIterates {
        max_abs_x: f64,
        threshold: f64,
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP maximum CPU time exceeded (elapsed {elapsed_seconds}, limit {limit_seconds})")]
    CpuTimeExceeded {
        elapsed_seconds: f64,
        limit_seconds: f64,
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP maximum wall time exceeded (elapsed {elapsed_seconds}, limit {limit_seconds})")]
    WallTimeExceeded {
        elapsed_seconds: f64,
        limit_seconds: f64,
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP stopped at current point as requested by user")]
    UserRequestedStop {
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP search direction is becoming too small")]
    SearchDirectionTooSmall {
        context: Box<InteriorPointFailureContext>,
    },
    #[error("NLIP failed to converge in {iterations} iterations")]
    MaxIterations {
        iterations: Index,
        context: Box<InteriorPointFailureContext>,
    },
}

