impl InteriorPointKktSnapshot {
    fn reduced_system(&self, solver: InteriorPointLinearSolver) -> ReducedKktSystem<'_> {
        ReducedKktSystem {
            hessian: &self.hessian,
            equality_jacobian: &self.equality_jacobian,
            inequality_jacobian: &self.inequality_jacobian,
            equality_diagonal: &[],
            inequality_diagonal: &[],
            bound_diagonal: &self.bound_diagonal,
            bound_rhs: &self.bound_rhs,
            // KKT snapshots do not yet carry the full variable-bound state
            // needed for IPOPT's z_L/z_U residual rows, so replay diagnostics
            // use the algebraically equivalent eliminated bound branch.
            bound_data: None,
            bound_complementarity_lower_rhs: None,
            bound_complementarity_upper_rhs: None,
            slack: &self.slack,
            multipliers: &self.multipliers,
            r_dual: &self.r_dual,
            r_eq: &self.r_eq,
            r_ineq: &self.r_ineq,
            r_slack_stationarity: &self.r_slack_stationarity,
            r_cent: &self.r_cent,
            primal_dual_rhs_scale: 1.0,
            damping_rhs_scale: 1.0,
            barrier_parameter: self.barrier_parameter,
            kappa_d: self.kappa_d,
            solver,
            regularization: self.regularization,
            first_hessian_perturbation: self.first_hessian_perturbation,
            previous_hessian_perturbation: self.previous_hessian_perturbation,
            regularization_first_growth_factor: self.regularization_first_growth_factor,
            adaptive_regularization_retries: self.adaptive_regularization_retries,
            regularization_growth_factor: self.regularization_growth_factor,
            regularization_decay_factor: self.regularization_decay_factor,
            regularization_max: self.regularization_max,
            jacobian_regularization_value: self.jacobian_regularization_value,
            jacobian_regularization_exponent: self.jacobian_regularization_exponent,
            perturb_always_cd: false,
            forced_jacobian_regularization: None,
            min_refinement_steps: default_ipopt_linear_min_refinement_steps(),
            max_refinement_steps: default_ipopt_linear_max_refinement_steps(),
            residual_ratio_max: default_ipopt_linear_residual_ratio_max(),
            residual_ratio_singular: default_ipopt_linear_residual_ratio_singular(),
            residual_improvement_factor: default_ipopt_linear_residual_improvement_factor(),
            negative_curvature_test_tolerance: 0.0,
            negative_curvature_test_regularized: true,
            spral_pivot_method: self.spral_pivot_method,
            spral_action_on_zero_pivot: self.spral_action_on_zero_pivot,
            spral_small_pivot_tolerance: self.spral_small_pivot_tolerance,
            spral_threshold_pivot_u: self.spral_threshold_pivot_u,
            spral_pivot_tolerance_max: self.spral_pivot_tolerance_max,
        }
    }
}

fn linear_direction_inf_norm(direction: &NewtonDirection) -> f64 {
    direction
        .dx
        .iter()
        .chain(direction.d_lambda.iter())
        .chain(direction.ds.iter())
        .chain(direction.dz.iter())
        .fold(0.0_f64, |acc, value| acc.max(value.abs()))
}

fn step_direction_snapshot(direction: &NewtonDirection) -> InteriorPointStepDirectionSnapshot {
    InteriorPointStepDirectionSnapshot {
        x: direction.dx.clone(),
        slack: direction.ds.clone(),
        equality_multipliers: direction.d_lambda.clone(),
        inequality_multipliers: direction.d_ineq.clone(),
        slack_multipliers: direction.dz.clone(),
        lower_bound_multipliers: direction.dz_lower.clone(),
        upper_bound_multipliers: direction.dz_upper.clone(),
    }
}

fn should_run_linear_debug(
    schedule: InteriorPointLinearDebugSchedule,
    iteration: Index,
    primary_failed: bool,
) -> bool {
    match schedule {
        InteriorPointLinearDebugSchedule::FirstIteration => iteration == 0,
        InteriorPointLinearDebugSchedule::FailuresOnly => primary_failed,
        InteriorPointLinearDebugSchedule::EveryIteration => true,
    }
}

fn normalized_compare_solvers(
    options: &InteriorPointLinearDebugOptions,
    primary_solver: InteriorPointLinearSolver,
) -> Vec<InteriorPointLinearSolver> {
    let mut deduped = Vec::new();
    for solver in &options.compare_solvers {
        if *solver == InteriorPointLinearSolver::Auto
            || *solver == primary_solver
            || deduped.contains(solver)
        {
            continue;
        }
        deduped.push(*solver);
    }
    deduped
}

#[expect(
    clippy::too_many_arguments,
    reason = "KKT snapshot capture intentionally records both solver and nonlinear context."
)]
fn build_interior_point_kkt_snapshot(
    iteration: Index,
    phase: InteriorPointIterationPhase,
    primary_solver: InteriorPointLinearSolver,
    system: &ReducedKktSystem<'_>,
    primal_diagonal_shift_used: f64,
    dual_diagonal_shift_used: f64,
    barrier_parameter: f64,
    primal_inf: f64,
    dual_inf: f64,
    complementarity_inf: f64,
    line_search_trials: Index,
) -> std::result::Result<InteriorPointKktSnapshot, InteriorPointSolveError> {
    let pattern = build_spral_augmented_kkt_pattern(
        system.hessian.lower_triangle.as_ref(),
        system.equality_jacobian.structure.as_ref(),
        system.inequality_jacobian.structure.as_ref(),
    )?;
    let primal_shift = primal_diagonal_shift_used;
    let slack_shift = primal_diagonal_shift_used;
    let dual_shift = dual_diagonal_shift_used.max(0.0);
    let mut augmented_values = vec![0.0; pattern.ccs.nnz()];
    fill_spral_augmented_kkt_values(
        &pattern,
        &mut augmented_values,
        system,
        primal_shift,
        slack_shift,
        dual_shift,
    );
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let augmented_rhs =
        build_ipopt_augmented_kkt_rhs(system, &pattern, IpoptLinearRhsOrientation::FinalDirection);
    Ok(InteriorPointKktSnapshot {
        iteration,
        phase,
        primary_solver,
        matrix_dimension: pattern.dimension(),
        x_dimension: n,
        x_full_indices: system.bound_data.map_or_else(
            || (0..n).collect(),
            |bound_data| bound_data.fixed_variables.free_indices.clone(),
        ),
        equality_dimension: meq,
        inequality_dimension: mineq,
        hessian: system.hessian.clone(),
        equality_jacobian: system.equality_jacobian.clone(),
        inequality_jacobian: system.inequality_jacobian.clone(),
        bound_diagonal: system.bound_diagonal.to_vec(),
        bound_rhs: system.bound_rhs.to_vec(),
        slack: system.slack.to_vec(),
        multipliers: system.multipliers.to_vec(),
        r_dual: system.r_dual.to_vec(),
        r_eq: system.r_eq.to_vec(),
        r_ineq: system.r_ineq.to_vec(),
        r_slack_stationarity: system.r_slack_stationarity.to_vec(),
        r_cent: system.r_cent.to_vec(),
        regularization: primal_diagonal_shift_used,
        primal_diagonal_shift: primal_diagonal_shift_used,
        dual_regularization: dual_diagonal_shift_used,
        first_hessian_perturbation: system.first_hessian_perturbation,
        previous_hessian_perturbation: system.previous_hessian_perturbation,
        regularization_first_growth_factor: system.regularization_first_growth_factor,
        adaptive_regularization_retries: system.adaptive_regularization_retries,
        regularization_growth_factor: system.regularization_growth_factor,
        regularization_decay_factor: system.regularization_decay_factor,
        regularization_max: system.regularization_max,
        jacobian_regularization_value: system.jacobian_regularization_value,
        jacobian_regularization_exponent: system.jacobian_regularization_exponent,
        spral_pivot_method: system.spral_pivot_method,
        spral_action_on_zero_pivot: system.spral_action_on_zero_pivot,
        spral_small_pivot_tolerance: system.spral_small_pivot_tolerance,
        spral_threshold_pivot_u: system.spral_threshold_pivot_u,
        spral_pivot_tolerance_max: system.spral_pivot_tolerance_max,
        augmented_pattern: pattern.clone(),
        augmented_values,
        augmented_rhs,
        expected_augmented_inertia: spral_expected_augmented_inertia(&pattern),
        barrier_parameter,
        kappa_d: system.kappa_d,
        primal_inf,
        dual_inf,
        complementarity_inf,
        line_search_trials,
    })
}

fn linear_debug_result_from_stats(
    direction: &NewtonDirection,
    stats: &LinearBackendRunStats,
    regularization: f64,
) -> InteriorPointLinearDebugBackendResult {
    InteriorPointLinearDebugBackendResult {
        solver: stats.solver,
        success: true,
        regularization,
        inertia: stats.inertia,
        residual_inf: Some(stats.residual_inf),
        solution_inf: Some(stats.solution_inf),
        step_inf: Some(linear_direction_inf_norm(direction)),
        factorization_time: Some(stats.factorization_time),
        solve_time: Some(stats.solve_time),
        reused_symbolic: stats.reused_symbolic,
        step_delta_inf: None,
        dx_delta_inf: None,
        d_lambda_delta_inf: None,
        ds_delta_inf: None,
        dz_delta_inf: None,
        detail: stats.detail.clone(),
    }
}

fn linear_debug_result_from_attempt(
    solver: InteriorPointLinearSolver,
    attempt: &InteriorPointLinearSolveAttempt,
) -> InteriorPointLinearDebugBackendResult {
    InteriorPointLinearDebugBackendResult {
        solver,
        success: false,
        regularization: attempt.regularization,
        inertia: attempt.inertia.as_deref().copied(),
        residual_inf: attempt.residual_inf,
        solution_inf: attempt.solution_inf,
        step_inf: None,
        factorization_time: None,
        solve_time: None,
        reused_symbolic: None,
        step_delta_inf: None,
        dx_delta_inf: None,
        d_lambda_delta_inf: None,
        ds_delta_inf: None,
        dz_delta_inf: None,
        detail: attempt.detail.clone(),
    }
}

fn annotate_linear_debug_delta(
    primary: &NewtonDirection,
    comparison: &NewtonDirection,
    result: &mut InteriorPointLinearDebugBackendResult,
) {
    result.step_delta_inf = Some(delta_inf_norm(
        &primary.linear_solution,
        &comparison.linear_solution,
    ));
    result.dx_delta_inf = Some(delta_inf_norm(&primary.dx, &comparison.dx));
    result.d_lambda_delta_inf = Some(delta_inf_norm(&primary.d_lambda, &comparison.d_lambda));
    result.ds_delta_inf = Some(delta_inf_norm(&primary.ds, &comparison.ds));
    result.dz_delta_inf = Some(delta_inf_norm(&primary.dz, &comparison.dz));
}

fn scaled_linear_debug_delta_matches(delta: Option<f64>, primary_scale: f64) -> bool {
    delta
        .is_some_and(|delta| delta <= LINEAR_DEBUG_RELATIVE_DELTA_TOLERANCE * (1.0 + primary_scale))
}

fn slice_inf_norm(values: &[f64]) -> f64 {
    values
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()))
}

fn linear_debug_matches_primary(
    primary: &NewtonDirection,
    result: &InteriorPointLinearDebugBackendResult,
) -> bool {
    result.success
        && scaled_linear_debug_delta_matches(
            result.step_delta_inf,
            linear_direction_inf_norm(primary),
        )
        && scaled_linear_debug_delta_matches(result.dx_delta_inf, slice_inf_norm(&primary.dx))
        && scaled_linear_debug_delta_matches(
            result.d_lambda_delta_inf,
            slice_inf_norm(&primary.d_lambda),
        )
        && scaled_linear_debug_delta_matches(result.ds_delta_inf, slice_inf_norm(&primary.ds))
        && scaled_linear_debug_delta_matches(result.dz_delta_inf, slice_inf_norm(&primary.dz))
}

fn newton_direction_from_augmented_solution(
    snapshot: &InteriorPointKktSnapshot,
    solver: InteriorPointLinearSolver,
    solution: Vec<f64>,
    upper_slack_multiplier_step: Option<Vec<f64>>,
    backend_stats: LinearBackendRunStats,
) -> NewtonDirection {
    let n = snapshot.x_dimension;
    let meq = snapshot.equality_dimension;
    let mineq = snapshot.inequality_dimension;
    let dx = solution[..n].to_vec();
    let ipopt_ds = solution
        [snapshot.augmented_pattern.p_offset..snapshot.augmented_pattern.p_offset + mineq]
        .to_vec();
    let d_lambda = solution
        [snapshot.augmented_pattern.lambda_offset..snapshot.augmented_pattern.lambda_offset + meq]
        .to_vec();
    let d_ineq = solution
        [snapshot.augmented_pattern.z_offset..snapshot.augmented_pattern.z_offset + mineq]
        .to_vec();
    let ds = ipopt_ds;
    let dz = upper_slack_multiplier_step.unwrap_or_else(|| {
        snapshot
            .r_cent
            .iter()
            .zip(snapshot.multipliers.iter())
            .zip(snapshot.slack.iter())
            .zip(ds.iter())
            .map(|(((r_cent_i, z_i), s_i), ds_i)| {
                ipopt_final_upper_slack_bound_multiplier_step(*s_i, *z_i, *r_cent_i, *ds_i)
            })
            .collect::<Vec<_>>()
    });
    NewtonDirection {
        dx,
        d_lambda,
        d_ineq,
        ds,
        dz,
        dz_lower: Vec::new(),
        dz_upper: Vec::new(),
        solver_used: solver,
        regularization_used: snapshot.regularization.max(snapshot.primal_diagonal_shift),
        dual_regularization_used: snapshot.dual_regularization,
        primal_diagonal_shift_used: snapshot.primal_diagonal_shift,
        linear_solution: solution,
        linear_trace: None,
        backend_stats,
        linear_debug: None,
    }
}

fn replay_snapshot_with_solver(
    snapshot: &InteriorPointKktSnapshot,
    solver: InteriorPointLinearSolver,
    debug_state: &mut InteriorPointLinearDebugState,
) -> std::result::Result<NewtonDirection, Vec<InteriorPointLinearSolveAttempt>> {
    let system = snapshot.reduced_system(solver);
    let mut scratch_profiling = InteriorPointProfiling::default();
    match solver {
        InteriorPointLinearSolver::SsidsRs => {
            if debug_state.rust_workspace.is_none() && !debug_state.rust_workspace_unavailable {
                match prepare_spral_workspace(
                    snapshot.hessian.lower_triangle.as_ref(),
                    snapshot.equality_jacobian.structure.as_ref(),
                    snapshot.inequality_jacobian.structure.as_ref(),
                    &mut scratch_profiling,
                    false,
                ) {
                    Ok(workspace) => {
                        debug_state.rust_workspace = Some(workspace);
                    }
                    Err(error) => {
                        debug_state.rust_workspace_unavailable = true;
                        debug_state.rust_workspace_error = Some(error.to_string());
                    }
                }
            }
            let Some(workspace) = debug_state.rust_workspace.as_mut() else {
                return Err(vec![spral_error_attempt(
                    snapshot.regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    debug_state
                        .rust_workspace_error
                        .as_deref()
                        .unwrap_or("rust ssids_rs workspace unavailable"),
                )]);
            };
            if workspace.values.len() != snapshot.augmented_values.len() {
                return Err(vec![spral_error_attempt(
                    snapshot.regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    "snapshot pattern does not match rust SPRAL workspace",
                )]);
            }
            workspace.values.copy_from_slice(&snapshot.augmented_values);
            factor_solve_spral_ssids(
                &system,
                workspace,
                &snapshot.augmented_rhs,
                snapshot.regularization,
                &mut scratch_profiling,
                false,
            )
            .map(|(solution, backend_stats)| {
                newton_direction_from_augmented_solution(
                    snapshot,
                    solver,
                    solution,
                    None,
                    backend_stats,
                )
            })
            .map_err(|attempt| vec![attempt])
        }
        InteriorPointLinearSolver::SpralSrc => {
            if debug_state.native_workspace.is_none() && !debug_state.native_workspace_unavailable {
                match prepare_native_spral_workspace(
                    snapshot.hessian.lower_triangle.as_ref(),
                    snapshot.equality_jacobian.structure.as_ref(),
                    snapshot.inequality_jacobian.structure.as_ref(),
                    &system_spral_numeric_factor_options(&system),
                    &mut scratch_profiling,
                    false,
                ) {
                    Ok(workspace) => {
                        debug_state.native_workspace = Some(workspace);
                    }
                    Err(error) => {
                        debug_state.native_workspace_unavailable = true;
                        debug_state.native_workspace_error = Some(error.to_string());
                    }
                }
            }
            let Some(workspace) = debug_state.native_workspace.as_mut() else {
                return Err(vec![native_spral_error_attempt(
                    snapshot.regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    debug_state
                        .native_workspace_error
                        .as_deref()
                        .unwrap_or("native ssids_rs workspace unavailable"),
                )]);
            };
            if workspace.values.len() != snapshot.augmented_values.len() {
                return Err(vec![native_spral_error_attempt(
                    snapshot.regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    "snapshot pattern does not match native SPRAL workspace",
                )]);
            }
            workspace.values.copy_from_slice(&snapshot.augmented_values);
            let prefinal_rhs = snapshot
                .augmented_rhs
                .iter()
                .map(|value| -*value)
                .collect::<Vec<_>>();
            factor_solve_spral_src(
                &system,
                workspace,
                &prefinal_rhs,
                snapshot.regularization,
                IpoptLinearSolveContext {
                    shifts: IpoptLinearRefinementShifts {
                        primal: snapshot.primal_diagonal_shift,
                        slack: snapshot.primal_diagonal_shift,
                        dual: snapshot.dual_regularization,
                    },
                    rhs_orientation: IpoptLinearRhsOrientation::PreFinal,
                    allow_inexact: false,
                    native_spral_quality_was_increased: false,
                    pretend_singular_last_time: false,
                    capture_trace: false,
                },
                &mut scratch_profiling,
                false,
            )
            .map(|(solution, _linear_trace, backend_stats)| {
                newton_direction_from_augmented_solution(
                    snapshot,
                    solver,
                    solution.augmented_solution,
                    Some(solution.upper_slack_multiplier_step),
                    backend_stats,
                )
            })
            .map_err(|attempt| vec![attempt])
        }
        InteriorPointLinearSolver::SparseQdldl => solve_reduced_kkt_with_sparse_qdldl(&system),
        InteriorPointLinearSolver::Auto => Err(vec![InteriorPointLinearSolveAttempt {
            solver,
            regularization: snapshot.regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: Some("auto is not a concrete comparison backend".into()),
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        }]),
    }
}

fn run_linear_debug_report_on_success(
    snapshot: &InteriorPointKktSnapshot,
    primary_direction: &NewtonDirection,
    debug_state: &mut InteriorPointLinearDebugState,
) -> InteriorPointLinearDebugReport {
    let compare_solvers =
        normalized_compare_solvers(&debug_state.options, primary_direction.solver_used);
    let mut results = vec![linear_debug_result_from_stats(
        primary_direction,
        &primary_direction.backend_stats,
        primary_direction.regularization_used,
    )];
    let mut notes = Vec::new();
    let mut mismatch = false;
    let mut incomplete = false;
    let mut matched_solvers = Vec::new();
    for solver in compare_solvers {
        match replay_snapshot_with_solver(snapshot, solver, debug_state) {
            Ok(direction) => {
                let mut result = linear_debug_result_from_stats(
                    &direction,
                    &direction.backend_stats,
                    direction.regularization_used,
                );
                annotate_linear_debug_delta(primary_direction, &direction, &mut result);
                if linear_debug_matches_primary(primary_direction, &result) {
                    matched_solvers.push(solver.label());
                } else {
                    mismatch = true;
                }
                results.push(result);
            }
            Err(attempts) => {
                incomplete = true;
                let fallback_attempt = InteriorPointLinearSolveAttempt {
                    solver,
                    regularization: snapshot.regularization,
                    inertia: None,
                    failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    detail: Some("comparison backend failed without diagnostics".into()),
                    solution_inf: None,
                    solution_inf_limit: None,
                    residual_inf: None,
                    residual_inf_limit: None,
                };
                let attempt = attempts.last().unwrap_or(&fallback_attempt);
                notes.push(format!(
                    "{} comparison failed: {}",
                    solver.label(),
                    attempt
                        .detail
                        .clone()
                        .unwrap_or_else(|| attempt.failure_kind.label().into())
                ));
                results.push(linear_debug_result_from_attempt(solver, attempt));
            }
        }
    }
    if mismatch && !matched_solvers.is_empty() {
        notes.push(format!(
            "matched primary within tolerance: {}",
            matched_solvers.join(", ")
        ));
    }
    let successful_compares = results.iter().skip(1).any(|result| result.success);
    let verdict = if mismatch {
        InteriorPointLinearDebugVerdict::LinearSolverMismatch
    } else if incomplete {
        InteriorPointLinearDebugVerdict::ComparisonIncomplete
    } else if successful_compares || results.len() == 1 {
        InteriorPointLinearDebugVerdict::Consistent
    } else {
        InteriorPointLinearDebugVerdict::ComparisonIncomplete
    };
    InteriorPointLinearDebugReport {
        primary_solver: primary_direction.solver_used,
        schedule: debug_state.options.schedule,
        verdict,
        results,
        notes,
    }
}

fn run_linear_debug_report_on_failure(
    snapshot: &InteriorPointKktSnapshot,
    preferred_solver: InteriorPointLinearSolver,
    attempts: &[InteriorPointLinearSolveAttempt],
    debug_state: &mut InteriorPointLinearDebugState,
) -> InteriorPointLinearDebugReport {
    let compare_solvers = normalized_compare_solvers(&debug_state.options, preferred_solver);
    let mut results = vec![linear_debug_result_from_attempt(
        preferred_solver,
        attempts.last().unwrap_or(&InteriorPointLinearSolveAttempt {
            solver: preferred_solver,
            regularization: snapshot.regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: Some("primary backend failed without diagnostics".into()),
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        }),
    )];
    let mut notes = attempts
        .iter()
        .filter_map(|attempt| {
            attempt.detail.as_ref().map(|detail| {
                format!(
                    "primary attempt reg={:.3e}: {detail}",
                    attempt.regularization
                )
            })
        })
        .collect::<Vec<_>>();
    let mut compare_success = false;
    for solver in compare_solvers {
        match replay_snapshot_with_solver(snapshot, solver, debug_state) {
            Ok(direction) => {
                compare_success = true;
                results.push(linear_debug_result_from_stats(
                    &direction,
                    &direction.backend_stats,
                    direction.regularization_used,
                ));
            }
            Err(compare_attempts) => {
                let fallback_attempt = InteriorPointLinearSolveAttempt {
                    solver,
                    regularization: snapshot.regularization,
                    inertia: None,
                    failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    detail: Some("comparison backend failed without diagnostics".into()),
                    solution_inf: None,
                    solution_inf_limit: None,
                    residual_inf: None,
                    residual_inf_limit: None,
                };
                let attempt = compare_attempts.last().unwrap_or(&fallback_attempt);
                notes.push(format!(
                    "{} comparison failed: {}",
                    solver.label(),
                    attempt
                        .detail
                        .clone()
                        .unwrap_or_else(|| attempt.failure_kind.label().into())
                ));
                results.push(linear_debug_result_from_attempt(solver, attempt));
            }
        }
    }
    InteriorPointLinearDebugReport {
        primary_solver: preferred_solver,
        schedule: debug_state.options.schedule,
        verdict: if compare_success {
            InteriorPointLinearDebugVerdict::LinearSolverMismatch
        } else {
            InteriorPointLinearDebugVerdict::ComparisonIncomplete
        },
        results,
        notes,
    }
}

fn dump_linear_debug_snapshot(
    options: &InteriorPointLinearDebugOptions,
    snapshot: &InteriorPointKktSnapshot,
    report: &InteriorPointLinearDebugReport,
    primary_direction: Option<&NewtonDirection>,
) {
    let Some(dir) = options.dump_dir.as_ref() else {
        return;
    };
    let _ = fs::create_dir_all(dir);
    let path = dir.join(format!("nlip_kkt_iter_{:04}.txt", snapshot.iteration));
    let mut body = String::new();
    body.push_str(&format!(
        "iteration={}\nphase={:?}\nprimary_solver={}\nmatrix_dimension={}\nx_dimension={}\ninequality_dimension={}\nequality_dimension={}\np_offset={}\nlambda_offset={}\nz_offset={}\nexpected_inertia=+{}/-{}/0={}\nregularization={:.6e}\nprimal_diagonal_shift={:.6e}\ndual_regularization={:.6e}\nbarrier_parameter={:.6e}\nprimal_inf={:.6e}\ndual_inf={:.6e}\ncomplementarity_inf={:.6e}\nline_search_trials={}\nverdict={:?}\n",
        snapshot.iteration,
        snapshot.phase,
        snapshot.primary_solver.label(),
        snapshot.matrix_dimension,
        snapshot.x_dimension,
        snapshot.inequality_dimension,
        snapshot.equality_dimension,
        snapshot.augmented_pattern.p_offset,
        snapshot.augmented_pattern.lambda_offset,
        snapshot.augmented_pattern.z_offset,
        snapshot.expected_augmented_inertia.positive,
        snapshot.expected_augmented_inertia.negative,
        snapshot.expected_augmented_inertia.zero,
        snapshot.regularization,
        snapshot.primal_diagonal_shift,
        snapshot.dual_regularization,
        snapshot.barrier_parameter,
        snapshot.primal_inf,
        snapshot.dual_inf,
        snapshot.complementarity_inf,
        snapshot.line_search_trials,
        report.verdict,
    ));
    for result in &report.results {
        body.push_str(&format!(
            "result solver={} success={} reg={:.6e} inertia={:?} residual={:?} solution_inf={:?} step_inf={:?} step_delta={:?} dx_delta={:?} dlambda_delta={:?} ds_delta={:?} dz_delta={:?} detail={:?}\n",
            result.solver.label(),
            result.success,
            result.regularization,
            result.inertia,
            result.residual_inf,
            result.solution_inf,
            result.step_inf,
            result.step_delta_inf,
            result.dx_delta_inf,
            result.d_lambda_delta_inf,
            result.ds_delta_inf,
            result.dz_delta_inf,
            result.detail,
        ));
    }
    for note in &report.notes {
        body.push_str(&format!("note={note}\n"));
    }
    body.push_str(&format!(
        "x_full_indices={:?}\ncol_ptrs={:?}\nrow_indices={:?}\nvalues={:?}\nrhs={:?}\nr_dual={:?}\nbound_diagonal={:?}\nbound_rhs={:?}\nslack={:?}\nmultipliers={:?}\n",
        snapshot.x_full_indices,
        snapshot.augmented_pattern.ccs.col_ptrs,
        snapshot.augmented_pattern.ccs.row_indices,
        snapshot.augmented_values,
        snapshot.augmented_rhs,
        snapshot.r_dual,
        snapshot.bound_diagonal,
        snapshot.bound_rhs,
        snapshot.slack,
        snapshot.multipliers,
    ));
    if let Some(direction) = primary_direction {
        // For the IPOPT full-space path, `linear_solution` is stored after
        // PDSearchDirCalc's final alpha=-1 scaling.  The prefinal vector is
        // the post-refinement accumulated solution before that final scaling;
        // individual IpStdAugSystemSolver.cpp SOL[0] lines are compared by the
        // glider diagnostic's cumulative-window reconstruction.
        let prefinal_solution = direction
            .linear_solution
            .iter()
            .map(|value| -*value)
            .collect::<Vec<_>>();
        body.push_str(&format!(
            "linear_solution_final={:?}\nlinear_solution_prefinal={:?}\n",
            direction.linear_solution, prefinal_solution,
        ));
        if let Some(trace) = direction.linear_trace.as_ref() {
            let refinement_rhs = trace
                .refinement_steps
                .iter()
                .map(|step| step.correction_rhs.clone())
                .collect::<Vec<_>>();
            let refinement_solution = trace
                .refinement_steps
                .iter()
                .map(|step| step.correction_solution.clone())
                .collect::<Vec<_>>();
            let refinement_accumulated_solution = trace
                .refinement_steps
                .iter()
                .map(|step| step.solution_prefinal_after.clone())
                .collect::<Vec<_>>();
            let refinement_residual_ratios = trace
                .refinement_steps
                .iter()
                .map(|step| [step.residual_ratio_before, step.residual_ratio_after])
                .collect::<Vec<_>>();
            let refinement_residual_x = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_x_after_w = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x_after_w.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_x_after_jc = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x_after_jc.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_x_after_jd = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x_after_jd.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_x_after_pxl = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x_after_pxl.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_x_after_pxu = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x_after_pxu.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_x_after_add_two_vectors = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.x_after_add_two_vectors.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_s = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.s.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_s_after_pdu = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.s_after_pdu.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_s_after_pdl = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.s_after_pdl.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_s_after_add_two_vectors = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.s_after_add_two_vectors.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_s_after_delta = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.s_after_delta.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_c = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.c.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_d = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.d.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_z_lower = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.z_lower.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_z_upper = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.z_upper.clone())
                })
                .collect::<Vec<_>>();
            let refinement_residual_v_upper = trace
                .refinement_steps
                .iter()
                .filter_map(|step| {
                    step.full_residual
                        .as_ref()
                        .map(|residual| residual.v_upper.clone())
                })
                .collect::<Vec<_>>();
            body.push_str(&format!(
                "linear_trace_rhs_prefinal={:?}\nlinear_trace_solution_prefinal_unrefined={:?}\nlinear_trace_refinement_rhs={:?}\nlinear_trace_refinement_solution={:?}\nlinear_trace_refinement_accumulated_solution={:?}\nlinear_trace_refinement_residual_ratios={:?}\nlinear_trace_refinement_residual_x={:?}\nlinear_trace_refinement_residual_x_after_w={:?}\nlinear_trace_refinement_residual_x_after_jc={:?}\nlinear_trace_refinement_residual_x_after_jd={:?}\nlinear_trace_refinement_residual_x_after_pxl={:?}\nlinear_trace_refinement_residual_x_after_pxu={:?}\nlinear_trace_refinement_residual_x_after_add_two_vectors={:?}\nlinear_trace_refinement_residual_s={:?}\nlinear_trace_refinement_residual_s_after_pdu={:?}\nlinear_trace_refinement_residual_s_after_pdl={:?}\nlinear_trace_refinement_residual_s_after_add_two_vectors={:?}\nlinear_trace_refinement_residual_s_after_delta={:?}\nlinear_trace_refinement_residual_c={:?}\nlinear_trace_refinement_residual_d={:?}\nlinear_trace_refinement_residual_z_lower={:?}\nlinear_trace_refinement_residual_z_upper={:?}\nlinear_trace_refinement_residual_v_upper={:?}\n",
                trace.rhs_prefinal,
                trace.solution_prefinal_unrefined,
                refinement_rhs,
                refinement_solution,
                refinement_accumulated_solution,
                refinement_residual_ratios,
                refinement_residual_x,
                refinement_residual_x_after_w,
                refinement_residual_x_after_jc,
                refinement_residual_x_after_jd,
                refinement_residual_x_after_pxl,
                refinement_residual_x_after_pxu,
                refinement_residual_x_after_add_two_vectors,
                refinement_residual_s,
                refinement_residual_s_after_pdu,
                refinement_residual_s_after_pdl,
                refinement_residual_s_after_add_two_vectors,
                refinement_residual_s_after_delta,
                refinement_residual_c,
                refinement_residual_d,
                refinement_residual_z_lower,
                refinement_residual_z_upper,
                refinement_residual_v_upper,
            ));
        }
    }
    let _ = fs::write(path, body);
}

#[expect(
    clippy::too_many_arguments,
    reason = "Diagnostic-only dump preserves the reduced AugResto solve boundary for IPOPT parity."
)]
fn dump_restoration_inner_linear_debug_snapshot(
    parent_dump_dir: Option<&std::path::Path>,
    iteration: Index,
    phase: InteriorPointIterationPhase,
    restoration_reduced_kkt: &RestorationReducedKktSystem,
    initial_reduced_rhs: &RestorationReducedAugmentedRhs,
    reduced_system: &ReducedKktSystem<'_>,
    augmented_values: &[f64],
    rhs_prefinal: &[f64],
    solution_prefinal_unrefined: &[f64],
    refinement_corrections: &[(Vec<f64>, Vec<f64>)],
    refinement_trace_steps: &[IpoptLinearRefinementStepTrace],
    primal_shift: f64,
    dual_shift: f64,
    backend_stats: &LinearBackendRunStats,
) {
    let Some(parent_dump_dir) = parent_dump_dir else {
        return;
    };
    let Ok(mut snapshot) = build_interior_point_kkt_snapshot(
        iteration,
        phase,
        InteriorPointLinearSolver::SpralSrc,
        reduced_system,
        primal_shift,
        dual_shift,
        reduced_system.barrier_parameter,
        0.0,
        0.0,
        0.0,
        0,
    ) else {
        return;
    };
    if snapshot.augmented_values.len() != augmented_values.len()
        || snapshot.augmented_rhs.len() != rhs_prefinal.len()
        || solution_prefinal_unrefined.len() != snapshot.matrix_dimension
    {
        return;
    }
    snapshot.augmented_values.copy_from_slice(augmented_values);
    snapshot.augmented_rhs.copy_from_slice(rhs_prefinal);

    let n = snapshot.x_dimension;
    let meq = snapshot.equality_dimension;
    let mineq = snapshot.inequality_dimension;
    let mut cumulative_solution = solution_prefinal_unrefined.to_vec();
    let refinement_steps = refinement_corrections
        .iter()
        .enumerate()
        .map(|(step_index, (correction_rhs, correction_solution))| {
            for (slot, correction) in cumulative_solution
                .iter_mut()
                .zip(correction_solution.iter())
            {
                *slot = ipopt_blas_axpy_value(*slot, -1.0, *correction);
            }
            let residual_ratios = refinement_trace_steps.get(step_index);
            IpoptLinearRefinementStepTrace {
                correction_rhs: correction_rhs.clone(),
                correction_solution: correction_solution.clone(),
                solution_prefinal_after: cumulative_solution.clone(),
                full_residual: None,
                residual_ratio_before: residual_ratios
                    .map_or(f64::NAN, |step| step.residual_ratio_before),
                residual_ratio_after: residual_ratios
                    .map_or(f64::NAN, |step| step.residual_ratio_after),
            }
        })
        .collect::<Vec<_>>();
    let linear_trace = IpoptLinearSolveTrace {
        rhs_prefinal: rhs_prefinal.to_vec(),
        solution_prefinal_unrefined: solution_prefinal_unrefined.to_vec(),
        refinement_steps,
    };
    let direction = NewtonDirection {
        dx: solution_prefinal_unrefined[..n].to_vec(),
        d_lambda: solution_prefinal_unrefined[snapshot.augmented_pattern.lambda_offset
            ..snapshot.augmented_pattern.lambda_offset + meq]
            .to_vec(),
        d_ineq: solution_prefinal_unrefined
            [snapshot.augmented_pattern.z_offset..snapshot.augmented_pattern.z_offset + mineq]
            .to_vec(),
        ds: solution_prefinal_unrefined
            [snapshot.augmented_pattern.p_offset..snapshot.augmented_pattern.p_offset + mineq]
            .to_vec(),
        dz: vec![0.0; mineq],
        dz_lower: Vec::new(),
        dz_upper: Vec::new(),
        solver_used: InteriorPointLinearSolver::SpralSrc,
        regularization_used: primal_shift,
        dual_regularization_used: dual_shift,
        primal_diagonal_shift_used: primal_shift,
        linear_solution: solution_prefinal_unrefined.to_vec(),
        linear_trace: Some(linear_trace),
        backend_stats: backend_stats.clone(),
        linear_debug: None,
    };
    let report = InteriorPointLinearDebugReport {
        primary_solver: InteriorPointLinearSolver::SpralSrc,
        schedule: InteriorPointLinearDebugSchedule::EveryIteration,
        verdict: InteriorPointLinearDebugVerdict::Consistent,
        results: vec![linear_debug_result_from_stats(
            &direction,
            &direction.backend_stats,
            primal_shift,
        )],
        notes: vec!["aug_resto_inner_reduced_system".to_string()],
    };
    let options = InteriorPointLinearDebugOptions {
        compare_solvers: Vec::new(),
        schedule: InteriorPointLinearDebugSchedule::EveryIteration,
        dump_dir: Some(parent_dump_dir.join("aug_resto_inner")),
    };
    dump_linear_debug_snapshot(&options, &snapshot, &report, Some(&direction));

    let component_dir = parent_dump_dir.join("aug_resto_inner");
    let _ = fs::create_dir_all(&component_dir);
    let component_path =
        component_dir.join(format!("nlip_reduction_components_iter_{iteration:04}.txt"));
    let meq = restoration_reduced_kkt.sigma_nc_inv.len();
    let mineq = restoration_reduced_kkt.sigma_nd_inv.len();
    let reduced_rhs_c = &initial_reduced_rhs.augmented_rhs
        [snapshot.augmented_pattern.lambda_offset..snapshot.augmented_pattern.lambda_offset + meq];
    let reduced_rhs_d = &initial_reduced_rhs.augmented_rhs
        [snapshot.augmented_pattern.z_offset..snapshot.augmented_pattern.z_offset + mineq];
    let sigma_nc_tilde = restoration_reduced_kkt
        .sigma_nc_inv
        .iter()
        .map(|value| value.recip())
        .collect::<Vec<_>>();
    let sigma_pc_tilde = restoration_reduced_kkt
        .sigma_pc_inv
        .iter()
        .map(|value| value.recip())
        .collect::<Vec<_>>();
    let sigma_nd_tilde = restoration_reduced_kkt
        .sigma_nd_inv
        .iter()
        .map(|value| value.recip())
        .collect::<Vec<_>>();
    let sigma_pd_tilde = restoration_reduced_kkt
        .sigma_pd_inv
        .iter()
        .map(|value| value.recip())
        .collect::<Vec<_>>();
    let mut body = String::new();
    body.push_str(&format!(
        "iteration={iteration}\nphase={phase:?}\noriginal_reduced_dimension={}\nfull_reduced_dimension={}\nnc_offset={}\npc_offset={}\nnd_offset={}\npd_offset={}\nmeq={meq}\nmineq={mineq}\n",
        restoration_reduced_kkt.original_reduced_dimension,
        restoration_reduced_kkt.full_reduced_dimension,
        restoration_reduced_kkt.nc_offset,
        restoration_reduced_kkt.pc_offset,
        restoration_reduced_kkt.nd_offset,
        restoration_reduced_kkt.pd_offset,
    ));
    body.push_str(&format!(
        "sigma_nc_tilde={:?}\nsigma_pc_tilde={:?}\nsigma_nd_tilde={:?}\nsigma_pd_tilde={:?}\nsigma_nc_inv={:?}\nsigma_pc_inv={:?}\nsigma_nd_inv={:?}\nsigma_pd_inv={:?}\nrhs_nc={:?}\nrhs_pc={:?}\nrhs_nd={:?}\nrhs_pd={:?}\nreduced_rhs_c={:?}\nreduced_rhs_d={:?}\nequality_diagonal={:?}\ninequality_diagonal={:?}\nreduced_r_dual={:?}\nreduced_r_eq={:?}\nreduced_r_ineq={:?}\nreduced_bound_diagonal={:?}\nreduced_bound_rhs={:?}\n",
        sigma_nc_tilde,
        sigma_pc_tilde,
        sigma_nd_tilde,
        sigma_pd_tilde,
        restoration_reduced_kkt.sigma_nc_inv,
        restoration_reduced_kkt.sigma_pc_inv,
        restoration_reduced_kkt.sigma_nd_inv,
        restoration_reduced_kkt.sigma_pd_inv,
        initial_reduced_rhs.rhs_nc,
        initial_reduced_rhs.rhs_pc,
        initial_reduced_rhs.rhs_nd,
        initial_reduced_rhs.rhs_pd,
        reduced_rhs_c,
        reduced_rhs_d,
        restoration_reduced_kkt.equality_diagonal,
        restoration_reduced_kkt.inequality_diagonal,
        restoration_reduced_kkt.r_dual,
        restoration_reduced_kkt.r_eq,
        restoration_reduced_kkt.r_ineq,
        restoration_reduced_kkt.bound_diagonal,
        restoration_reduced_kkt.bound_rhs,
    ));
    let _ = fs::write(component_path, body);
}

fn spawn_spral_stage_heartbeat(label: &'static str) -> (Arc<AtomicBool>, thread::JoinHandle<()>) {
    let finished = Arc::new(AtomicBool::new(false));
    let finished_for_thread = Arc::clone(&finished);
    let handle = thread::spawn(move || {
        let started = Instant::now();
        let mut next_notice_after = Duration::from_secs(5);
        loop {
            let elapsed = started.elapsed();
            if elapsed < next_notice_after {
                thread::park_timeout(next_notice_after - elapsed);
            }
            if finished_for_thread.load(Ordering::Relaxed) {
                break;
            }
            if let Some(progress) = spral_current_factorization_progress() {
                let root_tail_status = if progress.current_root_delayed_block > 0 {
                    format!(
                        " root_delayed={}/{} size={} stage={}",
                        progress.current_root_delayed_block,
                        progress.total_root_delayed_blocks,
                        progress.current_root_delayed_block_size,
                        progress.root_delayed_stage.label(),
                    )
                } else if progress.completed_root_delayed_blocks > 0
                    && progress.completed_pivots < progress.total_pivots
                {
                    format!(
                        " root_delayed={}/{} stage=between_blocks",
                        progress.completed_root_delayed_blocks, progress.total_root_delayed_blocks,
                    )
                } else {
                    String::new()
                };
                println!(
                    "{label} still running after {}: weighted={:.0}% pivots={}/{} ({:.0}%) fronts={}/{} roots={}/{}{}",
                    compact_duration_text(started.elapsed().as_secs_f64()),
                    progress.weighted_percent(),
                    progress.completed_pivots,
                    progress.total_pivots,
                    progress.pivot_percent(),
                    progress.completed_fronts,
                    progress.total_fronts,
                    progress.completed_roots,
                    progress.total_roots,
                    root_tail_status,
                );
            } else {
                println!(
                    "{label} still running after {}",
                    compact_duration_text(started.elapsed().as_secs_f64()),
                );
            }
            next_notice_after += Duration::from_secs(10);
        }
    });
    (finished, handle)
}

#[derive(Clone)]
struct EvalState {
    objective_value: f64,
    gradient: Vec<f64>,
    equality_values: Vec<f64>,
    augmented_inequality_values: Vec<f64>,
    equality_jacobian: SparseMatrix,
    inequality_jacobian: SparseMatrix,
}

fn eval_state_is_finite(state: &EvalState) -> bool {
    state.objective_value.is_finite()
        && state.gradient.iter().all(|value| value.is_finite())
        && state.equality_values.iter().all(|value| value.is_finite())
        && state
            .augmented_inequality_values
            .iter()
            .all(|value| value.is_finite())
        && state
            .equality_jacobian
            .values
            .iter()
            .all(|value| value.is_finite())
        && state
            .inequality_jacobian
            .values
            .iter()
            .all(|value| value.is_finite())
}

fn evaluation_error_line_search_trial(
    alpha_pr: f64,
    alpha_du: f64,
    slack_positive: bool,
    multipliers_positive: bool,
) -> InteriorPointLineSearchTrial {
    InteriorPointLineSearchTrial {
        alpha: alpha_pr,
        alpha_du: Some(alpha_du),
        slack_positive,
        multipliers_positive,
        objective: None,
        barrier_objective: None,
        merit: None,
        eq_inf: None,
        ineq_inf: None,
        primal_inf: None,
        dual_inf: None,
        comp_inf: None,
        mu: None,
        local_filter_acceptable: None,
        filter_acceptable: None,
        filter_dominated: None,
        filter_sufficient_objective_reduction: None,
        filter_sufficient_violation_reduction: None,
        switching_condition_satisfied: None,
    }
}

fn ipopt_last_rejection_due_to_filter(rejected_trials: &[InteriorPointLineSearchTrial]) -> bool {
    let mut last_rejection_due_to_filter = false;
    for trial in rejected_trials {
        match (
            trial.local_filter_acceptable,
            trial.filter_acceptable,
            trial.objective.is_some(),
        ) {
            (Some(true), Some(false), _) => {
                last_rejection_due_to_filter = true;
            }
            (Some(false), _, _) => {
                last_rejection_due_to_filter = false;
            }
            (None, None, false) => {
                // BacktrackingLineSearch catches Eval_Error without touching
                // FilterLSAcceptor::last_rejection_due_to_filter_.
            }
            _ => {}
        }
    }
    last_rejection_due_to_filter
}

fn ipopt_filter_reset_heuristic_applies(
    filter_reset_heuristic_checked: bool,
    max_filter_resets: Index,
    filter_reset_trigger: Index,
    last_rejection_due_to_filter: bool,
    successive_filter_rejections: &mut Index,
) -> bool {
    if !filter_reset_heuristic_checked || max_filter_resets == 0 {
        return false;
    }

    if last_rejection_due_to_filter {
        *successive_filter_rejections += 1;
        if *successive_filter_rejections >= filter_reset_trigger {
            // IPOPT 3.14's n_filter_resets_ is checked but not incremented, so
            // max_filter_resets behaves as an enable/disable flag in practice.
            *successive_filter_rejections = 0;
            true
        } else {
            false
        }
    } else {
        *successive_filter_rejections = 0;
        false
    }
}

fn merit_residual(primal_inf: f64, dual_inf: f64, complementarity_inf: f64, mu: f64) -> f64 {
    primal_inf.max(dual_inf).max(complementarity_inf).max(mu)
}

fn l1_norm(values: &[f64]) -> f64 {
    values.iter().map(|value| value.abs()).sum()
}

fn slack_form_inequality_residuals(augmented_inequality_values: &[f64], slack: &[f64]) -> Vec<f64> {
    debug_assert_eq!(augmented_inequality_values.len(), slack.len());
    augmented_inequality_values
        .iter()
        .zip(slack.iter())
        .map(|(&g_i, &s_i)| g_i - s_i)
        .collect()
}

fn slack_form_inequality_l1_norm(augmented_inequality_values: &[f64], slack: &[f64]) -> f64 {
    debug_assert_eq!(augmented_inequality_values.len(), slack.len());
    augmented_inequality_values
        .iter()
        .zip(slack.iter())
        .map(|(&g_i, &s_i)| (g_i - s_i).abs())
        .sum()
}

fn slack_form_inequality_inf_norm(augmented_inequality_values: &[f64], slack: &[f64]) -> f64 {
    debug_assert_eq!(augmented_inequality_values.len(), slack.len());
    augmented_inequality_values
        .iter()
        .zip(slack.iter())
        .fold(0.0, |acc, (&g_i, &s_i)| acc.max((g_i - s_i).abs()))
}

fn filter_theta_l1_norm(
    equality_values: &[f64],
    augmented_inequality_values: &[f64],
    slack: &[f64],
) -> f64 {
    l1_norm(equality_values) + slack_form_inequality_l1_norm(augmented_inequality_values, slack)
}

fn native_lower_bound_slack(x: &[f64], index: usize, lower: f64) -> f64 {
    x[index] - lower
}

fn native_upper_bound_slack(x: &[f64], index: usize, upper: f64) -> f64 {
    upper - x[index]
}

fn bound_relaxation_amount(bound: f64, options: &InteriorPointOptions) -> f64 {
    if options.bound_relax_factor <= 0.0 {
        return 0.0;
    }
    options
        .constraint_tol
        .min(options.bound_relax_factor * bound.abs().max(1.0))
}

fn slack_bound_relaxation(options: &InteriorPointOptions) -> f64 {
    bound_relaxation_amount(0.0, options)
}

fn slack_upper_bound_values(count: usize, options: &InteriorPointOptions) -> Vec<f64> {
    vec![slack_bound_relaxation(options); count]
}

fn inequality_upper_bound_inf_norm(values: &[f64], upper_bounds: &[f64]) -> f64 {
    debug_assert_eq!(values.len(), upper_bounds.len());
    values
        .iter()
        .zip(upper_bounds.iter())
        .fold(0.0_f64, |acc, (&value, &upper)| {
            acc.max((value - upper).max(0.0))
        })
}

fn slack_barrier_values(slack: &[f64], upper_bounds: &[f64]) -> Vec<f64> {
    debug_assert_eq!(slack.len(), upper_bounds.len());
    // NLIP stores inequality slacks in IPOPT's internal upper-bound
    // convention: d(x) - s = 0 and s <= d_U. IPOPT's barrier,
    // complementarity, and sigma routines operate on curr_slack_s_U = d_U - s.
    // See IpIpoptCalculatedQuantities.cpp::curr_slack_s_U/curr_sigma_s and
    // OrigIpoptNLP.cpp::relax_bounds for the relaxed d_U construction.
    upper_bounds
        .iter()
        .zip(slack.iter())
        .map(|(&upper, &value)| upper - value)
        .collect()
}

#[derive(Clone)]
struct TrialSafeSlackState {
    lower_slack: Vec<f64>,
    upper_slack: Vec<f64>,
    slack_barrier: Vec<f64>,
    adjusted_slacks: Index,
    bounds: BoundConstraints,
    slack_upper_bounds: Vec<f64>,
}

impl TrialSafeSlackState {
    fn all_strictly_positive(&self) -> bool {
        self.lower_slack.iter().all(|value| *value > 0.0)
            && self.upper_slack.iter().all(|value| *value > 0.0)
            && self.slack_barrier.iter().all(|value| *value > 0.0)
    }

    fn bound_adjustment(&self) -> Option<AcceptedTrialBoundAdjustment> {
        (self.adjusted_slacks > 0).then(|| AcceptedTrialBoundAdjustment {
            adjusted_slacks: self.adjusted_slacks,
            bounds: self.bounds.clone(),
            slack_upper_bounds: self.slack_upper_bounds.clone(),
        })
    }
}

struct TrialSafeSlackInputs<'a> {
    trial_x: &'a [f64],
    trial_slack: &'a [f64],
    bounds: &'a BoundConstraints,
    slack_upper_bounds: &'a [f64],
    current_z_lower: &'a [f64],
    current_z_upper: &'a [f64],
    current_z: &'a [f64],
    mu: f64,
    slack_move: f64,
}

fn ipopt_safe_slack_min(mu: f64) -> f64 {
    let mut s_min = f64::EPSILON * 1.0_f64.min(mu);
    if s_min == 0.0 {
        s_min = f64::MIN_POSITIVE;
    }
    s_min
}

fn ipopt_calculate_safe_slack(
    slack: f64,
    bound: f64,
    multiplier: f64,
    mu: f64,
    slack_move: f64,
) -> (f64, bool) {
    let s_min = ipopt_safe_slack_min(mu);
    if slack >= s_min {
        return (slack, false);
    }

    let nonnegative_slack = slack.max(0.0);
    let target = (mu / multiplier).max(s_min);
    let max_moved = slack_move.mul_add(bound.abs().max(1.0), nonnegative_slack);
    (target.min(max_moved), true)
}

fn trial_safe_slack_state(inputs: TrialSafeSlackInputs<'_>) -> TrialSafeSlackState {
    debug_assert_eq!(
        inputs.bounds.lower_indices.len(),
        inputs.current_z_lower.len()
    );
    debug_assert_eq!(
        inputs.bounds.upper_indices.len(),
        inputs.current_z_upper.len()
    );
    debug_assert_eq!(inputs.slack_upper_bounds.len(), inputs.trial_slack.len());
    debug_assert_eq!(inputs.current_z.len(), inputs.trial_slack.len());

    let mut adjusted_slacks = 0;
    let mut adjusted_bounds = inputs.bounds.clone();
    let lower_slack = inputs
        .bounds
        .lower_indices
        .iter()
        .zip(inputs.bounds.lower_values.iter())
        .zip(inputs.current_z_lower.iter())
        .zip(adjusted_bounds.lower_values.iter_mut())
        .map(|(((&index, &lower), &multiplier), adjusted_lower)| {
            let slack = native_lower_bound_slack(inputs.trial_x, index, lower);
            let (safe_slack, adjusted) =
                ipopt_calculate_safe_slack(slack, lower, multiplier, inputs.mu, inputs.slack_move);
            if adjusted {
                adjusted_slacks += 1;
            }
            *adjusted_lower = inputs.trial_x[index] - safe_slack;
            safe_slack
        })
        .collect::<Vec<_>>();
    let upper_slack = inputs
        .bounds
        .upper_indices
        .iter()
        .zip(inputs.bounds.upper_values.iter())
        .zip(inputs.current_z_upper.iter())
        .zip(adjusted_bounds.upper_values.iter_mut())
        .map(|(((&index, &upper), &multiplier), adjusted_upper)| {
            let slack = native_upper_bound_slack(inputs.trial_x, index, upper);
            let (safe_slack, adjusted) =
                ipopt_calculate_safe_slack(slack, upper, multiplier, inputs.mu, inputs.slack_move);
            if adjusted {
                adjusted_slacks += 1;
            }
            *adjusted_upper = inputs.trial_x[index] + safe_slack;
            safe_slack
        })
        .collect::<Vec<_>>();
    let mut adjusted_slack_upper_bounds = inputs.slack_upper_bounds.to_vec();
    let slack_barrier = inputs
        .slack_upper_bounds
        .iter()
        .zip(inputs.trial_slack.iter())
        .zip(inputs.current_z.iter())
        .zip(adjusted_slack_upper_bounds.iter_mut())
        .map(|(((&upper, &slack_value), &multiplier), adjusted_upper)| {
            let slack = upper - slack_value;
            let (safe_slack, adjusted) =
                ipopt_calculate_safe_slack(slack, upper, multiplier, inputs.mu, inputs.slack_move);
            if adjusted {
                adjusted_slacks += 1;
            }
            *adjusted_upper = slack_value + safe_slack;
            safe_slack
        })
        .collect::<Vec<_>>();

    TrialSafeSlackState {
        lower_slack,
        upper_slack,
        slack_barrier,
        adjusted_slacks,
        bounds: adjusted_bounds,
        slack_upper_bounds: adjusted_slack_upper_bounds,
    }
}

fn apply_ipopt_upper_slack_magic_step(
    slack: &mut [f64],
    augmented_inequality_values: &[f64],
    upper_bounds: &[f64],
) -> bool {
    debug_assert_eq!(slack.len(), augmented_inequality_values.len());
    debug_assert_eq!(slack.len(), upper_bounds.len());
    // BacktrackingLineSearch::PerformMagicStep first projects the trial
    // d(x)-s residual onto bounded slack variables. NLIP's inequality
    // representation has only IPOPT's upper slack bound d_U, so the Pd_U slice
    // reduces to delta_s_magic = min(0, trial_d_minus_s).
    let mut delta_s_magic_amax = 0.0_f64;
    for (&d_i, s_i) in augmented_inequality_values.iter().zip(slack.iter_mut()) {
        let delta = (d_i - *s_i).min(0.0);
        delta_s_magic_amax = delta_s_magic_amax.max(delta.abs());
        *s_i += delta;
    }
    delta_s_magic_amax > 0.0
}

fn slack_barrier_direction_values(slack_direction: &[f64]) -> Vec<f64> {
    slack_direction.iter().map(|value| -*value).collect()
}

fn native_lower_bound_log_sum(x: &[f64], bounds: &BoundConstraints) -> f64 {
    bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .map(|(&index, &lower)| native_lower_bound_slack(x, index, lower).ln())
        .sum::<f64>()
}

fn native_upper_bound_log_sum(x: &[f64], bounds: &BoundConstraints) -> f64 {
    bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .map(|(&index, &upper)| native_upper_bound_slack(x, index, upper).ln())
        .sum::<f64>()
}

fn native_lower_bound_damping_sum(x: &[f64], bounds: &BoundConstraints) -> f64 {
    bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .filter(|(index, _)| !bounds.upper_indices.contains(index))
        .map(|(&index, &lower)| native_lower_bound_slack(x, index, lower))
        .sum::<f64>()
}

fn native_upper_bound_damping_sum(x: &[f64], bounds: &BoundConstraints) -> f64 {
    bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .filter(|(index, _)| !bounds.lower_indices.contains(index))
        .map(|(&index, &upper)| native_upper_bound_slack(x, index, upper))
        .sum::<f64>()
}

fn positive_slack_damping(barrier_parameter: f64, kappa_d: f64) -> f64 {
    if barrier_parameter > 0.0 && kappa_d > 0.0 {
        barrier_parameter * kappa_d
    } else {
        0.0
    }
}

fn system_positive_slack_damping(system: &ReducedKktSystem<'_>) -> f64 {
    system.damping_rhs_scale * positive_slack_damping(system.barrier_parameter, system.kappa_d)
}

fn damped_slack_stationarity_residual(system: &ReducedKktSystem<'_>, index: usize) -> f64 {
    system.r_slack_stationarity[index] - system_positive_slack_damping(system)
}

fn lower_bound_complementarity_rhs(
    system: &ReducedKktSystem<'_>,
    position: usize,
    slack: f64,
    multiplier: f64,
) -> f64 {
    system
        .bound_complementarity_lower_rhs
        .and_then(|rhs| rhs.get(position))
        .copied()
        .unwrap_or(slack * multiplier - system.barrier_parameter)
}

fn upper_bound_complementarity_rhs(
    system: &ReducedKktSystem<'_>,
    position: usize,
    slack: f64,
    multiplier: f64,
) -> f64 {
    system
        .bound_complementarity_upper_rhs
        .and_then(|rhs| rhs.get(position))
        .copied()
        .unwrap_or(slack * multiplier - system.barrier_parameter)
}

fn fill_ipopt_augmented_x_rhs(rhs: &mut [f64], system: &ReducedKktSystem<'_>, sign: f64) {
    let rhs_scale = system.primal_dual_rhs_scale;
    if let Some(bound_data) = system.bound_data {
        rhs.iter_mut()
            .zip(system.r_dual.iter())
            .for_each(|(rhs_i, r_i)| *rhs_i = sign * rhs_scale * *r_i);
        let damping = system_positive_slack_damping(system);
        // Mirrors IpPDSearchDirCalc.cpp::ComputeSearchDirection followed by
        // IpPDFullSpaceSolver.cpp::SolveOnce: `augRhs_x` starts as
        // `curr_grad_lag_with_damping_x`, then lower and upper bound relaxed
        // complementarity terms are applied with AddMSinvZ in this order.
        for (bound_position, ((&index, &lower), &z_i)) in bound_data
            .bounds
            .lower_indices
            .iter()
            .zip(bound_data.bounds.lower_values.iter())
            .zip(bound_data.z_lower.iter())
            .enumerate()
        {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                continue;
            };
            if damping > 0.0 && !bound_data.bounds.upper_indices.contains(&index) {
                rhs[reduced_index] += sign * rhs_scale * damping;
            }
            let slack = native_lower_bound_slack(bound_data.x, index, lower);
            let relaxed_complementarity =
                lower_bound_complementarity_rhs(system, bound_position, slack, z_i);
            rhs[reduced_index] += sign * (relaxed_complementarity / slack);
        }
        for (bound_position, ((&index, &upper), &z_i)) in bound_data
            .bounds
            .upper_indices
            .iter()
            .zip(bound_data.bounds.upper_values.iter())
            .zip(bound_data.z_upper.iter())
            .enumerate()
        {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                continue;
            };
            if damping > 0.0 && !bound_data.bounds.lower_indices.contains(&index) {
                rhs[reduced_index] += sign * rhs_scale * -damping;
            }
            let slack = native_upper_bound_slack(bound_data.x, index, upper);
            let relaxed_complementarity =
                upper_bound_complementarity_rhs(system, bound_position, slack, z_i);
            rhs[reduced_index] += sign * -(relaxed_complementarity / slack);
        }
    } else {
        rhs.iter_mut()
            .zip(system.r_dual.iter())
            .zip(system.bound_rhs.iter())
            .for_each(|((rhs_i, r_i), bound_rhs_i)| {
                *rhs_i = sign * (rhs_scale * *r_i - *bound_rhs_i)
            });
    }
}

fn build_ipopt_augmented_kkt_rhs(
    system: &ReducedKktSystem<'_>,
    pattern: &SpralAugmentedKktPattern,
    orientation: IpoptLinearRhsOrientation,
) -> Vec<f64> {
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let mut rhs = vec![0.0; pattern.dimension()];
    let sign = orientation.rhs_sign();
    fill_ipopt_augmented_x_rhs(&mut rhs[..n], system, sign);
    for row in 0..mineq {
        // Mirror IpPDFullSpaceSolver::SolveOnce: augRhs_s starts as
        // rhs.s(), then Pd_U.AddMSinvZ(-1.0, slack_s_U, rhs.v_U(), augRhs_s)
        // applies `rhs_s -= rhs_v / slack`. This avoids the different rounding
        // from the algebraically equivalent `-(rhs_v / slack - rhs_s)`.
        let mut rhs_s =
            sign * system.primal_dual_rhs_scale * damped_slack_stationarity_residual(system, row);
        rhs_s -= (sign * system.r_cent[row]) / system.slack[row];
        rhs[pattern.p_offset + row] = rhs_s;
    }
    for row in 0..meq {
        rhs[pattern.lambda_offset + row] = sign * system.r_eq[row];
    }
    for row in 0..mineq {
        rhs[pattern.z_offset + row] = sign * system.r_ineq[row];
    }
    rhs
}

fn ipopt_final_upper_slack_bound_multiplier_step(
    slack: f64,
    multiplier: f64,
    complementarity_residual: f64,
    ipopt_internal_slack_step: f64,
) -> f64 {
    // Mirrors IPOPT's operation order in PDFullSpaceSolver::Solve:
    // SolveOnce first computes Pd_U.SinvBlrmZMTdBr(1., ...) using the
    // pre-final slack step, then PDSearchDirCalc's Solve(-1., 0., ...) negates
    // the whole IteratesVector. Keep that order instead of recomputing the
    // algebraically equivalent final formula directly.
    -ipopt_prefinal_upper_slack_bound_multiplier_step(
        slack,
        multiplier,
        complementarity_residual,
        -ipopt_internal_slack_step,
    )
}

fn ipopt_prefinal_upper_slack_bound_multiplier_step(
    slack: f64,
    multiplier: f64,
    complementarity_residual: f64,
    ipopt_internal_slack_step: f64,
) -> f64 {
    // Mirrors IPOPT PDFullSpaceSolver::SolveOnce Pd_U.SinvBlrmZMTdBr(1., ...)
    // before PDSearchDirCalc's final Solve(-1., 0., ...) scaling.
    multiplier.mul_add(ipopt_internal_slack_step, complementarity_residual) / slack
}

fn ipopt_oriented_upper_slack_bound_multiplier_step(
    slack: f64,
    multiplier: f64,
    oriented_complementarity_rhs: f64,
    oriented_slack_step: f64,
) -> f64 {
    // Mirrors ExpansionMatrix::SinvBlrmZMTdBrImpl for the upper slack block:
    // X[i] = (R[i] + Z[i] * D[exp_pos[i]]) / S[i].  The caller passes R and D
    // in the same orientation as the current PDFullSpaceSolver rhs/res vector.
    multiplier.mul_add(oriented_slack_step, oriented_complementarity_rhs) / slack
}

fn ipopt_oriented_lower_bound_multiplier_step(
    slack: f64,
    multiplier: f64,
    oriented_complementarity_rhs: f64,
    oriented_primal_step: f64,
) -> f64 {
    // Mirrors IPOPT PDFullSpaceSolver::SolveOnce:
    // Px_L.SinvBlrmZMTdBr(-1., slack_x_L, rhs.z_L, z_L, sol.x, sol.z_L).
    (-multiplier).mul_add(oriented_primal_step, oriented_complementarity_rhs) / slack
}

fn ipopt_oriented_upper_bound_multiplier_step(
    slack: f64,
    multiplier: f64,
    oriented_complementarity_rhs: f64,
    oriented_primal_step: f64,
) -> f64 {
    // Mirrors IPOPT PDFullSpaceSolver::SolveOnce:
    // Px_U.SinvBlrmZMTdBr(1., slack_x_U, rhs.z_U, z_U, sol.x, sol.z_U).
    multiplier.mul_add(oriented_primal_step, oriented_complementarity_rhs) / slack
}

fn ipopt_bound_multiplier_steps_for_orientation(
    system: &ReducedKktSystem<'_>,
    bound_data: ReducedBoundKktData<'_>,
    reduced_primal_step: &[f64],
    orientation: IpoptLinearRhsOrientation,
) -> (Vec<f64>, Vec<f64>) {
    let sign = orientation.rhs_sign();
    let lower_steps = bound_data
        .bounds
        .lower_indices
        .iter()
        .zip(bound_data.bounds.lower_values.iter())
        .zip(bound_data.z_lower.iter())
        .enumerate()
        .map(|(bound_position, ((&index, &lower), &z_i))| {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                return 0.0;
            };
            let slack = native_lower_bound_slack(bound_data.x, index, lower);
            let complementarity =
                lower_bound_complementarity_rhs(system, bound_position, slack, z_i);
            ipopt_oriented_lower_bound_multiplier_step(
                slack,
                z_i,
                sign * complementarity,
                reduced_primal_step[reduced_index],
            )
        })
        .collect::<Vec<_>>();
    let upper_steps = bound_data
        .bounds
        .upper_indices
        .iter()
        .zip(bound_data.bounds.upper_values.iter())
        .zip(bound_data.z_upper.iter())
        .enumerate()
        .map(|(bound_position, ((&index, &upper), &z_i))| {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                return 0.0;
            };
            let slack = native_upper_bound_slack(bound_data.x, index, upper);
            let complementarity =
                upper_bound_complementarity_rhs(system, bound_position, slack, z_i);
            ipopt_oriented_upper_bound_multiplier_step(
                slack,
                z_i,
                sign * complementarity,
                reduced_primal_step[reduced_index],
            )
        })
        .collect::<Vec<_>>();
    (lower_steps, upper_steps)
}

fn ipopt_upper_slack_bound_multiplier_steps_for_orientation(
    system: &ReducedKktSystem<'_>,
    slack_steps: &[f64],
    orientation: IpoptLinearRhsOrientation,
) -> Vec<f64> {
    let sign = orientation.rhs_sign();
    system
        .r_cent
        .iter()
        .zip(system.multipliers.iter())
        .zip(system.slack.iter())
        .zip(slack_steps.iter())
        .map(|(((r_cent_i, z_i), s_i), ds_i)| {
            ipopt_oriented_upper_slack_bound_multiplier_step(*s_i, *z_i, sign * *r_cent_i, *ds_i)
        })
        .collect()
}

fn slack_stationarity_residuals(lambda_ineq: &[f64], z: &[f64]) -> Vec<f64> {
    lambda_ineq
        .iter()
        .zip(z.iter())
        .map(|(y_i, z_i)| z_i - y_i)
        .collect()
}

fn slack_stationarity_inf_norm(lambda_ineq: &[f64], z: &[f64]) -> f64 {
    lambda_ineq
        .iter()
        .zip(z.iter())
        .fold(0.0_f64, |acc, (y_i, z_i)| acc.max((z_i - y_i).abs()))
}

fn damped_slack_stationarity_residuals(
    lambda_ineq: &[f64],
    z: &[f64],
    barrier_parameter: f64,
    kappa_d: f64,
) -> Vec<f64> {
    let damping = positive_slack_damping(barrier_parameter, kappa_d);
    slack_stationarity_residuals(lambda_ineq, z)
        .into_iter()
        .map(|residual| residual - damping)
        .collect()
}

fn slack_complementarity_residuals(slack_barrier: &[f64], z: &[f64], mu: f64) -> Vec<f64> {
    slack_barrier
        .iter()
        .zip(z.iter())
        .map(|(slack_i, z_i)| slack_i * z_i - mu)
        .collect()
}

fn slack_sigma_values(slack_barrier: &[f64], z: &[f64]) -> Vec<f64> {
    slack_barrier
        .iter()
        .zip(z.iter())
        .map(|(slack_i, z_i)| z_i / slack_i)
        .collect()
}

fn barrier_objective_value(
    objective_value: f64,
    slack: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    barrier_parameter: f64,
    kappa_d: f64,
) -> f64 {
    if (slack.is_empty() && bounds.total_count() == 0) || barrier_parameter <= 0.0 {
        return objective_value;
    }
    // Mirror IpoptCalculatedQuantities::CalcBarrierTerm: accumulate x_L,
    // x_U, s_L, then s_U before applying -mu, then add damping in the same
    // component order. NLIP currently has only upper slacks for inequalities.
    let mut barrier_term = 0.0;
    barrier_term += native_lower_bound_log_sum(x, bounds);
    barrier_term += native_upper_bound_log_sum(x, bounds);
    barrier_term += slack.iter().map(|value| value.ln()).sum::<f64>();
    let mut result = objective_value + (-barrier_parameter * barrier_term);
    let damping_weight = positive_slack_damping(barrier_parameter, kappa_d);
    if damping_weight > 0.0 {
        result += damping_weight * native_lower_bound_damping_sum(x, bounds);
        result += damping_weight * native_upper_bound_damping_sum(x, bounds);
        result += damping_weight * slack.iter().sum::<f64>();
    }
    result
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT filter derivative uses separate primal, slack, bound, and damping inputs."
)]
fn barrier_objective_directional_derivative(
    gradient: &[f64],
    slack: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    dx: &[f64],
    ds: &[f64],
    barrier_parameter: f64,
    kappa_d: f64,
) -> f64 {
    if (slack.is_empty() && bounds.total_count() == 0) || barrier_parameter <= 0.0 {
        return gradient
            .iter()
            .zip(dx.iter())
            .map(|(gradient_i, dx_i)| gradient_i * dx_i)
            .sum::<f64>();
    }
    // Mirror IpoptCalculatedQuantities::curr_gradBarrTDelta: first build
    // curr_grad_barrier_obj_x and curr_grad_barrier_obj_s in source order, then
    // take the two dots. This preserves IPOPT's x_L/x_U/s_L/s_U update order
    // instead of regrouping the algebra into independent sums.
    let mut grad_x = gradient.to_vec();
    for (&index, &lower) in bounds.lower_indices.iter().zip(bounds.lower_values.iter()) {
        grad_x[index] += -barrier_parameter / native_lower_bound_slack(x, index, lower);
    }
    for (&index, &upper) in bounds.upper_indices.iter().zip(bounds.upper_values.iter()) {
        grad_x[index] += barrier_parameter / native_upper_bound_slack(x, index, upper);
    }
    let damping_weight = positive_slack_damping(barrier_parameter, kappa_d);
    if damping_weight > 0.0 {
        for &index in bounds
            .lower_indices
            .iter()
            .filter(|index| !bounds.upper_indices.contains(index))
        {
            grad_x[index] += damping_weight;
        }
        for &index in bounds
            .upper_indices
            .iter()
            .filter(|index| !bounds.lower_indices.contains(index))
        {
            grad_x[index] -= damping_weight;
        }
    }
    let x_dot = grad_x
        .iter()
        .zip(dx.iter())
        .map(|(gradient_i, dx_i)| gradient_i * dx_i)
        .sum::<f64>();

    let mut grad_s = vec![0.0; slack.len()];
    for (grad_i, slack_i) in grad_s.iter_mut().zip(slack.iter()) {
        *grad_i += barrier_parameter / slack_i;
    }
    if damping_weight > 0.0 {
        for grad_i in &mut grad_s {
            *grad_i -= damping_weight;
        }
    }
    let s_dot = grad_s
        .iter()
        .zip(ds.iter())
        .map(|(gradient_i, ds_i)| gradient_i * ds_i)
        .sum::<f64>();
    x_dot + s_dot
}

fn ipopt_filter_reference_directional_derivative(theta: f64, derivative: f64) -> f64 {
    let mach_eps = f64::EPSILON;
    if theta == 0.0 && derivative > 0.0 && derivative < 100.0 * mach_eps {
        -mach_eps
    } else {
        derivative
    }
}

fn filter_switching_assessment_inputs(
    theta: f64,
    barrier_directional_derivative: f64,
    alpha_primal: f64,
    options: &InteriorPointOptions,
) -> (f64, bool) {
    let effective_derivative =
        ipopt_filter_reference_directional_derivative(theta, barrier_directional_derivative);
    (
        effective_derivative,
        effective_derivative < 0.0
            && alpha_primal * (-effective_derivative).powf(options.s_phi)
                > options.delta * theta.max(0.0).powf(options.s_theta),
    )
}

fn calculate_filter_alpha_min(
    theta: f64,
    theta_min: f64,
    barrier_directional_derivative: f64,
    options: &InteriorPointOptions,
) -> f64 {
    let mut alpha_min = options.filter_gamma_violation;
    if barrier_directional_derivative < 0.0 {
        alpha_min = alpha_min.min(
            options.filter_gamma_objective * theta
                / (-barrier_directional_derivative).max(f64::MIN_POSITIVE),
        );
        if theta <= theta_min {
            alpha_min = alpha_min.min(
                options.delta * theta.max(0.0).powf(options.s_theta)
                    / (-barrier_directional_derivative).powf(options.s_phi),
            );
        }
    }
    // IPOPT `FilterLSAcceptor::CalculateAlphaMin` returns only
    // `alpha_min_frac * alpha_min`; the backtracking loop itself is
    // responsible for always checking the first trial point.
    options.alpha_min_frac * alpha_min
}

fn barrier_objective_increase_too_large(
    reference_barrier_objective: f64,
    trial_barrier_objective: f64,
    obj_max_inc: f64,
) -> bool {
    if trial_barrier_objective <= reference_barrier_objective {
        return false;
    }
    let increase = trial_barrier_objective - reference_barrier_objective;
    let mut baseline = 1.0;
    if reference_barrier_objective.abs() > 10.0 {
        baseline = reference_barrier_objective.abs().log10();
    }
    increase > 0.0 && increase.log10() > obj_max_inc + baseline
}

fn should_reduce_barrier_parameter(
    barrier_subproblem_error: f64,
    barrier_parameter: f64,
    options: &InteriorPointOptions,
) -> bool {
    barrier_subproblem_error <= options.barrier_tol_factor * barrier_parameter
}

fn minimum_monotone_barrier_parameter(options: &InteriorPointOptions) -> f64 {
    let tol = options.overall_tol.min(options.complementarity_tol);
    // IPOPT MonotoneMuUpdate::CalcNewMuAndTau uses mu_target and the
    // tol/compl_inf_tol floor here. The separate mu_min option belongs to the
    // adaptive/free-mu path, not to monotone mu updates.
    options
        .mu_target
        .max(tol / (options.barrier_tol_factor + 1.0))
}

fn next_barrier_parameter_once(barrier_parameter: f64, options: &InteriorPointOptions) -> f64 {
    let minimum_barrier = minimum_monotone_barrier_parameter(options);
    if barrier_parameter <= minimum_barrier {
        return minimum_barrier;
    }
    minimum_barrier.max(
        (options.mu_linear_decrease_factor * barrier_parameter)
            .min(barrier_parameter.powf(options.mu_superlinear_decrease_power)),
    )
}

#[derive(Clone, Copy, Debug, PartialEq)]
struct MonotoneBarrierUpdate {
    barrier_parameter: f64,
    stop_at_tiny_step: bool,
}

fn next_barrier_parameter<F>(
    barrier_parameter: f64,
    tiny_step: bool,
    mu_update_initialized: bool,
    options: &InteriorPointOptions,
    mut barrier_error: F,
) -> MonotoneBarrierUpdate
where
    F: FnMut(f64) -> f64,
{
    let mut current_barrier = barrier_parameter;
    let mut current_tiny_step = tiny_step;
    let minimum_barrier = minimum_monotone_barrier_parameter(options);
    loop {
        let current_barrier_error = barrier_error(current_barrier);
        if !current_tiny_step
            && !should_reduce_barrier_parameter(current_barrier_error, current_barrier, options)
        {
            break;
        }
        let next_barrier = next_barrier_parameter_once(current_barrier, options);
        // IpMonotoneMuUpdate::UpdateBarrierParameter uses exact `mu !=
        // new_mu` to decide whether the barrier changed; avoid a local
        // tolerance that can skip a source-visible mu update near the floor.
        if next_barrier == current_barrier {
            if current_tiny_step {
                return MonotoneBarrierUpdate {
                    barrier_parameter: current_barrier.max(minimum_barrier),
                    stop_at_tiny_step: true,
                };
            }
            break;
        }
        current_barrier = next_barrier.max(minimum_barrier);
        if mu_update_initialized && !options.mu_allow_fast_monotone_decrease {
            break;
        }
        current_tiny_step = false;
    }
    MonotoneBarrierUpdate {
        barrier_parameter: current_barrier.max(minimum_barrier),
        stop_at_tiny_step: false,
    }
}

fn skip_first_restoration_barrier_update(
    restoration_depth: Index,
    mu_update_initialized: bool,
) -> bool {
    // IPOPT MonotoneMuUpdate::UpdateBarrierParameter excludes the update loop
    // while first_iter_resto_ is set, then clears the flag at the end of the
    // first restoration-phase call.
    restoration_depth > 0 && !mu_update_initialized
}

fn initial_monotone_barrier_parameter(
    has_barrier_pairs: bool,
    options: &InteriorPointOptions,
) -> f64 {
    if has_barrier_pairs {
        // IPOPT IpMonotoneMuUpdate::Initialize sets IpData().Set_mu(mu_init_)
        // directly; mu_min and current complementarity belong to other update
        // modes and must not alter the monotone initial barrier parameter.
        options.mu_init
    } else {
        0.0
    }
}

#[derive(Clone, Copy, Debug, PartialEq)]
struct AdaptiveMuFilterEntry {
    objective: f64,
    constraint_violation: f64,
}

#[derive(Clone, Debug)]
struct AdaptiveMuAcceptedIterate {
    x: Vec<f64>,
    lambda_eq: Vec<f64>,
    lambda_ineq: Vec<f64>,
    slack: Vec<f64>,
    slack_barrier: Vec<f64>,
    z: Vec<f64>,
    z_lower: Vec<f64>,
    z_upper: Vec<f64>,
    r_dual: Vec<f64>,
    r_eq: Vec<f64>,
    r_ineq: Vec<f64>,
    r_slack_stationarity: Vec<f64>,
}

#[derive(Clone, Debug)]
struct AdaptiveMuUpdateState {
    mu_max: f64,
    initial_dual_inf: Option<f64>,
    initial_primal_inf: Option<f64>,
    no_bounds_checked: bool,
    no_bounds: bool,
    free_mu_mode: bool,
    filter_entries: Vec<AdaptiveMuFilterEntry>,
    kkt_error_refs: Vec<f64>,
    accepted_iterate: Option<AdaptiveMuAcceptedIterate>,
}

impl Default for AdaptiveMuUpdateState {
    fn default() -> Self {
        Self {
            mu_max: -1.0,
            initial_dual_inf: None,
            initial_primal_inf: None,
            no_bounds_checked: false,
            no_bounds: false,
            free_mu_mode: true,
            filter_entries: Vec::new(),
            kkt_error_refs: Vec::new(),
            accepted_iterate: None,
        }
    }
}

#[derive(Clone)]
struct AdaptiveMuUpdateResult {
    mu: f64,
    tau: f64,
    reset_line_search: bool,
    restored_iterate: Option<AdaptiveMuAcceptedIterate>,
    affine_direction: Option<NewtonDirection>,
    improve_direction: Option<NewtonDirection>,
}

#[expect(
    clippy::too_many_arguments,
    reason = "The adaptive-mu restore option snapshots the full IPOPT current iterate and residual blocks."
)]
fn adaptive_mu_current_iterate_snapshot(
    options: &InteriorPointOptions,
    x: &[f64],
    lambda_eq: &[f64],
    lambda_ineq: &[f64],
    slack: &[f64],
    slack_barrier: &[f64],
    z: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    r_dual: &[f64],
    r_eq: &[f64],
    r_ineq: &[f64],
    r_slack_stationarity: &[f64],
) -> Option<AdaptiveMuAcceptedIterate> {
    options
        .adaptive_mu_restore_previous_iterate
        .then(|| AdaptiveMuAcceptedIterate {
            x: x.to_vec(),
            lambda_eq: lambda_eq.to_vec(),
            lambda_ineq: lambda_ineq.to_vec(),
            slack: slack.to_vec(),
            slack_barrier: slack_barrier.to_vec(),
            z: z.to_vec(),
            z_lower: z_lower.to_vec(),
            z_upper: z_upper.to_vec(),
            r_dual: r_dual.to_vec(),
            r_eq: r_eq.to_vec(),
            r_ineq: r_ineq.to_vec(),
            r_slack_stationarity: r_slack_stationarity.to_vec(),
        })
}

#[expect(
    clippy::too_many_arguments,
    reason = "Restoring an IPOPT accepted iterate mutates every primal and multiplier block."
)]
fn apply_adaptive_mu_restored_iterate(
    restored_iterate: AdaptiveMuAcceptedIterate,
    x: &mut Vec<f64>,
    lambda_eq: &mut Vec<f64>,
    lambda_ineq: &mut Vec<f64>,
    slack: &mut Vec<f64>,
    z: &mut Vec<f64>,
    z_lower: &mut Vec<f64>,
    z_upper: &mut Vec<f64>,
    nonlinear_inequality_multipliers: &mut Vec<f64>,
) {
    *x = restored_iterate.x;
    *lambda_eq = restored_iterate.lambda_eq;
    *lambda_ineq = restored_iterate.lambda_ineq;
    *slack = restored_iterate.slack;
    *z = restored_iterate.z;
    *z_lower = restored_iterate.z_lower;
    *z_upper = restored_iterate.z_upper;
    *nonlinear_inequality_multipliers = lambda_ineq.clone();
}

#[derive(Clone, Copy, Debug)]
struct ComplementarityProductStats {
    count: usize,
    abs_sum: f64,
    squared_sum: f64,
    abs_max: f64,
    min_product: f64,
}

impl ComplementarityProductStats {
    fn empty() -> Self {
        Self {
            count: 0,
            abs_sum: 0.0,
            squared_sum: 0.0,
            abs_max: 0.0,
            min_product: f64::INFINITY,
        }
    }

    fn push(&mut self, value: f64) {
        let abs_value = value.abs();
        self.count += 1;
        self.abs_sum += abs_value;
        self.squared_sum += value * value;
        self.abs_max = self.abs_max.max(abs_value);
        self.min_product = self.min_product.min(value);
    }

    fn average(self) -> f64 {
        if self.count == 0 {
            0.0
        } else {
            self.abs_sum / self.count as f64
        }
    }

    fn centrality_measure(self) -> f64 {
        if self.count == 0 {
            return 0.0;
        }
        debug_assert!(
            self.min_product > 0.0,
            "IPOPT expects strictly positive complementarity products"
        );
        let average = self.average();
        if average <= 0.0 {
            0.0
        } else {
            (self.min_product / average).min(1.0)
        }
    }

    fn norm_measure(self, norm_type: InteriorPointQualityFunctionNorm) -> f64 {
        quality_function_norm_measure(
            norm_type,
            self.abs_sum,
            self.squared_sum,
            self.abs_max,
            self.count,
        )
    }
}

fn complementarity_product_stats(
    slack: &[f64],
    z: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
) -> ComplementarityProductStats {
    let mut stats = ComplementarityProductStats::empty();
    for (&slack_i, &z_i) in slack.iter().zip(z.iter()) {
        stats.push(slack_i * z_i);
    }
    for ((&index, &lower), &z_i) in bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .zip(z_lower.iter())
    {
        stats.push(native_lower_bound_slack(x, index, lower) * z_i);
    }
    for ((&index, &upper), &z_i) in bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .zip(z_upper.iter())
    {
        stats.push(native_upper_bound_slack(x, index, upper) * z_i);
    }
    stats
}

fn adaptive_mu_min(options: &InteriorPointOptions) -> f64 {
    // IpAdaptiveMuUpdate::UpdateBarrierParameter computes the default mu_min
    // lazily after NLP scaling is known. NLIP parity runs use no objective
    // scaling, so this is min(mu_min, 0.5 * min(tol, compl_inf_tol)).
    options
        .mu_min
        .min(0.5 * options.overall_tol.min(options.complementarity_tol))
}

fn adaptive_mu_initial_max(
    state: &mut AdaptiveMuUpdateState,
    stats: ComplementarityProductStats,
    options: &InteriorPointOptions,
) -> f64 {
    if let Some(mu_max) = options.mu_max {
        state.mu_max = mu_max;
    } else if state.mu_max < 0.0 {
        state.mu_max = options.mu_max_fact * stats.average();
    }
    state.mu_max
}

fn loqo_adaptive_mu_from_stats(
    mu_min: f64,
    mu_max: f64,
    stats: ComplementarityProductStats,
) -> f64 {
    let average = stats.average();
    let xi = stats.centrality_measure();
    let centrality_factor = if xi <= 0.0 {
        2.0
    } else {
        (0.05 * (1.0 - xi) / xi).min(2.0)
    };
    let sigma = 0.1 * centrality_factor.powi(3);
    (sigma * average).min(mu_max).max(mu_min)
}

fn adaptive_mu_filter_acceptable(
    entries: &[AdaptiveMuFilterEntry],
    objective: f64,
    constraint_violation: f64,
) -> bool {
    entries.iter().all(|entry| {
        objective <= entry.objective || constraint_violation <= entry.constraint_violation
    })
}

fn adaptive_mu_filter_update_frontier(
    entries: &mut Vec<AdaptiveMuFilterEntry>,
    accepted: AdaptiveMuFilterEntry,
) {
    entries.retain(|entry| {
        accepted.objective > entry.objective
            || accepted.constraint_violation > entry.constraint_violation
    });
    entries.push(accepted);
}

fn adaptive_mu_check_sufficient_progress(
    objective: f64,
    constraint_violation: f64,
    nlp_error: f64,
    kkt_error: f64,
    state: &AdaptiveMuUpdateState,
    options: &InteriorPointOptions,
) -> bool {
    match options.adaptive_mu_globalization {
        InteriorPointAdaptiveMuGlobalization::NeverMonotoneMode => true,
        InteriorPointAdaptiveMuGlobalization::ObjectiveConstraintFilter => {
            let margin = options.adaptive_mu_filter_margin_fact
                * options.adaptive_mu_filter_max_margin.min(nlp_error);
            adaptive_mu_filter_acceptable(
                &state.filter_entries,
                objective + margin,
                constraint_violation + margin,
            )
        }
        InteriorPointAdaptiveMuGlobalization::KktError => {
            if state.kkt_error_refs.len() < options.adaptive_mu_kkt_error_red_iters {
                return true;
            }
            state
                .kkt_error_refs
                .iter()
                .any(|&reference| kkt_error <= options.adaptive_mu_kkt_error_red_fact * reference)
        }
    }
}

fn adaptive_mu_remember_current_point_as_accepted(
    objective: f64,
    constraint_violation: f64,
    kkt_error: f64,
    current_iterate: Option<AdaptiveMuAcceptedIterate>,
    state: &mut AdaptiveMuUpdateState,
    options: &InteriorPointOptions,
) {
    match options.adaptive_mu_globalization {
        InteriorPointAdaptiveMuGlobalization::NeverMonotoneMode => {}
        InteriorPointAdaptiveMuGlobalization::ObjectiveConstraintFilter => {
            adaptive_mu_filter_update_frontier(
                &mut state.filter_entries,
                AdaptiveMuFilterEntry {
                    objective,
                    constraint_violation,
                },
            );
        }
        InteriorPointAdaptiveMuGlobalization::KktError => {
            if options.adaptive_mu_kkt_error_red_iters > 0 {
                if state.kkt_error_refs.len() >= options.adaptive_mu_kkt_error_red_iters {
                    state.kkt_error_refs.remove(0);
                }
                state.kkt_error_refs.push(kkt_error);
            }
        }
    }
    if options.adaptive_mu_restore_previous_iterate {
        state.accepted_iterate = current_iterate;
    }
}

fn adaptive_mu_restored_fixed_mode_components(
    state: &mut AdaptiveMuUpdateState,
    bounds: &BoundConstraints,
    current_stats: ComplementarityProductStats,
    current_lower_mu_safeguard: f64,
    options: &InteriorPointOptions,
) -> (
    ComplementarityProductStats,
    f64,
    Option<AdaptiveMuAcceptedIterate>,
) {
    if !options.adaptive_mu_restore_previous_iterate {
        return (current_stats, current_lower_mu_safeguard, None);
    }

    let Some(restored_iterate) = state.accepted_iterate.clone() else {
        return (current_stats, current_lower_mu_safeguard, None);
    };
    let restored_stats = complementarity_product_stats(
        &restored_iterate.slack_barrier,
        &restored_iterate.z,
        &restored_iterate.x,
        bounds,
        &restored_iterate.z_lower,
        &restored_iterate.z_upper,
    );
    let (restored_dual_l1_average, restored_primal_l1_average) =
        adaptive_mu_l1_infeasibility_averages(
            &restored_iterate.r_dual,
            &restored_iterate.r_eq,
            &restored_iterate.r_ineq,
            &restored_iterate.r_slack_stationarity,
        );
    let restored_lower_mu_safeguard = adaptive_mu_lower_safeguard(
        restored_dual_l1_average,
        restored_primal_l1_average,
        state,
        options,
    );
    (
        restored_stats,
        restored_lower_mu_safeguard,
        Some(restored_iterate),
    )
}

fn adaptive_fixed_mu_from_current_complementarity(
    mu_min: f64,
    mu_max: f64,
    stats: ComplementarityProductStats,
    lower_mu_safeguard: f64,
    options: &InteriorPointOptions,
) -> f64 {
    let mut new_mu = options.adaptive_mu_monotone_init_factor * stats.average();
    new_mu = new_mu.max(lower_mu_safeguard);
    new_mu = new_mu.max(mu_min);
    new_mu.min(mu_max)
}

fn adaptive_fixed_mu_reduction(barrier_parameter: f64, options: &InteriorPointOptions) -> f64 {
    let floor =
        options.overall_tol.min(options.complementarity_tol) / (options.barrier_tol_factor + 1.0);
    let new_mu = (options.mu_linear_decrease_factor * barrier_parameter)
        .min(barrier_parameter.powf(options.mu_superlinear_decrease_power));
    new_mu.max(floor)
}

fn adaptive_free_mu_oracle_update(
    nlp_error: f64,
    mu_min: f64,
    mu_max: f64,
    lower_mu_safeguard: f64,
    stats: ComplementarityProductStats,
    options: &InteriorPointOptions,
) -> AdaptiveMuUpdateResult {
    let tau = options
        .fraction_to_boundary
        .max(1.0 - nlp_error)
        .clamp(0.0, 1.0);
    let mut mu = loqo_adaptive_mu_from_stats(mu_min.max(options.mu_target), mu_max, stats);
    mu = mu.max(mu_min);
    if mu < lower_mu_safeguard {
        mu = lower_mu_safeguard;
    }
    mu = mu.min(mu_max);
    AdaptiveMuUpdateResult {
        mu,
        tau,
        reset_line_search: true,
        restored_iterate: None,
        affine_direction: None,
        improve_direction: None,
    }
}

fn adaptive_mu_l1_infeasibility_averages(
    r_dual: &[f64],
    r_eq: &[f64],
    r_ineq: &[f64],
    r_slack_stationarity: &[f64],
) -> (f64, f64) {
    let n_dual = r_dual.len() + r_slack_stationarity.len();
    debug_assert!(n_dual > 0);
    let dual_inf = if n_dual > 0 {
        (l1_norm(r_dual) + l1_norm(r_slack_stationarity)) / n_dual as f64
    } else {
        0.0
    };

    let n_primal = r_eq.len() + r_ineq.len();
    let primal_inf = if n_primal > 0 {
        (l1_norm(r_eq) + l1_norm(r_ineq)) / n_primal as f64
    } else {
        0.0
    };

    (dual_inf, primal_inf)
}

fn adaptive_mu_lower_safeguard(
    dual_inf: f64,
    primal_inf: f64,
    state: &mut AdaptiveMuUpdateState,
    options: &InteriorPointOptions,
) -> f64 {
    if options.adaptive_mu_safeguard_factor == 0.0 {
        return 0.0;
    }

    let initial_dual_inf = *state
        .initial_dual_inf
        .get_or_insert_with(|| 1.0_f64.max(dual_inf));
    let initial_primal_inf = *state
        .initial_primal_inf
        .get_or_insert_with(|| 1.0_f64.max(primal_inf));

    let dual_safeguard = options.adaptive_mu_safeguard_factor * dual_inf / initial_dual_inf;
    let primal_safeguard = options.adaptive_mu_safeguard_factor * primal_inf / initial_primal_inf;
    let mut lower_mu_safeguard = dual_safeguard.max(primal_safeguard);
    if matches!(
        options.adaptive_mu_globalization,
        InteriorPointAdaptiveMuGlobalization::KktError
    ) && let Some(min_ref) = state.kkt_error_refs.iter().copied().reduce(f64::min)
    {
        lower_mu_safeguard = lower_mu_safeguard.min(min_ref);
    }
    lower_mu_safeguard
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT AdaptiveMuUpdate::quality_function_pd_system combines all residual and complementarity blocks."
)]
fn adaptive_mu_quality_function_pd_system_error(
    x: &[f64],
    bounds: &BoundConstraints,
    slack_barrier: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    z: &[f64],
    r_dual: &[f64],
    r_eq: &[f64],
    r_ineq: &[f64],
    r_slack_stationarity: &[f64],
    options: &InteriorPointOptions,
) -> f64 {
    let norm_type = options.quality_function_norm_type;
    let dual_inf =
        scaled_quality_function_norm_measure(norm_type, 1.0, r_dual, r_slack_stationarity);
    let primal_inf = scaled_quality_function_norm_measure(norm_type, 1.0, r_eq, r_ineq);
    let complementarity_stats =
        complementarity_product_stats(slack_barrier, z, x, bounds, z_lower, z_upper);
    let complementarity = complementarity_stats.norm_measure(norm_type);

    add_quality_function_centrality_and_balancing(
        dual_inf,
        primal_inf,
        complementarity,
        complementarity_stats,
        options,
    )
}

const QUALITY_FUNCTION_SIGMA_MAX: f64 = 1.0e2;
const QUALITY_FUNCTION_SIGMA_MIN: f64 = 1.0e-6;
const QUALITY_FUNCTION_MAX_SECTION_STEPS: usize = 8;
const QUALITY_FUNCTION_SECTION_SIGMA_TOL: f64 = 1.0e-2;
const QUALITY_FUNCTION_SECTION_QF_TOL: f64 = 0.0;

fn ipopt_affine_centering_step(affine: f64, sigma: f64, centering: f64) -> f64 {
    if sigma == 0.0 {
        affine
    } else if sigma == 1.0 {
        affine + centering
    } else if sigma == -1.0 {
        affine - centering
    } else {
        sigma.mul_add(centering, affine)
    }
}

fn squared_norm(values: &[f64]) -> f64 {
    values.iter().map(|value| value * value).sum()
}

fn quality_function_norm_measure(
    norm_type: InteriorPointQualityFunctionNorm,
    l1: f64,
    squared: f64,
    max_abs: f64,
    count: usize,
) -> f64 {
    if count == 0 {
        return 0.0;
    }
    match norm_type {
        InteriorPointQualityFunctionNorm::OneNorm => l1 / count as f64,
        InteriorPointQualityFunctionNorm::TwoNormSquared => squared / count as f64,
        InteriorPointQualityFunctionNorm::MaxNorm => max_abs,
        InteriorPointQualityFunctionNorm::TwoNorm => squared.sqrt() / (count as f64).sqrt(),
    }
}

fn scaled_quality_function_norm_measure(
    norm_type: InteriorPointQualityFunctionNorm,
    scale: f64,
    first: &[f64],
    second: &[f64],
) -> f64 {
    let count = first.len() + second.len();
    if count == 0 {
        return 0.0;
    }
    match norm_type {
        InteriorPointQualityFunctionNorm::OneNorm => {
            scale * (l1_norm(first) + l1_norm(second)) / count as f64
        }
        InteriorPointQualityFunctionNorm::TwoNormSquared => {
            scale.powi(2) * (squared_norm(first) + squared_norm(second)) / count as f64
        }
        InteriorPointQualityFunctionNorm::MaxNorm => scale * inf_norm(first).max(inf_norm(second)),
        InteriorPointQualityFunctionNorm::TwoNorm => {
            scale * (squared_norm(first) + squared_norm(second)).sqrt() / (count as f64).sqrt()
        }
    }
}

fn add_quality_function_centrality_and_balancing(
    dual_inf: f64,
    primal_inf: f64,
    compl_inf: f64,
    complementarity_stats: ComplementarityProductStats,
    options: &InteriorPointOptions,
) -> f64 {
    let mut quality_function = dual_inf + primal_inf + compl_inf;
    match options.quality_function_centrality {
        InteriorPointQualityFunctionCentrality::None => {}
        InteriorPointQualityFunctionCentrality::Log => {
            quality_function -= compl_inf * complementarity_stats.centrality_measure().ln();
        }
        InteriorPointQualityFunctionCentrality::Reciprocal => {
            quality_function += compl_inf / complementarity_stats.centrality_measure();
        }
        InteriorPointQualityFunctionCentrality::CubedReciprocal => {
            quality_function += compl_inf / complementarity_stats.centrality_measure().powi(3);
        }
    }
    match options.quality_function_balancing_term {
        InteriorPointQualityFunctionBalancingTerm::None => {}
        InteriorPointQualityFunctionBalancingTerm::Cubic => {
            quality_function += (dual_inf.max(primal_inf) - compl_inf).max(0.0).powi(3);
        }
    }
    quality_function
}

fn quality_function_primal_fraction_to_boundary(
    x: &[f64],
    bounds: &BoundConstraints,
    slack_barrier: &[f64],
    step_x: &[f64],
    step_s: &[f64],
    tau: f64,
) -> f64 {
    let mut alpha = 1.0_f64;
    for (&index, &lower) in bounds.lower_indices.iter().zip(bounds.lower_values.iter()) {
        let value = native_lower_bound_slack(x, index, lower);
        let delta = step_x[index];
        if delta < 0.0 {
            alpha = alpha.min(ipopt_dense_frac_to_bound_candidate(tau, value, delta));
        }
    }
    for (&index, &upper) in bounds.upper_indices.iter().zip(bounds.upper_values.iter()) {
        let value = native_upper_bound_slack(x, index, upper);
        let delta = -step_x[index];
        if delta < 0.0 {
            alpha = alpha.min(ipopt_dense_frac_to_bound_candidate(tau, value, delta));
        }
    }
    for (&value, &delta_s) in slack_barrier.iter().zip(step_s.iter()) {
        let delta = -delta_s;
        if delta < 0.0 {
            alpha = alpha.min(ipopt_dense_frac_to_bound_candidate(tau, value, delta));
        }
    }
    alpha
}

#[expect(
    clippy::too_many_arguments,
    reason = "QualityFunctionMuOracle evaluates all current residual and complementarity blocks explicitly."
)]
fn quality_function_value(
    sigma: f64,
    x: &[f64],
    bounds: &BoundConstraints,
    slack_barrier: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    z: &[f64],
    r_dual: &[f64],
    r_eq: &[f64],
    r_ineq: &[f64],
    r_slack_stationarity: &[f64],
    tau: f64,
    step_aff: &NewtonDirection,
    step_cen: &NewtonDirection,
    options: &InteriorPointOptions,
) -> f64 {
    let step_x = step_aff
        .dx
        .iter()
        .zip(step_cen.dx.iter())
        .map(|(&aff, &cen)| ipopt_affine_centering_step(aff, sigma, cen))
        .collect::<Vec<_>>();
    let step_s = step_aff
        .ds
        .iter()
        .zip(step_cen.ds.iter())
        .map(|(&aff, &cen)| ipopt_affine_centering_step(aff, sigma, cen))
        .collect::<Vec<_>>();
    let step_z_lower = step_aff
        .dz_lower
        .iter()
        .zip(step_cen.dz_lower.iter())
        .map(|(&aff, &cen)| ipopt_affine_centering_step(aff, sigma, cen))
        .collect::<Vec<_>>();
    let step_z_upper = step_aff
        .dz_upper
        .iter()
        .zip(step_cen.dz_upper.iter())
        .map(|(&aff, &cen)| ipopt_affine_centering_step(aff, sigma, cen))
        .collect::<Vec<_>>();
    let step_z = step_aff
        .dz
        .iter()
        .zip(step_cen.dz.iter())
        .map(|(&aff, &cen)| ipopt_affine_centering_step(aff, sigma, cen))
        .collect::<Vec<_>>();

    let alpha_primal = quality_function_primal_fraction_to_boundary(
        x,
        bounds,
        slack_barrier,
        &step_x,
        &step_s,
        tau,
    );
    let (alpha_dual, _) = ipopt_dual_fraction_to_boundary_with_limiter(
        z_lower,
        &step_z_lower,
        z_upper,
        &step_z_upper,
        z,
        &step_z,
        tau,
    );

    let mut complementarity_stats = ComplementarityProductStats::empty();
    for (position, (&index, &lower)) in bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .enumerate()
    {
        let slack = native_lower_bound_slack(x, index, lower);
        let trial_slack = ipopt_dense_current_plus_step(slack, alpha_primal, step_x[index]);
        let trial_z =
            ipopt_dense_current_plus_step(z_lower[position], alpha_dual, step_z_lower[position]);
        let product = trial_slack * trial_z;
        complementarity_stats.push(product);
    }
    for (position, (&index, &upper)) in bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .enumerate()
    {
        let slack = native_upper_bound_slack(x, index, upper);
        let trial_slack = ipopt_dense_current_plus_step(slack, alpha_primal, -step_x[index]);
        let trial_z =
            ipopt_dense_current_plus_step(z_upper[position], alpha_dual, step_z_upper[position]);
        let product = trial_slack * trial_z;
        complementarity_stats.push(product);
    }
    for (position, (&slack, &step_s_i)) in slack_barrier.iter().zip(step_s.iter()).enumerate() {
        let trial_slack = ipopt_dense_current_plus_step(slack, alpha_primal, -step_s_i);
        let trial_z = ipopt_dense_current_plus_step(z[position], alpha_dual, step_z[position]);
        let product = trial_slack * trial_z;
        complementarity_stats.push(product);
    }

    let n_dual = r_dual.len() + r_slack_stationarity.len();
    debug_assert!(n_dual > 0);
    debug_assert!(complementarity_stats.count > 0);

    let one_minus_alpha_dual = 1.0 - alpha_dual;
    let one_minus_alpha_primal = 1.0 - alpha_primal;
    let norm_type = options.quality_function_norm_type;
    let dual_inf = scaled_quality_function_norm_measure(
        norm_type,
        one_minus_alpha_dual,
        r_dual,
        r_slack_stationarity,
    );
    let primal_inf =
        scaled_quality_function_norm_measure(norm_type, one_minus_alpha_primal, r_eq, r_ineq);
    let compl_inf = complementarity_stats.norm_measure(norm_type);

    add_quality_function_centrality_and_balancing(
        dual_inf,
        primal_inf,
        compl_inf,
        complementarity_stats,
        options,
    )
}

#[derive(Clone, Copy, Debug)]
struct QualityFunctionSectionSearchOptions {
    sigma_tol: f64,
    qf_tol: f64,
    max_steps: usize,
}

fn quality_function_golden_section(
    sigma_up_in: f64,
    mut q_up: f64,
    sigma_lo_in: f64,
    mut q_lo: f64,
    search_options: QualityFunctionSectionSearchOptions,
    mut evaluate: impl FnMut(f64) -> f64,
) -> f64 {
    let scale_sigma = |sigma: f64| sigma;
    let unscale_sigma = |scaled_sigma: f64| scaled_sigma;
    let mut sigma_up = scale_sigma(sigma_up_in);
    let mut sigma_lo = scale_sigma(sigma_lo_in);
    let gfac = (3.0 - 5.0_f64.sqrt()) / 2.0;
    let mut sigma_mid1 = sigma_lo + gfac * (sigma_up - sigma_lo);
    let mut sigma_mid2 = sigma_lo + (1.0 - gfac) * (sigma_up - sigma_lo);
    let mut qmid1 = evaluate(unscale_sigma(sigma_mid1));
    let mut qmid2 = evaluate(unscale_sigma(sigma_mid2));
    let mut nsections = 0;

    while (sigma_up - sigma_lo) >= search_options.sigma_tol * sigma_up
        && (1.0
            - ipopt_cxx_min(ipopt_cxx_min(q_lo, q_up), ipopt_cxx_min(qmid1, qmid2))
                / ipopt_cxx_max(ipopt_cxx_max(q_lo, q_up), ipopt_cxx_max(qmid1, qmid2)))
            >= search_options.qf_tol
        && nsections < search_options.max_steps
    {
        nsections += 1;
        if qmid1 > qmid2 {
            sigma_lo = sigma_mid1;
            q_lo = qmid1;
            sigma_mid1 = sigma_mid2;
            qmid1 = qmid2;
            sigma_mid2 = sigma_lo + (1.0 - gfac) * (sigma_up - sigma_lo);
            qmid2 = evaluate(unscale_sigma(sigma_mid2));
        } else {
            sigma_up = sigma_mid2;
            q_up = qmid2;
            sigma_mid2 = sigma_mid1;
            qmid2 = qmid1;
            sigma_mid1 = sigma_lo + gfac * (sigma_up - sigma_lo);
            qmid1 = evaluate(unscale_sigma(sigma_mid1));
        }
    }

    if (sigma_up - sigma_lo) >= search_options.sigma_tol * sigma_up
        && (1.0
            - ipopt_cxx_min(ipopt_cxx_min(q_lo, q_up), ipopt_cxx_min(qmid1, qmid2))
                / ipopt_cxx_max(ipopt_cxx_max(q_lo, q_up), ipopt_cxx_max(qmid1, qmid2)))
            < search_options.qf_tol
    {
        let qf_min = ipopt_cxx_min(ipopt_cxx_min(q_lo, q_up), ipopt_cxx_min(qmid1, qmid2));
        let sigma = if qf_min == q_lo {
            sigma_lo
        } else if qf_min == qmid1 {
            sigma_mid1
        } else if qf_min == qmid2 {
            sigma_mid2
        } else {
            sigma_up
        };
        unscale_sigma(sigma)
    } else {
        let (mut sigma, q) = if qmid1 < qmid2 {
            (sigma_mid1, qmid1)
        } else {
            (sigma_mid2, qmid2)
        };
        if sigma_up == scale_sigma(sigma_up_in) {
            let qtmp = if q_up < 0.0 {
                evaluate(unscale_sigma(sigma_up))
            } else {
                q_up
            };
            if qtmp < q {
                sigma = sigma_up;
            }
        } else if sigma_lo == scale_sigma(sigma_lo_in) {
            let qtmp = if q_lo < 0.0 {
                evaluate(unscale_sigma(sigma_lo))
            } else {
                q_lo
            };
            if qtmp < q {
                sigma = sigma_lo;
            }
        }
        unscale_sigma(sigma)
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT ProbingMuOracle::CalculateAffineMu evaluates all complementarity blocks."
)]
fn probing_affine_average_complementarity(
    x: &[f64],
    bounds: &BoundConstraints,
    slack_barrier: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    z: &[f64],
    alpha_primal: f64,
    alpha_dual: f64,
    step: &NewtonDirection,
) -> f64 {
    let n_complementarity = z_lower.len() + z_upper.len() + z.len();
    debug_assert!(n_complementarity > 0);
    if n_complementarity == 0 {
        return 0.0;
    }

    let mut sum = 0.0_f64;
    for (position, (&index, &lower)) in bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .enumerate()
    {
        let trial_slack = ipopt_dense_current_plus_step(
            native_lower_bound_slack(x, index, lower),
            alpha_primal,
            step.dx[index],
        );
        let trial_z =
            ipopt_dense_current_plus_step(z_lower[position], alpha_dual, step.dz_lower[position]);
        sum += trial_slack * trial_z;
    }
    for (position, (&index, &upper)) in bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .enumerate()
    {
        let trial_slack = ipopt_dense_current_plus_step(
            native_upper_bound_slack(x, index, upper),
            alpha_primal,
            -step.dx[index],
        );
        let trial_z =
            ipopt_dense_current_plus_step(z_upper[position], alpha_dual, step.dz_upper[position]);
        sum += trial_slack * trial_z;
    }
    for (position, (&slack, &step_s_i)) in slack_barrier.iter().zip(step.ds.iter()).enumerate() {
        let trial_slack = ipopt_dense_current_plus_step(slack, alpha_primal, -step_s_i);
        let trial_z = ipopt_dense_current_plus_step(z[position], alpha_dual, step.dz[position]);
        sum += trial_slack * trial_z;
    }

    sum / n_complementarity as f64
}

struct IpoptMehrotraComplementarityRhs {
    r_cent: Vec<f64>,
    lower: Vec<f64>,
    upper: Vec<f64>,
}

fn ipopt_mehrotra_complementarity_rhs(
    system: &ReducedKktSystem<'_>,
    fixed_variables: &FixedVariableElimination,
    affine_direction: &NewtonDirection,
) -> IpoptMehrotraComplementarityRhs {
    let affine_full_dx = fixed_variables.expand_direction(&affine_direction.dx);
    let r_cent = system
        .r_cent
        .iter()
        .zip(affine_direction.ds.iter())
        .zip(affine_direction.dz.iter())
        .map(|((&relaxed, &ds_i), &dz_i)| {
            let product = (-ds_i) * dz_i;
            ipopt_blas_axpy_value(relaxed, 1.0, product)
        })
        .collect::<Vec<_>>();
    let Some(bound_data) = system.bound_data else {
        return IpoptMehrotraComplementarityRhs {
            r_cent,
            lower: Vec::new(),
            upper: Vec::new(),
        };
    };
    let lower = bound_data
        .bounds
        .lower_indices
        .iter()
        .zip(bound_data.bounds.lower_values.iter())
        .zip(bound_data.z_lower.iter())
        .zip(affine_direction.dz_lower.iter())
        .enumerate()
        .map(|(position, (((&index, &lower), &z_i), &dz_i))| {
            let slack = native_lower_bound_slack(bound_data.x, index, lower);
            let relaxed = lower_bound_complementarity_rhs(system, position, slack, z_i);
            let product = affine_full_dx[index] * dz_i;
            ipopt_blas_axpy_value(relaxed, 1.0, product)
        })
        .collect::<Vec<_>>();
    let upper = bound_data
        .bounds
        .upper_indices
        .iter()
        .zip(bound_data.bounds.upper_values.iter())
        .zip(bound_data.z_upper.iter())
        .zip(affine_direction.dz_upper.iter())
        .enumerate()
        .map(|(position, (((&index, &upper), &z_i), &dz_i))| {
            let slack = native_upper_bound_slack(bound_data.x, index, upper);
            let relaxed = upper_bound_complementarity_rhs(system, position, slack, z_i);
            let product = (-affine_full_dx[index]) * dz_i;
            ipopt_blas_axpy_value(relaxed, 1.0, product)
        })
        .collect::<Vec<_>>();

    IpoptMehrotraComplementarityRhs {
        r_cent,
        lower,
        upper,
    }
}

fn ipopt_quality_function_combined_direction(
    affine: &NewtonDirection,
    centering: &NewtonDirection,
    sigma: f64,
) -> NewtonDirection {
    let mut combined = affine.clone();
    for ((value, &affine_i), &centering_i) in combined
        .dx
        .iter_mut()
        .zip(affine.dx.iter())
        .zip(centering.dx.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    for ((value, &affine_i), &centering_i) in combined
        .d_lambda
        .iter_mut()
        .zip(affine.d_lambda.iter())
        .zip(centering.d_lambda.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    for ((value, &affine_i), &centering_i) in combined
        .d_ineq
        .iter_mut()
        .zip(affine.d_ineq.iter())
        .zip(centering.d_ineq.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    for ((value, &affine_i), &centering_i) in combined
        .ds
        .iter_mut()
        .zip(affine.ds.iter())
        .zip(centering.ds.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    for ((value, &affine_i), &centering_i) in combined
        .dz
        .iter_mut()
        .zip(affine.dz.iter())
        .zip(centering.dz.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    for ((value, &affine_i), &centering_i) in combined
        .dz_lower
        .iter_mut()
        .zip(affine.dz_lower.iter())
        .zip(centering.dz_lower.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    for ((value, &affine_i), &centering_i) in combined
        .dz_upper
        .iter_mut()
        .zip(affine.dz_upper.iter())
        .zip(centering.dz_upper.iter())
    {
        *value = ipopt_affine_centering_step(affine_i, sigma, centering_i);
    }
    combined
}

fn add_newton_direction_step(
    base: &NewtonDirection,
    correction: NewtonDirection,
) -> NewtonDirection {
    let mut combined = base.clone();
    for (value, delta) in combined.dx.iter_mut().zip(correction.dx.iter()) {
        *value += *delta;
    }
    for (value, delta) in combined.d_lambda.iter_mut().zip(correction.d_lambda.iter()) {
        *value += *delta;
    }
    for (value, delta) in combined.d_ineq.iter_mut().zip(correction.d_ineq.iter()) {
        *value += *delta;
    }
    for (value, delta) in combined.ds.iter_mut().zip(correction.ds.iter()) {
        *value += *delta;
    }
    for (value, delta) in combined.dz.iter_mut().zip(correction.dz.iter()) {
        *value += *delta;
    }
    for (value, delta) in combined.dz_lower.iter_mut().zip(correction.dz_lower.iter()) {
        *value += *delta;
    }
    for (value, delta) in combined.dz_upper.iter_mut().zip(correction.dz_upper.iter()) {
        *value += *delta;
    }
    combined.solver_used = correction.solver_used;
    combined.regularization_used = correction.regularization_used;
    combined.dual_regularization_used = correction.dual_regularization_used;
    combined.primal_diagonal_shift_used = correction.primal_diagonal_shift_used;
    combined.linear_solution = correction.linear_solution;
    combined.linear_trace = correction.linear_trace;
    combined.backend_stats = correction.backend_stats;
    combined.linear_debug = correction.linear_debug;
    combined
}

#[expect(
    clippy::too_many_arguments,
    reason = "IpFilterLSAcceptor::TryCorrector builds distinct complementarity RHS blocks for bounds and slacks."
)]
fn solve_ipopt_filter_corrector_direction(
    corrector_type: InteriorPointCorrectorType,
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    fixed_variables: &FixedVariableElimination,
    x: &[f64],
    bounds: &BoundConstraints,
    slack_barrier: &[f64],
    z: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    base_direction_reduced: &NewtonDirection,
    base_direction_full_dx: &[f64],
    barrier_parameter: f64,
) -> std::result::Result<Option<(NewtonDirection, usize)>, InteriorPointSolveError> {
    let zero_dual = vec![0.0; system.r_dual.len()];
    let zero_eq = vec![0.0; system.r_eq.len()];
    let zero_ineq = vec![0.0; system.r_ineq.len()];
    let zero_slack_stationarity = vec![0.0; system.r_slack_stationarity.len()];

    let (r_cent, lower_rhs, upper_rhs) = match corrector_type {
        InteriorPointCorrectorType::None => return Ok(None),
        InteriorPointCorrectorType::Affine => {
            let r_cent_affine = system
                .slack
                .iter()
                .zip(system.multipliers.iter())
                .map(|(&slack, &multiplier)| slack * multiplier)
                .collect::<Vec<_>>();
            let lower_affine = bounds
                .lower_indices
                .iter()
                .zip(bounds.lower_values.iter())
                .zip(z_lower.iter())
                .map(|((&index, &lower), &z_i)| native_lower_bound_slack(x, index, lower) * z_i)
                .collect::<Vec<_>>();
            let upper_affine = bounds
                .upper_indices
                .iter()
                .zip(bounds.upper_values.iter())
                .zip(z_upper.iter())
                .map(|((&index, &upper), &z_i)| native_upper_bound_slack(x, index, upper) * z_i)
                .collect::<Vec<_>>();
            let affine_system = system.with_explicit_rhs(
                system.r_dual,
                system.r_eq,
                system.r_ineq,
                system.r_slack_stationarity,
                &r_cent_affine,
                Some(&lower_affine),
                Some(&upper_affine),
                0.0,
            );
            let Ok(step_aff) = solve_reduced_kkt_with_spral_src_oriented(
                &affine_system,
                workspace,
                profiling,
                verbose,
                false,
                false,
                IpoptLinearRhsOrientation::PreFinal,
            ) else {
                return Ok(None);
            };
            let affine_full_dx = fixed_variables.expand_direction(&step_aff.dx);
            let lower_rhs = bounds
                .lower_indices
                .iter()
                .zip(step_aff.dz_lower.iter())
                .map(|(&index, &dz_i)| -affine_full_dx[index] * dz_i)
                .collect::<Vec<_>>();
            let upper_rhs = bounds
                .upper_indices
                .iter()
                .zip(step_aff.dz_upper.iter())
                .map(|(&index, &dz_i)| affine_full_dx[index] * dz_i)
                .collect::<Vec<_>>();
            let r_cent = step_aff
                .ds
                .iter()
                .zip(step_aff.dz.iter())
                .map(|(&ds_i, &dz_i)| ds_i * dz_i)
                .collect::<Vec<_>>();
            (r_cent, lower_rhs, upper_rhs)
        }
        InteriorPointCorrectorType::PrimalDual => {
            let lower_rhs = bounds
                .lower_indices
                .iter()
                .zip(bounds.lower_values.iter())
                .zip(z_lower.iter())
                .zip(base_direction_reduced.dz_lower.iter())
                .map(|(((&index, &lower), &z_i), &dz_i)| {
                    let slack = native_lower_bound_slack(x, index, lower);
                    let shifted_slack = -slack - base_direction_full_dx[index];
                    let shifted_multiplier = z_i + dz_i;
                    shifted_slack * shifted_multiplier + barrier_parameter
                })
                .collect::<Vec<_>>();
            let upper_rhs = bounds
                .upper_indices
                .iter()
                .zip(bounds.upper_values.iter())
                .zip(z_upper.iter())
                .zip(base_direction_reduced.dz_upper.iter())
                .map(|(((&index, &upper), &z_i), &dz_i)| {
                    let slack = native_upper_bound_slack(x, index, upper);
                    let shifted_slack = base_direction_full_dx[index] - slack;
                    let shifted_multiplier = z_i + dz_i;
                    shifted_slack * shifted_multiplier + barrier_parameter
                })
                .collect::<Vec<_>>();
            let r_cent = slack_barrier
                .iter()
                .zip(base_direction_reduced.ds.iter())
                .zip(z.iter())
                .zip(base_direction_reduced.dz.iter())
                .map(|(((&slack, &ds_i), &z_i), &dz_i)| {
                    let shifted_slack = ds_i - slack;
                    let shifted_multiplier = z_i + dz_i;
                    shifted_slack * shifted_multiplier + barrier_parameter
                })
                .collect::<Vec<_>>();
            (r_cent, lower_rhs, upper_rhs)
        }
    };

    let correction_system = system.with_explicit_rhs(
        &zero_dual,
        &zero_eq,
        &zero_ineq,
        &zero_slack_stationarity,
        &r_cent,
        Some(&lower_rhs),
        Some(&upper_rhs),
        0.0,
    );
    let correction = match solve_reduced_kkt_with_spral_src_oriented(
        &correction_system,
        workspace,
        profiling,
        verbose,
        true,
        false,
        IpoptLinearRhsOrientation::SourceDirection,
    ) {
        Ok(direction) => direction,
        Err(_) => return Ok(None),
    };
    let solve_count = match corrector_type {
        InteriorPointCorrectorType::None => 0,
        InteriorPointCorrectorType::Affine => 2,
        InteriorPointCorrectorType::PrimalDual => 1,
    };
    Ok(Some((
        add_newton_direction_step(base_direction_reduced, correction),
        solve_count,
    )))
}

fn grad_kappa_times_damping_x_reduced(
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    kappa_d: f64,
) -> Vec<f64> {
    let mut result = vec![0.0; fixed_variables.reduced_dimension()];
    if kappa_d <= 0.0 {
        return result;
    }
    for &index in bounds
        .lower_indices
        .iter()
        .filter(|index| !bounds.upper_indices.contains(index))
    {
        if let Some(reduced_index) = fixed_variables.free_position[index] {
            result[reduced_index] += kappa_d;
        }
    }
    for &index in bounds
        .upper_indices
        .iter()
        .filter(|index| !bounds.lower_indices.contains(index))
    {
        if let Some(reduced_index) = fixed_variables.free_position[index] {
            result[reduced_index] -= kappa_d;
        }
    }
    result
}

fn grad_kappa_times_damping_s(inequality_count: usize, kappa_d: f64) -> Vec<f64> {
    if kappa_d > 0.0 {
        vec![-kappa_d; inequality_count]
    } else {
        vec![0.0; inequality_count]
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT ProbingMuOracle builds an explicit affine IteratesVector RHS and evaluates all complementarity blocks."
)]
fn probing_free_mu_oracle_update(
    nlp_error: f64,
    mu_min: f64,
    mu_max: f64,
    lower_mu_safeguard: f64,
    stats: ComplementarityProductStats,
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
    options: &InteriorPointOptions,
) -> std::result::Result<AdaptiveMuUpdateResult, InteriorPointSolveError> {
    let tau = options
        .fraction_to_boundary
        .max(1.0 - nlp_error)
        .clamp(0.0, 1.0);
    let average_complementarity = stats.average();
    if average_complementarity <= 0.0 {
        return Ok(adaptive_free_mu_oracle_update(
            nlp_error,
            mu_min,
            mu_max,
            lower_mu_safeguard,
            stats,
            options,
        ));
    }

    let r_cent_affine = system
        .slack
        .iter()
        .zip(system.multipliers.iter())
        .map(|(&slack, &multiplier)| slack * multiplier)
        .collect::<Vec<_>>();
    let lower_affine = if let Some(bound_data) = system.bound_data {
        bound_data
            .bounds
            .lower_indices
            .iter()
            .zip(bound_data.bounds.lower_values.iter())
            .zip(z_lower.iter())
            .map(|((&index, &lower), &z_i)| native_lower_bound_slack(x, index, lower) * z_i)
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let upper_affine = if let Some(bound_data) = system.bound_data {
        bound_data
            .bounds
            .upper_indices
            .iter()
            .zip(bound_data.bounds.upper_values.iter())
            .zip(z_upper.iter())
            .map(|((&index, &upper), &z_i)| native_upper_bound_slack(x, index, upper) * z_i)
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let affine_system = system.with_explicit_rhs(
        system.r_dual,
        system.r_eq,
        system.r_ineq,
        system.r_slack_stationarity,
        &r_cent_affine,
        Some(&lower_affine),
        Some(&upper_affine),
        0.0,
    );
    let step_aff = solve_reduced_kkt_with_spral_src_oriented(
        &affine_system,
        workspace,
        profiling,
        verbose,
        true,
        false,
        IpoptLinearRhsOrientation::PreFinal,
    )
    .map_err(|attempts| {
        linear_solve_error(
            InteriorPointLinearSolver::SpralSrc,
            workspace.pattern.dimension(),
            attempts,
        )
    })?;

    let alpha_primal = quality_function_primal_fraction_to_boundary(
        x,
        bounds,
        system.slack,
        &step_aff.dx,
        &step_aff.ds,
        1.0,
    );
    let (alpha_dual, _) = ipopt_dual_fraction_to_boundary_with_limiter(
        z_lower,
        &step_aff.dz_lower,
        z_upper,
        &step_aff.dz_upper,
        system.multipliers,
        &step_aff.dz,
        1.0,
    );
    let affine_mu = probing_affine_average_complementarity(
        x,
        bounds,
        system.slack,
        z_lower,
        z_upper,
        system.multipliers,
        alpha_primal,
        alpha_dual,
        &step_aff,
    );
    let sigma = (affine_mu / average_complementarity)
        .powi(3)
        .min(options.sigma_max);
    let mu = (sigma * average_complementarity)
        .max(mu_min.max(options.mu_target))
        .max(lower_mu_safeguard)
        .min(mu_max);

    Ok(AdaptiveMuUpdateResult {
        mu,
        tau,
        reset_line_search: true,
        restored_iterate: None,
        affine_direction: options.mehrotra_algorithm.then_some(step_aff),
        improve_direction: None,
    })
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT QualityFunctionMuOracle depends on all complementarity blocks and current residual components."
)]
fn quality_function_free_mu_oracle_update(
    nlp_error: f64,
    mu_min: f64,
    mu_max: f64,
    lower_mu_safeguard: f64,
    stats: ComplementarityProductStats,
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    x: &[f64],
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    z_lower: &[f64],
    z_upper: &[f64],
    options: &InteriorPointOptions,
) -> std::result::Result<AdaptiveMuUpdateResult, InteriorPointSolveError> {
    let tau = options
        .fraction_to_boundary
        .max(1.0 - nlp_error)
        .clamp(0.0, 1.0);
    let average_complementarity = stats.average();
    if average_complementarity <= 0.0 {
        return Ok(adaptive_free_mu_oracle_update(
            nlp_error,
            mu_min,
            mu_max,
            lower_mu_safeguard,
            stats,
            options,
        ));
    }

    let r_cent_affine = system
        .slack
        .iter()
        .zip(system.multipliers.iter())
        .map(|(&slack, &multiplier)| slack * multiplier)
        .collect::<Vec<_>>();
    let lower_affine = if let Some(bound_data) = system.bound_data {
        bound_data
            .bounds
            .lower_indices
            .iter()
            .zip(bound_data.bounds.lower_values.iter())
            .zip(z_lower.iter())
            .map(|((&index, &lower), &z_i)| native_lower_bound_slack(x, index, lower) * z_i)
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let upper_affine = if let Some(bound_data) = system.bound_data {
        bound_data
            .bounds
            .upper_indices
            .iter()
            .zip(bound_data.bounds.upper_values.iter())
            .zip(z_upper.iter())
            .map(|((&index, &upper), &z_i)| native_upper_bound_slack(x, index, upper) * z_i)
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let affine_system = system.with_explicit_rhs(
        system.r_dual,
        system.r_eq,
        system.r_ineq,
        system.r_slack_stationarity,
        &r_cent_affine,
        Some(&lower_affine),
        Some(&upper_affine),
        0.0,
    );
    let step_aff = solve_reduced_kkt_with_spral_src_oriented(
        &affine_system,
        workspace,
        profiling,
        verbose,
        true,
        false,
        IpoptLinearRhsOrientation::PreFinal,
    )
    .map_err(|attempts| {
        linear_solve_error(
            InteriorPointLinearSolver::SpralSrc,
            workspace.pattern.dimension(),
            attempts,
        )
    })?;

    let centering_r_dual =
        grad_kappa_times_damping_x_reduced(bounds, fixed_variables, options.kappa_d)
            .into_iter()
            .map(|value| -average_complementarity * value)
            .collect::<Vec<_>>();
    let centering_r_slack = grad_kappa_times_damping_s(system.slack.len(), options.kappa_d)
        .into_iter()
        .map(|value| -average_complementarity * value)
        .collect::<Vec<_>>();
    let zero_eq = vec![0.0; system.r_eq.len()];
    let zero_ineq = vec![0.0; system.r_ineq.len()];
    let r_cent_centering = vec![average_complementarity; system.r_cent.len()];
    let lower_centering = vec![average_complementarity; lower_affine.len()];
    let upper_centering = vec![average_complementarity; upper_affine.len()];
    let centering_system = system.with_explicit_rhs(
        &centering_r_dual,
        &zero_eq,
        &zero_ineq,
        &centering_r_slack,
        &r_cent_centering,
        Some(&lower_centering),
        Some(&upper_centering),
        0.0,
    );
    let step_cen = solve_reduced_kkt_with_spral_src_oriented(
        &centering_system,
        workspace,
        profiling,
        verbose,
        true,
        false,
        IpoptLinearRhsOrientation::SourceDirection,
    )
    .map_err(|attempts| {
        linear_solve_error(
            InteriorPointLinearSolver::SpralSrc,
            workspace.pattern.dimension(),
            attempts,
        )
    })?;

    let evaluate = |sigma: f64| {
        quality_function_value(
            sigma,
            x,
            bounds,
            system.slack,
            z_lower,
            z_upper,
            system.multipliers,
            system.r_dual,
            system.r_eq,
            system.r_ineq,
            system.r_slack_stationarity,
            tau,
            &step_aff,
            &step_cen,
            options,
        )
    };
    let qf_1 = evaluate(1.0);
    let sigma_1minus = 1.0 - 1.0e-4_f64.max(options.quality_function_section_sigma_tol);
    let qf_1minus = evaluate(sigma_1minus);
    let search_options = QualityFunctionSectionSearchOptions {
        sigma_tol: options.quality_function_section_sigma_tol,
        qf_tol: options.quality_function_section_qf_tol,
        max_steps: options.quality_function_max_section_steps,
    };
    let sigma = if qf_1minus > qf_1 {
        let sigma_up = options.sigma_max.min(mu_max / average_complementarity);
        let sigma_lo = 1.0;
        if sigma_lo >= sigma_up {
            sigma_up
        } else {
            quality_function_golden_section(
                sigma_up,
                -100.0,
                sigma_lo,
                qf_1,
                search_options,
                evaluate,
            )
        }
    } else {
        let sigma_lo = options.sigma_min.max(mu_min / average_complementarity);
        let sigma_up = sigma_lo
            .max(sigma_1minus)
            .min(mu_max / average_complementarity);
        if sigma_lo >= sigma_up {
            sigma_lo
        } else {
            quality_function_golden_section(
                sigma_up,
                qf_1minus,
                sigma_lo,
                -100.0,
                search_options,
                evaluate,
            )
        }
    };
    let mut mu = sigma * average_complementarity;
    mu = mu
        .max(mu_min.max(options.mu_target))
        .max(lower_mu_safeguard)
        .min(mu_max);
    let improve_direction = ipopt_quality_function_combined_direction(&step_aff, &step_cen, sigma);

    Ok(AdaptiveMuUpdateResult {
        mu,
        tau,
        reset_line_search: true,
        restored_iterate: None,
        affine_direction: None,
        improve_direction: Some(improve_direction),
    })
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT adaptive mu update depends on all current complementarity blocks and the PD solver for source PD-oracle modes."
)]
fn adaptive_spral_pd_mu_oracle_update(
    objective: f64,
    constraint_violation: f64,
    nlp_error: f64,
    barrier_subproblem_error: f64,
    current_mu: f64,
    current_tau: f64,
    tiny_step_flag: bool,
    skipped_line_search: bool,
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    x: &[f64],
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    z_lower: &[f64],
    z_upper: &[f64],
    current_iterate: Option<AdaptiveMuAcceptedIterate>,
    state: &mut AdaptiveMuUpdateState,
    options: &InteriorPointOptions,
) -> std::result::Result<AdaptiveMuUpdateResult, InteriorPointSolveError> {
    let mu_min = adaptive_mu_min(options);
    let stats = complementarity_product_stats(
        system.slack,
        system.multipliers,
        x,
        bounds,
        z_lower,
        z_upper,
    );
    let mu_max = adaptive_mu_initial_max(state, stats, options);
    let (dual_l1_average, primal_l1_average) = adaptive_mu_l1_infeasibility_averages(
        system.r_dual,
        system.r_eq,
        system.r_ineq,
        system.r_slack_stationarity,
    );
    let lower_mu_safeguard =
        adaptive_mu_lower_safeguard(dual_l1_average, primal_l1_average, state, options);
    let current_kkt_error = adaptive_mu_quality_function_pd_system_error(
        x,
        bounds,
        system.slack,
        z_lower,
        z_upper,
        system.multipliers,
        system.r_dual,
        system.r_eq,
        system.r_ineq,
        system.r_slack_stationarity,
        options,
    );

    if !state.no_bounds_checked {
        state.no_bounds = stats.count == 0;
        state.no_bounds_checked = true;
    }
    if state.no_bounds {
        return Ok(AdaptiveMuUpdateResult {
            mu: mu_min,
            tau: options.fraction_to_boundary,
            reset_line_search: false,
            restored_iterate: None,
            affine_direction: None,
            improve_direction: None,
        });
    }

    let mut switched_from_fixed_to_free = false;
    if !state.free_mu_mode {
        let sufficient_progress = adaptive_mu_check_sufficient_progress(
            objective,
            constraint_violation,
            nlp_error,
            current_kkt_error,
            state,
            options,
        );
        if sufficient_progress && !tiny_step_flag {
            state.free_mu_mode = true;
            switched_from_fixed_to_free = true;
            adaptive_mu_remember_current_point_as_accepted(
                objective,
                constraint_violation,
                current_kkt_error,
                current_iterate.clone(),
                state,
                options,
            );
        } else if should_reduce_barrier_parameter(barrier_subproblem_error, current_mu, options)
            || tiny_step_flag
        {
            return Ok(AdaptiveMuUpdateResult {
                mu: adaptive_fixed_mu_reduction(current_mu, options),
                tau: current_fraction_to_boundary_tau(current_mu, options),
                reset_line_search: true,
                restored_iterate: None,
                affine_direction: None,
                improve_direction: None,
            });
        } else {
            return Ok(AdaptiveMuUpdateResult {
                mu: current_mu,
                tau: current_tau,
                reset_line_search: false,
                restored_iterate: None,
                affine_direction: None,
                improve_direction: None,
            });
        }
    }

    if state.free_mu_mode && !switched_from_fixed_to_free {
        let mut sufficient_progress = adaptive_mu_check_sufficient_progress(
            objective,
            constraint_violation,
            nlp_error,
            current_kkt_error,
            state,
            options,
        );
        if options.adaptive_mu_globalization
            != InteriorPointAdaptiveMuGlobalization::NeverMonotoneMode
            && (skipped_line_search || tiny_step_flag)
        {
            sufficient_progress = false;
        }
        if sufficient_progress {
            adaptive_mu_remember_current_point_as_accepted(
                objective,
                constraint_violation,
                current_kkt_error,
                current_iterate,
                state,
                options,
            );
        } else {
            state.free_mu_mode = false;
            let (fixed_stats, fixed_lower_mu_safeguard, restored_iterate) =
                adaptive_mu_restored_fixed_mode_components(
                    state,
                    bounds,
                    stats,
                    lower_mu_safeguard,
                    options,
                );
            let mu = adaptive_fixed_mu_from_current_complementarity(
                mu_min,
                mu_max,
                fixed_stats,
                fixed_lower_mu_safeguard,
                options,
            );
            return Ok(AdaptiveMuUpdateResult {
                mu,
                tau: current_fraction_to_boundary_tau(mu, options),
                reset_line_search: true,
                restored_iterate,
                affine_direction: None,
                improve_direction: None,
            });
        }
    }

    match options.adaptive_mu_oracle {
        InteriorPointAdaptiveMuOracle::QualityFunction => quality_function_free_mu_oracle_update(
            nlp_error,
            mu_min,
            mu_max,
            lower_mu_safeguard,
            stats,
            system,
            workspace,
            profiling,
            verbose,
            x,
            bounds,
            fixed_variables,
            z_lower,
            z_upper,
            options,
        ),
        InteriorPointAdaptiveMuOracle::Probing => probing_free_mu_oracle_update(
            nlp_error,
            mu_min,
            mu_max,
            lower_mu_safeguard,
            stats,
            system,
            workspace,
            profiling,
            verbose,
            x,
            bounds,
            z_lower,
            z_upper,
            options,
        ),
        InteriorPointAdaptiveMuOracle::Loqo => unreachable!("LOQO adaptive mu is handled earlier"),
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT adaptive mu update depends on all current complementarity blocks."
)]
fn adaptive_loqo_update(
    objective: f64,
    constraint_violation: f64,
    nlp_error: f64,
    barrier_subproblem_error: f64,
    current_mu: f64,
    current_tau: f64,
    tiny_step_flag: bool,
    skipped_line_search: bool,
    slack: &[f64],
    z: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
    r_dual: &[f64],
    r_eq: &[f64],
    r_ineq: &[f64],
    r_slack_stationarity: &[f64],
    current_iterate: Option<AdaptiveMuAcceptedIterate>,
    state: &mut AdaptiveMuUpdateState,
    options: &InteriorPointOptions,
) -> AdaptiveMuUpdateResult {
    let mu_min = adaptive_mu_min(options);
    let stats = complementarity_product_stats(slack, z, x, bounds, z_lower, z_upper);
    let mu_max = adaptive_mu_initial_max(state, stats, options);

    if !state.no_bounds_checked {
        state.no_bounds = stats.count == 0;
        state.no_bounds_checked = true;
    }
    if state.no_bounds {
        return AdaptiveMuUpdateResult {
            mu: mu_min,
            tau: options.fraction_to_boundary,
            reset_line_search: false,
            restored_iterate: None,
            affine_direction: None,
            improve_direction: None,
        };
    }
    let (dual_l1_average, primal_l1_average) =
        adaptive_mu_l1_infeasibility_averages(r_dual, r_eq, r_ineq, r_slack_stationarity);
    let lower_mu_safeguard =
        adaptive_mu_lower_safeguard(dual_l1_average, primal_l1_average, state, options);
    let current_kkt_error = adaptive_mu_quality_function_pd_system_error(
        x,
        bounds,
        slack,
        z_lower,
        z_upper,
        z,
        r_dual,
        r_eq,
        r_ineq,
        r_slack_stationarity,
        options,
    );

    let mut switched_from_fixed_to_free = false;
    if !state.free_mu_mode {
        let sufficient_progress = adaptive_mu_check_sufficient_progress(
            objective,
            constraint_violation,
            nlp_error,
            current_kkt_error,
            state,
            options,
        );
        if sufficient_progress && !tiny_step_flag {
            state.free_mu_mode = true;
            switched_from_fixed_to_free = true;
            adaptive_mu_remember_current_point_as_accepted(
                objective,
                constraint_violation,
                current_kkt_error,
                current_iterate.clone(),
                state,
                options,
            );
        } else if should_reduce_barrier_parameter(barrier_subproblem_error, current_mu, options)
            || tiny_step_flag
        {
            return AdaptiveMuUpdateResult {
                mu: adaptive_fixed_mu_reduction(current_mu, options),
                // IpAdaptiveMuUpdate computes this tau from the old fixed mu.
                tau: current_fraction_to_boundary_tau(current_mu, options),
                reset_line_search: true,
                restored_iterate: None,
                affine_direction: None,
                improve_direction: None,
            };
        } else {
            return AdaptiveMuUpdateResult {
                mu: current_mu,
                tau: current_tau,
                reset_line_search: false,
                restored_iterate: None,
                affine_direction: None,
                improve_direction: None,
            };
        }
    }

    if state.free_mu_mode && !switched_from_fixed_to_free {
        let mut sufficient_progress = adaptive_mu_check_sufficient_progress(
            objective,
            constraint_violation,
            nlp_error,
            current_kkt_error,
            state,
            options,
        );
        if options.adaptive_mu_globalization
            != InteriorPointAdaptiveMuGlobalization::NeverMonotoneMode
            && (skipped_line_search || tiny_step_flag)
        {
            sufficient_progress = false;
        }
        if sufficient_progress {
            adaptive_mu_remember_current_point_as_accepted(
                objective,
                constraint_violation,
                current_kkt_error,
                current_iterate,
                state,
                options,
            );
        } else {
            state.free_mu_mode = false;
            let (fixed_stats, fixed_lower_mu_safeguard, restored_iterate) =
                adaptive_mu_restored_fixed_mode_components(
                    state,
                    bounds,
                    stats,
                    lower_mu_safeguard,
                    options,
                );
            let mu = adaptive_fixed_mu_from_current_complementarity(
                mu_min,
                mu_max,
                fixed_stats,
                fixed_lower_mu_safeguard,
                options,
            );
            return AdaptiveMuUpdateResult {
                mu,
                tau: current_fraction_to_boundary_tau(mu, options),
                reset_line_search: true,
                restored_iterate,
                affine_direction: None,
                improve_direction: None,
            };
        }
    }

    adaptive_free_mu_oracle_update(
        nlp_error,
        mu_min,
        mu_max,
        lower_mu_safeguard,
        stats,
        options,
    )
}

fn initial_barrier_parameter(has_barrier_pairs: bool, options: &InteriorPointOptions) -> f64 {
    match options.mu_strategy {
        InteriorPointMuStrategy::Monotone => {
            initial_monotone_barrier_parameter(has_barrier_pairs, options)
        }
        InteriorPointMuStrategy::Adaptive => {
            if has_barrier_pairs {
                // IpAdaptiveMuUpdate::Initialize sets mu=1 and tau=0 so that
                // the first output line has a defined barrier value. The first
                // UpdateBarrierParameter call replaces both before the solve.
                1.0
            } else {
                0.0
            }
        }
    }
}

fn interior_point_complementarity_target_inf_norm(
    slack: &[f64],
    multipliers: &[f64],
    mu_target: f64,
) -> f64 {
    slack
        .iter()
        .zip(multipliers.iter())
        .fold(0.0, |acc, (s, z)| acc.max((s * z - mu_target).abs()))
}

fn interior_point_current_is_acceptable(
    state: InteriorPointAcceptableState,
    last_objective: f64,
    options: &InteriorPointOptions,
) -> bool {
    let relative_objective_change =
        (state.objective - last_objective).abs() / state.objective.abs().max(1.0);
    state.overall_error <= options.acceptable_tol
        && state.dual_inf <= options.acceptable_dual_inf_tol
        && state.constr_viol <= options.acceptable_constr_viol_tol
        && state.compl_inf <= options.acceptable_compl_inf_tol
        && relative_objective_change <= options.acceptable_obj_change_tol
}

fn step_inf_norm(step: &[f64]) -> f64 {
    step.iter().fold(0.0, |acc, value| acc.max(value.abs()))
}

fn ipopt_primal_step_inf_norm(direction: &NewtonDirection) -> f64 {
    step_inf_norm(&direction.dx).max(step_inf_norm(&direction.ds))
}

fn is_tiny_ip_step(
    x: &[f64],
    slack: &[f64],
    direction: &NewtonDirection,
    primal_inf: f64,
    options: &InteriorPointOptions,
) -> bool {
    if options.tiny_step_tol == 0.0 || primal_inf > 1.0e-4 {
        return false;
    }
    let max_x = x
        .iter()
        .zip(direction.dx.iter())
        .fold(0.0_f64, |acc, (&value, &delta)| {
            acc.max(delta.abs() / (1.0 + value.abs()))
        });
    if max_x > options.tiny_step_tol {
        return false;
    }
    let max_s = slack
        .iter()
        .zip(direction.ds.iter())
        .fold(0.0_f64, |acc, (&value, &delta)| {
            acc.max(delta.abs() / (1.0 + value.abs()))
        });
    max_s <= options.tiny_step_tol
}

fn watchdog_restore_retry_alpha(
    stored_alpha_pr: f64,
    stop_kind: WatchdogStopKind,
    options: &InteriorPointOptions,
) -> f64 {
    match stop_kind {
        WatchdogStopKind::PreLineSearch => stored_alpha_pr,
        WatchdogStopKind::EvaluationError => stored_alpha_pr * options.line_search_beta,
        WatchdogStopKind::TrialBudget => stored_alpha_pr * options.line_search_beta,
    }
}

fn alpha_for_y(
    alpha_primal: f64,
    alpha_dual: f64,
    direction: &NewtonDirection,
    options: &InteriorPointOptions,
) -> f64 {
    let primal_step_norm = step_inf_norm(&direction.dx).max(step_inf_norm(&direction.ds));
    let alpha = match options.alpha_for_y {
        InteriorPointAlphaForYStrategy::Primal => alpha_primal,
        InteriorPointAlphaForYStrategy::BoundMultiplier => alpha_dual,
        // IPOPT IpBacktrackingLineSearch::PerformDualStep calls
        // Min(alpha_dual, alpha_primal) and Max(alpha_dual, alpha_primal).
        InteriorPointAlphaForYStrategy::Min => ipopt_cxx_min(alpha_dual, alpha_primal),
        InteriorPointAlphaForYStrategy::Max => ipopt_cxx_max(alpha_dual, alpha_primal),
        InteriorPointAlphaForYStrategy::Full => 1.0,
        InteriorPointAlphaForYStrategy::MinDualInfeas
        | InteriorPointAlphaForYStrategy::SaferMinDualInfeas => {
            panic!("min-dual-infeas alpha_for_y requires trial dual-infeasibility inputs")
        }
        InteriorPointAlphaForYStrategy::PrimalAndFull => {
            if primal_step_norm <= options.alpha_for_y_tol {
                1.0
            } else {
                alpha_primal
            }
        }
        InteriorPointAlphaForYStrategy::DualAndFull => {
            if primal_step_norm <= options.alpha_for_y_tol {
                1.0
            } else {
                alpha_dual
            }
        }
    };
    alpha.clamp(0.0, 1.0)
}

#[expect(
    clippy::too_many_arguments,
    reason = "Mirrors IpBacktrackingLineSearch::PerformDualStep data dependencies explicitly."
)]
fn alpha_for_y_with_trial_dual_infeasibility(
    alpha_primal: f64,
    alpha_dual: f64,
    direction: &NewtonDirection,
    trial_state: &EvalState,
    current_lambda_eq: &[f64],
    current_lambda_ineq: &[f64],
    trial_z: &[f64],
    trial_z_lower: &[f64],
    trial_z_upper: &[f64],
    bounds: &BoundConstraints,
    options: &InteriorPointOptions,
) -> f64 {
    match options.alpha_for_y {
        InteriorPointAlphaForYStrategy::MinDualInfeas
        | InteriorPointAlphaForYStrategy::SaferMinDualInfeas => {
            // IpBacktrackingLineSearch::PerformDualStep first installs the
            // primal trial point and bound multipliers, then temporarily keeps
            // y_c/y_d at the current iterate to evaluate trial_grad_lag_x/s.
            let current_y_lagrangian = lagrangian_gradient_components(
                &trial_state.gradient,
                &trial_state.equality_jacobian,
                current_lambda_eq,
                &trial_state.inequality_jacobian,
                current_lambda_ineq,
            );
            let mut dual_inf_x = current_y_lagrangian.curr_grad_lag_x;
            add_native_bound_multiplier_terms(
                &mut dual_inf_x,
                bounds,
                trial_z_lower,
                trial_z_upper,
            );

            let mut new_jac_times_delta_y = vec![0.0; trial_state.gradient.len()];
            sparse_add_transpose_mat_vec_ipopt_order(
                &mut new_jac_times_delta_y,
                &trial_state.equality_jacobian,
                &direction.d_lambda,
            );
            sparse_add_transpose_mat_vec_ipopt_order(
                &mut new_jac_times_delta_y,
                &trial_state.inequality_jacobian,
                &direction.d_ineq,
            );
            let dual_inf_s = slack_stationarity_residuals(current_lambda_ineq, trial_z);
            let a = squared_l2_norm(&new_jac_times_delta_y) + squared_l2_norm(&direction.d_ineq);
            let b = dot(&dual_inf_x, &new_jac_times_delta_y) - dot(&dual_inf_s, &direction.d_ineq);
            let alpha = -b / a;
            if options.alpha_for_y == InteriorPointAlphaForYStrategy::SaferMinDualInfeas {
                ipopt_cxx_min(
                    ipopt_cxx_max(alpha_primal, alpha_dual),
                    ipopt_cxx_max(alpha, ipopt_cxx_min(alpha_primal, alpha_dual)),
                )
            } else {
                ipopt_cxx_min(1.0, ipopt_cxx_max(0.0, alpha))
            }
        }
        _ => alpha_for_y(alpha_primal, alpha_dual, direction, options),
    }
}

fn squared_l2_norm(values: &[f64]) -> f64 {
    values.iter().map(|value| value * value).sum()
}

fn dot(lhs: &[f64], rhs: &[f64]) -> f64 {
    debug_assert_eq!(lhs.len(), rhs.len());
    lhs.iter()
        .zip(rhs.iter())
        .map(|(lhs_i, rhs_i)| lhs_i * rhs_i)
        .sum()
}

fn ipopt_cxx_min(first: f64, second: f64) -> f64 {
    if second < first { second } else { first }
}

fn ipopt_cxx_max(first: f64, second: f64) -> f64 {
    if first < second { second } else { first }
}

fn kkt_regularization(
    has_inequalities: bool,
    primal_inf: f64,
    complementarity_inf: f64,
    dual_inf: f64,
    options: &InteriorPointOptions,
) -> f64 {
    let _ = (has_inequalities, primal_inf, complementarity_inf, dual_inf);
    options.regularization
}

#[derive(Clone, Copy, Debug)]
struct InteriorPointDisplayTolerances {
    constraint: f64,
    dual: f64,
    complementarity: f64,
    overall: f64,
}

#[derive(Clone, Copy, Debug)]
enum InteriorPointResidualMetric {
    Constraint,
    Dual,
    Complementarity,
    Overall,
}

#[derive(Clone, Copy, Debug)]
enum InteriorPointDisplayMode {
    Strict(InteriorPointDisplayTolerances),
    Acceptable {
        strict: InteriorPointDisplayTolerances,
        acceptable: InteriorPointDisplayTolerances,
    },
}

impl InteriorPointDisplayMode {
    fn strict(options: &InteriorPointOptions) -> Self {
        Self::Strict(interior_point_display_tolerances(
            options,
            InteriorPointTermination::Converged,
        ))
    }

    fn for_termination(
        options: &InteriorPointOptions,
        termination: InteriorPointTermination,
    ) -> Self {
        let strict =
            interior_point_display_tolerances(options, InteriorPointTermination::Converged);
        match termination {
            InteriorPointTermination::Converged | InteriorPointTermination::FeasiblePointFound => {
                Self::Strict(strict)
            }
            InteriorPointTermination::Acceptable => Self::Acceptable {
                strict,
                acceptable: interior_point_display_tolerances(options, termination),
            },
        }
    }

    fn tolerances(self, metric: InteriorPointResidualMetric) -> (f64, Option<f64>) {
        let select = |tolerances: InteriorPointDisplayTolerances| match metric {
            InteriorPointResidualMetric::Constraint => tolerances.constraint,
            InteriorPointResidualMetric::Dual => tolerances.dual,
            InteriorPointResidualMetric::Complementarity => tolerances.complementarity,
            InteriorPointResidualMetric::Overall => tolerances.overall,
        };
        match self {
            Self::Strict(strict) => (select(strict), None),
            Self::Acceptable { strict, acceptable } => (select(strict), Some(select(acceptable))),
        }
    }
}

fn interior_point_display_tolerances(
    options: &InteriorPointOptions,
    termination: InteriorPointTermination,
) -> InteriorPointDisplayTolerances {
    match termination {
        InteriorPointTermination::Converged => InteriorPointDisplayTolerances {
            constraint: options.constraint_tol,
            dual: options.dual_tol,
            complementarity: options.complementarity_tol,
            overall: options.overall_tol,
        },
        InteriorPointTermination::FeasiblePointFound => InteriorPointDisplayTolerances {
            constraint: options.constraint_tol,
            dual: options.dual_tol,
            complementarity: options.complementarity_tol,
            overall: options.overall_tol,
        },
        InteriorPointTermination::Acceptable => InteriorPointDisplayTolerances {
            constraint: options.acceptable_constr_viol_tol,
            dual: options.acceptable_dual_inf_tol,
            complementarity: options.acceptable_compl_inf_tol,
            overall: options.acceptable_tol,
        },
    }
}

fn is_shortened_ip_step(
    _alpha_pr: f64,
    _alpha_du: Option<f64>,
    line_search_iterations: Index,
) -> bool {
    line_search_iterations > 0
}

fn current_fraction_to_boundary_tau(barrier_parameter: f64, options: &InteriorPointOptions) -> f64 {
    options
        .fraction_to_boundary
        .max(1.0 - barrier_parameter.max(0.0))
        .clamp(0.0, 1.0)
}

fn ipopt_dense_frac_to_bound_candidate(tau: f64, value: f64, delta: f64) -> f64 {
    // IPOPT `DenseVector::FracToBoundImpl` evaluates this as
    // `-tau / values_delta[i] * values_x[i]`; keep that operation order so
    // fraction-to-boundary alphas do not drift by a bit on tight limiters.
    -tau / delta * value
}

fn ipopt_dense_current_plus_step(value: f64, alpha: f64, delta: f64) -> f64 {
    // IpIpoptData.cpp::SetTrial*FromStep calls DenseVector::AddTwoVectors
    // with a=1, b=alpha, c=0. IpDenseVector.cpp special-cases b before
    // falling back to `value + alpha * delta`. The source-built IPOPT C++ path
    // contracts that general multiply-add, while the exact alpha==0/1/-1
    // branches are plain copies/adds/subtracts.
    if alpha == 0.0 {
        value
    } else if alpha == 1.0 {
        value + delta
    } else if alpha == -1.0 {
        value - delta
    } else {
        alpha.mul_add(delta, value)
    }
}

fn ipopt_soc_constraint_accumulator(trial: f64, alpha: f64, previous: f64) -> f64 {
    // IpFilterLSAcceptor::TrySecondOrderCorrection calls
    // c_soc->AddOneVector(1.0, trial, alpha), starting from the previous
    // SOC accumulator. DenseVector keeps exact alpha branches before the
    // general fused multiply-add path.
    if alpha == 0.0 {
        trial
    } else if alpha == 1.0 {
        ipopt_blas_axpy_value(previous, 1.0, trial)
    } else if alpha == -1.0 {
        trial - previous
    } else {
        alpha.mul_add(previous, trial)
    }
}

fn fraction_to_boundary_with_limiter(
    current: &[f64],
    direction: &[f64],
    tau: f64,
    kind: InteriorPointBoundaryLimiterKind,
) -> (f64, Option<InteriorPointBoundaryLimiter>) {
    let mut alpha = 1.0_f64;
    let mut limiter = None;
    for (idx, (&value, &delta)) in current.iter().zip(direction.iter()).enumerate() {
        if delta < 0.0 {
            let candidate = ipopt_dense_frac_to_bound_candidate(tau, value, delta);
            if candidate < alpha {
                alpha = candidate;
                limiter = Some(InteriorPointBoundaryLimiter {
                    kind,
                    index: idx,
                    value,
                    direction: delta,
                    alpha: candidate,
                });
            }
        }
    }
    (alpha, limiter)
}

fn ipopt_min_boundary_candidate(
    first: (f64, Option<InteriorPointBoundaryLimiter>),
    second: (f64, Option<InteriorPointBoundaryLimiter>),
) -> (f64, Option<InteriorPointBoundaryLimiter>) {
    if second.0 < first.0 { second } else { first }
}

fn ipopt_dual_fraction_to_boundary_with_limiter(
    z_lower: &[f64],
    dz_lower: &[f64],
    z_upper: &[f64],
    dz_upper: &[f64],
    slack_upper_multiplier: &[f64],
    slack_upper_multiplier_step: &[f64],
    tau: f64,
) -> (f64, Option<InteriorPointBoundaryLimiter>) {
    // IpoptCalculatedQuantities::dual_frac_to_the_bound checks z_L, z_U,
    // v_L, then v_U. NLIP has no lower slack multiplier block, so this keeps
    // the source ordering as z_L, z_U, v_U.
    let lower = fraction_to_boundary_with_limiter(
        z_lower,
        dz_lower,
        tau,
        InteriorPointBoundaryLimiterKind::Multiplier,
    );
    let upper = fraction_to_boundary_with_limiter(
        z_upper,
        dz_upper,
        tau,
        InteriorPointBoundaryLimiterKind::Multiplier,
    );
    let slack_upper = fraction_to_boundary_with_limiter(
        slack_upper_multiplier,
        slack_upper_multiplier_step,
        tau,
        InteriorPointBoundaryLimiterKind::Multiplier,
    );
    ipopt_min_boundary_candidate(ipopt_min_boundary_candidate(lower, upper), slack_upper)
}

fn fraction_to_boundary_limiters(
    current: &[f64],
    direction: &[f64],
    tau: f64,
    max_count: usize,
    kind: InteriorPointBoundaryLimiterKind,
) -> Vec<InteriorPointBoundaryLimiter> {
    if max_count == 0 {
        return Vec::new();
    }
    let mut limiters = current
        .iter()
        .zip(direction.iter())
        .enumerate()
        .filter_map(|(index, (&value, &delta))| {
            if delta < 0.0 {
                Some(InteriorPointBoundaryLimiter {
                    kind,
                    index,
                    value,
                    direction: delta,
                    alpha: ipopt_dense_frac_to_bound_candidate(tau, value, delta),
                })
            } else {
                None
            }
        })
        .collect::<Vec<_>>();
    limiters.sort_by(|lhs, rhs| {
        lhs.alpha
            .total_cmp(&rhs.alpha)
            .then_with(|| lhs.index.cmp(&rhs.index))
    });
    limiters.truncate(max_count);
    limiters
}

fn fraction_to_variable_bounds_with_limiter(
    x: &[f64],
    dx: &[f64],
    bounds: &BoundConstraints,
    tau: f64,
) -> (f64, Option<InteriorPointBoundaryLimiter>) {
    let mut alpha = 1.0_f64;
    let mut limiter = None;
    for (&index, &lower) in bounds.lower_indices.iter().zip(bounds.lower_values.iter()) {
        let value = native_lower_bound_slack(x, index, lower);
        let direction = dx[index];
        if direction < 0.0 {
            let candidate = ipopt_dense_frac_to_bound_candidate(tau, value, direction);
            if candidate < alpha {
                alpha = candidate;
                limiter = Some(InteriorPointBoundaryLimiter {
                    kind: InteriorPointBoundaryLimiterKind::VariableLowerBound,
                    index,
                    value,
                    direction,
                    alpha: candidate,
                });
            }
        }
    }
    for (&index, &upper) in bounds.upper_indices.iter().zip(bounds.upper_values.iter()) {
        let value = native_upper_bound_slack(x, index, upper);
        let direction = -dx[index];
        if direction < 0.0 {
            let candidate = ipopt_dense_frac_to_bound_candidate(tau, value, direction);
            if candidate < alpha {
                alpha = candidate;
                limiter = Some(InteriorPointBoundaryLimiter {
                    kind: InteriorPointBoundaryLimiterKind::VariableUpperBound,
                    index,
                    value,
                    direction,
                    alpha: candidate,
                });
            }
        }
    }
    (alpha, limiter)
}

fn add_native_bound_multiplier_terms(
    residual: &mut [f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
) {
    for (&index, &z_i) in bounds.lower_indices.iter().zip(z_lower.iter()) {
        residual[index] -= z_i;
    }
    for (&index, &z_i) in bounds.upper_indices.iter().zip(z_upper.iter()) {
        residual[index] += z_i;
    }
}

fn add_native_bound_damping_terms(
    residual: &mut [f64],
    bounds: &BoundConstraints,
    barrier_parameter: f64,
    kappa_d: f64,
) {
    let damping = positive_slack_damping(barrier_parameter, kappa_d);
    if damping == 0.0 {
        return;
    }
    // Mirrors IpoptCalculatedQuantities::curr_grad_lag_with_damping_x:
    // Px_L adds kappa_d*mu for lower-only bounds, then Px_U adds
    // -kappa_d*mu for upper-only bounds. Two-sided relaxed bounds cancel in
    // IPOPT's damping indicators and receive no x damping.
    for &index in bounds
        .lower_indices
        .iter()
        .filter(|index| !bounds.upper_indices.contains(index))
    {
        residual[index] += damping;
    }
    for &index in bounds
        .upper_indices
        .iter()
        .filter(|index| !bounds.lower_indices.contains(index))
    {
        residual[index] -= damping;
    }
}

fn damped_lagrangian_gradient_x(
    lagrangian_gradient_x: &[f64],
    bounds: &BoundConstraints,
    barrier_parameter: f64,
    kappa_d: f64,
) -> Vec<f64> {
    let mut result = lagrangian_gradient_x.to_vec();
    add_native_bound_damping_terms(&mut result, bounds, barrier_parameter, kappa_d);
    result
}

fn lagrangian_gradient_x_with_bound_terms(
    raw_lagrangian_gradient_x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
) -> Vec<f64> {
    let mut result = raw_lagrangian_gradient_x.to_vec();
    add_native_bound_multiplier_terms(&mut result, bounds, z_lower, z_upper);
    result
}

fn damped_lagrangian_gradient_x_with_bound_terms(
    raw_lagrangian_gradient_x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
    barrier_parameter: f64,
    kappa_d: f64,
) -> Vec<f64> {
    let mut result =
        lagrangian_gradient_x_with_bound_terms(raw_lagrangian_gradient_x, bounds, z_lower, z_upper);
    add_native_bound_damping_terms(&mut result, bounds, barrier_parameter, kappa_d);
    result
}

fn zero_fixed_entries(values: &mut [f64], fixed_variables: &FixedVariableElimination) {
    if !fixed_variables.has_fixed() {
        return;
    }
    for &index in &fixed_variables.fixed_indices {
        values[index] = 0.0;
    }
}

fn snapshot_x_component_vector(
    values: &[f64],
    fixed_variables: &FixedVariableElimination,
) -> Vec<f64> {
    let mut result = values.to_vec();
    zero_fixed_entries(&mut result, fixed_variables);
    result
}

fn snapshot_lagrangian_gradient_x_with_bound_terms(
    raw_lagrangian_gradient_x: &[f64],
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    z_lower: &[f64],
    z_upper: &[f64],
) -> Vec<f64> {
    let mut result =
        lagrangian_gradient_x_with_bound_terms(raw_lagrangian_gradient_x, bounds, z_lower, z_upper);
    zero_fixed_entries(&mut result, fixed_variables);
    result
}

fn snapshot_damped_lagrangian_gradient_x(
    lagrangian_gradient_x: &[f64],
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    barrier_parameter: f64,
    kappa_d: f64,
) -> Vec<f64> {
    let mut result =
        damped_lagrangian_gradient_x(lagrangian_gradient_x, bounds, barrier_parameter, kappa_d);
    zero_fixed_entries(&mut result, fixed_variables);
    result
}

fn snapshot_damped_lagrangian_gradient_x_with_bound_terms(
    raw_lagrangian_gradient_x: &[f64],
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    z_lower: &[f64],
    z_upper: &[f64],
    barrier_parameter: f64,
    kappa_d: f64,
) -> Vec<f64> {
    let mut result = damped_lagrangian_gradient_x_with_bound_terms(
        raw_lagrangian_gradient_x,
        bounds,
        z_lower,
        z_upper,
        barrier_parameter,
        kappa_d,
    );
    zero_fixed_entries(&mut result, fixed_variables);
    result
}

#[expect(
    clippy::too_many_arguments,
    reason = "Bound KKT assembly keeps IPOPT damping and complementarity terms explicit."
)]
fn native_bound_kkt_terms(
    x: &[f64],
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    z_lower: &[f64],
    z_upper: &[f64],
    barrier_parameter: f64,
    sigma: f64,
    kappa_d: f64,
) -> (Vec<f64>, Vec<f64>) {
    let mut diagonal = vec![0.0; fixed_variables.reduced_dimension()];
    let mut rhs = vec![0.0; fixed_variables.reduced_dimension()];
    let damping_weight = positive_slack_damping(barrier_parameter, kappa_d);
    for ((&index, &lower), &z_i) in bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .zip(z_lower.iter())
    {
        let Some(reduced_index) = fixed_variables.free_position[index] else {
            continue;
        };
        let slack = native_lower_bound_slack(x, index, lower);
        let residual = slack * z_i - sigma * barrier_parameter;
        diagonal[reduced_index] += z_i / slack;
        rhs[reduced_index] += -residual / slack;
        if damping_weight > 0.0 && !bounds.upper_indices.contains(&index) {
            rhs[reduced_index] -= damping_weight;
        }
    }
    for ((&index, &upper), &z_i) in bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .zip(z_upper.iter())
    {
        let Some(reduced_index) = fixed_variables.free_position[index] else {
            continue;
        };
        let slack = native_upper_bound_slack(x, index, upper);
        let residual = slack * z_i - sigma * barrier_parameter;
        diagonal[reduced_index] += z_i / slack;
        rhs[reduced_index] += residual / slack;
        if damping_weight > 0.0 && !bounds.lower_indices.contains(&index) {
            rhs[reduced_index] += damping_weight;
        }
    }
    (diagonal, rhs)
}

fn native_bound_multiplier_steps(
    x: &[f64],
    dx: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
    barrier_parameter: f64,
    sigma: f64,
) -> (Vec<f64>, Vec<f64>) {
    let dz_lower = bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .zip(z_lower.iter())
        .map(|((&index, &lower), &z_i)| {
            let slack = native_lower_bound_slack(x, index, lower);
            let residual = slack * z_i - sigma * barrier_parameter;
            (-residual - z_i * dx[index]) / slack
        })
        .collect::<Vec<_>>();
    let dz_upper = bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .zip(z_upper.iter())
        .map(|((&index, &upper), &z_i)| {
            let slack = native_upper_bound_slack(x, index, upper);
            let residual = slack * z_i - sigma * barrier_parameter;
            (-residual + z_i * dx[index]) / slack
        })
        .collect::<Vec<_>>();
    (dz_lower, dz_upper)
}

fn ipopt_restoration_bound_multiplier_step(
    current_multiplier: f64,
    current_slack: f64,
    trial_slack: f64,
    barrier_parameter: f64,
) -> f64 {
    // Mirrors Ipopt::MinC_1NrmRestorationPhase::ComputeBoundMultiplierStep.
    let mut delta = current_slack;
    delta -= trial_slack;
    delta *= current_multiplier;
    delta += barrier_parameter;
    delta /= current_slack;
    delta - current_multiplier
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT restoration multiplier reset touches each bound block explicitly."
)]
fn ipopt_restoration_bound_multiplier_update(
    current_x: &[f64],
    trial_x: &[f64],
    bounds: &BoundConstraints,
    current_slack_barrier: &[f64],
    trial_slack_barrier: &[f64],
    current_z_lower: &[f64],
    current_z_upper: &[f64],
    current_z: &[f64],
    barrier_parameter: f64,
    tau: f64,
) -> (Vec<f64>, Vec<f64>, Vec<f64>, f64, bool) {
    const BOUND_MULT_RESET_THRESHOLD: f64 = 1.0e3;

    let dz_lower = bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .zip(current_z_lower.iter())
        .map(|((&index, &lower), &z_i)| {
            ipopt_restoration_bound_multiplier_step(
                z_i,
                native_lower_bound_slack(current_x, index, lower),
                native_lower_bound_slack(trial_x, index, lower),
                barrier_parameter,
            )
        })
        .collect::<Vec<_>>();
    let dz_upper = bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .zip(current_z_upper.iter())
        .map(|((&index, &upper), &z_i)| {
            ipopt_restoration_bound_multiplier_step(
                z_i,
                native_upper_bound_slack(current_x, index, upper),
                native_upper_bound_slack(trial_x, index, upper),
                barrier_parameter,
            )
        })
        .collect::<Vec<_>>();
    let dz = current_z
        .iter()
        .zip(current_slack_barrier.iter())
        .zip(trial_slack_barrier.iter())
        .map(|((&z_i, &current_slack), &trial_slack)| {
            ipopt_restoration_bound_multiplier_step(
                z_i,
                current_slack,
                trial_slack,
                barrier_parameter,
            )
        })
        .collect::<Vec<_>>();

    let alpha_dual = ipopt_dual_fraction_to_boundary_with_limiter(
        current_z_lower,
        &dz_lower,
        current_z_upper,
        &dz_upper,
        current_z,
        &dz,
        tau,
    )
    .0
    .clamp(0.0, 1.0);

    let mut trial_z_lower = current_z_lower
        .iter()
        .zip(dz_lower.iter())
        .map(|(value, delta)| ipopt_dense_current_plus_step(*value, alpha_dual, *delta))
        .collect::<Vec<_>>();
    let mut trial_z_upper = current_z_upper
        .iter()
        .zip(dz_upper.iter())
        .map(|(value, delta)| ipopt_dense_current_plus_step(*value, alpha_dual, *delta))
        .collect::<Vec<_>>();
    let mut trial_z = current_z
        .iter()
        .zip(dz.iter())
        .map(|(value, delta)| ipopt_dense_current_plus_step(*value, alpha_dual, *delta))
        .collect::<Vec<_>>();

    let bound_mult_max = trial_z_lower
        .iter()
        .chain(trial_z_upper.iter())
        .chain(trial_z.iter())
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let reset = bound_mult_max > BOUND_MULT_RESET_THRESHOLD;
    if reset {
        trial_z_lower.fill(1.0);
        trial_z_upper.fill(1.0);
        trial_z.fill(1.0);
    }

    (trial_z_lower, trial_z_upper, trial_z, alpha_dual, reset)
}

fn interior_point_direction_diagnostics(
    direction: &NewtonDirection,
    alpha_pr_limiter: Option<InteriorPointBoundaryLimiter>,
    alpha_du_limiter: Option<InteriorPointBoundaryLimiter>,
    alpha_pr_limiters: Vec<InteriorPointBoundaryLimiter>,
    alpha_du_limiters: Vec<InteriorPointBoundaryLimiter>,
) -> InteriorPointDirectionDiagnostics {
    InteriorPointDirectionDiagnostics {
        dx_inf: step_inf_norm(&direction.dx),
        d_lambda_inf: step_inf_norm(&direction.d_lambda).max(step_inf_norm(&direction.d_ineq)),
        ds_inf: step_inf_norm(&direction.ds),
        dz_inf: step_inf_norm(&direction.dz)
            .max(step_inf_norm(&direction.dz_lower))
            .max(step_inf_norm(&direction.dz_upper)),
        regularization_size: direction.regularization_used,
        primal_diagonal_shift: direction.primal_diagonal_shift_used,
        dual_regularization: direction.dual_regularization_used,
        alpha_pr_limiter,
        alpha_du_limiter,
        alpha_pr_limiters,
        alpha_du_limiters,
    }
}

fn native_bound_complementarity_inf_norm(
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
) -> f64 {
    let lower_inf = bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .zip(z_lower.iter())
        .fold(0.0_f64, |acc, ((&index, &lower), &z_i)| {
            acc.max((native_lower_bound_slack(x, index, lower) * z_i).abs())
        });
    bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .zip(z_upper.iter())
        .fold(lower_inf, |acc, ((&index, &upper), &z_i)| {
            acc.max((native_upper_bound_slack(x, index, upper) * z_i).abs())
        })
}

fn combined_complementarity_inf_norm(
    slack: &[f64],
    z: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
) -> f64 {
    let slack_inf = if slack.is_empty() {
        0.0
    } else {
        complementarity_inf_norm(slack, z)
    };
    slack_inf.max(native_bound_complementarity_inf_norm(
        x, bounds, z_lower, z_upper,
    ))
}

fn combined_complementarity_target_inf_norm(
    slack: &[f64],
    z: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
    mu_target: f64,
) -> f64 {
    let slack_inf = interior_point_complementarity_target_inf_norm(slack, z, mu_target);
    let lower_inf = bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .zip(z_lower.iter())
        .fold(0.0_f64, |acc, ((&index, &lower), &z_i)| {
            acc.max((native_lower_bound_slack(x, index, lower) * z_i - mu_target).abs())
        });
    bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .zip(z_upper.iter())
        .fold(slack_inf.max(lower_inf), |acc, ((&index, &upper), &z_i)| {
            acc.max((native_upper_bound_slack(x, index, upper) * z_i - mu_target).abs())
        })
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT barrier-error scaling depends on every multiplier block."
)]
fn barrier_subproblem_error_components(
    primal_inf: f64,
    dual_inf: f64,
    slack: &[f64],
    z: &[f64],
    x: &[f64],
    bounds: &BoundConstraints,
    z_lower: &[f64],
    z_upper: &[f64],
    lambda_eq: &[f64],
    lambda_ineq: &[f64],
    barrier_parameter: f64,
    options: &InteriorPointOptions,
) -> (f64, f64) {
    let complementarity_inf = combined_complementarity_target_inf_norm(
        slack,
        z,
        x,
        bounds,
        z_lower,
        z_upper,
        barrier_parameter,
    );
    let all_dual_multipliers =
        ipopt_all_dual_multiplier_vector(lambda_eq, lambda_ineq, z_lower, z_upper, z);
    let complementarity_multipliers = ipopt_complementarity_multiplier_vector(z_lower, z_upper, z);
    let error = scaled_overall_inf_norm(
        primal_inf,
        dual_inf,
        complementarity_inf,
        &all_dual_multipliers,
        &complementarity_multipliers,
        options.overall_scale_max,
    );
    (complementarity_inf, error)
}

fn combined_multiplier_vector<'a>(slices: impl IntoIterator<Item = &'a [f64]>) -> Vec<f64> {
    slices
        .into_iter()
        .flat_map(|slice| slice.iter().copied())
        .collect()
}

fn ipopt_all_dual_multiplier_vector(
    lambda_eq: &[f64],
    lambda_ineq: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    z: &[f64],
) -> Vec<f64> {
    // IpoptCalculatedQuantities::ComputeOptimalityErrorScaling accumulates
    // y_c, y_d, z_L, z_U, v_L, then v_U. NLIP has no lower slack multiplier,
    // so the upper-slack multiplier block comes after bound multipliers.
    combined_multiplier_vector([lambda_eq, lambda_ineq, z_lower, z_upper, z])
}

fn ipopt_complementarity_multiplier_vector(
    z_lower: &[f64],
    z_upper: &[f64],
    z: &[f64],
) -> Vec<f64> {
    // Same source order as IpoptCalculatedQuantities::curr_complementarity:
    // z_L, z_U, v_L, then v_U; NLIP omits v_L.
    combined_multiplier_vector([z_lower, z_upper, z])
}

fn correct_bound_multiplier_estimate(
    trial_z: &[f64],
    trial_slack: &[f64],
    barrier_parameter: f64,
    kappa_sigma: f64,
) -> (Vec<f64>, f64) {
    if kappa_sigma < 1.0 || trial_z.is_empty() {
        return (trial_z.to_vec(), 0.0);
    }

    let upper_complementarity = kappa_sigma * barrier_parameter;
    let lower_complementarity = barrier_parameter / kappa_sigma;
    let needs_correction = trial_z
        .iter()
        .zip(trial_slack.iter())
        .any(|(z_i, slack_i)| {
            let compl = z_i * slack_i;
            compl > upper_complementarity || compl < lower_complementarity
        });
    if !needs_correction {
        return (trial_z.to_vec(), 0.0);
    }

    let mut corrected_z = trial_z.to_vec();
    let mut max_correction = 0.0_f64;
    for (z_i, slack_i) in corrected_z.iter_mut().zip(trial_slack.iter()) {
        // IPOPT `IpoptAlgorithm::correct_bound_multiplier` computes a
        // correction vector using one_over_s, then adds the negative/positive
        // correction back to z.  Preserve that order instead of assigning the
        // mathematically equivalent clamp endpoints directly. The correction
        // vector is built through DenseVector::AddTwoVectors, so the native C++
        // build contracts the multiply-subtract in the general branch.
        let one_over_s = 1.0 / *slack_i;
        let step_to_upper = upper_complementarity.mul_add(one_over_s, -*z_i);
        let max_correction_up = (-step_to_upper).max(0.0);
        if step_to_upper < 0.0 {
            *z_i += step_to_upper;
        }
        let step_to_lower = lower_complementarity.mul_add(one_over_s, -*z_i);
        let max_correction_low = step_to_lower.max(0.0);
        if step_to_lower > 0.0 {
            *z_i += step_to_lower;
        }
        max_correction = max_correction.max(max_correction_up.max(max_correction_low));
    }

    (corrected_z, max_correction)
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT kappa_sigma correction needs the full accepted trial multiplier state."
)]
fn apply_bound_multiplier_safeguard(
    inequality_multipliers: &[f64],
    raw_dual_residual: &[f64],
    fixed_variables: &FixedVariableElimination,
    x: &[f64],
    bounds: &BoundConstraints,
    slack: &[f64],
    z: &[f64],
    z_lower: &[f64],
    z_upper: &[f64],
    barrier_parameter_value: f64,
    options: &InteriorPointOptions,
) -> Option<AcceptedTrialMultiplierState> {
    let (corrected_z, max_correction) =
        correct_bound_multiplier_estimate(z, slack, barrier_parameter_value, options.kappa_sigma);

    let lower_slack = bounds
        .lower_indices
        .iter()
        .zip(bounds.lower_values.iter())
        .map(|(&index, &lower)| native_lower_bound_slack(x, index, lower))
        .collect::<Vec<_>>();
    let (corrected_z_lower, lower_max_correction) = correct_bound_multiplier_estimate(
        z_lower,
        &lower_slack,
        barrier_parameter_value,
        options.kappa_sigma,
    );

    let upper_slack = bounds
        .upper_indices
        .iter()
        .zip(bounds.upper_values.iter())
        .map(|(&index, &upper)| native_upper_bound_slack(x, index, upper))
        .collect::<Vec<_>>();
    let (corrected_z_upper, upper_max_correction) = correct_bound_multiplier_estimate(
        z_upper,
        &upper_slack,
        barrier_parameter_value,
        options.kappa_sigma,
    );

    if max_correction
        .max(lower_max_correction)
        .max(upper_max_correction)
        <= 0.0
    {
        return None;
    }

    let mut corrected_dual_residual = raw_dual_residual.to_vec();
    add_native_bound_multiplier_terms(
        &mut corrected_dual_residual,
        bounds,
        &corrected_z_lower,
        &corrected_z_upper,
    );
    let corrected_dual_x_inf = fixed_variables.free_inf_norm(&corrected_dual_residual);
    let corrected_slack_stationarity_inf =
        slack_stationarity_inf_norm(inequality_multipliers, &corrected_z);
    let corrected_dual_inf = corrected_dual_x_inf.max(corrected_slack_stationarity_inf);

    Some(AcceptedTrialMultiplierState {
        z: corrected_z,
        z_lower: corrected_z_lower,
        z_upper: corrected_z_upper,
        dual_inf: corrected_dual_inf,
    })
}

fn adapter_timing_delta<P>(
    problem: &P,
    previous: &mut Option<SolverAdapterTiming>,
) -> Option<SolverAdapterTiming>
where
    P: CompiledNlpProblem,
{
    let current = problem.adapter_timing_snapshot();
    let delta = match (current, *previous) {
        (Some(current), Some(previous)) => Some(current.saturating_sub(previous)),
        (Some(current), None) => Some(current),
        (None, _) => None,
    };
    *previous = current;
    delta
}

fn push_scalar_to_bounds_interior(
    value: f64,
    lower: Option<f64>,
    upper: Option<f64>,
    bound_push: f64,
    bound_frac: f64,
) -> f64 {
    let snapped = match (lower, upper) {
        (Some(lower), Some(upper)) if lower <= upper => value.clamp(lower, upper),
        (Some(lower), _) => value.max(lower),
        (_, Some(upper)) => value.min(upper),
        (None, None) => value,
    };
    if bound_frac <= 0.0 {
        return snapped;
    }

    // Mirrors Ipopt::DefaultIterateInitializer::push_variables: IPOPT first
    // snaps to the original bounds, then applies bound_push/bound_frac margins
    // with the same asymmetric tiny-double handling for lower and upper sides.
    let tiny_double = 100.0 * f64::MIN_POSITIVE;
    let mut lower_correction = 0.0_f64;
    if let Some(lower) = lower {
        let mut lower_margin = bound_push * lower.abs().max(1.0);
        if let Some(upper) = upper
            && upper > lower
        {
            let fractional_margin = bound_frac * (upper - lower) - tiny_double;
            if fractional_margin > 0.0 {
                lower_margin = lower_margin.min(fractional_margin);
            }
        }
        lower_correction = (lower + lower_margin - snapped).max(0.0);
    }
    let mut upper_correction = 0.0_f64;
    if let Some(upper) = upper {
        let mut upper_margin = bound_push * upper.abs().max(1.0);
        if let Some(lower) = lower
            && upper > lower
        {
            let fractional_margin = bound_frac * (upper - lower) - tiny_double;
            if fractional_margin > 0.0 {
                upper_margin = upper_margin.min(fractional_margin);
            }
        }
        upper_margin += tiny_double;
        upper_correction = (snapped - (upper - upper_margin)).max(0.0);
    }
    snapped + lower_correction - upper_correction
}

fn project_initial_point_into_box_interior(
    x: &mut [f64],
    bounds: &BoundConstraints,
    options: &InteriorPointOptions,
) {
    for (idx, x_i) in x.iter_mut().enumerate() {
        let lower = bounds
            .lower_indices
            .iter()
            .position(|lower_idx| *lower_idx == idx)
            .map(|position| bounds.lower_values[position]);
        let upper = bounds
            .upper_indices
            .iter()
            .position(|upper_idx| *upper_idx == idx)
            .map(|position| bounds.upper_values[position]);
        *x_i = push_scalar_to_bounds_interior(
            *x_i,
            lower,
            upper,
            options.bound_push,
            options.bound_frac,
        );
    }
}

fn collect_interior_point_bounds_and_fixed<P>(
    problem: &P,
    options: &InteriorPointOptions,
) -> std::result::Result<(BoundConstraints, FixedVariableElimination), InteriorPointSolveError>
where
    P: CompiledNlpProblem,
{
    let dimension = problem.dimension();
    let Some(bounds_view) = problem.variable_bounds() else {
        return Ok((
            BoundConstraints::default(),
            FixedVariableElimination::none(dimension),
        ));
    };
    let lower = bounds_view.lower.unwrap_or_default();
    let upper = bounds_view.upper.unwrap_or_default();

    let mut bounds = BoundConstraints::default();
    let mut fixed_indices = Vec::new();
    let mut fixed_values = Vec::new();
    for idx in 0..dimension {
        let lower_bound = lower.get(idx).copied().flatten();
        let upper_bound = upper.get(idx).copied().flatten();
        if let (Some(lower_bound), Some(upper_bound)) = (lower_bound, upper_bound) {
            if lower_bound > upper_bound {
                return Err(InteriorPointSolveError::InvalidInput(format!(
                    "variable bound interval is empty at index {idx}: lower={lower_bound} > upper={upper_bound}"
                )));
            }
            if lower_bound == upper_bound {
                fixed_indices.push(idx);
                fixed_values.push(lower_bound);
                continue;
            }
        }
        if let Some(lower_bound) = lower_bound {
            bounds.lower_indices.push(idx);
            let relaxation = if problem.relax_variable_lower_bound(idx) {
                bound_relaxation_amount(lower_bound, options)
            } else {
                0.0
            };
            bounds.lower_values.push(lower_bound - relaxation);
        }
        if let Some(upper_bound) = upper_bound {
            bounds.upper_indices.push(idx);
            let relaxation = if problem.relax_variable_upper_bound(idx) {
                bound_relaxation_amount(upper_bound, options)
            } else {
                0.0
            };
            bounds.upper_values.push(upper_bound + relaxation);
        }
    }

    Ok((
        bounds,
        FixedVariableElimination::new(dimension, fixed_indices, fixed_values),
    ))
}

fn initialise_slacks(
    augmented_inequality_values: &[f64],
    upper_bounds: &[f64],
    slack: &mut [f64],
    options: &InteriorPointOptions,
) {
    debug_assert_eq!(augmented_inequality_values.len(), slack.len());
    debug_assert_eq!(augmented_inequality_values.len(), upper_bounds.len());
    for ((&g_i, &upper), s_i) in augmented_inequality_values
        .iter()
        .zip(upper_bounds.iter())
        .zip(slack.iter_mut())
    {
        // Mirrors Ipopt::DefaultIterateInitializer::push_variables for the
        // slack variable s with only a relaxed upper bound d_U: start from
        // trial_d() = d(x), snap to d_U if needed, then push strictly inside.
        *s_i = push_scalar_to_bounds_interior(
            g_i,
            None,
            Some(upper),
            options.slack_bound_push,
            options.slack_bound_frac,
        );
    }
}

fn sparse_row_entries(ccs: &CCS) -> Vec<Vec<(usize, usize)>> {
    let mut row_entries = vec![Vec::new(); ccs.nrow];
    for col in 0..ccs.ncol {
        for index in ccs.col_ptrs[col]..ccs.col_ptrs[col + 1] {
            row_entries[ccs.row_indices[index]].push((col, index));
        }
    }
    row_entries
}

fn sparse_structure_from_ccs(ccs: &CCS) -> SparseMatrixStructure {
    SparseMatrixStructure {
        ccs: ccs.clone(),
        row_entries: sparse_row_entries(ccs),
    }
}

fn build_sparse_column_reduction(
    source: &SparseMatrixStructure,
    fixed_variables: &FixedVariableElimination,
) -> SparseColumnReduction {
    if !fixed_variables.has_fixed() {
        return SparseColumnReduction {
            structure: Arc::new(source.clone()),
            source_value_indices: (0..source.ccs.nnz()).collect(),
        };
    }

    let mut col_ptrs = Vec::with_capacity(fixed_variables.reduced_dimension() + 1);
    let mut row_indices = Vec::new();
    let mut source_value_indices = Vec::new();
    col_ptrs.push(0);
    for &source_col in &fixed_variables.free_indices {
        for source_index in source.ccs.col_ptrs[source_col]..source.ccs.col_ptrs[source_col + 1] {
            row_indices.push(source.ccs.row_indices[source_index]);
            source_value_indices.push(source_index);
        }
        col_ptrs.push(row_indices.len());
    }
    let ccs = CCS::new(
        source.ccs.nrow,
        fixed_variables.reduced_dimension(),
        col_ptrs,
        row_indices,
    );
    SparseColumnReduction {
        structure: Arc::new(sparse_structure_from_ccs(&ccs)),
        source_value_indices,
    }
}

fn reduce_sparse_matrix_columns(
    matrix: &SparseMatrix,
    reduction: &SparseColumnReduction,
) -> SparseMatrix {
    SparseMatrix {
        structure: Arc::clone(&reduction.structure),
        values: reduction
            .source_value_indices
            .iter()
            .map(|&source_index| matrix.values[source_index])
            .collect(),
    }
}

fn build_symmetric_submatrix_reduction(
    source: &CCS,
    fixed_variables: &FixedVariableElimination,
) -> SymmetricSubmatrixReduction {
    if !fixed_variables.has_fixed() {
        return SymmetricSubmatrixReduction {
            lower_triangle: Arc::new(source.clone()),
            source_value_indices: (0..source.nnz()).collect(),
        };
    }

    let mut col_ptrs = Vec::with_capacity(fixed_variables.reduced_dimension() + 1);
    let mut row_indices = Vec::new();
    let mut source_value_indices = Vec::new();
    col_ptrs.push(0);
    for &source_col in &fixed_variables.free_indices {
        for source_index in source.col_ptrs[source_col]..source.col_ptrs[source_col + 1] {
            let source_row = source.row_indices[source_index];
            if let Some(reduced_row) = fixed_variables.free_position[source_row] {
                row_indices.push(reduced_row);
                source_value_indices.push(source_index);
            }
        }
        col_ptrs.push(row_indices.len());
    }
    SymmetricSubmatrixReduction {
        lower_triangle: Arc::new(CCS::new(
            fixed_variables.reduced_dimension(),
            fixed_variables.reduced_dimension(),
            col_ptrs,
            row_indices,
        )),
        source_value_indices,
    }
}

fn reduce_symmetric_matrix(
    matrix: &SparseSymmetricMatrix,
    reduction: &SymmetricSubmatrixReduction,
) -> SparseSymmetricMatrix {
    SparseSymmetricMatrix {
        lower_triangle: Arc::clone(&reduction.lower_triangle),
        values: reduction
            .source_value_indices
            .iter()
            .map(|&source_index| matrix.values[source_index])
            .collect(),
    }
}

fn sparse_add_transpose_mat_vec(out: &mut [f64], matrix: &SparseMatrix, vector: &[f64]) {
    debug_assert_eq!(matrix.nrows(), vector.len());
    debug_assert_eq!(matrix.ncols(), out.len());
    for (col, out_col) in out.iter_mut().enumerate().take(matrix.ncols()) {
        let mut sum = 0.0;
        for index in matrix.structure.ccs.col_ptrs[col]..matrix.structure.ccs.col_ptrs[col + 1] {
            sum += matrix.values[index] * vector[matrix.structure.ccs.row_indices[index]];
        }
        *out_col += sum;
    }
}

fn sparse_add_transpose_mat_vec_ipopt_order(
    out: &mut [f64],
    matrix: &SparseMatrix,
    vector: &[f64],
) {
    debug_assert_eq!(matrix.nrows(), vector.len());
    debug_assert_eq!(matrix.ncols(), out.len());
    // IpGenTMatrix.cpp::TransMultVectorImpl accumulates directly into y in
    // the stored triplet order.  The observed source-built IPOPT C++ path contracts
    // `y += value * x` to FMA, so use `mul_add` in this IPOPT-parity helper.
    for (col, out_col) in out.iter_mut().enumerate().take(matrix.ncols()) {
        for index in matrix.structure.ccs.col_ptrs[col]..matrix.structure.ccs.col_ptrs[col + 1] {
            *out_col = matrix.values[index]
                .mul_add(vector[matrix.structure.ccs.row_indices[index]], *out_col);
        }
    }
}

fn sparse_mat_vec(matrix: &SparseMatrix, vector: &[f64]) -> Vec<f64> {
    debug_assert_eq!(matrix.ncols(), vector.len());
    let mut product = vec![0.0; matrix.nrows()];
    for (col, &x) in vector.iter().enumerate().take(matrix.ncols()) {
        if x == 0.0 {
            continue;
        }
        for index in matrix.structure.ccs.col_ptrs[col]..matrix.structure.ccs.col_ptrs[col + 1] {
            product[matrix.structure.ccs.row_indices[index]] += matrix.values[index] * x;
        }
    }
    product
}

fn sparse_mat_vec_ipopt_order(matrix: &SparseMatrix, vector: &[f64]) -> Vec<f64> {
    debug_assert_eq!(matrix.ncols(), vector.len());
    let mut product = vec![0.0; matrix.nrows()];
    // IpGenTMatrix.cpp::MultVectorImpl visits every stored nonzero in triplet
    // order, even when the corresponding dense-vector entry is exactly zero,
    // and the observed source-built IPOPT C++ path contracts the multiply-add.
    for (col, &x) in vector.iter().enumerate().take(matrix.ncols()) {
        for index in matrix.structure.ccs.col_ptrs[col]..matrix.structure.ccs.col_ptrs[col + 1] {
            let row = matrix.structure.ccs.row_indices[index];
            product[row] = matrix.values[index].mul_add(x, product[row]);
        }
    }
    product
}

fn symmetric_ccs_lower_mat_vec(ccs: &CCS, values: &[f64], vector: &[f64]) -> Vec<f64> {
    debug_assert_eq!(ccs.nrow, ccs.ncol);
    debug_assert_eq!(ccs.nrow, vector.len());
    debug_assert_eq!(ccs.nnz(), values.len());
    let mut product = vec![0.0; ccs.nrow];
    for col in 0..ccs.ncol {
        let x_col = vector[col];
        let start = ccs.col_ptrs[col];
        let end = ccs.col_ptrs[col + 1];
        for (&row, &value) in ccs.row_indices[start..end]
            .iter()
            .zip(values[start..end].iter())
        {
            product[row] += value * x_col;
            if row != col {
                product[col] += value * vector[row];
            }
        }
    }
    product
}

fn symmetric_ccs_lower_mat_vec_ipopt_order(ccs: &CCS, values: &[f64], vector: &[f64]) -> Vec<f64> {
    debug_assert_eq!(ccs.nrow, ccs.ncol);
    debug_assert_eq!(ccs.nrow, vector.len());
    debug_assert_eq!(ccs.nnz(), values.len());
    let mut product = vec![0.0; ccs.nrow];
    // IpSymTMatrix.cpp::MultVectorImpl traverses the lower-triangular triplets
    // in storage order and accumulates directly into the dense output.  The
    // full-space residual replay uses the alpha=1 branch, so the source
    // expression reduces to `y += value * x` for each diagonal and mirrored
    // off-diagonal contribution.
    for col in 0..ccs.ncol {
        let x_col = vector[col];
        let start = ccs.col_ptrs[col];
        let end = ccs.col_ptrs[col + 1];
        for (&row, &value) in ccs.row_indices[start..end]
            .iter()
            .zip(values[start..end].iter())
        {
            product[row] = value.mul_add(x_col, product[row]);
            if row != col {
                product[col] = value.mul_add(vector[row], product[col]);
            }
        }
    }
    product
}

fn ipopt_add_delta_minus_rhs(values: &mut [f64], delta_scale: f64, delta: &[f64], rhs: &[f64]) {
    debug_assert_eq!(values.len(), delta.len());
    debug_assert_eq!(values.len(), rhs.len());

    // Mirror IpDenseVector.cpp::AddTwoVectorsImpl for c=1, b=-1. IPOPT takes
    // a BLAS axpy branch when a==0, so the delta vector is not evaluated. In
    // the general source-built C++ branch, `a * v1 - v2` is contracted before
    // adding into the destination.
    if delta_scale == 0.0 {
        for (value, rhs_i) in values.iter_mut().zip(rhs.iter()) {
            *value -= *rhs_i;
        }
    } else {
        for ((value, delta_i), rhs_i) in values.iter_mut().zip(delta.iter()).zip(rhs.iter()) {
            *value += delta_scale.mul_add(*delta_i, -*rhs_i);
        }
    }
}

fn ipopt_blas_axpy_value(value: f64, alpha: f64, delta: f64) -> f64 {
    // DenseVector::AxpyImpl dispatches to IpBlasAxpy for dense vectors on this
    // path. The source-built BLAS DAXPY contracts the multiply-add; keep the
    // alpha==0 branch inactive just as IPOPT skips perturbation Axpy calls.
    if alpha == 0.0 {
        value
    } else {
        alpha.mul_add(delta, value)
    }
}

fn ipopt_lower_bound_residual_z(slack: f64, dz: f64, z: f64, dx: f64, rhs_z: f64) -> f64 {
    let mut residual = slack * dz;
    residual += z * dx - rhs_z;
    residual
}

fn ipopt_upper_bound_residual_z(slack: f64, dz: f64, z: f64, dx: f64, rhs_z: f64) -> f64 {
    let mut residual = slack * dz;
    residual += -(z * dx) - rhs_z;
    residual
}

fn symmetric_ccs_lower_abs_mat_vec(ccs: &CCS, values: &[f64], vector_abs: &[f64]) -> Vec<f64> {
    debug_assert_eq!(ccs.nrow, ccs.ncol);
    debug_assert_eq!(ccs.nrow, vector_abs.len());
    debug_assert_eq!(ccs.nnz(), values.len());
    let mut product = vec![0.0; ccs.nrow];
    for col in 0..ccs.ncol {
        let x_col_abs = vector_abs[col];
        let start = ccs.col_ptrs[col];
        let end = ccs.col_ptrs[col + 1];
        for (&row, &value) in ccs.row_indices[start..end]
            .iter()
            .zip(values[start..end].iter())
        {
            let value_abs = value.abs();
            product[row] += value_abs * x_col_abs;
            if row != col {
                product[col] += value_abs * vector_abs[row];
            }
        }
    }
    product
}

fn build_spral_augmented_kkt_pattern(
    hessian_structure: &CCS,
    equality_jacobian: &SparseMatrixStructure,
    inequality_jacobian: &SparseMatrixStructure,
) -> std::result::Result<SpralAugmentedKktPattern, InteriorPointSolveError> {
    let n = hessian_structure.nrow;
    if hessian_structure.ncol != n {
        return Err(InteriorPointSolveError::InvalidInput(
            "interior-point Hessian structure must be square".into(),
        ));
    }
    let meq = equality_jacobian.ccs.nrow;
    let mineq = inequality_jacobian.ccs.nrow;
    let p_offset = n;
    let lambda_offset = p_offset + mineq;
    let z_offset = lambda_offset + meq;
    let total_dimension = z_offset + mineq;

    let mut columns = vec![Vec::<usize>::new(); total_dimension];
    for (col, column) in columns.iter_mut().enumerate().take(n) {
        column.push(col);
        for index in hessian_structure.col_ptrs[col]..hessian_structure.col_ptrs[col + 1] {
            column.push(hessian_structure.row_indices[index]);
        }
    }
    for (col, column) in columns
        .iter_mut()
        .enumerate()
        .take(equality_jacobian.ccs.ncol)
    {
        for index in equality_jacobian.ccs.col_ptrs[col]..equality_jacobian.ccs.col_ptrs[col + 1] {
            column.push(lambda_offset + equality_jacobian.ccs.row_indices[index]);
        }
    }
    for (col, column) in columns
        .iter_mut()
        .enumerate()
        .take(inequality_jacobian.ccs.ncol)
    {
        for index in
            inequality_jacobian.ccs.col_ptrs[col]..inequality_jacobian.ccs.col_ptrs[col + 1]
        {
            column.push(z_offset + inequality_jacobian.ccs.row_indices[index]);
        }
    }
    for row in 0..mineq {
        let p_index = p_offset + row;
        columns[p_index].push(p_index);
        columns[p_index].push(z_offset + row);
    }
    for row in 0..meq {
        let lambda_index = lambda_offset + row;
        columns[lambda_index].push(lambda_index);
    }
    for row in 0..mineq {
        let z_index = z_offset + row;
        columns[z_index].push(z_index);
    }

    let mut col_ptrs = Vec::with_capacity(total_dimension + 1);
    let mut row_indices = Vec::new();
    col_ptrs.push(0);
    for (col, rows) in columns.iter_mut().enumerate() {
        rows.sort_unstable();
        rows.dedup();
        if rows.iter().any(|&row| row < col) {
            return Err(InteriorPointSolveError::InvalidInput(format!(
                "invalid lower-triangular sparse KKT pattern in column {col}"
            )));
        }
        row_indices.extend_from_slice(rows);
        col_ptrs.push(row_indices.len());
    }
    let ccs = Arc::new(CCS::new(
        total_dimension,
        total_dimension,
        col_ptrs,
        row_indices,
    ));
    let mut column_maps = vec![HashMap::<usize, usize>::new(); total_dimension];
    for (col, column_map) in column_maps.iter_mut().enumerate().take(total_dimension) {
        for index in ccs.col_ptrs[col]..ccs.col_ptrs[col + 1] {
            column_map.insert(ccs.row_indices[index], index);
        }
    }
    let lookup = |col: usize, row: usize| -> std::result::Result<usize, InteriorPointSolveError> {
        column_maps[col].get(&row).copied().ok_or_else(|| {
            InteriorPointSolveError::InvalidInput(format!(
                "missing sparse KKT slot for entry ({row}, {col})"
            ))
        })
    };
    let mut hessian_value_indices = Vec::with_capacity(hessian_structure.nnz());
    for col in 0..n {
        for index in hessian_structure.col_ptrs[col]..hessian_structure.col_ptrs[col + 1] {
            hessian_value_indices.push(lookup(col, hessian_structure.row_indices[index])?);
        }
    }
    let mut equality_jacobian_value_indices = Vec::with_capacity(equality_jacobian.ccs.nnz());
    for col in 0..equality_jacobian.ccs.ncol {
        for index in equality_jacobian.ccs.col_ptrs[col]..equality_jacobian.ccs.col_ptrs[col + 1] {
            equality_jacobian_value_indices.push(lookup(
                col,
                lambda_offset + equality_jacobian.ccs.row_indices[index],
            )?);
        }
    }
    let mut inequality_jacobian_value_indices = Vec::with_capacity(inequality_jacobian.ccs.nnz());
    for col in 0..inequality_jacobian.ccs.ncol {
        for index in
            inequality_jacobian.ccs.col_ptrs[col]..inequality_jacobian.ccs.col_ptrs[col + 1]
        {
            inequality_jacobian_value_indices.push(lookup(
                col,
                z_offset + inequality_jacobian.ccs.row_indices[index],
            )?);
        }
    }
    let x_diagonal_indices = (0..n)
        .map(|diag| lookup(diag, diag))
        .collect::<std::result::Result<Vec<_>, _>>()?;
    let p_diagonal_indices = (0..mineq)
        .map(|diag| {
            let index = p_offset + diag;
            lookup(index, index)
        })
        .collect::<std::result::Result<Vec<_>, _>>()?;
    let lambda_diagonal_indices = (0..meq)
        .map(|diag| {
            let index = lambda_offset + diag;
            lookup(index, index)
        })
        .collect::<std::result::Result<Vec<_>, _>>()?;
    let z_diagonal_indices = (0..mineq)
        .map(|diag| {
            let index = z_offset + diag;
            lookup(index, index)
        })
        .collect::<std::result::Result<Vec<_>, _>>()?;
    let pz_indices = (0..mineq)
        .map(|row| lookup(p_offset + row, z_offset + row))
        .collect::<std::result::Result<Vec<_>, _>>()?;

    Ok(SpralAugmentedKktPattern {
        ccs,
        x_dimension: n,
        inequality_dimension: mineq,
        equality_dimension: meq,
        p_offset,
        lambda_offset,
        z_offset,
        hessian_value_indices,
        equality_jacobian_value_indices,
        inequality_jacobian_value_indices,
        x_diagonal_indices,
        p_diagonal_indices,
        lambda_diagonal_indices,
        z_diagonal_indices,
        pz_indices,
    })
}

#[derive(Clone, Debug)]
struct LagrangianGradientComponents {
    curr_grad_f: Vec<f64>,
    curr_jac_c_t_y_c: Vec<f64>,
    curr_jac_d_t_y_d: Vec<f64>,
    curr_grad_lag_x: Vec<f64>,
}

fn lagrangian_gradient_components(
    gradient: &[f64],
    equality_jacobian: &SparseMatrix,
    equality_multipliers: &[f64],
    inequality_jacobian: &SparseMatrix,
    inequality_multipliers: &[f64],
) -> LagrangianGradientComponents {
    let curr_grad_f = gradient.to_vec();
    let mut curr_jac_c_t_y_c = vec![0.0; gradient.len()];
    let mut curr_jac_d_t_y_d = vec![0.0; gradient.len()];
    sparse_add_transpose_mat_vec_ipopt_order(
        &mut curr_jac_c_t_y_c,
        equality_jacobian,
        equality_multipliers,
    );
    sparse_add_transpose_mat_vec_ipopt_order(
        &mut curr_jac_d_t_y_d,
        inequality_jacobian,
        inequality_multipliers,
    );
    // Mirrors IpIpoptCalculatedQuantities.cpp::curr_grad_lag_x:
    // tmp starts as curr_grad_f(), then AddTwoVectors(1., jac_cT*y_c,
    // 1., jac_dT*y_d, 1.) accumulates both multiplier products in one pass.
    let mut curr_grad_lag_x = curr_grad_f.clone();
    for ((residual_i, equality_i), inequality_i) in curr_grad_lag_x
        .iter_mut()
        .zip(curr_jac_c_t_y_c.iter())
        .zip(curr_jac_d_t_y_d.iter())
    {
        *residual_i += *equality_i + *inequality_i;
    }
    LagrangianGradientComponents {
        curr_grad_f,
        curr_jac_c_t_y_c,
        curr_jac_d_t_y_d,
        curr_grad_lag_x,
    }
}

fn lagrangian_gradient_sparse(
    gradient: &[f64],
    equality_jacobian: &SparseMatrix,
    equality_multipliers: &[f64],
    inequality_jacobian: &SparseMatrix,
    inequality_multipliers: &[f64],
) -> Vec<f64> {
    lagrangian_gradient_components(
        gradient,
        equality_jacobian,
        equality_multipliers,
        inequality_jacobian,
        inequality_multipliers,
    )
    .curr_grad_lag_x
}

struct TrialEvaluationContext<'a> {
    equality_jacobian_structure: &'a Arc<SparseMatrixStructure>,
    inequality_jacobian_structure: &'a Arc<SparseMatrixStructure>,
}

fn trial_state<P>(
    problem: &P,
    x: &[f64],
    parameters: &[ParameterMatrix<'_>],
    context: &TrialEvaluationContext<'_>,
    profiling: &mut InteriorPointProfiling,
    callback_time: &mut Duration,
) -> EvalState
where
    P: CompiledNlpProblem,
{
    let mut gradient = vec![0.0; problem.dimension()];
    let mut equality_values = vec![0.0; problem.equality_count()];
    let mut augmented_inequality_values = vec![0.0; problem.inequality_count()];
    let mut equality_jacobian_values = vec![0.0; problem.equality_jacobian_ccs().nnz()];
    let mut inequality_jacobian_values = vec![0.0; problem.inequality_jacobian_ccs().nnz()];
    let objective_value = time_callback(&mut profiling.objective_value, callback_time, || {
        problem.objective_value(x, parameters)
    });
    time_callback(&mut profiling.objective_gradient, callback_time, || {
        problem.objective_gradient(x, parameters, &mut gradient);
    });
    time_callback(&mut profiling.equality_values, callback_time, || {
        problem.equality_values(x, parameters, &mut equality_values);
    });
    time_callback(&mut profiling.inequality_values, callback_time, || {
        problem.inequality_values(x, parameters, &mut augmented_inequality_values);
    });
    time_callback(
        &mut profiling.equality_jacobian_values,
        callback_time,
        || problem.equality_jacobian_values(x, parameters, &mut equality_jacobian_values),
    );
    time_callback(
        &mut profiling.inequality_jacobian_values,
        callback_time,
        || problem.inequality_jacobian_values(x, parameters, &mut inequality_jacobian_values),
    );
    EvalState {
        objective_value,
        gradient,
        equality_values,
        augmented_inequality_values,
        equality_jacobian: SparseMatrix {
            structure: Arc::clone(context.equality_jacobian_structure),
            values: equality_jacobian_values,
        },
        inequality_jacobian: SparseMatrix {
            structure: Arc::clone(context.inequality_jacobian_structure),
            values: inequality_jacobian_values,
        },
    }
}

fn least_squares_constraint_multipliers(
    state: &EvalState,
    z: &[f64],
    hessian_structure: &CCS,
    regularization: f64,
    solver: InteriorPointLinearSolver,
) -> (Vec<f64>, Vec<f64>) {
    let debug_ls_multipliers = std::env::var_os("NLIP_DEBUG_LS_MULT").is_some();
    let meq = state.equality_values.len();
    let mineq = state.augmented_inequality_values.len();
    let total_constraints = meq + mineq;
    if total_constraints == 0 {
        return (Vec::new(), Vec::new());
    }

    let n = state.gradient.len();
    let slack_offset = n;
    let lambda_offset = slack_offset + mineq;
    let ineq_offset = lambda_offset + meq;
    let dimension = ineq_offset + mineq;
    let mut rows = Vec::new();
    let mut cols = Vec::new();
    let mut values = Vec::new();
    let mut rhs = vec![0.0; dimension];
    rhs[..n].copy_from_slice(&state.gradient);
    for (row, &z_i) in z.iter().enumerate().take(mineq) {
        rhs[slack_offset + row] = z_i;
    }

    // IpLeastSquareMults.cpp passes IpNLP().uninitialized_h() with
    // W_factor=0 into StdAugSystemSolver. The numeric contribution is zero,
    // but TSymLinearSolver still includes the Hessian sparsity in the KKT
    // pattern before SPRAL's value-dependent matching analysis.
    for col in 0..hessian_structure.ncol {
        for index in hessian_structure.col_ptrs[col]..hessian_structure.col_ptrs[col + 1] {
            let row = hessian_structure.row_indices[index];
            rows.push(col.min(row));
            cols.push(col.max(row));
            values.push(0.0);
        }
    }
    for diag in 0..n {
        rows.push(diag);
        cols.push(diag);
        values.push(1.0);
    }
    for diag in 0..mineq {
        let index = slack_offset + diag;
        rows.push(index);
        cols.push(index);
        values.push(1.0);
    }
    for col in 0..n {
        for index in state.equality_jacobian.structure.ccs.col_ptrs[col]
            ..state.equality_jacobian.structure.ccs.col_ptrs[col + 1]
        {
            let dual_col = lambda_offset + state.equality_jacobian.structure.ccs.row_indices[index];
            rows.push(col.min(dual_col));
            cols.push(col.max(dual_col));
            values.push(state.equality_jacobian.values[index]);
        }
        for index in state.inequality_jacobian.structure.ccs.col_ptrs[col]
            ..state.inequality_jacobian.structure.ccs.col_ptrs[col + 1]
        {
            let dual_col = ineq_offset + state.inequality_jacobian.structure.ccs.row_indices[index];
            rows.push(col.min(dual_col));
            cols.push(col.max(dual_col));
            values.push(state.inequality_jacobian.values[index]);
        }
    }
    for row in 0..mineq {
        let slack_index = slack_offset + row;
        let dual_index = ineq_offset + row;
        rows.push(slack_index.min(dual_index));
        cols.push(slack_index.max(dual_index));
        values.push(-1.0);
    }

    let augmented_matrix = CscMatrix::new_from_triplets(dimension, dimension, rows, cols, values);
    let dsigns = quasidefinite_dsigns(n + mineq, total_constraints);
    match try_solve_symmetric_system_with_metrics(
        solver,
        &augmented_matrix,
        &rhs,
        regularization.max(1e-12),
        Some(&dsigns),
        0,
        1.0,
        regularization.max(1e-12),
    ) {
        Ok((solution, stats, _regularization_used)) => {
            let lambda_eq = solution[lambda_offset..lambda_offset + meq]
                .iter()
                .map(|value| -*value)
                .collect::<Vec<_>>();
            let lambda_ineq = solution[ineq_offset..ineq_offset + mineq]
                .iter()
                .map(|value| -*value)
                .collect::<Vec<_>>();
            if debug_ls_multipliers {
                let residual_current = lagrangian_gradient_sparse(
                    &state.gradient,
                    &state.equality_jacobian,
                    &lambda_eq,
                    &state.inequality_jacobian,
                    &lambda_ineq,
                );
                let neg_lambda_eq = lambda_eq.iter().map(|value| -*value).collect::<Vec<_>>();
                let neg_lambda_ineq = lambda_ineq.iter().map(|value| -*value).collect::<Vec<_>>();
                let residual_neg_eq = lagrangian_gradient_sparse(
                    &state.gradient,
                    &state.equality_jacobian,
                    &neg_lambda_eq,
                    &state.inequality_jacobian,
                    &lambda_ineq,
                );
                let residual_neg_ineq = lagrangian_gradient_sparse(
                    &state.gradient,
                    &state.equality_jacobian,
                    &lambda_eq,
                    &state.inequality_jacobian,
                    &neg_lambda_ineq,
                );
                let residual_neg_both = lagrangian_gradient_sparse(
                    &state.gradient,
                    &state.equality_jacobian,
                    &neg_lambda_eq,
                    &state.inequality_jacobian,
                    &neg_lambda_ineq,
                );
                let slack_stationarity_inf = lambda_ineq
                    .iter()
                    .zip(z.iter())
                    .fold(0.0_f64, |acc, (y_i, z_i)| acc.max((y_i - z_i).abs()));
                let rhs_plus_slack_report = {
                    let mut alt_rhs = rhs.clone();
                    for (row, &z_i) in z.iter().enumerate().take(mineq) {
                        alt_rhs[slack_offset + row] = z_i;
                    }
                    try_solve_symmetric_system_with_metrics(
                        solver,
                        &augmented_matrix,
                        &alt_rhs,
                        regularization.max(1e-12),
                        Some(&dsigns),
                        0,
                        1.0,
                        regularization.max(1e-12),
                    )
                    .ok()
                    .map(|(alt_solution, _stats, _regularization_used)| {
                        let alt_lambda_eq =
                            alt_solution[lambda_offset..lambda_offset + meq].to_vec();
                        let alt_lambda_ineq =
                            alt_solution[ineq_offset..ineq_offset + mineq].to_vec();
                        let alt_residual = lagrangian_gradient_sparse(
                            &state.gradient,
                            &state.equality_jacobian,
                            &alt_lambda_eq,
                            &state.inequality_jacobian,
                            &alt_lambda_ineq,
                        );
                        let neg_alt_lambda_eq =
                            alt_lambda_eq.iter().map(|value| -*value).collect::<Vec<_>>();
                        let neg_alt_lambda_ineq =
                            alt_lambda_ineq.iter().map(|value| -*value).collect::<Vec<_>>();
                        let alt_neg_both_residual = lagrangian_gradient_sparse(
                            &state.gradient,
                            &state.equality_jacobian,
                            &neg_alt_lambda_eq,
                            &state.inequality_jacobian,
                            &neg_alt_lambda_ineq,
                        );
                        let alt_slack_stationarity_inf = alt_lambda_ineq
                            .iter()
                            .zip(z.iter())
                            .fold(0.0_f64, |acc, (y_i, z_i)| acc.max((y_i - z_i).abs()));
                        let alt_neg_slack_stationarity_inf = neg_alt_lambda_ineq
                            .iter()
                            .zip(z.iter())
                            .fold(0.0_f64, |acc, (y_i, z_i)| acc.max((y_i - z_i).abs()));
                        format!(
                            "rhs_plus_lag={:.6e} rhs_plus_slack_stat={:.6e} rhs_plus_neg_both_lag={:.6e} rhs_plus_neg_slack_stat={:.6e} rhs_plus_lambda_eq_inf={:.6e} rhs_plus_lambda_ineq_inf={:.6e}",
                            inf_norm(&alt_residual),
                            alt_slack_stationarity_inf,
                            inf_norm(&alt_neg_both_residual),
                            alt_neg_slack_stationarity_inf,
                            inf_norm(&alt_lambda_eq),
                            inf_norm(&alt_lambda_ineq),
                        )
                    })
                    .unwrap_or_else(|| "rhs_plus_failed".to_string())
                };
                eprintln!(
                    "NLIP_DEBUG_LS_MULT success solver={} n={} meq={} mineq={} lambda_eq_inf={:.6e} lambda_ineq_inf={:.6e} residual_inf={:.6e} solution_inf={:.6e} inertia={} lag_current={:.6e} lag_neg_eq={:.6e} lag_neg_ineq={:.6e} lag_neg_both={:.6e} slack_stat={:.6e} {}",
                    solver.label(),
                    n,
                    meq,
                    mineq,
                    inf_norm(&lambda_eq),
                    inf_norm(&lambda_ineq),
                    stats.residual_inf,
                    stats.solution_inf,
                    stats.inertia.map_or_else(
                        || "none".to_owned(),
                        |inertia| format!(
                            "+{}/-{}/0{}",
                            inertia.positive, inertia.negative, inertia.zero
                        )
                    ),
                    inf_norm(&residual_current),
                    inf_norm(&residual_neg_eq),
                    inf_norm(&residual_neg_ineq),
                    inf_norm(&residual_neg_both),
                    slack_stationarity_inf,
                    rhs_plus_slack_report,
                );
            }
            (lambda_eq, lambda_ineq)
        }
        Err(attempts) => {
            if debug_ls_multipliers {
                let details = attempts
                    .iter()
                    .map(|attempt| {
                        format!(
                            "{}:{} reg={:.3e} detail={}",
                            attempt.solver.label(),
                            attempt.failure_kind.label(),
                            attempt.regularization,
                            attempt.detail.as_deref().unwrap_or("none")
                        )
                    })
                    .collect::<Vec<_>>()
                    .join("; ");
                eprintln!(
                    "NLIP_DEBUG_LS_MULT fallback_zero n={} meq={} mineq={} attempts=[{}]",
                    n, meq, mineq, details
                );
            }
            (vec![0.0; meq], vec![0.0; mineq])
        }
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "IPOPT dual initializer maps every multiplier block explicitly."
)]
fn least_square_dual_initialization(
    state: &EvalState,
    bounds: &BoundConstraints,
    fixed_variables: &FixedVariableElimination,
    trial_z: &[f64],
    trial_z_lower: &[f64],
    trial_z_upper: &[f64],
    hessian_structure: &CCS,
    regularization: f64,
    solver: InteriorPointLinearSolver,
) -> Option<LeastSquareDualInitialization> {
    let n = state.gradient.len();
    let meq = state.equality_values.len();
    let mineq = state.augmented_inequality_values.len();
    debug_assert_eq!(state.equality_jacobian.ncols(), n);
    debug_assert_eq!(state.inequality_jacobian.ncols(), n);
    debug_assert_eq!(trial_z.len(), mineq);
    debug_assert_eq!(trial_z_lower.len(), bounds.lower_indices.len());
    debug_assert_eq!(trial_z_upper.len(), bounds.upper_indices.len());

    let p_offset = n;
    let lambda_offset = p_offset + mineq;
    let z_offset = lambda_offset + meq;
    let dimension = z_offset + mineq;
    if dimension == 0 {
        return Some(LeastSquareDualInitialization {
            lambda_eq: Vec::new(),
            lambda_ineq: Vec::new(),
            z: Vec::new(),
            z_lower: Vec::new(),
            z_upper: Vec::new(),
        });
    }

    let mut x_diagonal = vec![0.0; n];
    for &index in &bounds.lower_indices {
        if let Some(reduced_index) = fixed_variables.free_position[index] {
            x_diagonal[reduced_index] -= 1.0;
        }
    }
    for &index in &bounds.upper_indices {
        if let Some(reduced_index) = fixed_variables.free_position[index] {
            x_diagonal[reduced_index] -= 1.0;
        }
    }

    let mut rows = Vec::new();
    let mut cols = Vec::new();
    let mut values = Vec::new();
    let mut rhs = vec![0.0; dimension];
    rhs[..n].copy_from_slice(&state.gradient);

    // Mirrors IpDefaultIterateInitializer::CalculateLeastSquareDuals:
    // StdAugSystemSolver receives IpNLP().uninitialized_h() with W_factor=0,
    // so Hessian structure is present but contributes zero numerically.
    for col in 0..hessian_structure.ncol {
        for index in hessian_structure.col_ptrs[col]..hessian_structure.col_ptrs[col + 1] {
            let row = hessian_structure.row_indices[index];
            rows.push(col.min(row));
            cols.push(col.max(row));
            values.push(0.0);
        }
    }
    for (diag, &value) in x_diagonal.iter().enumerate() {
        rows.push(diag);
        cols.push(diag);
        values.push(value);
    }
    for diag in 0..mineq {
        let index = p_offset + diag;
        rows.push(index);
        cols.push(index);
        // NLIP stores inequality slacks in IPOPT's upper-bound convention, so
        // Ds is exactly -Pd_U*ones for every internal inequality slack.
        values.push(-1.0);
    }
    for col in 0..n {
        for index in state.equality_jacobian.structure.ccs.col_ptrs[col]
            ..state.equality_jacobian.structure.ccs.col_ptrs[col + 1]
        {
            let dual_col = lambda_offset + state.equality_jacobian.structure.ccs.row_indices[index];
            rows.push(col.min(dual_col));
            cols.push(col.max(dual_col));
            values.push(state.equality_jacobian.values[index]);
        }
        for index in state.inequality_jacobian.structure.ccs.col_ptrs[col]
            ..state.inequality_jacobian.structure.ccs.col_ptrs[col + 1]
        {
            let dual_col = z_offset + state.inequality_jacobian.structure.ccs.row_indices[index];
            rows.push(col.min(dual_col));
            cols.push(col.max(dual_col));
            values.push(state.inequality_jacobian.values[index]);
        }
    }
    for row in 0..mineq {
        let slack_index = p_offset + row;
        let dual_index = z_offset + row;
        rows.push(slack_index.min(dual_index));
        cols.push(slack_index.max(dual_index));
        values.push(-1.0);
    }
    for row in 0..meq {
        let index = lambda_offset + row;
        rows.push(index);
        cols.push(index);
        values.push(0.0);
    }
    for row in 0..mineq {
        let index = z_offset + row;
        rows.push(index);
        cols.push(index);
        values.push(0.0);
    }

    let augmented_matrix = CscMatrix::new_from_triplets(dimension, dimension, rows, cols, values);
    let solution = try_solve_symmetric_system_with_metrics(
        solver,
        &augmented_matrix,
        &rhs,
        regularization.max(1e-12),
        None,
        0,
        1.0,
        regularization.max(1e-12),
    )
    .ok()
    .map(|(solution, _stats, _regularization_used)| solution)?;

    let sol_x = &solution[..n];
    let sol_s = &solution[p_offset..p_offset + mineq];
    let lambda_eq = solution[lambda_offset..lambda_offset + meq]
        .iter()
        .map(|value| -*value)
        .collect::<Vec<_>>();
    let lambda_ineq = solution[z_offset..z_offset + mineq]
        .iter()
        .map(|value| -*value)
        .collect::<Vec<_>>();
    let z_lower = bounds
        .lower_indices
        .iter()
        .zip(trial_z_lower.iter())
        .map(|(&index, &trial)| {
            fixed_variables.free_position[index]
                .map(|reduced_index| (-sol_x[reduced_index]).max(trial))
                .unwrap_or(trial)
        })
        .collect::<Vec<_>>();
    let z_upper = bounds
        .upper_indices
        .iter()
        .zip(trial_z_upper.iter())
        .map(|(&index, &trial)| {
            fixed_variables.free_position[index]
                .map(|reduced_index| sol_x[reduced_index].max(trial))
                .unwrap_or(trial)
        })
        .collect::<Vec<_>>();
    let z = sol_s
        .iter()
        .zip(trial_z.iter())
        .map(|(&candidate, &trial)| candidate.max(trial))
        .collect::<Vec<_>>();

    Some(LeastSquareDualInitialization {
        lambda_eq,
        lambda_ineq,
        z,
        z_lower,
        z_upper,
    })
}

#[derive(Clone, Copy, Debug, PartialEq)]
struct LinearSolutionAssessment {
    solution_inf: f64,
    solution_inf_limit: f64,
    residual_inf: f64,
    residual_inf_limit: f64,
}

fn symmetric_csc_upper_mat_vec(matrix: &CscMatrix<f64>, vector: &[f64]) -> Vec<f64> {
    debug_assert_eq!(matrix.m, matrix.n);
    debug_assert_eq!(matrix.n, vector.len());
    let mut product = vec![0.0; matrix.n];
    for col in 0..matrix.n {
        let x_col = vector[col];
        for index in matrix.colptr[col]..matrix.colptr[col + 1] {
            let row = matrix.rowval[index];
            let value = matrix.nzval[index];
            product[row] += value * x_col;
            if row != col {
                product[col] += value * vector[row];
            }
        }
    }
    product
}

fn symmetric_csc_upper_abs_mat_vec(matrix: &CscMatrix<f64>, vector_abs: &[f64]) -> Vec<f64> {
    debug_assert_eq!(matrix.m, matrix.n);
    debug_assert_eq!(matrix.n, vector_abs.len());
    let mut product = vec![0.0; matrix.n];
    for col in 0..matrix.n {
        let x_col_abs = vector_abs[col];
        for index in matrix.colptr[col]..matrix.colptr[col + 1] {
            let row = matrix.rowval[index];
            let value_abs = matrix.nzval[index].abs();
            product[row] += value_abs * x_col_abs;
            if row != col {
                product[col] += value_abs * vector_abs[row];
            }
        }
    }
    product
}

fn symmetric_csc_lower_from_any_triangle(matrix: &CscMatrix<f64>) -> CscMatrix<f64> {
    debug_assert_eq!(matrix.m, matrix.n);
    let mut rows = Vec::with_capacity(matrix.nzval.len());
    let mut cols = Vec::with_capacity(matrix.nzval.len());
    let mut values = Vec::with_capacity(matrix.nzval.len());
    for col in 0..matrix.n {
        for index in matrix.colptr[col]..matrix.colptr[col + 1] {
            let row = matrix.rowval[index];
            rows.push(row.max(col));
            cols.push(row.min(col));
            values.push(matrix.nzval[index]);
        }
    }
    CscMatrix::new_from_triplets(matrix.m, matrix.n, rows, cols, values)
}

fn assess_linear_solution(
    matrix: &CscMatrix<f64>,
    rhs: &[f64],
    solution: &[f64],
) -> std::result::Result<LinearSolutionAssessment, InteriorPointLinearSolveAttempt> {
    let rhs_inf = rhs.iter().fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let solution_inf_limit = LINEAR_SOLUTION_MAX_RELATIVE_INF_NORM * (1.0 + rhs_inf);
    let residual_inf_limit = LINEAR_SOLUTION_MAX_RELATIVE_RESIDUAL * (1.0 + rhs_inf);
    let solution_inf = solution
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    if !solution.iter().all(|value| value.is_finite()) {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::Auto,
            regularization: 0.0,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::NonFiniteSolution,
            detail: None,
            solution_inf: Some(solution_inf),
            solution_inf_limit: Some(solution_inf_limit),
            residual_inf: None,
            residual_inf_limit: Some(residual_inf_limit),
        });
    }
    if solution_inf > LINEAR_SOLUTION_MAX_RELATIVE_INF_NORM * (1.0 + rhs_inf) {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::Auto,
            regularization: 0.0,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::SolutionNormTooLarge,
            detail: None,
            solution_inf: Some(solution_inf),
            solution_inf_limit: Some(solution_inf_limit),
            residual_inf: None,
            residual_inf_limit: Some(residual_inf_limit),
        });
    }

    let residual = symmetric_csc_upper_mat_vec(matrix, solution)
        .into_iter()
        .zip(rhs.iter().copied())
        .map(|(lhs, rhs_i)| lhs - rhs_i)
        .collect::<Vec<_>>();
    let abs_solution = solution.iter().map(|value| value.abs()).collect::<Vec<_>>();
    let lhs_scale = symmetric_csc_upper_abs_mat_vec(matrix, &abs_solution);
    let residual_inf = residual
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let backward_error_residual_limit =
        lhs_scale
            .iter()
            .zip(rhs.iter())
            .fold(0.0_f64, |acc, (lhs_scale_i, rhs_i)| {
                acc.max(LINEAR_SOLUTION_MAX_RELATIVE_RESIDUAL * (1.0 + lhs_scale_i + rhs_i.abs()))
            });
    let residual_inf_limit = residual_inf_limit.max(backward_error_residual_limit);
    if residual_inf > residual_inf_limit {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::Auto,
            regularization: 0.0,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::ResidualTooLarge,
            detail: None,
            solution_inf: Some(solution_inf),
            solution_inf_limit: Some(solution_inf_limit),
            residual_inf: Some(residual_inf),
            residual_inf_limit: Some(residual_inf_limit),
        });
    }

    Ok(LinearSolutionAssessment {
        solution_inf,
        solution_inf_limit,
        residual_inf,
        residual_inf_limit,
    })
}

fn assess_linear_solution_ccs(
    ccs: &CCS,
    values: &[f64],
    rhs: &[f64],
    solution: &[f64],
) -> std::result::Result<LinearSolutionAssessment, InteriorPointLinearSolveAttempt> {
    let rhs_inf = rhs.iter().fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let solution_inf_limit = LINEAR_SOLUTION_MAX_RELATIVE_INF_NORM * (1.0 + rhs_inf);
    let residual_inf_limit = LINEAR_SOLUTION_MAX_RELATIVE_RESIDUAL * (1.0 + rhs_inf);
    let solution_inf = solution
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    if !solution.iter().all(|value| value.is_finite()) {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::Auto,
            regularization: 0.0,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::NonFiniteSolution,
            detail: None,
            solution_inf: Some(solution_inf),
            solution_inf_limit: Some(solution_inf_limit),
            residual_inf: None,
            residual_inf_limit: Some(residual_inf_limit),
        });
    }
    if solution_inf > solution_inf_limit {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::Auto,
            regularization: 0.0,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::SolutionNormTooLarge,
            detail: None,
            solution_inf: Some(solution_inf),
            solution_inf_limit: Some(solution_inf_limit),
            residual_inf: None,
            residual_inf_limit: Some(residual_inf_limit),
        });
    }

    let residual = symmetric_ccs_lower_mat_vec(ccs, values, solution)
        .into_iter()
        .zip(rhs.iter().copied())
        .map(|(lhs, rhs_i)| lhs - rhs_i)
        .collect::<Vec<_>>();
    let abs_solution = solution.iter().map(|value| value.abs()).collect::<Vec<_>>();
    let lhs_scale = symmetric_ccs_lower_abs_mat_vec(ccs, values, &abs_solution);
    let residual_inf = residual
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let backward_error_residual_limit =
        lhs_scale
            .iter()
            .zip(rhs.iter())
            .fold(0.0_f64, |acc, (lhs_scale_i, rhs_i)| {
                acc.max(LINEAR_SOLUTION_MAX_RELATIVE_RESIDUAL * (1.0 + lhs_scale_i + rhs_i.abs()))
            });
    let residual_inf_limit = residual_inf_limit.max(backward_error_residual_limit);
    if residual_inf > residual_inf_limit {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::Auto,
            regularization: 0.0,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::ResidualTooLarge,
            detail: None,
            solution_inf: Some(solution_inf),
            solution_inf_limit: Some(solution_inf_limit),
            residual_inf: Some(residual_inf),
            residual_inf_limit: Some(residual_inf_limit),
        });
    }

    Ok(LinearSolutionAssessment {
        solution_inf,
        solution_inf_limit,
        residual_inf,
        residual_inf_limit,
    })
}

const IPOPT_LINEAR_MIN_REFINEMENT_STEPS: usize = 1;
const IPOPT_LINEAR_MAX_REFINEMENT_STEPS: usize = 10;
const IPOPT_LINEAR_RESIDUAL_RATIO_MAX: f64 = 1e-10;
const IPOPT_LINEAR_RESIDUAL_RATIO_SINGULAR: f64 = 1e-5;
const IPOPT_LINEAR_RESIDUAL_IMPROVEMENT_FACTOR: f64 = 0.999_999_999;
const IPOPT_LINEAR_RESIDUAL_MAX_COND: f64 = 1e6;

fn default_ipopt_linear_min_refinement_steps() -> Index {
    IPOPT_LINEAR_MIN_REFINEMENT_STEPS
}

fn default_ipopt_linear_max_refinement_steps() -> Index {
    IPOPT_LINEAR_MAX_REFINEMENT_STEPS
}

fn default_ipopt_linear_residual_ratio_max() -> f64 {
    IPOPT_LINEAR_RESIDUAL_RATIO_MAX
}

fn default_ipopt_linear_residual_ratio_singular() -> f64 {
    IPOPT_LINEAR_RESIDUAL_RATIO_SINGULAR
}

fn default_ipopt_linear_residual_improvement_factor() -> f64 {
    IPOPT_LINEAR_RESIDUAL_IMPROVEMENT_FACTOR
}

#[cfg(feature = "serde")]
fn default_ipopt_negative_curvature_test_regularized() -> bool {
    true
}

fn default_ipopt_slack_move() -> f64 {
    f64::EPSILON.powf(0.75)
}

#[derive(Clone, Copy, Debug)]
struct IpoptLinearRefinementOptions {
    min_refinement_steps: usize,
    max_refinement_steps: usize,
    residual_ratio_max: f64,
    residual_ratio_singular: f64,
    residual_improvement_factor: f64,
}

impl IpoptLinearRefinementOptions {
    fn source_defaults() -> Self {
        Self {
            min_refinement_steps: default_ipopt_linear_min_refinement_steps(),
            max_refinement_steps: default_ipopt_linear_max_refinement_steps(),
            residual_ratio_max: default_ipopt_linear_residual_ratio_max(),
            residual_ratio_singular: default_ipopt_linear_residual_ratio_singular(),
            residual_improvement_factor: default_ipopt_linear_residual_improvement_factor(),
        }
    }
}

fn ipopt_refinement_should_continue(
    steps: usize,
    residual_ratio: f64,
    options: IpoptLinearRefinementOptions,
) -> bool {
    steps < options.min_refinement_steps || residual_ratio > options.residual_ratio_max
}

fn ipopt_refinement_failed_after_step(
    steps: usize,
    residual_ratio: f64,
    previous_residual_ratio: f64,
    options: IpoptLinearRefinementOptions,
) -> bool {
    residual_ratio > options.residual_ratio_max
        && steps > options.min_refinement_steps
        && (steps > options.max_refinement_steps
            || residual_ratio > options.residual_improvement_factor * previous_residual_ratio)
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum IpoptRefinementFailureDecision {
    RetryWithHigherQuality,
    PretendSingular,
    AcceptCurrentSolution { after_pretend_singular_retry: bool },
}

fn ipopt_refinement_failure_detail(decision: IpoptRefinementFailureDecision) -> &'static str {
    match decision {
        IpoptRefinementFailureDecision::RetryWithHigherQuality => "spral_quality_retry_requested",
        IpoptRefinementFailureDecision::PretendSingular => {
            "ipopt_pretend_singular_after_refinement_failure"
        }
        IpoptRefinementFailureDecision::AcceptCurrentSolution {
            after_pretend_singular_retry: true,
        } => "ipopt_accept_current_solution_after_pretend_singular_refinement_failure",
        IpoptRefinementFailureDecision::AcceptCurrentSolution {
            after_pretend_singular_retry: false,
        } => "ipopt_accept_current_solution_after_refinement_failure",
    }
}

#[cfg(test)]
fn ipopt_refinement_failure_info_marker(decision: IpoptRefinementFailureDecision) -> Option<char> {
    match decision {
        IpoptRefinementFailureDecision::RetryWithHigherQuality => Some('q'),
        IpoptRefinementFailureDecision::PretendSingular => Some('s'),
        IpoptRefinementFailureDecision::AcceptCurrentSolution {
            after_pretend_singular_retry: false,
        } => Some('S'),
        IpoptRefinementFailureDecision::AcceptCurrentSolution {
            after_pretend_singular_retry: true,
        } => None,
    }
}

fn ipopt_refinement_failure_decision(
    residual_ratio: f64,
    options: IpoptLinearRefinementOptions,
    quality_was_increased: bool,
    quality_can_increase: bool,
    pretend_singular_last_time: bool,
) -> IpoptRefinementFailureDecision {
    if pretend_singular_last_time {
        return IpoptRefinementFailureDecision::AcceptCurrentSolution {
            after_pretend_singular_retry: true,
        };
    }
    if !quality_was_increased && quality_can_increase {
        return IpoptRefinementFailureDecision::RetryWithHigherQuality;
    }
    if residual_ratio < options.residual_ratio_singular {
        IpoptRefinementFailureDecision::AcceptCurrentSolution {
            after_pretend_singular_retry: false,
        }
    } else {
        IpoptRefinementFailureDecision::PretendSingular
    }
}

fn ipopt_refinement_residual_ratio_ccs(
    ccs: &CCS,
    values: &[f64],
    rhs: &[f64],
    solution: &[f64],
) -> (Vec<f64>, f64) {
    let residual = symmetric_ccs_lower_mat_vec(ccs, values, solution)
        .into_iter()
        .zip(rhs.iter().copied())
        .map(|(lhs, rhs_i)| lhs - rhs_i)
        .collect::<Vec<_>>();
    let rhs_inf = rhs.iter().fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let solution_inf = solution
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let residual_inf = residual
        .iter()
        .fold(0.0_f64, |acc, value| acc.max(value.abs()));
    let denominator = solution_inf.min(IPOPT_LINEAR_RESIDUAL_MAX_COND * rhs_inf) + rhs_inf;
    let ratio = if denominator == 0.0 {
        residual_inf
    } else {
        residual_inf / denominator
    };
    (residual, ratio)
}

fn refine_linear_solution_ccs<E>(
    ccs: &CCS,
    values: &[f64],
    rhs: &[f64],
    solution: &mut [f64],
    refinement_options: IpoptLinearRefinementOptions,
    solve_time: &mut Duration,
    mut solve_correction: impl FnMut(&[f64]) -> Result<Vec<f64>, E>,
) -> Result<usize, E> {
    let mut steps = 0;
    let (mut residual, mut residual_ratio) =
        ipopt_refinement_residual_ratio_ccs(ccs, values, rhs, solution);
    let mut previous_residual_ratio = residual_ratio;
    while ipopt_refinement_should_continue(steps, residual_ratio, refinement_options) {
        let correction_started = Instant::now();
        let correction = solve_correction(&residual)?;
        *solve_time += correction_started.elapsed();
        for (solution_i, correction_i) in solution.iter_mut().zip(correction.iter()) {
            *solution_i -= correction_i;
        }
        steps += 1;
        let (new_residual, new_residual_ratio) =
            ipopt_refinement_residual_ratio_ccs(ccs, values, rhs, solution);
        if ipopt_refinement_failed_after_step(
            steps,
            new_residual_ratio,
            previous_residual_ratio,
            refinement_options,
        ) {
            break;
        }
        residual = new_residual;
        previous_residual_ratio = new_residual_ratio;
        residual_ratio = new_residual_ratio;
    }
    Ok(steps)
}

