#[derive(Clone, Copy, Debug)]
struct VectorFingerprint {
    len: usize,
    inf: f64,
    sum: f64,
    hash: u64,
    negative_zero_count: usize,
    positive_zero_count: usize,
}

#[derive(Clone, Copy, Debug)]
struct IpoptAugmentedBlockFingerprints {
    x: VectorFingerprint,
    p: VectorFingerprint,
    lambda: VectorFingerprint,
    z: VectorFingerprint,
}

fn vector_fingerprint(values: &[f64]) -> VectorFingerprint {
    const FNV_OFFSET: u64 = 0xcbf2_9ce4_8422_2325;
    const FNV_PRIME: u64 = 0x0000_0100_0000_01b3;
    let mut inf = 0.0_f64;
    let mut sum = 0.0_f64;
    let mut hash = FNV_OFFSET ^ values.len() as u64;
    let mut negative_zero_count = 0;
    let mut positive_zero_count = 0;
    for value in values {
        inf = inf.max(value.abs());
        sum += *value;
        hash = (hash ^ value.to_bits()).wrapping_mul(FNV_PRIME);
        if *value == 0.0 {
            if value.is_sign_negative() {
                negative_zero_count += 1;
            } else {
                positive_zero_count += 1;
            }
        }
    }
    VectorFingerprint {
        len: values.len(),
        inf,
        sum,
        hash,
        negative_zero_count,
        positive_zero_count,
    }
}

fn vector_fingerprint_text(fingerprint: VectorFingerprint) -> String {
    format!(
        "len={} inf={:.12e} sum={:.12e} hash={:016x} z[-/+]={}/{}",
        fingerprint.len,
        fingerprint.inf,
        fingerprint.sum,
        fingerprint.hash,
        fingerprint.negative_zero_count,
        fingerprint.positive_zero_count,
    )
}

fn ipopt_augmented_block_fingerprints(
    pattern: &SpralAugmentedKktPattern,
    values: &[f64],
) -> IpoptAugmentedBlockFingerprints {
    debug_assert_eq!(values.len(), pattern.dimension());
    IpoptAugmentedBlockFingerprints {
        x: vector_fingerprint(&values[..pattern.x_dimension]),
        p: vector_fingerprint(
            &values[pattern.p_offset..pattern.p_offset + pattern.inequality_dimension],
        ),
        lambda: vector_fingerprint(
            &values[pattern.lambda_offset..pattern.lambda_offset + pattern.equality_dimension],
        ),
        z: vector_fingerprint(
            &values[pattern.z_offset..pattern.z_offset + pattern.inequality_dimension],
        ),
    }
}

fn ipopt_augmented_block_fingerprints_text(
    fingerprints: IpoptAugmentedBlockFingerprints,
) -> String {
    format!(
        "x[{}],p[{}],lambda[{}],z[{}]",
        vector_fingerprint_text(fingerprints.x),
        vector_fingerprint_text(fingerprints.p),
        vector_fingerprint_text(fingerprints.lambda),
        vector_fingerprint_text(fingerprints.z),
    )
}

#[derive(Clone, Copy)]
struct IpoptLinearRefinementShifts {
    primal: f64,
    slack: f64,
    dual: f64,
}

struct IpoptNegativeCurvatureTestInputs<'a> {
    hessian: &'a SparseSymmetricMatrix,
    bound_diagonal: &'a [f64],
    slack_sigma: &'a [f64],
    x_direction: &'a [f64],
    slack_direction: &'a [f64],
    shifts: IpoptLinearRefinementShifts,
    include_regularization: bool,
    tolerance: f64,
}

#[derive(Clone, Copy, Debug)]
struct IpoptNegativeCurvatureTestResult {
    x_w_x: f64,
    x_s_norm_squared: f64,
    threshold: f64,
    sufficiently_positive: bool,
}

fn weighted_square_sum(values: &[f64], weights: &[f64]) -> f64 {
    debug_assert_eq!(values.len(), weights.len());
    values
        .iter()
        .zip(weights.iter())
        .fold(0.0, |acc, (&value, &weight)| {
            weight.mul_add(value * value, acc)
        })
}

fn ipopt_negative_curvature_test(
    inputs: IpoptNegativeCurvatureTestInputs<'_>,
) -> IpoptNegativeCurvatureTestResult {
    debug_assert_eq!(inputs.bound_diagonal.len(), inputs.x_direction.len());
    debug_assert_eq!(inputs.slack_sigma.len(), inputs.slack_direction.len());
    let wx = symmetric_ccs_lower_mat_vec_ipopt_order(
        &inputs.hessian.lower_triangle,
        &inputs.hessian.values,
        inputs.x_direction,
    );
    let mut x_w_x = dot(&wx, inputs.x_direction);
    x_w_x += weighted_square_sum(inputs.x_direction, inputs.bound_diagonal);
    x_w_x += weighted_square_sum(inputs.slack_direction, inputs.slack_sigma);
    if inputs.include_regularization {
        x_w_x += inputs.shifts.primal * squared_l2_norm(inputs.x_direction);
        x_w_x += inputs.shifts.slack * squared_l2_norm(inputs.slack_direction);
    }
    let x_s_norm_squared =
        squared_l2_norm(inputs.x_direction) + squared_l2_norm(inputs.slack_direction);
    let threshold = inputs.tolerance * x_s_norm_squared;
    IpoptNegativeCurvatureTestResult {
        x_w_x,
        x_s_norm_squared,
        threshold,
        sufficiently_positive: x_w_x >= threshold,
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum IpoptLinearRhsOrientation {
    PreFinal,
    FinalDirection,
    SourceDirection,
}

impl IpoptLinearRhsOrientation {
    fn rhs_sign(self) -> f64 {
        match self {
            Self::PreFinal | Self::SourceDirection => 1.0,
            Self::FinalDirection => -1.0,
        }
    }

    fn applies_final_negation(self) -> bool {
        self == Self::PreFinal
    }
}

#[derive(Clone, Copy)]
struct IpoptLinearSolveContext {
    shifts: IpoptLinearRefinementShifts,
    rhs_orientation: IpoptLinearRhsOrientation,
    allow_inexact: bool,
    native_spral_quality_was_increased: bool,
    pretend_singular_last_time: bool,
    capture_trace: bool,
}

fn ipopt_full_space_residual_ratio(
    system: &ReducedKktSystem<'_>,
    pattern: &SpralAugmentedKktPattern,
    full_solution: &SpralSrcFullSpaceSolution,
    rhs_orientation: IpoptLinearRhsOrientation,
    shifts: IpoptLinearRefinementShifts,
    capture_trace: bool,
) -> IpoptFullSpaceResidual {
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let solution = &full_solution.augmented_solution;
    let dx = &solution[..n];
    let ipopt_ds = &solution[pattern.p_offset..pattern.p_offset + mineq];
    let d_lambda = &solution[pattern.lambda_offset..pattern.lambda_offset + meq];
    let d_ineq = &solution[pattern.z_offset..pattern.z_offset + mineq];
    let rhs_sign = rhs_orientation.rhs_sign();
    debug_assert_eq!(full_solution.upper_slack_multiplier_step.len(), mineq);

    let mut residual_x = symmetric_ccs_lower_mat_vec_ipopt_order(
        system.hessian.lower_triangle.as_ref(),
        &system.hessian.values,
        dx,
    );
    let residual_x_after_w = capture_trace.then(|| residual_x.clone());
    sparse_add_transpose_mat_vec_ipopt_order(&mut residual_x, system.equality_jacobian, d_lambda);
    let residual_x_after_jc = capture_trace.then(|| residual_x.clone());
    sparse_add_transpose_mat_vec_ipopt_order(&mut residual_x, system.inequality_jacobian, d_ineq);
    let residual_x_after_jd = capture_trace.then(|| residual_x.clone());

    let equality_dx = sparse_mat_vec_ipopt_order(system.equality_jacobian, dx);
    let inequality_dx = sparse_mat_vec_ipopt_order(system.inequality_jacobian, dx);
    let mut augmented_correction_rhs = vec![0.0; pattern.dimension()];

    let mut rhs_inf = 0.0_f64;
    let mut solution_inf = step_inf_norm(dx);
    let mut bound_residual_inf = 0.0_f64;
    let mut residual_z_lower = system.bound_data.map_or_else(Vec::new, |bound_data| {
        debug_assert_eq!(
            full_solution.lower_bound_multiplier_step.len(),
            bound_data.bounds.lower_indices.len()
        );
        vec![0.0; bound_data.bounds.lower_indices.len()]
    });
    let mut residual_z_upper = system.bound_data.map_or_else(Vec::new, |bound_data| {
        debug_assert_eq!(
            full_solution.upper_bound_multiplier_step.len(),
            bound_data.bounds.upper_indices.len()
        );
        vec![0.0; bound_data.bounds.upper_indices.len()]
    });
    let residual_x_after_pxl;
    let residual_x_after_pxu;

    if let Some(bound_data) = system.bound_data {
        let mut rhs_x = system
            .r_dual
            .iter()
            .map(|value| rhs_sign * *value)
            .collect::<Vec<_>>();
        let damping = system_positive_slack_damping(system);
        for (bound_position, ((&index, &lower), &z_i)) in bound_data
            .bounds
            .lower_indices
            .iter()
            .zip(bound_data.bounds.lower_values.iter())
            .zip(bound_data.z_lower.iter())
            .enumerate()
        {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                continue;
            };
            let slack = native_lower_bound_slack(bound_data.x, index, lower);
            let complementarity =
                lower_bound_complementarity_rhs(system, bound_position, slack, z_i);
            let dz_i = full_solution.lower_bound_multiplier_step[bound_position];
            let rhs_z = rhs_sign * complementarity;
            let residual_z =
                ipopt_lower_bound_residual_z(slack, dz_i, z_i, dx[reduced_index], rhs_z);
            residual_z_lower[bound_position] = residual_z;
            residual_x[reduced_index] -= dz_i;
            if damping > 0.0 && !bound_data.bounds.upper_indices.contains(&index) {
                rhs_x[reduced_index] += rhs_sign * damping;
            }
            bound_residual_inf = bound_residual_inf.max(residual_z.abs());
            rhs_inf = rhs_inf.max(complementarity.abs());
            solution_inf = solution_inf.max(dz_i.abs());
        }
        residual_x_after_pxl = capture_trace.then(|| residual_x.clone());
        for (bound_position, ((&index, &upper), &z_i)) in bound_data
            .bounds
            .upper_indices
            .iter()
            .zip(bound_data.bounds.upper_values.iter())
            .zip(bound_data.z_upper.iter())
            .enumerate()
        {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                continue;
            };
            let slack = native_upper_bound_slack(bound_data.x, index, upper);
            let complementarity =
                upper_bound_complementarity_rhs(system, bound_position, slack, z_i);
            let dz_i = full_solution.upper_bound_multiplier_step[bound_position];
            let rhs_z = rhs_sign * complementarity;
            let residual_z =
                ipopt_upper_bound_residual_z(slack, dz_i, z_i, dx[reduced_index], rhs_z);
            residual_z_upper[bound_position] = residual_z;
            residual_x[reduced_index] += dz_i;
            if damping > 0.0 && !bound_data.bounds.lower_indices.contains(&index) {
                rhs_x[reduced_index] += rhs_sign * -damping;
            }
            bound_residual_inf = bound_residual_inf.max(residual_z.abs());
            rhs_inf = rhs_inf.max(complementarity.abs());
            solution_inf = solution_inf.max(dz_i.abs());
        }
        residual_x_after_pxu = capture_trace.then(|| residual_x.clone());
        // Mirror IpPDFullSpaceSolver.cpp::ComputeResiduals: W/J/bound terms are
        // accumulated first, and the primal perturbation plus rhs.x contribution
        // is applied last with AddTwoVectors(delta_x, res.x, -1., rhs.x, 1.).
        ipopt_add_delta_minus_rhs(&mut residual_x, shifts.primal, dx, &rhs_x);
        for (rhs_i, residual_i) in augmented_correction_rhs[..n]
            .iter_mut()
            .zip(residual_x.iter())
        {
            *rhs_i = *residual_i;
        }
        // Mirror PDFullSpaceSolver::SolveOnce augmented x-RHS construction:
        // start with resid.x, then apply Px_L.AddMSinvZ(+1) followed by
        // Px_U.AddMSinvZ(-1).  The order is observable at glider precision.
        for (bound_position, (&index, &lower)) in bound_data
            .bounds
            .lower_indices
            .iter()
            .zip(bound_data.bounds.lower_values.iter())
            .enumerate()
        {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                continue;
            };
            let slack = native_lower_bound_slack(bound_data.x, index, lower);
            augmented_correction_rhs[reduced_index] += residual_z_lower[bound_position] / slack;
        }
        for (bound_position, (&index, &upper)) in bound_data
            .bounds
            .upper_indices
            .iter()
            .zip(bound_data.bounds.upper_values.iter())
            .enumerate()
        {
            let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                continue;
            };
            let slack = native_upper_bound_slack(bound_data.x, index, upper);
            augmented_correction_rhs[reduced_index] -= residual_z_upper[bound_position] / slack;
        }
        rhs_inf = rhs_inf.max(step_inf_norm(&rhs_x));
    } else {
        residual_x_after_pxl = residual_x_after_jd.clone();
        residual_x_after_pxu = residual_x_after_jd.clone();
        for (residual_i, (r_dual_i, bound_rhs_i)) in residual_x
            .iter_mut()
            .zip(system.r_dual.iter().zip(system.bound_rhs.iter()))
        {
            let rhs_i = rhs_sign * (*r_dual_i - *bound_rhs_i);
            *residual_i -= rhs_i;
        }
        for (index, residual_i) in residual_x.iter_mut().enumerate() {
            *residual_i += (shifts.primal
                + system.bound_diagonal.get(index).copied().unwrap_or(0.0))
                * dx[index];
        }
        augmented_correction_rhs[..n].copy_from_slice(&residual_x);
        rhs_inf = system
            .r_dual
            .iter()
            .zip(system.bound_rhs.iter())
            .fold(0.0_f64, |acc, (r_dual_i, bound_rhs_i)| {
                acc.max((*r_dual_i - *bound_rhs_i).abs())
            });
    }
    let residual_x_after_add_two_vectors = capture_trace.then(|| residual_x.clone());

    let mut residual_inf = step_inf_norm(&residual_x).max(bound_residual_inf);
    let mut residual_s_inf = 0.0_f64;
    let mut residual_d_inf = 0.0_f64;
    let mut residual_vu_inf = 0.0_f64;
    let mut residual_vu = vec![0.0; mineq];
    let mut residual_s_trace = capture_trace.then(|| Vec::with_capacity(mineq));
    let mut residual_s_after_pdu_trace = capture_trace.then(|| Vec::with_capacity(mineq));
    let mut residual_s_after_pdl_trace = capture_trace.then(|| Vec::with_capacity(mineq));
    let mut residual_s_after_add_two_vectors_trace =
        capture_trace.then(|| Vec::with_capacity(mineq));
    let mut residual_s_after_delta_trace = capture_trace.then(|| Vec::with_capacity(mineq));
    let mut residual_d_trace = capture_trace.then(|| Vec::with_capacity(mineq));

    for row in 0..mineq {
        let slack = system.slack[row];
        let multiplier = system.multipliers[row];
        let ipopt_ds_i = ipopt_ds[row];
        let dz_i = full_solution.upper_slack_multiplier_step[row];
        let damped_slack_stationarity = damped_slack_stationarity_residual(system, row);
        let (rhs_s_i, rhs_v_i, rhs_d_i) = (
            rhs_sign * damped_slack_stationarity,
            rhs_sign * system.r_cent[row],
            rhs_sign * system.r_ineq[row],
        );
        // Mirror IpPDFullSpaceSolver.cpp::ComputeResiduals and
        // DenseVector::AddTwoVectorsImpl grouping for the s, v_U, and y_d
        // blocks: start from the matrix product, add `-res - rhs` as one
        // expression, then apply the perturbation Axpy separately.
        let residual_s_after_pdu = dz_i;
        let residual_s_after_pdl = residual_s_after_pdu;
        let residual_s_after_add_two_vectors = residual_s_after_pdl + (-d_ineq[row] - rhs_s_i);
        let mut residual_s = residual_s_after_add_two_vectors;
        if shifts.slack != 0.0 {
            residual_s = ipopt_blas_axpy_value(residual_s, shifts.slack, ipopt_ds_i);
        }
        let residual_s_after_delta = residual_s;
        let residual_v = (slack * dz_i) + (-(multiplier * ipopt_ds_i) - rhs_v_i);
        let mut residual_d = inequality_dx[row] + (-ipopt_ds_i - rhs_d_i);
        if shifts.dual != 0.0 {
            residual_d = ipopt_blas_axpy_value(residual_d, -shifts.dual, d_ineq[row]);
        }
        if let Some(trace) = residual_s_after_pdu_trace.as_mut() {
            trace.push(residual_s_after_pdu);
        }
        if let Some(trace) = residual_s_after_pdl_trace.as_mut() {
            trace.push(residual_s_after_pdl);
        }
        if let Some(trace) = residual_s_after_add_two_vectors_trace.as_mut() {
            trace.push(residual_s_after_add_two_vectors);
        }
        if let Some(trace) = residual_s_after_delta_trace.as_mut() {
            trace.push(residual_s_after_delta);
        }
        if let Some(trace) = residual_s_trace.as_mut() {
            trace.push(residual_s);
        }
        if let Some(trace) = residual_d_trace.as_mut() {
            trace.push(residual_d);
        }
        residual_vu[row] = residual_v;
        residual_s_inf = residual_s_inf.max(residual_s.abs());
        residual_d_inf = residual_d_inf.max(residual_d.abs());
        residual_vu_inf = residual_vu_inf.max(residual_v.abs());
        // Mirrors Ipopt::PDFullSpaceSolver::SolveOnce: full-space residuals
        // from ComputeResiduals are converted to the augmented-system RHS with
        // Pd_U.AddMSinvZ(-1.0, ...), i.e. rhs_s - rhs_v_U / slack_s_U.
        augmented_correction_rhs[pattern.p_offset + row] = residual_s - residual_v / slack;
        augmented_correction_rhs[pattern.z_offset + row] = residual_d;
        residual_inf = residual_inf
            .max(residual_s.abs())
            .max(residual_v.abs())
            .max(residual_d.abs());
        rhs_inf = rhs_inf
            .max(damped_slack_stationarity.abs())
            .max(system.r_cent[row].abs())
            .max(system.r_ineq[row].abs());
        solution_inf = solution_inf
            .max(ipopt_ds_i.abs())
            .max(d_ineq[row].abs())
            .max(dz_i.abs());
    }

    let mut residual_c_inf = 0.0_f64;
    let mut residual_c_trace = capture_trace.then(|| Vec::with_capacity(meq));
    for row in 0..meq {
        let rhs_c_i = rhs_sign * system.r_eq[row];
        // IpPDFullSpaceSolver.cpp::ComputeResiduals forms this with
        // AddTwoVectors(-delta_c, res.y_c, -1., rhs.y_c, 1.).
        let mut residual_c = equality_dx[row];
        if shifts.dual == 0.0 {
            residual_c -= rhs_c_i;
        } else {
            residual_c += (-shifts.dual).mul_add(d_lambda[row], -rhs_c_i);
        }
        if let Some(trace) = residual_c_trace.as_mut() {
            trace.push(residual_c);
        }
        augmented_correction_rhs[pattern.lambda_offset + row] = residual_c;
        residual_c_inf = residual_c_inf.max(residual_c.abs());
        residual_inf = residual_inf.max(residual_c.abs());
        rhs_inf = rhs_inf.max(system.r_eq[row].abs());
        solution_inf = solution_inf.max(d_lambda[row].abs());
    }

    let residual_ratio = if rhs_inf + solution_inf == 0.0 {
        residual_inf
    } else {
        let denominator = solution_inf.min(IPOPT_LINEAR_RESIDUAL_MAX_COND * rhs_inf) + rhs_inf;
        residual_inf / denominator
    };
    let trace = capture_trace.then(|| IpoptFullSpaceResidualTrace {
        x_after_w: residual_x_after_w.unwrap_or_default(),
        x_after_jc: residual_x_after_jc.unwrap_or_default(),
        x_after_jd: residual_x_after_jd.unwrap_or_default(),
        x_after_pxl: residual_x_after_pxl.unwrap_or_default(),
        x_after_pxu: residual_x_after_pxu.unwrap_or_default(),
        x_after_add_two_vectors: residual_x_after_add_two_vectors.unwrap_or_default(),
        x: residual_x.clone(),
        s_after_pdu: residual_s_after_pdu_trace.unwrap_or_default(),
        s_after_pdl: residual_s_after_pdl_trace.unwrap_or_default(),
        s_after_add_two_vectors: residual_s_after_add_two_vectors_trace.unwrap_or_default(),
        s_after_delta: residual_s_after_delta_trace.unwrap_or_default(),
        s: residual_s_trace.unwrap_or_default(),
        c: residual_c_trace.unwrap_or_default(),
        d: residual_d_trace.unwrap_or_default(),
        z_lower: residual_z_lower.clone(),
        z_upper: residual_z_upper.clone(),
        v_upper: residual_vu.clone(),
    });

    IpoptFullSpaceResidual {
        augmented_correction_rhs,
        residual_z_lower,
        residual_z_upper,
        residual_vu,
        trace,
        residual_ratio,
        rhs_inf,
        solution_inf,
        residual_inf,
        residual_x_inf: step_inf_norm(&residual_x),
        residual_s_inf,
        residual_c_inf,
        residual_d_inf,
        residual_bound_inf: bound_residual_inf,
        residual_vu_inf,
    }
}

fn refine_ipopt_full_space_solution<E>(
    system: &ReducedKktSystem<'_>,
    pattern: &SpralAugmentedKktPattern,
    solution: &mut SpralSrcFullSpaceSolution,
    context: &IpoptLinearSolveContext,
    solve_time: &mut Duration,
    mut solve_correction: impl FnMut(&[f64]) -> Result<Vec<f64>, E>,
) -> Result<IpoptRefinementReport, E> {
    // IPOPT refines PDFullSpaceSolver systems on the full unsymmetric
    // primal-dual residual, not on the already-eliminated symmetric augmented
    // matrix residual; see IpPDFullSpaceSolver.cpp::ComputeResiduals,
    // SolveOnce, and ComputeResidualRatio.
    let mut steps = 0;
    let mut residual = ipopt_full_space_residual_ratio(
        system,
        pattern,
        solution,
        context.rhs_orientation,
        context.shifts,
        context.capture_trace,
    );
    let mut residual_ratio = residual.residual_ratio;
    let initial_residual_ratio = residual_ratio;
    let initial_residual = residual.metrics();
    let mut previous_residual_ratio = residual_ratio;
    let mut first_correction_rhs = None;
    let mut first_correction_rhs_blocks = None;
    let mut first_correction_solution = None;
    let mut first_correction_solution_blocks = None;
    let mut trace_steps = Vec::new();
    let mut failed = false;
    let refinement_options = system.refinement_options();
    while ipopt_refinement_should_continue(steps, residual_ratio, refinement_options) {
        if steps == 0 {
            first_correction_rhs = Some(vector_fingerprint(&residual.augmented_correction_rhs));
            first_correction_rhs_blocks = Some(ipopt_augmented_block_fingerprints(
                pattern,
                &residual.augmented_correction_rhs,
            ));
        }
        let correction_started = Instant::now();
        let correction = solve_correction(&residual.augmented_correction_rhs)?;
        *solve_time += correction_started.elapsed();
        let trace_correction_rhs = context
            .capture_trace
            .then(|| residual.augmented_correction_rhs.clone());
        let trace_correction_solution = context.capture_trace.then(|| correction.clone());
        let trace_full_residual = context.capture_trace.then(|| {
            residual
                .trace
                .as_ref()
                .expect("captured full residual")
                .clone()
        });
        let trace_residual_ratio_before = residual_ratio;
        if steps == 0 {
            first_correction_solution = Some(vector_fingerprint(&correction));
            first_correction_solution_blocks =
                Some(ipopt_augmented_block_fingerprints(pattern, &correction));
        }
        if let Some(bound_data) = system.bound_data {
            for (bound_position, ((&index, &lower), &z_i)) in bound_data
                .bounds
                .lower_indices
                .iter()
                .zip(bound_data.bounds.lower_values.iter())
                .zip(bound_data.z_lower.iter())
                .enumerate()
            {
                let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                    continue;
                };
                let slack = native_lower_bound_slack(bound_data.x, index, lower);
                let correction_z = ipopt_oriented_lower_bound_multiplier_step(
                    slack,
                    z_i,
                    residual.residual_z_lower[bound_position],
                    correction[reduced_index],
                );
                solution.lower_bound_multiplier_step[bound_position] = ipopt_blas_axpy_value(
                    solution.lower_bound_multiplier_step[bound_position],
                    -1.0,
                    correction_z,
                );
            }
            for (bound_position, ((&index, &upper), &z_i)) in bound_data
                .bounds
                .upper_indices
                .iter()
                .zip(bound_data.bounds.upper_values.iter())
                .zip(bound_data.z_upper.iter())
                .enumerate()
            {
                let Some(reduced_index) = bound_data.fixed_variables.free_position[index] else {
                    continue;
                };
                let slack = native_upper_bound_slack(bound_data.x, index, upper);
                let correction_z = ipopt_oriented_upper_bound_multiplier_step(
                    slack,
                    z_i,
                    residual.residual_z_upper[bound_position],
                    correction[reduced_index],
                );
                solution.upper_bound_multiplier_step[bound_position] = ipopt_blas_axpy_value(
                    solution.upper_bound_multiplier_step[bound_position],
                    -1.0,
                    correction_z,
                );
            }
        }
        for (row, upper_step_i) in solution.upper_slack_multiplier_step.iter_mut().enumerate() {
            // IpPDFullSpaceSolver.cpp::SolveOnce computes the correction's
            // v_U with Pd_U.SinvBlrmZMTdBr(1., ...), then the refinement call
            // uses alpha=-1, beta=1 to apply `res.v_U -= sol.v_U`.  Preserve
            // that operation order instead of recomputing v_U from the updated
            // slack step after the correction.
            let correction_s = correction[pattern.p_offset + row];
            let correction_vu = ipopt_oriented_upper_slack_bound_multiplier_step(
                system.slack[row],
                system.multipliers[row],
                residual.residual_vu[row],
                correction_s,
            );
            *upper_step_i = ipopt_blas_axpy_value(*upper_step_i, -1.0, correction_vu);
        }
        for (solution_i, correction_i) in solution
            .augmented_solution
            .iter_mut()
            .zip(correction.iter())
        {
            *solution_i = ipopt_blas_axpy_value(*solution_i, -1.0, *correction_i);
        }
        steps += 1;
        let new_residual = ipopt_full_space_residual_ratio(
            system,
            pattern,
            solution,
            context.rhs_orientation,
            context.shifts,
            context.capture_trace,
        );
        let new_residual_ratio = new_residual.residual_ratio;
        if let (Some(correction_rhs), Some(correction_solution)) =
            (trace_correction_rhs, trace_correction_solution)
        {
            trace_steps.push(IpoptLinearRefinementStepTrace {
                correction_rhs,
                correction_solution,
                solution_prefinal_after: solution.augmented_solution.clone(),
                full_residual: trace_full_residual,
                residual_ratio_before: trace_residual_ratio_before,
                residual_ratio_after: new_residual_ratio,
            });
        }
        residual_ratio = new_residual_ratio;
        if ipopt_refinement_failed_after_step(
            steps,
            new_residual_ratio,
            previous_residual_ratio,
            refinement_options,
        ) {
            failed = true;
            residual = new_residual;
            break;
        }
        residual = new_residual;
        previous_residual_ratio = new_residual_ratio;
    }
    Ok(IpoptRefinementReport {
        steps,
        initial_residual_ratio,
        initial_residual,
        residual_ratio,
        final_residual: residual.metrics(),
        first_correction_rhs,
        first_correction_rhs_blocks,
        first_correction_solution,
        first_correction_solution_blocks,
        trace_steps,
        failed,
    })
}

fn interior_point_linear_inertia(inertia: SpralInertia) -> InteriorPointLinearInertia {
    InteriorPointLinearInertia {
        positive: inertia.positive,
        negative: inertia.negative,
        zero: inertia.zero,
    }
}

fn delta_inf_norm(lhs: &[f64], rhs: &[f64]) -> f64 {
    lhs.iter()
        .zip(rhs.iter())
        .fold(0.0_f64, |acc, (lhs, rhs)| acc.max((lhs - rhs).abs()))
}

fn spral_error_attempt(
    regularization: f64,
    failure_kind: InteriorPointLinearSolveFailureKind,
    error: impl ToString,
) -> InteriorPointLinearSolveAttempt {
    InteriorPointLinearSolveAttempt {
        solver: InteriorPointLinearSolver::SsidsRs,
        regularization,
        inertia: None,
        failure_kind,
        detail: Some(error.to_string()),
        solution_inf: None,
        solution_inf_limit: None,
        residual_inf: None,
        residual_inf_limit: None,
    }
}

fn native_spral_error_attempt(
    regularization: f64,
    failure_kind: InteriorPointLinearSolveFailureKind,
    error: impl ToString,
) -> InteriorPointLinearSolveAttempt {
    InteriorPointLinearSolveAttempt {
        solver: InteriorPointLinearSolver::SpralSrc,
        regularization,
        inertia: None,
        failure_kind,
        detail: Some(error.to_string()),
        solution_inf: None,
        solution_inf_limit: None,
        residual_inf: None,
        residual_inf_limit: None,
    }
}

fn default_dsigns(dimension: usize) -> Vec<i8> {
    vec![1_i8; dimension]
}

fn quasidefinite_dsigns(primal_dimension: usize, dual_dimension: usize) -> Vec<i8> {
    let mut dsigns = default_dsigns(primal_dimension + dual_dimension);
    dsigns[primal_dimension..].fill(-1);
    dsigns
}

fn factor_solve_sparse_qdldl_with_metrics(
    matrix: &CscMatrix<f64>,
    rhs: &[f64],
    regularization: f64,
    dsigns: Option<&[i8]>,
) -> std::result::Result<(Vec<f64>, LinearBackendRunStats), InteriorPointLinearSolveAttempt> {
    let n = matrix.n;
    if matrix.m != n || rhs.len() != n {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SparseQdldl,
            regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: None,
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        });
    }
    let dsigns = dsigns.map_or_else(|| default_dsigns(n), ToOwned::to_owned);
    if dsigns.len() != n {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SparseQdldl,
            regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: None,
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        });
    }
    let settings = QDLDLSettings {
        amd_dense_scale: 1.5,
        Dsigns: Some(dsigns),
        regularize_enable: true,
        regularize_eps: regularization.max(1e-12),
        regularize_delta: regularization.max(1e-9),
        ..Default::default()
    };
    let factor_started = Instant::now();
    let mut factor = QDLDLFactorisation::new(matrix, Some(settings)).map_err(|_| {
        InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SparseQdldl,
            regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: None,
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        }
    })?;
    let factorization_time = factor_started.elapsed();
    let inertia = InteriorPointLinearInertia {
        positive: factor.positive_inertia(),
        negative: n.saturating_sub(factor.positive_inertia()),
        zero: 0,
    };
    let mut solution = rhs.to_vec();
    let solve_started = Instant::now();
    factor.solve(&mut solution);
    let solve_time = solve_started.elapsed();
    let mut assessment = assess_linear_solution(matrix, rhs, &solution);
    if assessment.is_err() {
        for _ in 0..10 {
            let residual = symmetric_csc_upper_mat_vec(matrix, &solution)
                .into_iter()
                .zip(rhs.iter().copied())
                .map(|(lhs, rhs_i)| rhs_i - lhs)
                .collect::<Vec<_>>();
            if residual.iter().all(|value| value.abs() <= f64::EPSILON) {
                break;
            }
            let mut correction = residual;
            factor.solve(&mut correction);
            for (solution_i, correction_i) in solution.iter_mut().zip(correction.iter()) {
                *solution_i += correction_i;
            }
            assessment = assess_linear_solution(matrix, rhs, &solution);
            if assessment.is_ok() {
                break;
            }
        }
    }
    assessment
        .map(|assessment| {
            (
                solution,
                LinearBackendRunStats {
                    solver: InteriorPointLinearSolver::SparseQdldl,
                    factorization_time,
                    solve_time,
                    reused_symbolic: None,
                    inertia: Some(inertia),
                    residual_inf: assessment.residual_inf,
                    solution_inf: assessment.solution_inf,
                    detail: None,
                },
            )
        })
        .map_err(|mut attempt| {
            attempt.solver = InteriorPointLinearSolver::SparseQdldl;
            attempt.regularization = regularization;
            attempt
        })
}

fn factor_solve_spral_ssids_symmetric_with_metrics(
    matrix: &CscMatrix<f64>,
    rhs: &[f64],
    regularization: f64,
) -> std::result::Result<(Vec<f64>, LinearBackendRunStats), InteriorPointLinearSolveAttempt> {
    let n = matrix.n;
    if matrix.m != n || rhs.len() != n {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SsidsRs,
            regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: None,
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        });
    }
    let lower_matrix = symmetric_csc_lower_from_any_triangle(matrix);
    let spral_matrix = SpralSymmetricCscMatrix::new(
        n,
        &lower_matrix.colptr,
        &lower_matrix.rowval,
        Some(&lower_matrix.nzval),
    )
    .map_err(|error| {
        spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let ccs = CCS::new(
        n,
        n,
        lower_matrix.colptr.clone(),
        lower_matrix.rowval.clone(),
    );
    let factor_started = Instant::now();
    let (symbolic, _) = spral_analyse(
        spral_matrix,
        &SpralSsidsOptions {
            // IPOPT's SPRAL path does not have this crate's `Auto` heuristic.
            // Keep sparse auxiliary solves on explicit AMD, matching the Rust
            // augmented-KKT integration and avoiding Auto's natural-order fill
            // simulation on glider-sized least-squares multiplier systems.
            ordering: SpralOrderingStrategy::ApproximateMinimumDegree,
        },
    )
    .map_err(|error| {
        spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let mut factor = spral_factorize(
        spral_matrix,
        &symbolic,
        &SpralNumericFactorOptions::default(),
    )
    .map_err(|error| {
        spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?
    .0;
    let factorization_time = factor_started.elapsed();
    let inertia = interior_point_linear_inertia(factor.inertia());
    let solve_started = Instant::now();
    let mut solution = factor.solve(rhs).map_err(|error| {
        spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let mut solve_time = solve_started.elapsed();
    let refinement_steps = refine_linear_solution_ccs(
        &ccs,
        &lower_matrix.nzval,
        rhs,
        &mut solution,
        IpoptLinearRefinementOptions::source_defaults(),
        &mut solve_time,
        |residual| {
            factor.solve(residual).map_err(|error| {
                spral_error_attempt(
                    regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    error,
                )
            })
        },
    )?;
    let assessment = assess_linear_solution_ccs(&ccs, &lower_matrix.nzval, rhs, &solution);
    assessment
        .map(|assessment| {
            (
                solution,
                LinearBackendRunStats {
                    solver: InteriorPointLinearSolver::SsidsRs,
                    factorization_time,
                    solve_time,
                    reused_symbolic: Some(false),
                    inertia: Some(inertia),
                    residual_inf: assessment.residual_inf,
                    solution_inf: assessment.solution_inf,
                    detail: (refinement_steps > 0)
                        .then(|| format!("iterative_refinement_steps={refinement_steps}")),
                },
            )
        })
        .map_err(|mut attempt| {
            attempt.solver = InteriorPointLinearSolver::SsidsRs;
            attempt.regularization = regularization;
            attempt
        })
}

fn factor_solve_spral_src_symmetric_with_metrics(
    matrix: &CscMatrix<f64>,
    rhs: &[f64],
    regularization: f64,
) -> std::result::Result<(Vec<f64>, LinearBackendRunStats), InteriorPointLinearSolveAttempt> {
    let n = matrix.n;
    if matrix.m != n || rhs.len() != n {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SpralSrc,
            regularization,
            inertia: None,
            failure_kind: InteriorPointLinearSolveFailureKind::FactorizationFailed,
            detail: None,
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        });
    }
    let lower_matrix = symmetric_csc_lower_from_any_triangle(matrix);
    let spral_matrix = SpralSymmetricCscMatrix::new(
        n,
        &lower_matrix.colptr,
        &lower_matrix.rowval,
        Some(&lower_matrix.nzval),
    )
    .map_err(|error| {
        native_spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let ccs = CCS::new(
        n,
        n,
        lower_matrix.colptr.clone(),
        lower_matrix.rowval.clone(),
    );
    let native = NativeSpralLibrary::load().map_err(|error| {
        native_spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let factor_started = Instant::now();
    let mut session = native
        // IpLeastSquareMults.cpp reaches SPRAL through StdAugSystemSolver and
        // IpSpralSolverInterface, not the generic native wrapper defaults.
        // Keep auxiliary multiplier solves on the same matching, one-based
        // ptr32 path used by IPOPT's SPRAL interface.
        .analyse_ipopt_compatible_with_options_and_ordering(
            spral_matrix,
            &SpralNumericFactorOptions::default(),
            SpralNativeOrdering::Matching,
        )
        .map_err(|error| {
            native_spral_error_attempt(
                regularization,
                InteriorPointLinearSolveFailureKind::FactorizationFailed,
                error,
            )
        })?;
    let factor_info = session.factorize(spral_matrix).map_err(|error| {
        native_spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let factorization_time = factor_started.elapsed();
    let inertia = interior_point_linear_inertia(factor_info.inertia);
    let solve_started = Instant::now();
    // IPOPT's SpralSolverInterface::MultiSolve calls spral_ssids_solve with
    // nrhs=1 even for a single right-hand side. Keep the NLIP source-built
    // SPRAL path on the same C entrypoint instead of spral_ssids_solve1.
    let solution = session.solve_ipopt_single_rhs(rhs).map_err(|error| {
        native_spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let solve_time = solve_started.elapsed();
    // IPOPT LeastSquareMultipliers calls StdAugSystemSolver::Solve directly;
    // the full-space PDFullSpaceSolver iterative refinement loop is not used
    // for this auxiliary multiplier estimate.
    let assessment = assess_linear_solution_ccs(&ccs, &lower_matrix.nzval, rhs, &solution);
    let (solution_inf, residual_inf) = match assessment {
        Ok(assessment) => (assessment.solution_inf, assessment.residual_inf),
        Err(attempt) => (
            attempt
                .solution_inf
                .unwrap_or_else(|| step_inf_norm(&solution)),
            attempt.residual_inf.unwrap_or(f64::NAN),
        ),
    };
    Ok((
        solution,
        LinearBackendRunStats {
            solver: InteriorPointLinearSolver::SpralSrc,
            factorization_time,
            solve_time,
            reused_symbolic: Some(false),
            inertia: Some(inertia),
            residual_inf,
            solution_inf,
            detail: Some("ipopt_least_square_multipliers_std_aug_solver_no_refinement".to_string()),
        },
    ))
}

fn preferred_linear_solver(
    solver: InteriorPointLinearSolver,
    equality_count: usize,
    inequality_count: usize,
) -> InteriorPointLinearSolver {
    match solver {
        InteriorPointLinearSolver::Auto if equality_count == 0 && inequality_count == 0 => {
            InteriorPointLinearSolver::SparseQdldl
        }
        InteriorPointLinearSolver::Auto | InteriorPointLinearSolver::SsidsRs => {
            InteriorPointLinearSolver::SsidsRs
        }
        InteriorPointLinearSolver::SpralSrc => InteriorPointLinearSolver::SpralSrc,
        InteriorPointLinearSolver::SparseQdldl => InteriorPointLinearSolver::SparseQdldl,
    }
}

fn secondary_linear_solver(solver: InteriorPointLinearSolver) -> Option<InteriorPointLinearSolver> {
    match solver {
        InteriorPointLinearSolver::Auto => Some(InteriorPointLinearSolver::SparseQdldl),
        InteriorPointLinearSolver::SsidsRs
        | InteriorPointLinearSolver::SpralSrc
        | InteriorPointLinearSolver::SparseQdldl => None,
    }
}

fn linear_solve_error(
    preferred_solver: InteriorPointLinearSolver,
    matrix_dimension: usize,
    attempts: Vec<InteriorPointLinearSolveAttempt>,
) -> InteriorPointSolveError {
    InteriorPointSolveError::LinearSolve {
        solver: preferred_solver,
        context: Box::new(InteriorPointFailureContext {
            final_state: None,
            last_accepted_state: None,
            failed_linear_solve: Some(InteriorPointLinearSolveDiagnostics {
                preferred_solver,
                matrix_dimension,
                attempts,
                debug_report: None,
            }),
            failed_line_search: None,
            failed_direction_diagnostics: None,
            profiling: InteriorPointProfiling::default(),
        }),
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "Linear-solver retries/regularization are passed explicitly at the solver boundary."
)]
fn try_solve_symmetric_system_with_metrics(
    solver: InteriorPointLinearSolver,
    matrix: &CscMatrix<f64>,
    rhs: &[f64],
    regularization: f64,
    dsigns: Option<&[i8]>,
    adaptive_regularization_retries: Index,
    regularization_growth_factor: f64,
    regularization_max: f64,
) -> std::result::Result<(Vec<f64>, LinearBackendRunStats, f64), Vec<InteriorPointLinearSolveAttempt>>
{
    let preferred_solver = preferred_linear_solver(solver, 0, 0);
    let try_solver = |matrix: &CscMatrix<f64>,
                      rhs: &[f64],
                      retries: Index,
                      growth_factor: f64,
                      regularization_max: f64| {
        let mut attempts = Vec::new();
        let mut current_regularization = regularization.max(1e-12);
        let max_regularization = regularization_max.max(current_regularization);
        for retry_index in 0..=retries {
            let attempt_result = match preferred_solver {
                InteriorPointLinearSolver::SpralSrc => {
                    factor_solve_spral_src_symmetric_with_metrics(
                        matrix,
                        rhs,
                        current_regularization,
                    )
                }
                InteriorPointLinearSolver::SsidsRs => {
                    factor_solve_spral_ssids_symmetric_with_metrics(
                        matrix,
                        rhs,
                        current_regularization,
                    )
                }
                InteriorPointLinearSolver::SparseQdldl | InteriorPointLinearSolver::Auto => {
                    factor_solve_sparse_qdldl_with_metrics(
                        matrix,
                        rhs,
                        current_regularization,
                        dsigns,
                    )
                }
            };
            match attempt_result {
                Ok((solution, stats)) => {
                    return Ok((solution, stats, current_regularization));
                }
                Err(attempt) => attempts.push(attempt),
            }
            if retry_index == retries || current_regularization >= max_regularization {
                break;
            }
            let next_regularization =
                (current_regularization * growth_factor.max(1.0)).min(max_regularization);
            if next_regularization <= current_regularization {
                break;
            }
            current_regularization = next_regularization;
        }
        Err(attempts)
    };
    let sparse_result = try_solver(
        matrix,
        rhs,
        adaptive_regularization_retries,
        regularization_growth_factor,
        regularization_max,
    );
    let attempts = match sparse_result {
        Ok(result) => return Ok(result),
        Err(attempts) => attempts,
    };
    Err(attempts)
}

fn finalised_interior_point_failure_profiling(
    profiling: &InteriorPointProfiling,
    solve_started: Instant,
) -> InteriorPointProfiling {
    let mut profiling = profiling.clone();
    finalise_interior_point_profiling(&mut profiling, solve_started);
    profiling
}

fn interior_point_failure_context(
    final_state: Option<InteriorPointIterationSnapshot>,
    last_accepted_state: Option<InteriorPointIterationSnapshot>,
    failed_linear_solve: Option<InteriorPointLinearSolveDiagnostics>,
    failed_line_search: Option<InteriorPointLineSearchInfo>,
    failed_direction_diagnostics: Option<InteriorPointDirectionDiagnostics>,
    profiling: &InteriorPointProfiling,
    solve_started: Instant,
) -> Box<InteriorPointFailureContext> {
    Box::new(InteriorPointFailureContext {
        final_state,
        last_accepted_state,
        failed_linear_solve,
        failed_line_search,
        failed_direction_diagnostics,
        profiling: finalised_interior_point_failure_profiling(profiling, solve_started),
    })
}

fn interior_point_error_context(
    error: &InteriorPointSolveError,
) -> Option<&InteriorPointFailureContext> {
    match error {
        InteriorPointSolveError::LinearSolve { context, .. }
        | InteriorPointSolveError::LineSearchFailed { context, .. }
        | InteriorPointSolveError::RestorationFailed { context, .. }
        | InteriorPointSolveError::LocalInfeasibility { context }
        | InteriorPointSolveError::DivergingIterates { context, .. }
        | InteriorPointSolveError::CpuTimeExceeded { context, .. }
        | InteriorPointSolveError::WallTimeExceeded { context, .. }
        | InteriorPointSolveError::UserRequestedStop { context }
        | InteriorPointSolveError::SearchDirectionTooSmall { context }
        | InteriorPointSolveError::MaxIterations { context, .. } => Some(context),
        InteriorPointSolveError::InvalidInput(_) => None,
    }
}

fn maybe_print_restoration_subproblem_error_debug(
    error: &InteriorPointSolveError,
    restoration_depth: usize,
    restoration_iteration_offset: usize,
) {
    if std::env::var_os("NLIP_RESTORATION_ERROR_DEBUG").is_none() {
        return;
    }
    eprintln!(
        "[NLIP][restoration-error] depth={restoration_depth} offset={restoration_iteration_offset} error={error}"
    );
    let Some(context) = interior_point_error_context(error) else {
        return;
    };
    for (label, snapshot) in [
        ("final", context.final_state.as_ref()),
        ("last_accepted", context.last_accepted_state.as_ref()),
    ] {
        let Some(snapshot) = snapshot else {
            continue;
        };
        eprintln!(
            "[NLIP][restoration-error] {label} iter={} phase={:?} obj={:.17e} primal={:.17e} dual={:.17e} comp={:.17e} overall={:.17e} mu={:.17e} alpha_pr={:?} alpha_du={:?} alpha_y={:?} tag={:?} ls={}",
            snapshot.iteration,
            snapshot.phase,
            snapshot.objective,
            snapshot
                .eq_inf
                .unwrap_or(0.0)
                .max(snapshot.ineq_inf.unwrap_or(0.0)),
            snapshot.dual_inf,
            snapshot.comp_inf.unwrap_or(0.0),
            snapshot.overall_inf,
            snapshot.barrier_parameter.unwrap_or(0.0),
            snapshot.alpha_pr,
            snapshot.alpha_du,
            snapshot.alpha_y,
            snapshot.step_tag,
            snapshot.line_search_trials,
        );
    }
    if let Some(line_search) = context.failed_line_search.as_ref() {
        eprintln!(
            "[NLIP][restoration-error] line_search alpha0={:.17e} alpha_du0={:?} alpha_y0={:?} last={:.17e} last_du={:?} last_y={:?} backtracks={} alpha_min={:.17e} rejected={} soc_attempted={} soc_used={} watchdog_active={} watchdog_accepted={} tiny_step={} current_merit={:.17e} barrier_obj={:.17e} primal={:.17e}",
            line_search.initial_alpha_pr,
            line_search.initial_alpha_du,
            line_search.initial_alpha_y,
            line_search.last_tried_alpha,
            line_search.last_tried_alpha_du,
            line_search.last_tried_alpha_y,
            line_search.backtrack_count,
            line_search.alpha_min,
            line_search.rejected_trials.len(),
            line_search.second_order_correction_attempted,
            line_search.second_order_correction_used,
            line_search.watchdog_active,
            line_search.watchdog_accepted,
            line_search.tiny_step,
            line_search.current_merit,
            line_search.current_barrier_objective,
            line_search.current_primal_inf,
        );
        for (index, trial) in line_search.rejected_trials.iter().enumerate().take(6) {
            eprintln!(
                "[NLIP][restoration-error] rejected[{index}] alpha={:.17e} alpha_du={:?} slack_positive={} multipliers_positive={} merit={:?} barrier={:?} primal={:?} dual={:?} comp={:?} local_filter={:?} filter={:?} dominated={:?} sufficient_phi={:?} sufficient_theta={:?} switching={:?}",
                trial.alpha,
                trial.alpha_du,
                trial.slack_positive,
                trial.multipliers_positive,
                trial.merit,
                trial.barrier_objective,
                trial.primal_inf,
                trial.dual_inf,
                trial.comp_inf,
                trial.local_filter_acceptable,
                trial.filter_acceptable,
                trial.filter_dominated,
                trial.filter_sufficient_objective_reduction,
                trial.filter_sufficient_violation_reduction,
                trial.switching_condition_satisfied,
            );
        }
        if line_search.rejected_trials.len() > 6
            && let Some(trial) = line_search.rejected_trials.last()
        {
            eprintln!(
                "[NLIP][restoration-error] rejected[last] alpha={:.17e} alpha_du={:?} slack_positive={} multipliers_positive={} merit={:?} barrier={:?} primal={:?} dual={:?} comp={:?} local_filter={:?} filter={:?} dominated={:?} sufficient_phi={:?} sufficient_theta={:?} switching={:?}",
                trial.alpha,
                trial.alpha_du,
                trial.slack_positive,
                trial.multipliers_positive,
                trial.merit,
                trial.barrier_objective,
                trial.primal_inf,
                trial.dual_inf,
                trial.comp_inf,
                trial.local_filter_acceptable,
                trial.filter_acceptable,
                trial.filter_dominated,
                trial.filter_sufficient_objective_reduction,
                trial.filter_sufficient_violation_reduction,
                trial.switching_condition_satisfied,
            );
        }
    }
    if let Some(direction) = context.failed_direction_diagnostics.as_ref() {
        eprintln!(
            "[NLIP][restoration-error] direction dx_inf={:.17e} dlambda_inf={:.17e} ds_inf={:.17e} dz_inf={:.17e} regularization={:.17e} primal_shift={:.17e} dual_reg={:.17e} alpha_pr_limiter={:?} alpha_du_limiter={:?}",
            direction.dx_inf,
            direction.d_lambda_inf,
            direction.ds_inf,
            direction.dz_inf,
            direction.regularization_size,
            direction.primal_diagonal_shift,
            direction.dual_regularization,
            direction.alpha_pr_limiter,
            direction.alpha_du_limiter,
        );
    }
}

fn with_interior_point_failure_profiling(
    error: InteriorPointSolveError,
    final_state: Option<InteriorPointIterationSnapshot>,
    last_accepted_state: Option<InteriorPointIterationSnapshot>,
    profiling: &InteriorPointProfiling,
    solve_started: Instant,
) -> InteriorPointSolveError {
    match error {
        InteriorPointSolveError::LinearSolve { solver, context } => {
            InteriorPointSolveError::LinearSolve {
                solver,
                context: interior_point_failure_context(
                    final_state.or(context.final_state),
                    last_accepted_state.or(context.last_accepted_state),
                    context.failed_linear_solve,
                    context.failed_line_search,
                    context.failed_direction_diagnostics,
                    profiling,
                    solve_started,
                ),
            }
        }
        InteriorPointSolveError::LineSearchFailed {
            merit,
            mu,
            step_inf_norm,
            context,
        } => InteriorPointSolveError::LineSearchFailed {
            merit,
            mu,
            step_inf_norm,
            context: interior_point_failure_context(
                final_state.or(context.final_state),
                last_accepted_state.or(context.last_accepted_state),
                context.failed_linear_solve,
                context.failed_line_search,
                context.failed_direction_diagnostics,
                profiling,
                solve_started,
            ),
        },
        InteriorPointSolveError::RestorationFailed { status, context } => {
            InteriorPointSolveError::RestorationFailed {
                status,
                context: interior_point_failure_context(
                    final_state.or(context.final_state),
                    last_accepted_state.or(context.last_accepted_state),
                    context.failed_linear_solve,
                    context.failed_line_search,
                    context.failed_direction_diagnostics,
                    profiling,
                    solve_started,
                ),
            }
        }
        InteriorPointSolveError::LocalInfeasibility { context } => {
            InteriorPointSolveError::LocalInfeasibility {
                context: interior_point_failure_context(
                    final_state.or(context.final_state),
                    last_accepted_state.or(context.last_accepted_state),
                    context.failed_linear_solve,
                    context.failed_line_search,
                    context.failed_direction_diagnostics,
                    profiling,
                    solve_started,
                ),
            }
        }
        InteriorPointSolveError::DivergingIterates {
            max_abs_x,
            threshold,
            context,
        } => InteriorPointSolveError::DivergingIterates {
            max_abs_x,
            threshold,
            context: interior_point_failure_context(
                final_state.or(context.final_state),
                last_accepted_state.or(context.last_accepted_state),
                context.failed_linear_solve,
                context.failed_line_search,
                context.failed_direction_diagnostics,
                profiling,
                solve_started,
            ),
        },
        InteriorPointSolveError::CpuTimeExceeded {
            elapsed_seconds,
            limit_seconds,
            context,
        } => InteriorPointSolveError::CpuTimeExceeded {
            elapsed_seconds,
            limit_seconds,
            context: interior_point_failure_context(
                final_state.or(context.final_state),
                last_accepted_state.or(context.last_accepted_state),
                context.failed_linear_solve,
                context.failed_line_search,
                context.failed_direction_diagnostics,
                profiling,
                solve_started,
            ),
        },
        InteriorPointSolveError::WallTimeExceeded {
            elapsed_seconds,
            limit_seconds,
            context,
        } => InteriorPointSolveError::WallTimeExceeded {
            elapsed_seconds,
            limit_seconds,
            context: interior_point_failure_context(
                final_state.or(context.final_state),
                last_accepted_state.or(context.last_accepted_state),
                context.failed_linear_solve,
                context.failed_line_search,
                context.failed_direction_diagnostics,
                profiling,
                solve_started,
            ),
        },
        InteriorPointSolveError::UserRequestedStop { context } => {
            InteriorPointSolveError::UserRequestedStop {
                context: interior_point_failure_context(
                    final_state.or(context.final_state),
                    last_accepted_state.or(context.last_accepted_state),
                    context.failed_linear_solve,
                    context.failed_line_search,
                    context.failed_direction_diagnostics,
                    profiling,
                    solve_started,
                ),
            }
        }
        InteriorPointSolveError::SearchDirectionTooSmall { context } => {
            InteriorPointSolveError::SearchDirectionTooSmall {
                context: interior_point_failure_context(
                    final_state.or(context.final_state),
                    last_accepted_state.or(context.last_accepted_state),
                    context.failed_linear_solve,
                    context.failed_line_search,
                    context.failed_direction_diagnostics,
                    profiling,
                    solve_started,
                ),
            }
        }
        InteriorPointSolveError::MaxIterations {
            iterations,
            context,
        } => InteriorPointSolveError::MaxIterations {
            iterations,
            context: interior_point_failure_context(
                final_state.or(context.final_state),
                last_accepted_state.or(context.last_accepted_state),
                context.failed_linear_solve,
                context.failed_line_search,
                context.failed_direction_diagnostics,
                profiling,
                solve_started,
            ),
        },
        InteriorPointSolveError::InvalidInput(message) => {
            InteriorPointSolveError::InvalidInput(message)
        }
    }
}

fn with_linear_debug_report(
    error: InteriorPointSolveError,
    report: InteriorPointLinearDebugReport,
) -> InteriorPointSolveError {
    match error {
        InteriorPointSolveError::LinearSolve {
            solver,
            mut context,
        } => {
            if let Some(diagnostics) = context.failed_linear_solve.as_mut() {
                diagnostics.debug_report = Some(report);
            }
            InteriorPointSolveError::LinearSolve { solver, context }
        }
        other => other,
    }
}

fn append_symmetric_hessian_triplets(
    hessian: &SparseSymmetricMatrix,
    diagonal_shift: f64,
    rows: &mut Vec<usize>,
    cols: &mut Vec<usize>,
    values: &mut Vec<f64>,
) {
    for col in 0..hessian.lower_triangle.ncol {
        for index in hessian.lower_triangle.col_ptrs[col]..hessian.lower_triangle.col_ptrs[col + 1]
        {
            let row = hessian.lower_triangle.row_indices[index];
            rows.push(col.min(row));
            cols.push(col.max(row));
            values.push(hessian.values[index]);
        }
    }
    if diagonal_shift != 0.0 {
        for diag in 0..hessian.lower_triangle.ncol {
            rows.push(diag);
            cols.push(diag);
            values.push(diagonal_shift);
        }
    }
}

fn sparse_hessian_diagonal_shift(hessian: &SparseSymmetricMatrix, minimum_shift: f64) -> f64 {
    let n = hessian.lower_triangle.nrow;
    let mut diagonal = vec![0.0; n];
    let mut off_diagonal_abs_sum = vec![0.0; n];
    for col in 0..hessian.lower_triangle.ncol {
        for index in hessian.lower_triangle.col_ptrs[col]..hessian.lower_triangle.col_ptrs[col + 1]
        {
            let row = hessian.lower_triangle.row_indices[index];
            let value = hessian.values[index];
            if row == col {
                diagonal[row] += value;
            } else {
                let abs_value = value.abs();
                off_diagonal_abs_sum[row] += abs_value;
                off_diagonal_abs_sum[col] += abs_value;
            }
        }
    }
    let mut shift = minimum_shift.max(0.0);
    for idx in 0..n {
        shift = shift.max(off_diagonal_abs_sum[idx] - diagonal[idx] + minimum_shift);
    }
    shift
}

fn spral_augmented_kkt_regularization_shifts(
    system: &ReducedKktSystem<'_>,
    solver: InteriorPointLinearSolver,
    regularization: f64,
) -> (f64, f64) {
    match solver {
        InteriorPointLinearSolver::SpralSrc => (regularization.max(0.0), 0.0),
        InteriorPointLinearSolver::SsidsRs | InteriorPointLinearSolver::Auto => (
            sparse_hessian_diagonal_shift(system.hessian, regularization),
            regularization.max(1e-8),
        ),
        InteriorPointLinearSolver::SparseQdldl => (
            sparse_hessian_diagonal_shift(system.hessian, regularization),
            regularization.max(1e-8),
        ),
    }
}

fn next_ipopt_hessian_perturbation(
    current: f64,
    previous_successful: Option<f64>,
    first: f64,
    first_growth_factor: f64,
    growth_factor: f64,
    decay_factor: f64,
    max_regularization: f64,
) -> Option<f64> {
    let previous_successful = previous_successful.unwrap_or(0.0).max(0.0);
    let next = if current <= 0.0 {
        if previous_successful <= 0.0 {
            first.max(0.0)
        } else {
            (previous_successful * decay_factor.clamp(0.0, 1.0)).max(1e-20)
        }
    } else if previous_successful <= 0.0 || 1e5 * previous_successful < current {
        current * first_growth_factor.max(1.0)
    } else {
        current * growth_factor.max(1.0)
    };
    if next <= current || next > max_regularization {
        None
    } else {
        Some(next.min(max_regularization))
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum IpoptPerturbationTestStatus {
    NoTest,
    DeltaCEq0DeltaXEq0,
    DeltaCGt0DeltaXEq0,
    DeltaCEq0DeltaXGt0,
    DeltaCGt0DeltaXGt0,
}

#[derive(Clone, Copy, Debug)]
struct IpoptPerturbationRetryConfig {
    previous_hessian_perturbation: Option<f64>,
    first_hessian_perturbation: f64,
    first_growth_factor: f64,
    growth_factor: f64,
    decay_factor: f64,
    max_regularization: f64,
    jacobian_regularization: f64,
    perturb_always_cd: bool,
}

#[derive(Clone, Copy, Debug, PartialEq)]
struct IpoptPerturbationRetry {
    regularization: f64,
    jacobian_regularization: f64,
    test_status: IpoptPerturbationTestStatus,
}

fn initial_ipopt_perturbation_test_status(
    perturb_always_cd: bool,
    jacobian_regularization_already_active: bool,
) -> IpoptPerturbationTestStatus {
    if perturb_always_cd {
        IpoptPerturbationTestStatus::DeltaCGt0DeltaXEq0
    } else if jacobian_regularization_already_active {
        IpoptPerturbationTestStatus::NoTest
    } else {
        IpoptPerturbationTestStatus::DeltaCEq0DeltaXEq0
    }
}

fn ipopt_perturbation_retry_config(
    system: &ReducedKktSystem<'_>,
    max_regularization: f64,
) -> IpoptPerturbationRetryConfig {
    IpoptPerturbationRetryConfig {
        previous_hessian_perturbation: system.previous_hessian_perturbation,
        first_hessian_perturbation: system.first_hessian_perturbation,
        first_growth_factor: system.regularization_first_growth_factor,
        growth_factor: system.regularization_growth_factor,
        decay_factor: system.regularization_decay_factor,
        max_regularization,
        jacobian_regularization: ipopt_jacobian_perturbation(system),
        perturb_always_cd: system.perturb_always_cd,
    }
}

fn ipopt_next_hessian_perturbation_from_config(
    current_regularization: f64,
    config: IpoptPerturbationRetryConfig,
) -> Option<f64> {
    next_ipopt_hessian_perturbation(
        current_regularization,
        config.previous_hessian_perturbation,
        config.first_hessian_perturbation,
        config.first_growth_factor,
        config.growth_factor,
        config.decay_factor,
        config.max_regularization,
    )
}

fn ipopt_perturb_for_singularity(
    current_regularization: f64,
    current_jacobian_regularization: f64,
    test_status: IpoptPerturbationTestStatus,
    config: IpoptPerturbationRetryConfig,
) -> Option<IpoptPerturbationRetry> {
    let jacobian_regularization = config.jacobian_regularization;
    match test_status {
        IpoptPerturbationTestStatus::DeltaCEq0DeltaXEq0 => {
            if jacobian_regularization > 0.0 {
                Some(IpoptPerturbationRetry {
                    regularization: current_regularization,
                    jacobian_regularization,
                    test_status: IpoptPerturbationTestStatus::DeltaCGt0DeltaXEq0,
                })
            } else {
                None
            }
        }
        IpoptPerturbationTestStatus::DeltaCGt0DeltaXEq0 => {
            let next_regularization =
                ipopt_next_hessian_perturbation_from_config(current_regularization, config)?;
            Some(IpoptPerturbationRetry {
                regularization: next_regularization,
                jacobian_regularization: if config.perturb_always_cd {
                    current_jacobian_regularization.max(jacobian_regularization)
                } else {
                    0.0
                },
                test_status: if config.perturb_always_cd {
                    IpoptPerturbationTestStatus::DeltaCGt0DeltaXGt0
                } else {
                    IpoptPerturbationTestStatus::DeltaCEq0DeltaXGt0
                },
            })
        }
        IpoptPerturbationTestStatus::DeltaCEq0DeltaXGt0 => {
            let next_regularization =
                ipopt_next_hessian_perturbation_from_config(current_regularization, config)?;
            Some(IpoptPerturbationRetry {
                regularization: next_regularization,
                jacobian_regularization,
                test_status: IpoptPerturbationTestStatus::DeltaCGt0DeltaXGt0,
            })
        }
        IpoptPerturbationTestStatus::DeltaCGt0DeltaXGt0 => {
            let next_regularization =
                ipopt_next_hessian_perturbation_from_config(current_regularization, config)?;
            Some(IpoptPerturbationRetry {
                regularization: next_regularization,
                jacobian_regularization: current_jacobian_regularization
                    .max(jacobian_regularization),
                test_status: IpoptPerturbationTestStatus::DeltaCGt0DeltaXGt0,
            })
        }
        IpoptPerturbationTestStatus::NoTest => {
            if current_jacobian_regularization > 0.0 {
                let next_regularization =
                    ipopt_next_hessian_perturbation_from_config(current_regularization, config)?;
                Some(IpoptPerturbationRetry {
                    regularization: next_regularization,
                    jacobian_regularization: current_jacobian_regularization,
                    test_status,
                })
            } else if jacobian_regularization > 0.0 {
                Some(IpoptPerturbationRetry {
                    regularization: current_regularization,
                    jacobian_regularization,
                    test_status,
                })
            } else {
                None
            }
        }
    }
}

fn ipopt_perturb_for_wrong_inertia(
    current_regularization: f64,
    current_jacobian_regularization: f64,
    test_status: IpoptPerturbationTestStatus,
    has_constraints: bool,
    config: IpoptPerturbationRetryConfig,
) -> Option<IpoptPerturbationRetry> {
    if let Some(next_regularization) =
        ipopt_next_hessian_perturbation_from_config(current_regularization, config)
    {
        return Some(IpoptPerturbationRetry {
            regularization: next_regularization,
            jacobian_regularization: current_jacobian_regularization,
            test_status,
        });
    }

    if !has_constraints
        || current_jacobian_regularization > 0.0
        || config.jacobian_regularization <= 0.0
    {
        return None;
    }

    let next_regularization = next_ipopt_hessian_perturbation(
        0.0,
        None,
        config.first_hessian_perturbation,
        config.first_growth_factor,
        config.growth_factor,
        config.decay_factor,
        config.max_regularization,
    )?;

    Some(IpoptPerturbationRetry {
        regularization: next_regularization,
        jacobian_regularization: config.jacobian_regularization,
        test_status: IpoptPerturbationTestStatus::NoTest,
    })
}

fn ipopt_jacobian_perturbation_value(
    jacobian_regularization_value: f64,
    barrier_parameter: f64,
    jacobian_regularization_exponent: f64,
) -> f64 {
    jacobian_regularization_value
        * barrier_parameter
            .max(0.0)
            .powf(jacobian_regularization_exponent)
}

fn ipopt_jacobian_perturbation(system: &ReducedKktSystem<'_>) -> f64 {
    ipopt_jacobian_perturbation_value(
        system.jacobian_regularization_value,
        system.barrier_parameter,
        system.jacobian_regularization_exponent,
    )
}

fn ipopt_initial_jacobian_regularization_value(
    forced_jacobian_regularization: Option<f64>,
    perturb_always_cd: bool,
    jacobian_regularization_value: f64,
    barrier_parameter: f64,
    jacobian_regularization_exponent: f64,
) -> (f64, bool) {
    if let Some(forced_regularization) = forced_jacobian_regularization {
        (forced_regularization, true)
    } else if perturb_always_cd {
        (
            ipopt_jacobian_perturbation_value(
                jacobian_regularization_value,
                barrier_parameter,
                jacobian_regularization_exponent,
            ),
            true,
        )
    } else {
        (0.0, false)
    }
}

fn ipopt_initial_jacobian_regularization(system: &ReducedKktSystem<'_>) -> (f64, bool) {
    ipopt_initial_jacobian_regularization_value(
        system.forced_jacobian_regularization,
        system.perturb_always_cd,
        system.jacobian_regularization_value,
        system.barrier_parameter,
        system.jacobian_regularization_exponent,
    )
}

fn is_factorization_failure(attempt: &InteriorPointLinearSolveAttempt) -> bool {
    attempt.failure_kind == InteriorPointLinearSolveFailureKind::FactorizationFailed
}

fn is_singularity_like_linear_failure(attempt: &InteriorPointLinearSolveAttempt) -> bool {
    is_factorization_failure(attempt)
        || (attempt.failure_kind == InteriorPointLinearSolveFailureKind::InertiaMismatch
            && attempt
                .detail
                .as_deref()
                .is_some_and(|detail| detail.contains("negative_eigenvalues_too_few")))
        || (attempt.failure_kind == InteriorPointLinearSolveFailureKind::ResidualTooLarge
            && attempt.detail.as_deref().is_some_and(|detail| {
                detail.contains("ipopt_pretend_singular_after_refinement_failure")
            }))
}

fn is_negative_eigenvalues_too_few(attempt: &InteriorPointLinearSolveAttempt) -> bool {
    attempt.failure_kind == InteriorPointLinearSolveFailureKind::InertiaMismatch
        && attempt
            .detail
            .as_deref()
            .is_some_and(|detail| detail.contains("negative_eigenvalues_too_few"))
}

fn append_attempt_detail(attempt: &mut InteriorPointLinearSolveAttempt, detail: impl Into<String>) {
    let detail = detail.into();
    attempt.detail = Some(match attempt.detail.take() {
        Some(existing) => format!("{existing}; {detail}"),
        None => detail,
    });
}

fn native_spral_quality_can_increase(
    workspace: &NativeSpralAugmentedKktWorkspace,
    system: &ReducedKktSystem<'_>,
) -> bool {
    let old_u = workspace.numeric_options.threshold_pivot_u;
    let max_u = system.spral_pivot_tolerance_max.max(0.0);
    if !old_u.is_finite() || !max_u.is_finite() || old_u >= max_u {
        return false;
    }
    let next_u = old_u.powf(0.75).min(max_u);
    next_u.is_finite() && next_u > old_u
}

fn try_increase_native_spral_quality(
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    system: &ReducedKktSystem<'_>,
) -> Option<(f64, f64)> {
    if !native_spral_quality_can_increase(workspace, system) {
        return None;
    }
    let old_u = workspace.numeric_options.threshold_pivot_u;
    let next_u = old_u
        .powf(0.75)
        .min(system.spral_pivot_tolerance_max.max(0.0));
    workspace.numeric_options.threshold_pivot_u = next_u;
    workspace.session = None;
    workspace.factor_regularization = None;
    Some((old_u, next_u))
}

fn linear_solver_quality_was_increased(stats: &LinearBackendRunStats) -> bool {
    stats
        .detail
        .as_deref()
        .is_some_and(|detail| detail.contains("spral_quality_retry="))
}

fn inertia_mismatch_detail(expected: SpralInertia, actual: SpralInertia) -> String {
    let prefix = if actual.negative < expected.negative {
        "negative_eigenvalues_too_few; "
    } else if actual.negative > expected.negative {
        "negative_eigenvalues_too_many; "
    } else {
        ""
    };
    format!(
        "{prefix}expected inertia (+{}, -{}, 0={}), got (+{}, -{}, 0={})",
        expected.positive,
        expected.negative,
        expected.zero,
        actual.positive,
        actual.negative,
        actual.zero
    )
}

fn append_selected_constraint_block_triplets(
    matrix: &SparseMatrix,
    selected_rows: &[usize],
    block_column_offset: usize,
    rows: &mut Vec<usize>,
    cols: &mut Vec<usize>,
    values: &mut Vec<f64>,
) {
    for (offset, &selected_row) in selected_rows.iter().enumerate() {
        let dual_col = block_column_offset + offset;
        for &(col, index) in &matrix.structure.row_entries[selected_row] {
            rows.push(col);
            cols.push(dual_col);
            values.push(matrix.values[index]);
        }
    }
}

fn append_quasidefinite_dual_diagonal(
    dual_offset: usize,
    dual_dimension: usize,
    shift: f64,
    rows: &mut Vec<usize>,
    cols: &mut Vec<usize>,
    values: &mut Vec<f64>,
) {
    for dual_index in 0..dual_dimension {
        let index = dual_offset + dual_index;
        rows.push(index);
        cols.push(index);
        values.push(-shift);
    }
}

fn ipopt_augmented_diagonal_with_shift(diagonal: f64, shift: f64) -> f64 {
    // Mirrors IpStdAugSystemSolver.cpp::CreateAugmentedSystem: D_x and D_s
    // are copied first, then `AddScalar(delta_*)` is applied before the
    // diagonal matrix term is coalesced into the augmented KKT structure.
    if shift == 0.0 {
        diagonal
    } else {
        diagonal + shift
    }
}

fn fill_spral_augmented_kkt_values(
    pattern: &SpralAugmentedKktPattern,
    values: &mut [f64],
    system: &ReducedKktSystem<'_>,
    primal_shift: f64,
    slack_shift: f64,
    dual_shift: f64,
) {
    values.fill(0.0);
    for (index, &slot) in pattern.hessian_value_indices.iter().enumerate() {
        values[slot] += system.hessian.values[index];
    }
    for (index, &slot) in pattern.x_diagonal_indices.iter().enumerate() {
        values[slot] += ipopt_augmented_diagonal_with_shift(
            system.bound_diagonal.get(index).copied().unwrap_or(0.0),
            primal_shift,
        );
    }
    for (index, &slot) in pattern.equality_jacobian_value_indices.iter().enumerate() {
        values[slot] += system.equality_jacobian.values[index];
    }
    for (index, &slot) in pattern.inequality_jacobian_value_indices.iter().enumerate() {
        values[slot] += system.inequality_jacobian.values[index];
    }
    for (index, &slot) in pattern.p_diagonal_indices.iter().enumerate() {
        values[slot] += ipopt_augmented_diagonal_with_shift(
            system.multipliers[index] / system.slack[index],
            slack_shift,
        );
    }
    for (index, &slot) in pattern.lambda_diagonal_indices.iter().enumerate() {
        values[slot] += system.equality_diagonal.get(index).copied().unwrap_or(0.0) - dual_shift;
    }
    for (index, &slot) in pattern.z_diagonal_indices.iter().enumerate() {
        values[slot] += system
            .inequality_diagonal
            .get(index)
            .copied()
            .unwrap_or(0.0)
            - dual_shift;
    }
    for &slot in &pattern.pz_indices {
        values[slot] += -1.0;
    }
}

fn assemble_spral_augmented_kkt_values(
    workspace: &mut SpralAugmentedKktWorkspace,
    system: &ReducedKktSystem<'_>,
    primal_shift: f64,
    slack_shift: f64,
    dual_shift: f64,
) {
    fill_spral_augmented_kkt_values(
        &workspace.pattern,
        &mut workspace.values,
        system,
        primal_shift,
        slack_shift,
        dual_shift,
    );
}

fn spral_expected_augmented_inertia(pattern: &SpralAugmentedKktPattern) -> SpralInertia {
    SpralInertia {
        positive: pattern.x_dimension + pattern.inequality_dimension,
        negative: pattern.equality_dimension + pattern.inequality_dimension,
        zero: 0,
    }
}

fn factor_solve_spral_ssids(
    system: &ReducedKktSystem<'_>,
    workspace: &mut SpralAugmentedKktWorkspace,
    rhs: &[f64],
    regularization: f64,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
) -> std::result::Result<(Vec<f64>, LinearBackendRunStats), InteriorPointLinearSolveAttempt> {
    let matrix = SpralSymmetricCscMatrix::new(
        workspace.pattern.dimension(),
        &workspace.pattern.ccs.col_ptrs,
        &workspace.pattern.ccs.row_indices,
        Some(&workspace.values),
    )
    .map_err(|error| {
        spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    // The assembled augmented KKT already includes the NLP regularization shifts.
    // Reusing that value as the LDL pivot regularization materially changes the
    // factorization path versus native SPRAL; keep the solver's own small pivot
    // floor instead.
    let numeric_options = system_spral_numeric_factor_options(system);

    let needs_new_factor = workspace.factor.is_none()
        || workspace
            .factor_regularization
            .is_none_or(|existing| (existing - regularization).abs() > 1e-18);
    let mut factorization_time = Duration::ZERO;
    let mut solve_time = Duration::ZERO;
    if !needs_new_factor {
        let started = Instant::now();
        profiling.sparse_numeric_refactorizations += 1;
        let refactorization_index = profiling.sparse_numeric_refactorizations;
        if let Some(factor) = workspace.factor.as_mut() {
            let refactor_heartbeat =
                verbose.then(|| spawn_spral_stage_heartbeat("[NLIP][SPRAL] Refactorization"));
            match factor.refactorize(matrix) {
                Ok(_) => {
                    if let Some((finished, handle)) = refactor_heartbeat {
                        finished.store(true, Ordering::Relaxed);
                        handle.thread().unpark();
                        let _ = handle.join();
                    }
                    let elapsed = started.elapsed();
                    factorization_time += elapsed;
                    profiling.sparse_numeric_refactorization_time += elapsed;
                    if verbose
                        && (refactorization_index <= 3 || refactorization_index.is_multiple_of(25))
                    {
                        println!(
                            "[NLIP][SPRAL] Refactorization #{} completed in {} (reg={:.3e})",
                            refactorization_index,
                            compact_duration_text(elapsed.as_secs_f64()),
                            regularization,
                        );
                    }
                }
                Err(error) => {
                    if let Some((finished, handle)) = refactor_heartbeat {
                        finished.store(true, Ordering::Relaxed);
                        handle.thread().unpark();
                        let _ = handle.join();
                    }
                    profiling.sparse_numeric_refactorization_time += started.elapsed();
                    workspace.factor = None;
                    workspace.factor_regularization = None;
                    return Err(spral_error_attempt(
                        regularization,
                        InteriorPointLinearSolveFailureKind::FactorizationFailed,
                        error,
                    ));
                }
            }
        }
    }
    if workspace.factor.is_none() {
        let started = Instant::now();
        profiling.sparse_numeric_factorizations += 1;
        if verbose {
            println!(
                "[NLIP][SPRAL] Starting numeric factorization: dim={} nnz={} reg={:.3e}",
                workspace.pattern.dimension(),
                workspace.pattern.ccs.nnz(),
                regularization,
            );
        }
        let factorization_heartbeat =
            verbose.then(|| spawn_spral_stage_heartbeat("[NLIP][SPRAL] Numeric factorization"));
        match spral_factorize(matrix, &workspace.symbolic, &numeric_options) {
            Ok((factor, _)) => {
                if let Some((finished, handle)) = factorization_heartbeat {
                    finished.store(true, Ordering::Relaxed);
                    handle.thread().unpark();
                    let _ = handle.join();
                }
                let elapsed = started.elapsed();
                factorization_time += elapsed;
                profiling.sparse_numeric_factorization_time += elapsed;
                if verbose {
                    println!(
                        "[NLIP][SPRAL] Numeric factorization completed in {}: stored_nnz={} factor_bytes={}",
                        compact_duration_text(elapsed.as_secs_f64()),
                        factor.stored_nnz(),
                        factor.factor_bytes(),
                    );
                }
                workspace.factor = Some(factor);
                workspace.factor_regularization = Some(regularization);
            }
            Err(error) => {
                if let Some((finished, handle)) = factorization_heartbeat {
                    finished.store(true, Ordering::Relaxed);
                    handle.thread().unpark();
                    let _ = handle.join();
                }
                profiling.sparse_numeric_factorization_time += started.elapsed();
                return Err(spral_error_attempt(
                    regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    error,
                ));
            }
        }
    }

    let reused_symbolic = !needs_new_factor;
    let factor = workspace.factor.as_mut().expect("factorization must exist");
    let expected_inertia = spral_expected_augmented_inertia(&workspace.pattern);
    let actual_inertia = factor.inertia();
    if actual_inertia != expected_inertia {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SsidsRs,
            regularization,
            inertia: Some(Box::new(interior_point_linear_inertia(actual_inertia))),
            failure_kind: InteriorPointLinearSolveFailureKind::InertiaMismatch,
            detail: Some(inertia_mismatch_detail(expected_inertia, actual_inertia)),
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        });
    }

    let solve_started = Instant::now();
    let mut solution = factor.solve(rhs).map_err(|error| {
        spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    solve_time += solve_started.elapsed();
    let refinement_steps = refine_linear_solution_ccs(
        &workspace.pattern.ccs,
        &workspace.values,
        rhs,
        &mut solution,
        IpoptLinearRefinementOptions::source_defaults(),
        &mut solve_time,
        |residual| {
            factor.solve(residual).map_err(|error| {
                spral_error_attempt(
                    regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    error,
                )
            })
        },
    )?;
    profiling.linear_backsolves += 1;
    profiling.linear_backsolve_time += solve_time;
    let assessment =
        assess_linear_solution_ccs(&workspace.pattern.ccs, &workspace.values, rhs, &solution);
    assessment
        .map(|assessment| {
            (
                solution,
                LinearBackendRunStats {
                    solver: InteriorPointLinearSolver::SsidsRs,
                    factorization_time,
                    solve_time,
                    reused_symbolic: Some(reused_symbolic),
                    inertia: Some(interior_point_linear_inertia(actual_inertia)),
                    residual_inf: assessment.residual_inf,
                    solution_inf: assessment.solution_inf,
                    detail: (refinement_steps > 0)
                        .then(|| format!("iterative_refinement_steps={refinement_steps}")),
                },
            )
        })
        .map_err(|mut attempt| {
            attempt.solver = InteriorPointLinearSolver::SsidsRs;
            attempt.regularization = regularization;
            attempt
        })
}

fn factor_solve_spral_src(
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    rhs: &[f64],
    regularization: f64,
    context: IpoptLinearSolveContext,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
) -> std::result::Result<
    (
        SpralSrcFullSpaceSolution,
        Option<IpoptLinearSolveTrace>,
        LinearBackendRunStats,
    ),
    InteriorPointLinearSolveAttempt,
> {
    let matrix = SpralSymmetricCscMatrix::new(
        workspace.pattern.dimension(),
        &workspace.pattern.ccs.col_ptrs,
        &workspace.pattern.ccs.row_indices,
        Some(&workspace.values),
    )
    .map_err(|error| {
        native_spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;

    let value_dependent_analysis = matches!(workspace.ordering, SpralNativeOrdering::Matching);
    let mut reused_symbolic =
        workspace.factor_regularization.is_some() && !value_dependent_analysis;
    if value_dependent_analysis || workspace.session.is_none() {
        let analyse_started = Instant::now();
        profiling.sparse_symbolic_analyses += 1;
        workspace.session = Some(
            workspace
                .native
                // IpSpralSolverInterface.cpp exposes SPRAL through the ptr32
                // one-based compressed sparse path. Keep NLIP's source-built
                // SPRAL parity lane on the same analyse/factor entrypoints.
                .analyse_ipopt_compatible_with_options_and_ordering(
                    matrix,
                    &workspace.numeric_options,
                    workspace.ordering,
                )
                .map_err(|error| {
                    native_spral_error_attempt(
                        regularization,
                        InteriorPointLinearSolveFailureKind::FactorizationFailed,
                        format!("native SPRAL analyse failed: {error}"),
                    )
                })?,
        );
        profiling.sparse_symbolic_analysis_time += analyse_started.elapsed();
        workspace.factor_regularization = None;
        reused_symbolic = false;
    }

    let mut factorization_time = Duration::ZERO;
    let session = workspace
        .session
        .as_mut()
        .expect("native SPRAL session must exist after analysis");
    let factor_started = Instant::now();
    let factor_info = if reused_symbolic {
        profiling.sparse_numeric_refactorizations += 1;
        session.refactorize(matrix).map_err(|error| {
            native_spral_error_attempt(
                regularization,
                InteriorPointLinearSolveFailureKind::FactorizationFailed,
                error,
            )
        })?
    } else {
        profiling.sparse_numeric_factorizations += 1;
        if verbose {
            println!(
                "[NLIP][Native-SPRAL] Starting numeric factorization: dim={} nnz={} reg={:.3e}",
                workspace.pattern.dimension(),
                workspace.pattern.ccs.nnz(),
                regularization,
            );
        }
        session.factorize(matrix).map_err(|error| {
            native_spral_error_attempt(
                regularization,
                InteriorPointLinearSolveFailureKind::FactorizationFailed,
                error,
            )
        })?
    };
    factorization_time += factor_started.elapsed();
    if reused_symbolic {
        profiling.sparse_numeric_refactorization_time += factorization_time;
    } else {
        profiling.sparse_numeric_factorization_time += factorization_time;
    }
    workspace.factor_regularization = Some(regularization);

    let expected_inertia = spral_expected_augmented_inertia(&workspace.pattern);
    let inertia_matches = factor_info.inertia == expected_inertia;
    if !inertia_matches && system.negative_curvature_test_tolerance == 0.0 {
        return Err(InteriorPointLinearSolveAttempt {
            solver: InteriorPointLinearSolver::SpralSrc,
            regularization,
            inertia: Some(Box::new(interior_point_linear_inertia(factor_info.inertia))),
            failure_kind: InteriorPointLinearSolveFailureKind::InertiaMismatch,
            detail: Some(inertia_mismatch_detail(
                expected_inertia,
                factor_info.inertia,
            )),
            solution_inf: None,
            solution_inf_limit: None,
            residual_inf: None,
            residual_inf_limit: None,
        });
    }

    let solve_started = Instant::now();
    let session = workspace
        .session
        .as_ref()
        .expect("native SPRAL session must exist after factorization");
    // IPOPT's SpralSolverInterface::MultiSolve calls spral_ssids_solve with
    // nrhs=1 even for a single right-hand side. Keep the live SpralSrc KKT path
    // on the same C entrypoint instead of spral_ssids_solve1.
    let solution = session.solve_ipopt_single_rhs(rhs).map_err(|error| {
        native_spral_error_attempt(
            regularization,
            InteriorPointLinearSolveFailureKind::FactorizationFailed,
            error,
        )
    })?;
    let solution_prefinal_unrefined = context.capture_trace.then(|| solution.clone());
    let pre_refinement_solution_fingerprint = vector_fingerprint(&solution);
    let pre_refinement_solution_block_fingerprints =
        ipopt_augmented_block_fingerprints(&workspace.pattern, &solution);
    let (lower_bound_multiplier_step, upper_bound_multiplier_step) = system.bound_data.map_or_else(
        || (Vec::new(), Vec::new()),
        |bound_data| {
            ipopt_bound_multiplier_steps_for_orientation(
                system,
                bound_data,
                &solution[..system.hessian.lower_triangle.nrow],
                context.rhs_orientation,
            )
        },
    );
    let upper_slack_multiplier_step = ipopt_upper_slack_bound_multiplier_steps_for_orientation(
        system,
        &solution[workspace.pattern.p_offset..workspace.pattern.p_offset + system.r_cent.len()],
        context.rhs_orientation,
    );
    let mut full_space_solution = SpralSrcFullSpaceSolution {
        augmented_solution: solution,
        lower_bound_multiplier_step,
        upper_bound_multiplier_step,
        upper_slack_multiplier_step,
    };
    let mut solve_time = solve_started.elapsed();
    if !inertia_matches && system.negative_curvature_test_tolerance > 0.0 {
        let slack_sigma = system
            .multipliers
            .iter()
            .zip(system.slack.iter())
            .map(|(&multiplier, &slack)| multiplier / slack)
            .collect::<Vec<_>>();
        let curvature = ipopt_negative_curvature_test(IpoptNegativeCurvatureTestInputs {
            hessian: system.hessian,
            bound_diagonal: system.bound_diagonal,
            slack_sigma: &slack_sigma,
            x_direction: &full_space_solution.augmented_solution
                [..system.hessian.lower_triangle.nrow],
            slack_direction: &full_space_solution.augmented_solution
                [workspace.pattern.p_offset..workspace.pattern.p_offset + system.r_cent.len()],
            shifts: context.shifts,
            include_regularization: system.negative_curvature_test_regularized,
            tolerance: system.negative_curvature_test_tolerance,
        });
        if !curvature.sufficiently_positive {
            profiling.linear_backsolves += 1;
            profiling.linear_backsolve_time += solve_time;
            return Err(InteriorPointLinearSolveAttempt {
                solver: InteriorPointLinearSolver::SpralSrc,
                regularization,
                inertia: Some(Box::new(interior_point_linear_inertia(factor_info.inertia))),
                failure_kind: InteriorPointLinearSolveFailureKind::InertiaMismatch,
                detail: Some(format!(
                    "inertia_free_curvature_test_failed; {}; xWx={:.3e} threshold={:.3e} xs_norm_sq={:.3e}",
                    inertia_mismatch_detail(expected_inertia, factor_info.inertia),
                    curvature.x_w_x,
                    curvature.threshold,
                    curvature.x_s_norm_squared,
                )),
                solution_inf: Some(step_inf_norm(&full_space_solution.augmented_solution)),
                solution_inf_limit: None,
                residual_inf: None,
                residual_inf_limit: None,
            });
        }
    }
    let refinement = if context.allow_inexact {
        // IpFilterLSAcceptor::TrySecondOrderCorrection calls
        // PDSystemSolver::Solve(..., allow_inexact=true), and
        // IpPDFullSpaceSolver::Solve then exits after SolveOnce without
        // full-space iterative refinement.
        None
    } else {
        Some(refine_ipopt_full_space_solution(
            system,
            &workspace.pattern,
            &mut full_space_solution,
            &context,
            &mut solve_time,
            |residual| {
                session.solve_ipopt_single_rhs(residual).map_err(|error| {
                    native_spral_error_attempt(
                        regularization,
                        InteriorPointLinearSolveFailureKind::FactorizationFailed,
                        error,
                    )
                })
            },
        )?)
    };
    profiling.linear_backsolves += 1;
    profiling.linear_backsolve_time += solve_time;
    let linear_trace = context.capture_trace.then(|| IpoptLinearSolveTrace {
        rhs_prefinal: rhs.to_vec(),
        solution_prefinal_unrefined: solution_prefinal_unrefined
            .expect("captured unrefined solution when trace is enabled"),
        refinement_steps: refinement
            .as_ref()
            .map_or_else(Vec::new, |report| report.trace_steps.clone()),
    });
    let post_refinement_prefinal_solution_fingerprint =
        vector_fingerprint(&full_space_solution.augmented_solution);
    let post_refinement_prefinal_solution_block_fingerprints = ipopt_augmented_block_fingerprints(
        &workspace.pattern,
        &full_space_solution.augmented_solution,
    );
    let native_factor_detail = if context.allow_inexact {
        format!(
            "ipopt_allow_inexact_no_refinement; native_spral_factor[delays={} nfactor={} nflops={} maxfront={} two_by_two={} supernodes={} maxsuper={}]; native_spral_rhs[{}]; native_spral_rhs_blocks[{}]; native_spral_solution_prefinal[{}]; native_spral_solution_prefinal_blocks[{}]",
            factor_info.delayed_pivots,
            factor_info.factor_entries,
            factor_info.flop_count,
            factor_info.max_front_size,
            factor_info.two_by_two_pivots,
            factor_info.supernode_count,
            factor_info.max_supernode_width,
            vector_fingerprint_text(vector_fingerprint(rhs)),
            ipopt_augmented_block_fingerprints_text(ipopt_augmented_block_fingerprints(
                &workspace.pattern,
                rhs,
            )),
            vector_fingerprint_text(pre_refinement_solution_fingerprint),
            ipopt_augmented_block_fingerprints_text(pre_refinement_solution_block_fingerprints),
        )
    } else {
        format!(
            "native_spral_factor[delays={} nfactor={} nflops={} maxfront={} two_by_two={} supernodes={} maxsuper={}]; native_spral_rhs[{}]; native_spral_rhs_blocks[{}]; native_spral_solution_prefinal[{}]; native_spral_solution_prefinal_blocks[{}]; native_spral_solution_prefinal_refined[{}]; native_spral_solution_prefinal_refined_blocks[{}]",
            factor_info.delayed_pivots,
            factor_info.factor_entries,
            factor_info.flop_count,
            factor_info.max_front_size,
            factor_info.two_by_two_pivots,
            factor_info.supernode_count,
            factor_info.max_supernode_width,
            vector_fingerprint_text(vector_fingerprint(rhs)),
            ipopt_augmented_block_fingerprints_text(ipopt_augmented_block_fingerprints(
                &workspace.pattern,
                rhs,
            )),
            vector_fingerprint_text(pre_refinement_solution_fingerprint),
            ipopt_augmented_block_fingerprints_text(pre_refinement_solution_block_fingerprints),
            vector_fingerprint_text(post_refinement_prefinal_solution_fingerprint),
            ipopt_augmented_block_fingerprints_text(
                post_refinement_prefinal_solution_block_fingerprints,
            ),
        )
    };
    let mut detail = refinement
        .as_ref()
        .filter(|refinement| refinement.steps > 0)
        .map(|refinement| {
            let first_correction_rhs = refinement
                .first_correction_rhs
                .map(vector_fingerprint_text)
                .unwrap_or_else(|| "--".to_string());
            let first_correction_rhs_blocks = refinement
                .first_correction_rhs_blocks
                .map(ipopt_augmented_block_fingerprints_text)
                .unwrap_or_else(|| "--".to_string());
            let first_correction_solution = refinement
                .first_correction_solution
                .map(vector_fingerprint_text)
                .unwrap_or_else(|| "--".to_string());
            let first_correction_solution_blocks = refinement
                .first_correction_solution_blocks
                .map(ipopt_augmented_block_fingerprints_text)
                .unwrap_or_else(|| "--".to_string());
            format!(
                "full_space_iterative_refinement_steps={} residual_ratio={:.3e}->{:.3e} residuals=[{}]->[{}] first_correction_rhs[{}] first_correction_rhs_blocks[{}] first_correction_solution[{}] first_correction_solution_blocks[{}]",
                refinement.steps,
                refinement.initial_residual_ratio,
                refinement.residual_ratio,
                ipopt_full_space_residual_metrics_text(refinement.initial_residual),
                ipopt_full_space_residual_metrics_text(refinement.final_residual),
                first_correction_rhs,
                first_correction_rhs_blocks,
                first_correction_solution,
                first_correction_solution_blocks,
            )
        })
        .map_or_else(
            || Some(native_factor_detail.clone()),
            |detail| Some(format!("{detail}; {native_factor_detail}")),
        );
    let mut accepted_after_failed_refinement = false;
    if let Some(refinement) = refinement.as_ref()
        && refinement.failed
    {
        let refinement_options = system.refinement_options();
        // IpPDFullSpaceSolver.cpp retries failed full-space iterative
        // refinement by asking the augmented solver IncreaseQuality() once;
        // if that has already happened, residual_ratio_singular decides
        // whether to accept the current solution or pretend singular.  If the
        // previous solve already used pretend_singular, IPOPT resets the flag
        // and accepts the current solution.
        let refinement_detail = format!(
            "ipopt_full_space_iterative_refinement_failed residual_ratio={:.3e}",
            refinement.residual_ratio
        );
        let failure_decision = ipopt_refinement_failure_decision(
            refinement.residual_ratio,
            refinement_options,
            context.native_spral_quality_was_increased,
            native_spral_quality_can_increase(workspace, system),
            context.pretend_singular_last_time,
        );
        match failure_decision {
            IpoptRefinementFailureDecision::RetryWithHigherQuality => {
                return Err(InteriorPointLinearSolveAttempt {
                    solver: InteriorPointLinearSolver::SpralSrc,
                    regularization,
                    inertia: Some(Box::new(interior_point_linear_inertia(factor_info.inertia))),
                    failure_kind: InteriorPointLinearSolveFailureKind::ResidualTooLarge,
                    detail: Some(format!(
                        "{refinement_detail}; {}",
                        ipopt_refinement_failure_detail(failure_decision)
                    )),
                    solution_inf: Some(
                        full_space_solution
                            .augmented_solution
                            .iter()
                            .fold(0.0_f64, |acc, value| acc.max(value.abs())),
                    ),
                    solution_inf_limit: None,
                    residual_inf: Some(refinement.residual_ratio),
                    residual_inf_limit: Some(refinement_options.residual_ratio_max),
                });
            }
            IpoptRefinementFailureDecision::PretendSingular => {
                return Err(InteriorPointLinearSolveAttempt {
                    solver: InteriorPointLinearSolver::SpralSrc,
                    regularization,
                    inertia: Some(Box::new(interior_point_linear_inertia(factor_info.inertia))),
                    failure_kind: InteriorPointLinearSolveFailureKind::ResidualTooLarge,
                    detail: Some(format!(
                        "{refinement_detail}; {}",
                        ipopt_refinement_failure_detail(failure_decision)
                    )),
                    solution_inf: Some(
                        full_space_solution
                            .augmented_solution
                            .iter()
                            .fold(0.0_f64, |acc, value| acc.max(value.abs())),
                    ),
                    solution_inf_limit: None,
                    residual_inf: Some(refinement.residual_ratio),
                    residual_inf_limit: Some(refinement_options.residual_ratio_singular),
                });
            }
            IpoptRefinementFailureDecision::AcceptCurrentSolution { .. } => {
                let accept_detail = ipopt_refinement_failure_detail(failure_decision);
                detail = Some(match detail.take() {
                    Some(existing) => format!("{existing}; {refinement_detail}; {accept_detail}"),
                    None => format!("{refinement_detail}; {accept_detail}"),
                });
                accepted_after_failed_refinement = true;
            }
        }
    }
    if context.rhs_orientation.applies_final_negation() {
        // IPOPT's PDSearchDirCalc calls PDFullSpaceSolver::Solve(-1., 0., ...)
        // and PDFullSpaceSolver::Solve applies the final scaling only after
        // SolveOnce and full-space iterative refinement have finished.
        for value in &mut full_space_solution.augmented_solution {
            *value = -*value;
        }
        for value in &mut full_space_solution.lower_bound_multiplier_step {
            *value = -*value;
        }
        for value in &mut full_space_solution.upper_bound_multiplier_step {
            *value = -*value;
        }
        for value in &mut full_space_solution.upper_slack_multiplier_step {
            *value = -*value;
        }
    }
    let final_rhs_storage;
    let final_rhs = if context.rhs_orientation.applies_final_negation() {
        final_rhs_storage = rhs.iter().map(|value| -*value).collect::<Vec<_>>();
        final_rhs_storage.as_slice()
    } else {
        rhs
    };
    let assessment = assess_linear_solution_ccs(
        &workspace.pattern.ccs,
        &workspace.values,
        final_rhs,
        &full_space_solution.augmented_solution,
    );
    if context.allow_inexact || accepted_after_failed_refinement {
        // IpPDFullSpaceSolver.cpp accepts this branch directly after the
        // allow_inexact early exit or the residual_ratio_singular check. Keep
        // the generic augmented residual assessment as reporting metadata only.
        let (solution_inf, residual_inf) = match assessment {
            Ok(assessment) => (assessment.solution_inf, assessment.residual_inf),
            Err(attempt) => (
                attempt
                    .solution_inf
                    .unwrap_or_else(|| step_inf_norm(&full_space_solution.augmented_solution)),
                attempt.residual_inf.unwrap_or(f64::NAN),
            ),
        };
        return Ok((
            full_space_solution,
            linear_trace,
            LinearBackendRunStats {
                solver: InteriorPointLinearSolver::SpralSrc,
                factorization_time,
                solve_time,
                reused_symbolic: Some(reused_symbolic),
                inertia: Some(interior_point_linear_inertia(factor_info.inertia)),
                residual_inf,
                solution_inf,
                detail,
            },
        ));
    }

    assessment
        .map(|assessment| {
            (
                full_space_solution,
                linear_trace,
                LinearBackendRunStats {
                    solver: InteriorPointLinearSolver::SpralSrc,
                    factorization_time,
                    solve_time,
                    reused_symbolic: Some(reused_symbolic),
                    inertia: Some(interior_point_linear_inertia(factor_info.inertia)),
                    residual_inf: assessment.residual_inf,
                    solution_inf: assessment.solution_inf,
                    detail,
                },
            )
        })
        .map_err(|mut attempt| {
            attempt.solver = InteriorPointLinearSolver::SpralSrc;
            attempt.regularization = regularization;
            attempt
        })
}

fn solve_quality_function_improved_direction_with_spral_src(
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    seed_direction: &NewtonDirection,
    profiling: &mut InteriorPointProfiling,
    capture_trace: bool,
) -> Option<NewtonDirection> {
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let rhs_started = Instant::now();
    let rhs = build_ipopt_augmented_kkt_rhs(
        system,
        &workspace.pattern,
        IpoptLinearRhsOrientation::PreFinal,
    );
    profiling.linear_rhs_assemblies += 1;
    profiling.linear_rhs_assembly_time += rhs_started.elapsed();

    let current_regularization = system.regularization.max(0.0);
    let primal_shift = current_regularization;
    let slack_shift = current_regularization;
    let (dual_shift, _) = ipopt_initial_jacobian_regularization(system);
    let values_started = Instant::now();
    fill_spral_augmented_kkt_values(
        &workspace.pattern,
        &mut workspace.values,
        system,
        primal_shift,
        slack_shift,
        dual_shift,
    );
    profiling.linear_kkt_value_assemblies += 1;
    profiling.linear_kkt_value_assembly_time += values_started.elapsed();

    let session = workspace.session.as_ref()?;
    let mut full_space_solution =
        ipopt_prefinal_full_space_solution_from_final_direction(seed_direction, &workspace.pattern);
    let solution_prefinal_unrefined =
        capture_trace.then(|| full_space_solution.augmented_solution.clone());
    let context = IpoptLinearSolveContext {
        shifts: IpoptLinearRefinementShifts {
            primal: primal_shift,
            slack: slack_shift,
            dual: dual_shift,
        },
        rhs_orientation: IpoptLinearRhsOrientation::PreFinal,
        allow_inexact: false,
        native_spral_quality_was_increased: false,
        pretend_singular_last_time: false,
        capture_trace,
    };
    let mut solve_time = Duration::ZERO;
    let refinement = match refine_ipopt_full_space_solution(
        system,
        &workspace.pattern,
        &mut full_space_solution,
        &context,
        &mut solve_time,
        |residual| {
            session.solve_ipopt_single_rhs(residual).map_err(|error| {
                native_spral_error_attempt(
                    current_regularization,
                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                    error,
                )
            })
        },
    ) {
        Ok(refinement) => refinement,
        Err(_) => return None,
    };
    profiling.linear_backsolves += refinement.steps;
    profiling.linear_backsolve_time += solve_time;
    if refinement.failed {
        return None;
    }

    let linear_trace = capture_trace.then(|| IpoptLinearSolveTrace {
        rhs_prefinal: rhs.clone(),
        solution_prefinal_unrefined: solution_prefinal_unrefined
            .expect("captured unrefined solution when trace is enabled"),
        refinement_steps: refinement.trace_steps.clone(),
    });
    negate_spral_full_space_solution(&mut full_space_solution);
    let final_rhs = rhs.iter().map(|value| -*value).collect::<Vec<_>>();
    let assessment = match assess_linear_solution_ccs(
        &workspace.pattern.ccs,
        &workspace.values,
        &final_rhs,
        &full_space_solution.augmented_solution,
    ) {
        Ok(assessment) => assessment,
        Err(_) => return None,
    };
    let SpralSrcFullSpaceSolution {
        augmented_solution: solution,
        lower_bound_multiplier_step,
        upper_bound_multiplier_step,
        upper_slack_multiplier_step,
    } = full_space_solution;
    let dx = solution[..n].to_vec();
    let ds = solution[workspace.pattern.p_offset..workspace.pattern.p_offset + mineq].to_vec();
    let d_lambda =
        solution[workspace.pattern.lambda_offset..workspace.pattern.lambda_offset + meq].to_vec();
    let d_ineq = solution[workspace.pattern.z_offset..workspace.pattern.z_offset + mineq].to_vec();
    let dz = upper_slack_multiplier_step;
    let detail = Some(format!(
        "ipopt_quality_function_improve_solution_seed; full_space_iterative_refinement_steps={} residual_ratio={:.3e}->{:.3e} residuals=[{}]->[{}]",
        refinement.steps,
        refinement.initial_residual_ratio,
        refinement.residual_ratio,
        ipopt_full_space_residual_metrics_text(refinement.initial_residual),
        ipopt_full_space_residual_metrics_text(refinement.final_residual),
    ));

    Some(NewtonDirection {
        dx,
        d_lambda,
        d_ineq,
        ds,
        dz,
        dz_lower: lower_bound_multiplier_step,
        dz_upper: upper_bound_multiplier_step,
        solver_used: InteriorPointLinearSolver::SpralSrc,
        regularization_used: current_regularization,
        dual_regularization_used: dual_shift,
        primal_diagonal_shift_used: primal_shift,
        linear_solution: solution,
        linear_trace,
        backend_stats: LinearBackendRunStats {
            solver: InteriorPointLinearSolver::SpralSrc,
            factorization_time: Duration::ZERO,
            solve_time,
            reused_symbolic: Some(true),
            inertia: None,
            residual_inf: assessment.residual_inf,
            solution_inf: assessment.solution_inf,
            detail,
        },
        linear_debug: None,
    })
}

fn solve_reduced_kkt_with_spral_src(
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    allow_inexact: bool,
    capture_trace: bool,
) -> std::result::Result<NewtonDirection, Vec<InteriorPointLinearSolveAttempt>> {
    solve_reduced_kkt_with_spral_src_oriented(
        system,
        workspace,
        profiling,
        verbose,
        allow_inexact,
        capture_trace,
        IpoptLinearRhsOrientation::PreFinal,
    )
}

fn solve_reduced_kkt_with_spral_src_oriented(
    system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    allow_inexact: bool,
    capture_trace: bool,
    rhs_orientation: IpoptLinearRhsOrientation,
) -> std::result::Result<NewtonDirection, Vec<InteriorPointLinearSolveAttempt>> {
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let rhs_started = Instant::now();
    let rhs = build_ipopt_augmented_kkt_rhs(system, &workspace.pattern, rhs_orientation);
    profiling.linear_rhs_assemblies += 1;
    profiling.linear_rhs_assembly_time += rhs_started.elapsed();

    let mut attempts: Vec<InteriorPointLinearSolveAttempt> = Vec::new();
    let mut current_regularization = system.regularization.max(0.0);
    let (mut current_jacobian_regularization, jacobian_regularization_already_active) =
        ipopt_initial_jacobian_regularization(system);
    let mut perturbation_test_status = initial_ipopt_perturbation_test_status(
        system.perturb_always_cd,
        jacobian_regularization_already_active,
    );
    let mut quality_retry_detail: Option<String> = None;
    // Mirrors IpPDFullSpaceSolver::augsys_improved_: scoped to this
    // primal-dual system solve, and not reset by perturbation retries because
    // IPOPT's cache dependencies exclude the perturbation shifts.
    let mut solver_quality_improved = false;
    let mut pretend_singular_refinement_last_time = false;
    let max_regularization = system.regularization_max.max(current_regularization);
    let max_retry_count = system.adaptive_regularization_retries + 2;
    for retry_index in 0..=max_retry_count {
        let primal_shift = current_regularization;
        let slack_shift = current_regularization;
        let dual_shift = current_jacobian_regularization;
        let values_started = Instant::now();
        fill_spral_augmented_kkt_values(
            &workspace.pattern,
            &mut workspace.values,
            system,
            primal_shift,
            slack_shift,
            dual_shift,
        );
        profiling.linear_kkt_value_assemblies += 1;
        profiling.linear_kkt_value_assembly_time += values_started.elapsed();
        match factor_solve_spral_src(
            system,
            workspace,
            &rhs,
            current_regularization,
            IpoptLinearSolveContext {
                shifts: IpoptLinearRefinementShifts {
                    primal: primal_shift,
                    slack: slack_shift,
                    dual: dual_shift,
                },
                rhs_orientation,
                allow_inexact,
                native_spral_quality_was_increased: solver_quality_improved,
                pretend_singular_last_time: pretend_singular_refinement_last_time,
                capture_trace,
            },
            profiling,
            verbose,
        ) {
            Ok((solution, linear_trace, mut backend_stats)) => {
                if !attempts.is_empty() {
                    let attempt_detail = attempts
                        .iter()
                        .map(|attempt| {
                            format!(
                                "reg={:.3e}:{}:{}",
                                attempt.regularization,
                                attempt.failure_kind.label(),
                                attempt.detail.as_deref().unwrap_or("--")
                            )
                        })
                        .collect::<Vec<_>>()
                        .join("; ");
                    let detail = match backend_stats.detail.take() {
                        Some(detail) => format!("{detail}; prior_attempts=[{attempt_detail}]"),
                        None => format!("prior_attempts=[{attempt_detail}]"),
                    };
                    backend_stats.detail = Some(match quality_retry_detail.take() {
                        Some(quality_detail) => format!("{detail}; {quality_detail}"),
                        None => detail,
                    });
                } else if let Some(quality_detail) = quality_retry_detail.take() {
                    backend_stats.detail = Some(match backend_stats.detail.take() {
                        Some(detail) => format!("{detail}; {quality_detail}"),
                        None => quality_detail,
                    });
                }
                let SpralSrcFullSpaceSolution {
                    augmented_solution: solution,
                    lower_bound_multiplier_step,
                    upper_bound_multiplier_step,
                    upper_slack_multiplier_step,
                } = solution;
                let dx = solution[..n].to_vec();
                let ipopt_ds = solution
                    [workspace.pattern.p_offset..workspace.pattern.p_offset + mineq]
                    .to_vec();
                let ds = ipopt_ds;
                let d_lambda = solution
                    [workspace.pattern.lambda_offset..workspace.pattern.lambda_offset + meq]
                    .to_vec();
                let d_ineq = solution
                    [workspace.pattern.z_offset..workspace.pattern.z_offset + mineq]
                    .to_vec();
                let dz = upper_slack_multiplier_step;
                return Ok(NewtonDirection {
                    dx,
                    d_lambda,
                    d_ineq,
                    ds,
                    dz,
                    dz_lower: lower_bound_multiplier_step,
                    dz_upper: upper_bound_multiplier_step,
                    solver_used: InteriorPointLinearSolver::SpralSrc,
                    regularization_used: current_regularization,
                    dual_regularization_used: current_jacobian_regularization,
                    primal_diagonal_shift_used: primal_shift,
                    linear_solution: solution,
                    linear_trace,
                    backend_stats,
                    linear_debug: None,
                });
            }
            Err(attempt) => {
                let singularity_like_failure = is_singularity_like_linear_failure(&attempt);
                let too_few_negative_eigenvalues = is_negative_eigenvalues_too_few(&attempt);
                let full_space_refinement_quality_retry = attempt.failure_kind
                    == InteriorPointLinearSolveFailureKind::ResidualTooLarge
                    && attempt
                        .detail
                        .as_deref()
                        .is_some_and(|detail| detail.contains("spral_quality_retry_requested"));
                let full_space_refinement_pretend_singular = attempt.failure_kind
                    == InteriorPointLinearSolveFailureKind::ResidualTooLarge
                    && attempt.detail.as_deref().is_some_and(|detail| {
                        detail.contains("ipopt_pretend_singular_after_refinement_failure")
                    });
                attempts.push(attempt);
                if (too_few_negative_eigenvalues || full_space_refinement_quality_retry)
                    && !solver_quality_improved
                    && let Some((old_u, new_u)) =
                        try_increase_native_spral_quality(workspace, system)
                {
                    solver_quality_improved = true;
                    let quality_detail = format!("spral_quality_retry=u:{old_u:.3e}->{new_u:.3e}");
                    if let Some(last_attempt) = attempts.last_mut() {
                        append_attempt_detail(last_attempt, quality_detail.clone());
                    }
                    quality_retry_detail = Some(quality_detail);
                    continue;
                }
                if full_space_refinement_pretend_singular {
                    pretend_singular_refinement_last_time = true;
                }
                if singularity_like_failure && meq + mineq > 0 {
                    if let Some(next_perturbation) = ipopt_perturb_for_singularity(
                        current_regularization,
                        current_jacobian_regularization,
                        perturbation_test_status,
                        ipopt_perturbation_retry_config(system, max_regularization),
                    ) {
                        current_regularization = next_perturbation.regularization;
                        current_jacobian_regularization = next_perturbation.jacobian_regularization;
                        perturbation_test_status = next_perturbation.test_status;
                        continue;
                    }
                    break;
                }
            }
        }
        if retry_index == max_retry_count || current_regularization >= max_regularization {
            break;
        }
        let Some(next_perturbation) = ipopt_perturb_for_wrong_inertia(
            current_regularization,
            current_jacobian_regularization,
            perturbation_test_status,
            meq + mineq > 0,
            ipopt_perturbation_retry_config(system, max_regularization),
        ) else {
            break;
        };
        current_regularization = next_perturbation.regularization;
        current_jacobian_regularization = next_perturbation.jacobian_regularization;
        perturbation_test_status = next_perturbation.test_status;
    }
    Err(attempts)
}

fn negate_spral_full_space_solution(solution: &mut SpralSrcFullSpaceSolution) {
    for value in &mut solution.augmented_solution {
        *value = -*value;
    }
    for value in &mut solution.lower_bound_multiplier_step {
        *value = -*value;
    }
    for value in &mut solution.upper_bound_multiplier_step {
        *value = -*value;
    }
    for value in &mut solution.upper_slack_multiplier_step {
        *value = -*value;
    }
}

fn spral_refinement_failure_attempt(
    regularization: f64,
    inertia: Option<InteriorPointLinearInertia>,
    refinement: &IpoptRefinementReport,
    detail_suffix: &str,
    residual_limit: f64,
) -> InteriorPointLinearSolveAttempt {
    InteriorPointLinearSolveAttempt {
        solver: InteriorPointLinearSolver::SpralSrc,
        regularization,
        inertia: inertia.map(Box::new),
        failure_kind: InteriorPointLinearSolveFailureKind::ResidualTooLarge,
        detail: Some(format!(
            "ipopt_full_space_iterative_refinement_failed residual_ratio={:.3e}; {detail_suffix}",
            refinement.residual_ratio
        )),
        solution_inf: Some(refinement.final_residual.solution_inf),
        solution_inf_limit: None,
        residual_inf: Some(refinement.residual_ratio),
        residual_inf_limit: Some(residual_limit),
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "Restoration reduced KKT solve mirrors IPOPT call inputs and diagnostic context."
)]
fn solve_restoration_reduced_kkt_with_spral_src(
    full_system: &ReducedKktSystem<'_>,
    restoration_reduced_kkt: &RestorationReducedKktSystem,
    reduced_system: &ReducedKktSystem<'_>,
    workspace: &mut NativeSpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    capture_trace: bool,
    debug_dump_dir: Option<&std::path::Path>,
    iteration: Index,
    phase: InteriorPointIterationPhase,
) -> std::result::Result<NewtonDirection, InteriorPointSolveError> {
    let full_pattern = build_spral_augmented_kkt_pattern(
        full_system.hessian.lower_triangle.as_ref(),
        full_system.equality_jacobian.structure.as_ref(),
        full_system.inequality_jacobian.structure.as_ref(),
    )?;
    let full_n = full_system.hessian.lower_triangle.nrow;
    let full_meq = full_system.equality_jacobian.nrows();
    let full_mineq = full_system.inequality_jacobian.nrows();
    let rhs_started = Instant::now();
    let full_rhs = build_ipopt_augmented_kkt_rhs(
        full_system,
        &full_pattern,
        IpoptLinearRhsOrientation::PreFinal,
    );
    let initial_reduced_rhs = restoration_reduced_kkt.reduce_augmented_rhs(
        &full_pattern,
        &workspace.pattern,
        &full_rhs,
    )?;
    profiling.linear_rhs_assemblies += 1;
    profiling.linear_rhs_assembly_time += rhs_started.elapsed();

    let mut attempts: Vec<InteriorPointLinearSolveAttempt> = Vec::new();
    let mut current_regularization = reduced_system.regularization.max(0.0);
    let (mut current_jacobian_regularization, jacobian_regularization_already_active) =
        ipopt_initial_jacobian_regularization(reduced_system);
    let mut perturbation_test_status = initial_ipopt_perturbation_test_status(
        reduced_system.perturb_always_cd,
        jacobian_regularization_already_active,
    );
    let mut quality_retry_detail: Option<String> = None;
    let mut solver_quality_improved = false;
    let max_regularization = reduced_system
        .regularization_max
        .max(current_regularization);
    let max_retry_count = reduced_system.adaptive_regularization_retries + 2;
    let mut pretend_singular_refinement_last_time = false;

    for retry_index in 0..=max_retry_count {
        let primal_shift = current_regularization;
        let slack_shift = current_regularization;
        let dual_shift = current_jacobian_regularization;
        let values_started = Instant::now();
        fill_spral_augmented_kkt_values(
            &workspace.pattern,
            &mut workspace.values,
            reduced_system,
            primal_shift,
            slack_shift,
            dual_shift,
        );
        profiling.linear_kkt_value_assemblies += 1;
        profiling.linear_kkt_value_assembly_time += values_started.elapsed();

        match factor_solve_spral_src(
            reduced_system,
            workspace,
            &initial_reduced_rhs.augmented_rhs,
            current_regularization,
            IpoptLinearSolveContext {
                shifts: IpoptLinearRefinementShifts {
                    primal: primal_shift,
                    slack: slack_shift,
                    dual: dual_shift,
                },
                // This is the inner IpAugRestoSystemSolver solve.  It receives
                // an already oriented augmented RHS from PDFullSpaceSolver and
                // returns the same orientation; the outer full-space solver
                // applies final PDSearchDirCalc scaling after refinement.
                rhs_orientation: IpoptLinearRhsOrientation::FinalDirection,
                allow_inexact: true,
                native_spral_quality_was_increased: solver_quality_improved,
                pretend_singular_last_time: false,
                capture_trace: false,
            },
            profiling,
            verbose,
        ) {
            Ok((reduced_solution, _, mut backend_stats)) => {
                let inner_solution_prefinal_unrefined = reduced_solution.augmented_solution.clone();
                let solution_prefinal_unrefined = restoration_reduced_kkt
                    .expand_prefinal_augmented_vector(
                        &workspace.pattern,
                        &full_pattern,
                        &reduced_solution.augmented_solution,
                        &initial_reduced_rhs,
                    );
                let mut full_space_solution = restoration_reduced_kkt
                    .expand_prefinal_full_space_solution(
                        &workspace.pattern,
                        full_system,
                        &full_pattern,
                        &reduced_solution.augmented_solution,
                        &initial_reduced_rhs,
                    );
                let mut refinement_solve_time = Duration::ZERO;
                let refinement_context = IpoptLinearSolveContext {
                    shifts: IpoptLinearRefinementShifts {
                        primal: primal_shift,
                        slack: slack_shift,
                        dual: dual_shift,
                    },
                    rhs_orientation: IpoptLinearRhsOrientation::PreFinal,
                    allow_inexact: false,
                    native_spral_quality_was_increased: solver_quality_improved,
                    pretend_singular_last_time: pretend_singular_refinement_last_time,
                    capture_trace,
                };
                let mut inner_refinement_corrections = Vec::new();
                let refinement = refine_ipopt_full_space_solution(
                    full_system,
                    &full_pattern,
                    &mut full_space_solution,
                    &refinement_context,
                    &mut refinement_solve_time,
                    |full_correction_rhs| {
                        let reduced_correction_rhs = restoration_reduced_kkt
                            .reduce_augmented_rhs(
                                &full_pattern,
                                &workspace.pattern,
                                full_correction_rhs,
                            )
                            .map_err(|error| {
                                native_spral_error_attempt(
                                    current_regularization,
                                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                                    error,
                                )
                            })?;
                        let session = workspace.session.as_ref().ok_or_else(|| {
                            native_spral_error_attempt(
                                current_regularization,
                                InteriorPointLinearSolveFailureKind::FactorizationFailed,
                                "native SPRAL session missing during restoration refinement",
                            )
                        })?;
                        let reduced_correction = session
                            .solve_ipopt_single_rhs(&reduced_correction_rhs.augmented_rhs)
                            .map_err(|error| {
                                native_spral_error_attempt(
                                    current_regularization,
                                    InteriorPointLinearSolveFailureKind::FactorizationFailed,
                                    error,
                                )
                            })?;
                        if capture_trace {
                            inner_refinement_corrections.push((
                                reduced_correction_rhs.augmented_rhs.clone(),
                                reduced_correction.clone(),
                            ));
                        }
                        Ok(restoration_reduced_kkt.expand_prefinal_augmented_vector(
                            &workspace.pattern,
                            &full_pattern,
                            &reduced_correction,
                            &reduced_correction_rhs,
                        ))
                    },
                )
                .map_err(|attempt| {
                    linear_solve_error(
                        InteriorPointLinearSolver::SpralSrc,
                        full_pattern.dimension(),
                        vec![attempt],
                    )
                })?;
                dump_restoration_inner_linear_debug_snapshot(
                    debug_dump_dir,
                    iteration,
                    phase,
                    restoration_reduced_kkt,
                    &initial_reduced_rhs,
                    reduced_system,
                    &workspace.values,
                    &initial_reduced_rhs.augmented_rhs,
                    &inner_solution_prefinal_unrefined,
                    &inner_refinement_corrections,
                    &refinement.trace_steps,
                    primal_shift,
                    dual_shift,
                    &backend_stats,
                );
                backend_stats.solve_time += refinement_solve_time;
                profiling.linear_backsolve_time += refinement_solve_time;

                let mut detail = Some(format!(
                    "aug_resto_full_space_iterative_refinement_steps={} residual_ratio={:.3e}->{:.3e} residuals=[{}]->[{}]",
                    refinement.steps,
                    refinement.initial_residual_ratio,
                    refinement.residual_ratio,
                    ipopt_full_space_residual_metrics_text(refinement.initial_residual),
                    ipopt_full_space_residual_metrics_text(refinement.final_residual),
                ));
                if let Some(inner_detail) = backend_stats.detail.take() {
                    detail = Some(format!(
                        "{}; aug_resto_inner=[{}]",
                        detail.expect("restoration refinement detail"),
                        inner_detail
                    ));
                }
                if !attempts.is_empty() {
                    let attempt_detail = attempts
                        .iter()
                        .map(|attempt| {
                            format!(
                                "reg={:.3e}:{}:{}",
                                attempt.regularization,
                                attempt.failure_kind.label(),
                                attempt.detail.as_deref().unwrap_or("--")
                            )
                        })
                        .collect::<Vec<_>>()
                        .join("; ");
                    detail = Some(format!(
                        "{}; prior_attempts=[{}]",
                        detail.expect("restoration refinement detail"),
                        attempt_detail
                    ));
                }
                if let Some(quality_detail) = quality_retry_detail.take() {
                    detail = Some(format!(
                        "{}; {}",
                        detail.expect("restoration refinement detail"),
                        quality_detail
                    ));
                }

                if refinement.failed {
                    let refinement_options = full_system.refinement_options();
                    let failure_decision = ipopt_refinement_failure_decision(
                        refinement.residual_ratio,
                        refinement_options,
                        solver_quality_improved,
                        native_spral_quality_can_increase(workspace, reduced_system),
                        pretend_singular_refinement_last_time,
                    );
                    match failure_decision {
                        IpoptRefinementFailureDecision::RetryWithHigherQuality => {
                            let mut attempt = spral_refinement_failure_attempt(
                                current_regularization,
                                backend_stats.inertia,
                                &refinement,
                                ipopt_refinement_failure_detail(failure_decision),
                                refinement_options.residual_ratio_max,
                            );
                            if let Some((old_u, new_u)) =
                                try_increase_native_spral_quality(workspace, reduced_system)
                            {
                                solver_quality_improved = true;
                                let quality_detail =
                                    format!("spral_quality_retry=u:{old_u:.3e}->{new_u:.3e}");
                                append_attempt_detail(&mut attempt, quality_detail.clone());
                                quality_retry_detail = Some(quality_detail);
                                attempts.push(attempt);
                                continue;
                            }
                        }
                        IpoptRefinementFailureDecision::PretendSingular => {
                            attempts.push(spral_refinement_failure_attempt(
                                current_regularization,
                                backend_stats.inertia,
                                &refinement,
                                ipopt_refinement_failure_detail(failure_decision),
                                refinement_options.residual_ratio_singular,
                            ));
                            pretend_singular_refinement_last_time = true;
                            if full_meq + full_mineq > 0 {
                                if let Some(next_perturbation) = ipopt_perturb_for_singularity(
                                    current_regularization,
                                    current_jacobian_regularization,
                                    perturbation_test_status,
                                    ipopt_perturbation_retry_config(
                                        reduced_system,
                                        max_regularization,
                                    ),
                                ) {
                                    current_regularization = next_perturbation.regularization;
                                    current_jacobian_regularization =
                                        next_perturbation.jacobian_regularization;
                                    perturbation_test_status = next_perturbation.test_status;
                                    continue;
                                }
                                break;
                            }
                            if retry_index == max_retry_count
                                || current_regularization >= max_regularization
                            {
                                break;
                            }
                            let Some(next_perturbation) = ipopt_perturb_for_wrong_inertia(
                                current_regularization,
                                current_jacobian_regularization,
                                perturbation_test_status,
                                full_meq + full_mineq > 0,
                                ipopt_perturbation_retry_config(reduced_system, max_regularization),
                            ) else {
                                break;
                            };
                            current_regularization = next_perturbation.regularization;
                            current_jacobian_regularization =
                                next_perturbation.jacobian_regularization;
                            perturbation_test_status = next_perturbation.test_status;
                            continue;
                        }
                        IpoptRefinementFailureDecision::AcceptCurrentSolution { .. } => {
                            let accept_detail = ipopt_refinement_failure_detail(failure_decision);
                            detail = Some(format!(
                                "{}; ipopt_full_space_iterative_refinement_failed residual_ratio={:.3e}; {accept_detail}",
                                detail.expect("restoration refinement detail"),
                                refinement.residual_ratio
                            ));
                        }
                    }
                }

                let linear_trace = capture_trace.then(|| IpoptLinearSolveTrace {
                    rhs_prefinal: full_rhs.clone(),
                    solution_prefinal_unrefined,
                    refinement_steps: refinement.trace_steps.clone(),
                });
                negate_spral_full_space_solution(&mut full_space_solution);
                let SpralSrcFullSpaceSolution {
                    augmented_solution: solution,
                    lower_bound_multiplier_step,
                    upper_bound_multiplier_step,
                    upper_slack_multiplier_step,
                } = full_space_solution;
                backend_stats.residual_inf = refinement.final_residual.residual_inf;
                backend_stats.solution_inf = refinement.final_residual.solution_inf;
                backend_stats.detail = detail;
                let dx = solution[..full_n].to_vec();
                let ds =
                    solution[full_pattern.p_offset..full_pattern.p_offset + full_mineq].to_vec();
                let d_lambda = solution
                    [full_pattern.lambda_offset..full_pattern.lambda_offset + full_meq]
                    .to_vec();
                let d_ineq =
                    solution[full_pattern.z_offset..full_pattern.z_offset + full_mineq].to_vec();
                let dz = upper_slack_multiplier_step;
                return Ok(NewtonDirection {
                    dx,
                    d_lambda,
                    d_ineq,
                    ds,
                    dz,
                    dz_lower: lower_bound_multiplier_step,
                    dz_upper: upper_bound_multiplier_step,
                    solver_used: InteriorPointLinearSolver::SpralSrc,
                    regularization_used: current_regularization,
                    dual_regularization_used: current_jacobian_regularization,
                    primal_diagonal_shift_used: primal_shift,
                    linear_solution: solution,
                    linear_trace,
                    backend_stats,
                    linear_debug: None,
                });
            }
            Err(attempt) => {
                let singularity_like_failure = is_singularity_like_linear_failure(&attempt);
                let too_few_negative_eigenvalues = is_negative_eigenvalues_too_few(&attempt);
                attempts.push(attempt);
                if too_few_negative_eigenvalues
                    && !solver_quality_improved
                    && let Some((old_u, new_u)) =
                        try_increase_native_spral_quality(workspace, reduced_system)
                {
                    solver_quality_improved = true;
                    let quality_detail = format!("spral_quality_retry=u:{old_u:.3e}->{new_u:.3e}");
                    if let Some(last_attempt) = attempts.last_mut() {
                        append_attempt_detail(last_attempt, quality_detail.clone());
                    }
                    quality_retry_detail = Some(quality_detail);
                    continue;
                }
                if singularity_like_failure && full_meq + full_mineq > 0 {
                    if let Some(next_perturbation) = ipopt_perturb_for_singularity(
                        current_regularization,
                        current_jacobian_regularization,
                        perturbation_test_status,
                        ipopt_perturbation_retry_config(reduced_system, max_regularization),
                    ) {
                        current_regularization = next_perturbation.regularization;
                        current_jacobian_regularization = next_perturbation.jacobian_regularization;
                        perturbation_test_status = next_perturbation.test_status;
                        continue;
                    }
                    break;
                }
            }
        }

        if retry_index == max_retry_count || current_regularization >= max_regularization {
            break;
        }
        let Some(next_perturbation) = ipopt_perturb_for_wrong_inertia(
            current_regularization,
            current_jacobian_regularization,
            perturbation_test_status,
            full_meq + full_mineq > 0,
            ipopt_perturbation_retry_config(reduced_system, max_regularization),
        ) else {
            break;
        };
        current_regularization = next_perturbation.regularization;
        current_jacobian_regularization = next_perturbation.jacobian_regularization;
        perturbation_test_status = next_perturbation.test_status;
    }

    Err(linear_solve_error(
        InteriorPointLinearSolver::SpralSrc,
        full_pattern.dimension(),
        attempts,
    ))
}

fn solve_reduced_kkt_with_spral_ssids(
    system: &ReducedKktSystem<'_>,
    workspace: &mut SpralAugmentedKktWorkspace,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
) -> std::result::Result<NewtonDirection, Vec<InteriorPointLinearSolveAttempt>> {
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let rhs_started = Instant::now();
    let rhs = build_ipopt_augmented_kkt_rhs(
        system,
        &workspace.pattern,
        IpoptLinearRhsOrientation::FinalDirection,
    );
    profiling.linear_rhs_assemblies += 1;
    profiling.linear_rhs_assembly_time += rhs_started.elapsed();

    let mut attempts = Vec::new();
    let mut current_regularization = if system.forced_jacobian_regularization.is_some() {
        system.regularization.max(0.0)
    } else {
        system.regularization.max(1e-12)
    };
    let max_regularization = system.regularization_max.max(current_regularization);
    for retry_index in 0..=system.adaptive_regularization_retries {
        let primal_shift = sparse_hessian_diagonal_shift(system.hessian, current_regularization);
        let slack_shift = primal_shift;
        let dual_shift = system
            .forced_jacobian_regularization
            .unwrap_or_else(|| current_regularization.max(1e-8));
        let values_started = Instant::now();
        assemble_spral_augmented_kkt_values(
            workspace,
            system,
            primal_shift,
            slack_shift,
            dual_shift,
        );
        profiling.linear_kkt_value_assemblies += 1;
        profiling.linear_kkt_value_assembly_time += values_started.elapsed();
        match factor_solve_spral_ssids(
            system,
            workspace,
            &rhs,
            current_regularization,
            profiling,
            verbose,
        ) {
            Ok((solution, backend_stats)) => {
                let dx = solution[..n].to_vec();
                let ipopt_ds = solution
                    [workspace.pattern.p_offset..workspace.pattern.p_offset + mineq]
                    .to_vec();
                let ds = ipopt_ds;
                let d_lambda = solution
                    [workspace.pattern.lambda_offset..workspace.pattern.lambda_offset + meq]
                    .to_vec();
                let d_ineq = solution
                    [workspace.pattern.z_offset..workspace.pattern.z_offset + mineq]
                    .to_vec();
                let dz = system
                    .r_cent
                    .iter()
                    .zip(system.multipliers.iter())
                    .zip(system.slack.iter())
                    .zip(ds.iter())
                    .map(|(((r_cent_i, z_i), s_i), ds_i)| {
                        ipopt_final_upper_slack_bound_multiplier_step(*s_i, *z_i, *r_cent_i, *ds_i)
                    })
                    .collect::<Vec<_>>();
                return Ok(NewtonDirection {
                    dx,
                    d_lambda,
                    d_ineq,
                    ds,
                    dz,
                    dz_lower: Vec::new(),
                    dz_upper: Vec::new(),
                    solver_used: InteriorPointLinearSolver::SsidsRs,
                    regularization_used: current_regularization.max(primal_shift),
                    dual_regularization_used: dual_shift,
                    primal_diagonal_shift_used: primal_shift,
                    linear_solution: solution,
                    linear_trace: None,
                    backend_stats,
                    linear_debug: None,
                });
            }
            Err(attempt) => {
                attempts.push(attempt);
                workspace.factor = None;
                workspace.factor_regularization = None;
            }
        }
        if retry_index == system.adaptive_regularization_retries
            || current_regularization >= max_regularization
        {
            break;
        }
        let next_regularization = (current_regularization
            * system.regularization_growth_factor.max(1.0))
        .min(max_regularization);
        if next_regularization <= current_regularization {
            break;
        }
        current_regularization = next_regularization;
    }
    Err(attempts)
}

fn solve_reduced_kkt_with_sparse_qdldl(
    system: &ReducedKktSystem<'_>,
) -> std::result::Result<NewtonDirection, Vec<InteriorPointLinearSolveAttempt>> {
    let n = system.hessian.lower_triangle.nrow;
    let meq = system.equality_jacobian.nrows();
    let mineq = system.inequality_jacobian.nrows();
    let mut rows = Vec::new();
    let mut cols = Vec::new();
    let mut values = Vec::new();
    let hessian_shift = if meq == 0 && mineq == 0 {
        system.regularization
    } else {
        sparse_hessian_diagonal_shift(system.hessian, system.regularization)
    };
    let fallback_hessian_shift =
        sparse_hessian_diagonal_shift(system.hessian, system.regularization);
    append_symmetric_hessian_triplets(
        system.hessian,
        hessian_shift,
        &mut rows,
        &mut cols,
        &mut values,
    );
    for (diag, &value) in system.bound_diagonal.iter().enumerate() {
        if value != 0.0 {
            rows.push(diag);
            cols.push(diag);
            values.push(value);
        }
    }
    let mut rhs_top = system
        .r_dual
        .iter()
        .zip(system.bound_rhs.iter())
        .map(|(value, bound_rhs)| -value + bound_rhs)
        .collect::<Vec<_>>();

    if mineq > 0 {
        for row in 0..mineq {
            let scale = system.multipliers[row] / system.slack[row];
            let row_entries = &system.inequality_jacobian.structure.row_entries[row];
            for (offset, &(col_i, index_i)) in row_entries.iter().enumerate() {
                let value_i = system.inequality_jacobian.values[index_i];
                for &(col_j, index_j) in &row_entries[offset..] {
                    rows.push(col_i.min(col_j));
                    cols.push(col_i.max(col_j));
                    values.push(scale * value_i * system.inequality_jacobian.values[index_j]);
                }
            }
        }
        let sz_term = system
            .r_cent
            .iter()
            .zip(system.multipliers.iter())
            .zip(system.r_ineq.iter())
            .zip(system.slack.iter())
            .enumerate()
            .map(|(index, (((r_cent_i, z_i), r_ineq_i), s_i))| {
                (r_cent_i - z_i * r_ineq_i) / s_i
                    - damped_slack_stationarity_residual(system, index)
            })
            .collect::<Vec<_>>();
        sparse_add_transpose_mat_vec(&mut rhs_top, system.inequality_jacobian, &sz_term);
    }

    if meq == 0 {
        let matrix = CscMatrix::new_from_triplets(n, n, rows, cols, values);
        let (solution, backend_stats, regularization_used) =
            match try_solve_symmetric_system_with_metrics(
                InteriorPointLinearSolver::SparseQdldl,
                &matrix,
                &rhs_top,
                system.regularization,
                None,
                system.adaptive_regularization_retries,
                system.regularization_growth_factor,
                system.regularization_max,
            ) {
                Ok(result) => result,
                Err(primary_attempts) if fallback_hessian_shift > hessian_shift * (1.0 + 1e-12) => {
                    let mut fallback_rows = Vec::new();
                    let mut fallback_cols = Vec::new();
                    let mut fallback_values = Vec::new();
                    append_symmetric_hessian_triplets(
                        system.hessian,
                        fallback_hessian_shift,
                        &mut fallback_rows,
                        &mut fallback_cols,
                        &mut fallback_values,
                    );
                    let fallback_matrix = CscMatrix::new_from_triplets(
                        n,
                        n,
                        fallback_rows,
                        fallback_cols,
                        fallback_values,
                    );
                    match try_solve_symmetric_system_with_metrics(
                        InteriorPointLinearSolver::SparseQdldl,
                        &fallback_matrix,
                        &rhs_top,
                        system.regularization,
                        None,
                        system.adaptive_regularization_retries,
                        system.regularization_growth_factor,
                        system.regularization_max,
                    ) {
                        Ok(result) => result,
                        Err(mut fallback_attempts) => {
                            let mut attempts = primary_attempts;
                            attempts.append(&mut fallback_attempts);
                            return Err(attempts);
                        }
                    }
                }
                Err(attempts) => return Err(attempts),
            };
        let dx = solution[..n].to_vec();
        let (ds, d_ineq, dz) = if mineq > 0 {
            let jacobian_dx = sparse_mat_vec(system.inequality_jacobian, &dx);
            let ds = jacobian_dx
                .iter()
                .zip(system.r_ineq.iter())
                .map(|(gdx_i, r_ineq_i)| r_ineq_i + gdx_i)
                .collect::<Vec<_>>();
            let d_ineq = ds
                .iter()
                .zip(system.r_cent.iter())
                .zip(system.multipliers.iter())
                .zip(system.slack.iter())
                .enumerate()
                .map(|(index, (((ds_i, r_cent_i), z_i), s_i))| {
                    (-r_cent_i
                        + s_i * damped_slack_stationarity_residual(system, index)
                        + z_i * ds_i)
                        / s_i
                })
                .collect::<Vec<_>>();
            let dz = d_ineq
                .iter()
                .enumerate()
                .map(|(index, dy_i)| *dy_i - damped_slack_stationarity_residual(system, index))
                .collect::<Vec<_>>();
            (ds, d_ineq, dz)
        } else {
            (Vec::new(), Vec::new(), Vec::new())
        };
        return Ok(NewtonDirection {
            dx,
            d_lambda: Vec::new(),
            d_ineq,
            ds,
            dz,
            dz_lower: Vec::new(),
            dz_upper: Vec::new(),
            solver_used: InteriorPointLinearSolver::SparseQdldl,
            regularization_used,
            dual_regularization_used: regularization_used,
            primal_diagonal_shift_used: regularization_used,
            linear_solution: solution,
            linear_trace: None,
            backend_stats,
            linear_debug: None,
        });
    }

    let mut rhs = vec![0.0; n + meq];
    rhs[..n].copy_from_slice(&rhs_top);
    for row in 0..meq {
        rhs[n + row] = -system.r_eq[row];
    }
    let dsigns = quasidefinite_dsigns(n, meq);
    let equality_rows = (0..meq).collect::<Vec<_>>();
    let base_rows = rows;
    let base_cols = cols;
    let base_values = values;
    let mut attempts = Vec::new();
    let mut current_regularization = system.regularization.max(1e-12);
    let max_regularization = system.regularization_max.max(current_regularization);
    for retry_index in 0..=system.adaptive_regularization_retries {
        let mut attempt_rows = base_rows.clone();
        let mut attempt_cols = base_cols.clone();
        let mut attempt_values = base_values.clone();
        let primal_shift = sparse_hessian_diagonal_shift(system.hessian, current_regularization);
        if primal_shift > hessian_shift * (1.0 + 1e-12) {
            let additional_shift = primal_shift - hessian_shift;
            for diag in 0..n {
                attempt_rows.push(diag);
                attempt_cols.push(diag);
                attempt_values.push(additional_shift);
            }
        }
        append_selected_constraint_block_triplets(
            system.equality_jacobian,
            &equality_rows,
            n,
            &mut attempt_rows,
            &mut attempt_cols,
            &mut attempt_values,
        );
        append_quasidefinite_dual_diagonal(
            n,
            meq,
            current_regularization.max(1e-8),
            &mut attempt_rows,
            &mut attempt_cols,
            &mut attempt_values,
        );
        let matrix = CscMatrix::new_from_triplets(
            n + meq,
            n + meq,
            attempt_rows,
            attempt_cols,
            attempt_values,
        );
        match factor_solve_sparse_qdldl_with_metrics(
            &matrix,
            &rhs,
            current_regularization,
            Some(&dsigns),
        ) {
            Ok((solution, backend_stats)) => {
                let dx = solution[..n].to_vec();
                let d_lambda = solution[n..n + meq].to_vec();
                let (ds, d_ineq, dz) = if mineq > 0 {
                    let jacobian_dx = sparse_mat_vec(system.inequality_jacobian, &dx);
                    let ds = jacobian_dx
                        .iter()
                        .zip(system.r_ineq.iter())
                        .map(|(gdx_i, r_ineq_i)| r_ineq_i + gdx_i)
                        .collect::<Vec<_>>();
                    let d_ineq = ds
                        .iter()
                        .zip(system.r_cent.iter())
                        .zip(system.multipliers.iter())
                        .zip(system.slack.iter())
                        .enumerate()
                        .map(|(index, (((ds_i, r_cent_i), z_i), s_i))| {
                            (-r_cent_i
                                + s_i * damped_slack_stationarity_residual(system, index)
                                + z_i * ds_i)
                                / s_i
                        })
                        .collect::<Vec<_>>();
                    let dz = d_ineq
                        .iter()
                        .enumerate()
                        .map(|(index, dy_i)| {
                            *dy_i - damped_slack_stationarity_residual(system, index)
                        })
                        .collect::<Vec<_>>();
                    (ds, d_ineq, dz)
                } else {
                    (Vec::new(), Vec::new(), Vec::new())
                };
                return Ok(NewtonDirection {
                    dx,
                    d_lambda,
                    d_ineq,
                    ds,
                    dz,
                    dz_lower: Vec::new(),
                    dz_upper: Vec::new(),
                    solver_used: InteriorPointLinearSolver::SparseQdldl,
                    regularization_used: current_regularization.max(primal_shift),
                    dual_regularization_used: current_regularization,
                    primal_diagonal_shift_used: primal_shift,
                    linear_solution: solution,
                    linear_trace: None,
                    backend_stats,
                    linear_debug: None,
                });
            }
            Err(attempt) => attempts.push(attempt),
        }
        if retry_index == system.adaptive_regularization_retries
            || current_regularization >= max_regularization
        {
            break;
        }
        let next_regularization = (current_regularization
            * system.regularization_growth_factor.max(1.0))
        .min(max_regularization);
        if next_regularization <= current_regularization {
            break;
        }
        current_regularization = next_regularization;
    }
    Err(attempts)
}

fn solve_reduced_kkt(
    system: &ReducedKktSystem<'_>,
    spral_workspace: Option<&mut SpralAugmentedKktWorkspace>,
    native_spral_workspace: Option<&mut NativeSpralAugmentedKktWorkspace>,
    profiling: &mut InteriorPointProfiling,
    verbose: bool,
    allow_inexact: bool,
    capture_trace: bool,
) -> std::result::Result<NewtonDirection, InteriorPointSolveError> {
    let preferred_solver = preferred_linear_solver(
        system.solver,
        system.equality_jacobian.nrows(),
        system.inequality_jacobian.nrows(),
    );
    let spral_matrix_dimension = spral_workspace
        .as_ref()
        .map(|workspace| workspace.pattern.dimension());
    let mut attempts = Vec::new();

    if preferred_solver == InteriorPointLinearSolver::SpralSrc
        && let Some(workspace) = native_spral_workspace
    {
        return solve_reduced_kkt_with_spral_src(
            system,
            workspace,
            profiling,
            verbose,
            allow_inexact,
            capture_trace,
        )
        .map_err(|attempts| {
            linear_solve_error(preferred_solver, workspace.pattern.dimension(), attempts)
        });
    }

    if preferred_solver == InteriorPointLinearSolver::SsidsRs
        && let Some(workspace) = spral_workspace
        && !workspace.auto_fallback_disabled
    {
        match solve_reduced_kkt_with_spral_ssids(system, workspace, profiling, verbose) {
            Ok(direction) => return Ok(direction),
            Err(mut spral_attempts) => {
                attempts.append(&mut spral_attempts);
                if secondary_linear_solver(system.solver).is_some() {
                    workspace.auto_fallback_disabled = true;
                } else {
                    return Err(linear_solve_error(
                        preferred_solver,
                        workspace.pattern.dimension(),
                        attempts,
                    ));
                }
            }
        }
    }

    match solve_reduced_kkt_with_sparse_qdldl(system) {
        Ok(direction) => Ok(direction),
        Err(mut qdldl_attempts) => {
            attempts.append(&mut qdldl_attempts);
            let matrix_dimension = if let Some(matrix_dimension) = spral_matrix_dimension {
                matrix_dimension
            } else if system.equality_jacobian.nrows() > 0 {
                system.hessian.lower_triangle.nrow + system.equality_jacobian.nrows()
            } else {
                system.hessian.lower_triangle.nrow
            };
            Err(linear_solve_error(
                preferred_solver,
                matrix_dimension,
                attempts,
            ))
        }
    }
}

fn style_ip_metric(
    text: &str,
    value: f64,
    metric: InteriorPointResidualMetric,
    mode: InteriorPointDisplayMode,
) -> String {
    let (strict_tolerance, acceptable_tolerance) = mode.tolerances(metric);
    if value <= strict_tolerance {
        return style_green_bold(text);
    }
    if let Some(acceptable_tolerance) = acceptable_tolerance {
        if value <= acceptable_tolerance {
            return style_yellow_bold(text);
        }
        return style_red_bold(text);
    }
    style_metric_against_tolerance(text, value, strict_tolerance)
}

fn style_ip_residual_text(
    value: f64,
    metric: InteriorPointResidualMetric,
    mode: InteriorPointDisplayMode,
    applicable: bool,
) -> String {
    if !applicable {
        return "--".to_string();
    }
    let text = sci_text(value);
    style_ip_metric(&text, value, metric, mode)
}

fn style_ip_residual_cell(
    value: f64,
    metric: InteriorPointResidualMetric,
    mode: InteriorPointDisplayMode,
    applicable: bool,
) -> String {
    if !applicable {
        return format!("{:>9}", "--");
    }
    let cell = format!("{:>9}", sci_text(value));
    style_ip_metric(&cell, value, metric, mode)
}

fn fmt_optional_ip_sci(value: Option<f64>) -> String {
    match value {
        Some(value) => format!("{:>9}", sci_text(value)),
        None => format!("{:>9}", "--"),
    }
}

fn fmt_optional_index(value: Option<Index>) -> String {
    match value {
        Some(value) => format!("{value:>5}"),
        None => format!("{:>5}", "--"),
    }
}

fn style_ip_line_search_cell(iterations: Option<Index>) -> String {
    let cell = fmt_optional_index(iterations);
    match iterations {
        Some(iterations) if iterations >= 10 => style_red_bold(&cell),
        Some(iterations) if iterations >= 4 => style_yellow_bold(&cell),
        _ => cell,
    }
}

struct InteriorPointIterationLog {
    iteration: Index,
    phase: InteriorPointIterationPhase,
    flags: InteriorPointIterationLogFlags,
    extra_events: Vec<InteriorPointIterationEvent>,
    display_mode: InteriorPointDisplayMode,
    objective_value: f64,
    barrier_objective: f64,
    equality_inf: f64,
    inequality_inf: f64,
    dual_inf: f64,
    complementarity_inf: f64,
    overall_inf: f64,
    barrier_parameter: f64,
    alpha: Option<f64>,
    alpha_pr: Option<f64>,
    alpha_du: Option<f64>,
    alpha_y: Option<f64>,
    line_search_iterations: Option<Index>,
    regularization_size: Option<f64>,
    step_kind: Option<InteriorPointStepKind>,
    step_tag: Option<char>,
    linear_time_secs: Option<f64>,
}

#[derive(Clone, Copy, Debug, Default)]
struct InteriorPointIterationLogFlags {
    has_equalities: bool,
    has_inequalities: bool,
    filter_accepted: bool,
    soc_attempted: bool,
    soc_used: bool,
    watchdog_active: bool,
    tiny_step: bool,
    iteration_limit_reached: bool,
}

fn nlip_log_snapshot(log: &InteriorPointIterationLog) -> InteriorPointIterationSnapshot {
    let mut snapshot = InteriorPointIterationSnapshot {
        iteration: log.iteration,
        phase: log.phase,
        x: Vec::new(),
        slack_primal: None,
        equality_multipliers: None,
        inequality_multipliers: None,
        slack_multipliers: None,
        lower_bound_multipliers: None,
        upper_bound_multipliers: None,
        kkt_inequality_residual: None,
        kkt_x_stationarity: None,
        kkt_slack_stationarity: None,
        kkt_slack_complementarity: None,
        kkt_slack_sigma: None,
        curr_grad_f: None,
        curr_jac_c_t_y_c: None,
        curr_jac_d_t_y_d: None,
        curr_grad_lag_x: None,
        curr_grad_lag_s: None,
        objective: log.objective_value,
        barrier_objective: Some(log.barrier_objective),
        eq_inf: Some(log.equality_inf),
        ineq_inf: Some(log.inequality_inf),
        dual_inf: log.dual_inf,
        comp_inf: Some(log.complementarity_inf),
        overall_inf: log.overall_inf,
        barrier_primal_inf: None,
        barrier_dual_inf: None,
        barrier_complementarity_inf: None,
        barrier_subproblem_error: None,
        barrier_parameter: Some(log.barrier_parameter),
        filter_theta: Some(log.equality_inf.max(log.inequality_inf)),
        step_inf: None,
        alpha: log.alpha,
        alpha_pr: log.alpha_pr,
        alpha_du: log.alpha_du,
        alpha_y: log.alpha_y,
        line_search_iterations: log.line_search_iterations,
        line_search_trials: log.line_search_iterations.unwrap_or(0),
        regularization_size: log.regularization_size,
        step_kind: log.step_kind,
        step_tag: log.step_tag,
        watchdog_active: log.flags.watchdog_active,
        line_search: None,
        direction_diagnostics: None,
        step_direction: None,
        linear_debug: None,
        linear_solver: InteriorPointLinearSolver::Auto,
        linear_solve_time: log.linear_time_secs.map(Duration::from_secs_f64),
        filter: None,
        events: log.extra_events.clone(),
        timing: InteriorPointIterationTiming::default(),
    };
    if matches!(log.line_search_iterations, Some(iterations) if iterations >= 4) {
        push_unique_nlip_event(
            &mut snapshot.events,
            InteriorPointIterationEvent::LongLineSearch,
        );
    }
    if log.flags.filter_accepted {
        push_unique_nlip_event(
            &mut snapshot.events,
            InteriorPointIterationEvent::FilterAccepted,
        );
    }
    if log.flags.soc_attempted {
        push_unique_nlip_event(
            &mut snapshot.events,
            InteriorPointIterationEvent::SecondOrderCorrectionAttempted,
        );
    }
    if log.flags.soc_used {
        push_unique_nlip_event(
            &mut snapshot.events,
            InteriorPointIterationEvent::SecondOrderCorrectionAccepted,
        );
    }
    if log.flags.watchdog_active {
        push_unique_nlip_event(
            &mut snapshot.events,
            InteriorPointIterationEvent::WatchdogActivated,
        );
    }
    if log.flags.tiny_step {
        push_unique_nlip_event(&mut snapshot.events, InteriorPointIterationEvent::TinyStep);
    }
    if log.flags.iteration_limit_reached {
        push_unique_nlip_event(
            &mut snapshot.events,
            InteriorPointIterationEvent::MaxIterationsReached,
        );
    }
    snapshot
}

fn fmt_ip_event_codes(log: &InteriorPointIterationLog) -> String {
    nlip_event_slot_codes(&nlip_log_snapshot(log))
}

fn style_ip_event_cell(log: &InteriorPointIterationLog) -> String {
    let codes = fmt_ip_event_codes(log);
    if !codes.chars().any(|code| code != ' ') {
        return codes;
    }
    if log.flags.iteration_limit_reached {
        style_red_bold(&codes)
    } else {
        style_yellow_bold(&codes)
    }
}

fn fmt_ip_event_header() -> String {
    format!("{:^width$}", "evt", width = NLIP_EVENT_CELL_WIDTH)
}

fn fmt_ip_event_prefix_cell() -> String {
    format!("{:width$}", "", width = NLIP_EVENT_CELL_WIDTH)
}

fn ip_event_legend_prefix() -> String {
    [format!("{:>4}", ""), fmt_ip_event_prefix_cell()].join("  ")
}

fn fmt_ip_event_header_row() -> String {
    [
        format!("{:>4}", "iter"),
        fmt_ip_event_header(),
        format!("{:>9}", "f"),
        format!("{:>9}", EQ_INF_LABEL),
        format!("{:>9}", INEQ_INF_LABEL),
        format!("{:>9}", DUAL_INF_LABEL),
        format!("{:>9}", IP_COMP_INF_LABEL),
        format!("{:>9}", OVERALL_INF_LABEL),
        format!("{:>9}", "mu"),
        format!("{:>9}", "α"),
        format!("{:>5}", "ls_it"),
        format!("{:>7}", "lin_t"),
    ]
    .join("  ")
}

fn log_interior_point_iteration(
    log: &InteriorPointIterationLog,
    event_state: &mut SqpEventLegendState,
) {
    if log.iteration.is_multiple_of(10) {
        eprintln!();
        eprintln!("{}", style_bold(&fmt_ip_event_header_row()));
    }
    for legend_line in ip_event_legend_lines(log, event_state) {
        eprintln!("{legend_line}");
    }
    let iteration_label = match log.phase {
        InteriorPointIterationPhase::Initial => "pre".to_string(),
        InteriorPointIterationPhase::AcceptedStep => log.iteration.to_string(),
        InteriorPointIterationPhase::Restoration => format!("{}r", log.iteration),
        InteriorPointIterationPhase::Converged => "post".to_string(),
    };
    let row = [
        style_iteration_label_cell(&iteration_label, log.flags.iteration_limit_reached),
        style_ip_event_cell(log),
        format!("{:>9}", sci_text(log.objective_value)),
        style_ip_residual_cell(
            log.equality_inf,
            InteriorPointResidualMetric::Constraint,
            log.display_mode,
            log.flags.has_equalities,
        ),
        style_ip_residual_cell(
            log.inequality_inf,
            InteriorPointResidualMetric::Constraint,
            log.display_mode,
            log.flags.has_inequalities,
        ),
        style_ip_residual_cell(
            log.dual_inf,
            InteriorPointResidualMetric::Dual,
            log.display_mode,
            true,
        ),
        style_ip_residual_cell(
            log.complementarity_inf,
            InteriorPointResidualMetric::Complementarity,
            log.display_mode,
            log.flags.has_inequalities,
        ),
        style_ip_residual_cell(
            log.overall_inf,
            InteriorPointResidualMetric::Overall,
            log.display_mode,
            true,
        ),
        format!("{:>9}", sci_text(log.barrier_parameter)),
        fmt_optional_ip_sci(log.alpha),
        style_ip_line_search_cell(log.line_search_iterations),
        match log.linear_time_secs {
            Some(seconds) => format!("{:>7}", compact_duration_text(seconds)),
            None => format!("{:>7}", "--"),
        },
    ];
    eprintln!("{}", row.join("  "));
}

fn ip_event_legend_lines(
    log: &InteriorPointIterationLog,
    state: &mut SqpEventLegendState,
) -> Vec<String> {
    let mut parts = Vec::new();
    let snapshot = nlip_log_snapshot(log);
    for (code, description) in nlip_event_legend_entries(&snapshot) {
        let is_new = match code {
            'L' => state.mark_line_search_if_new(),
            'F' => state.mark_filter_if_new(),
            'X' => state.mark_filter_reset_if_new(),
            's' => state.mark_soc_attempted_if_new(),
            'S' => state.mark_soc_if_new(),
            'A' => state.mark_watchdog_armed_if_new(),
            'W' => state.mark_watchdog_if_new(),
            'q' => state.mark_linear_solver_quality_if_new(),
            'B' => state.mark_bound_multiplier_safeguard_if_new(),
            'U' => state.mark_barrier_update_if_new(),
            'V' => state.mark_adaptive_regularization_if_new(),
            'T' => state.mark_tiny_step_if_new(),
            'M' => state.mark_max_iter_if_new(),
            _ => false,
        };
        if is_new {
            parts.push(description);
        }
    }

    let prefix = ip_event_legend_prefix();
    parts
        .into_iter()
        .map(|part| format!("{prefix}  {part}"))
        .collect()
}

