    #[test]
    fn ipopt_upper_slack_magic_step_moves_slacks_toward_trial_constraints() {
        let mut slack = vec![0.2, -0.3, -0.8, 0.0];
        let trial_d = vec![0.1, -0.1, -1.2, 0.0];
        let upper_bounds = vec![0.0; slack.len()];

        let changed = apply_ipopt_upper_slack_magic_step(&mut slack, &trial_d, &upper_bounds);

        assert!(changed);
        assert_eq!(slack[0].to_bits(), 0.1_f64.to_bits());
        assert_eq!(slack[1].to_bits(), (-0.3_f64).to_bits());
        assert!((slack[2] + 1.2).abs() <= f64::EPSILON);
        assert_eq!(slack[3].to_bits(), 0.0_f64.to_bits());

        let unchanged = apply_ipopt_upper_slack_magic_step(&mut slack, &trial_d, &upper_bounds);
        assert!(!unchanged);
        assert_eq!(slack[0].to_bits(), 0.1_f64.to_bits());
        assert_eq!(slack[1].to_bits(), (-0.3_f64).to_bits());
        assert!((slack[2] + 1.2).abs() <= f64::EPSILON);
        assert_eq!(slack[3].to_bits(), 0.0_f64.to_bits());
    }

    #[test]
    fn ipopt_safe_slack_uses_source_floor_target_and_move_cap() {
        let slack_move = 1.0e-3;

        let (capped, adjusted) = ipopt_calculate_safe_slack(-1.0e-12, 10.0, 2.0, 0.1, slack_move);
        assert!(adjusted);
        assert_eq!(capped.to_bits(), 0.01_f64.to_bits());

        let zero_mu_floor = ipopt_safe_slack_min(0.0);
        assert_eq!(zero_mu_floor.to_bits(), f64::MIN_POSITIVE.to_bits());
        let (floored, adjusted) =
            ipopt_calculate_safe_slack(0.0, 0.0, f64::INFINITY, 0.0, slack_move);
        assert!(adjusted);
        assert_eq!(floored.to_bits(), zero_mu_floor.to_bits());

        let large_slack = ipopt_safe_slack_min(0.1) * 2.0;
        let (unchanged, adjusted) =
            ipopt_calculate_safe_slack(large_slack, 1.0, 1.0, 0.1, slack_move);
        assert!(!adjusted);
        assert_eq!(unchanged.to_bits(), large_slack.to_bits());
    }

    #[test]
    fn ipopt_safe_slack_adjusts_bounds_like_calculated_quantities() {
        let options = InteriorPointOptions {
            slack_move: 1.0e-3,
            ..InteriorPointOptions::default()
        };
        let bounds = BoundConstraints {
            lower_indices: vec![0],
            lower_values: vec![2.0],
            upper_indices: vec![1],
            upper_values: vec![5.0],
        };
        let trial_x = vec![2.0, 5.0];
        let trial_slack = vec![0.0];
        let slack_upper_bounds = vec![0.0];
        let state = trial_safe_slack_state(TrialSafeSlackInputs {
            trial_x: &trial_x,
            trial_slack: &trial_slack,
            bounds: &bounds,
            slack_upper_bounds: &slack_upper_bounds,
            current_z_lower: &[1.0],
            current_z_upper: &[2.0],
            current_z: &[4.0],
            mu: 0.1,
            slack_move: options.slack_move,
        });

        assert_eq!(state.adjusted_slacks, 3);
        assert!(state.all_strictly_positive());
        assert_eq!(state.lower_slack[0].to_bits(), 0.002_f64.to_bits());
        assert_eq!(state.upper_slack[0].to_bits(), 0.005_f64.to_bits());
        assert_eq!(state.slack_barrier[0].to_bits(), 0.001_f64.to_bits());
        assert_eq!(state.bounds.lower_values[0].to_bits(), 1.998_f64.to_bits());
        assert_eq!(state.bounds.upper_values[0].to_bits(), 5.005_f64.to_bits());
        assert_eq!(state.slack_upper_bounds[0].to_bits(), 0.001_f64.to_bits());
    }

    #[test]
    fn ipopt_order_sparse_matvecs_use_fused_multiply_add() {
        let transpose_ccs = CCS::new(2, 1, vec![0, 2], vec![1, 0]);
        let transpose_matrix = SparseMatrix {
            structure: Arc::new(sparse_structure_from_ccs(&transpose_ccs)),
            values: vec![-1.0, 1.0e308],
        };
        let mut transpose_product = vec![0.0];

        sparse_add_transpose_mat_vec_ipopt_order(
            &mut transpose_product,
            &transpose_matrix,
            &[1.0e-308, 1.0],
        );

        assert_eq!(
            transpose_product[0].to_bits(),
            1.0e308_f64.mul_add(1.0e-308, -1.0).to_bits()
        );
        assert_ne!(
            transpose_product[0].to_bits(),
            ((1.0e308_f64 * 1.0e-308) - 1.0).to_bits()
        );

        let forward_ccs = CCS::new(1, 2, vec![0, 1, 2], vec![0, 0]);
        let forward_matrix = SparseMatrix {
            structure: Arc::new(sparse_structure_from_ccs(&forward_ccs)),
            values: vec![-1.0, 1.0e308],
        };
        let forward_product = sparse_mat_vec_ipopt_order(&forward_matrix, &[1.0, 1.0e-308]);

        assert_eq!(forward_product[0].to_bits(), transpose_product[0].to_bits());
    }

    #[test]
    fn ipopt_order_symmetric_hessian_matvec_uses_fused_multiply_add() {
        let ccs = CCS::new(2, 2, vec![0, 2, 2], vec![0, 1]);
        let values = vec![-1.0, 1.0e308];
        let vector = vec![1.0, 1.0e-308];

        let ipopt_order = symmetric_ccs_lower_mat_vec_ipopt_order(&ccs, &values, &vector);
        let old_order = symmetric_ccs_lower_mat_vec(&ccs, &values, &vector);

        assert_eq!(
            ipopt_order[0].to_bits(),
            1.0e308_f64.mul_add(1.0e-308, -1.0).to_bits()
        );
        assert_ne!(ipopt_order[0].to_bits(), old_order[0].to_bits());
    }

    #[test]
    fn ipopt_order_add_delta_minus_rhs_zero_scale_skips_delta() {
        let mut zero_scale_values = vec![1.0];
        ipopt_add_delta_minus_rhs(&mut zero_scale_values, 0.0, &[f64::INFINITY], &[0.25]);
        assert_eq!(zero_scale_values[0].to_bits(), 0.75_f64.to_bits());
    }

    #[test]
    fn ipopt_order_add_delta_minus_rhs_contracts_multiply_subtract() {
        let mut values = vec![0.5330491410581917];
        let delta = [-0.25905737736536555];
        let rhs = [-0.15777053191611318];
        ipopt_add_delta_minus_rhs(&mut values, 2.6666666666666665, &delta, &rhs);

        let expected = 0.5330491410581917
            + 2.6666666666666665_f64.mul_add(-0.25905737736536555, 0.15777053191611318);
        let separate = 0.5330491410581917
            + (2.6666666666666665_f64 * -0.25905737736536555 + 0.15777053191611318);

        assert_eq!(values[0].to_bits(), expected.to_bits());
        assert_ne!(values[0].to_bits(), separate.to_bits());
    }

    #[test]
    fn ipopt_order_axpy_contracts_multiply_add() {
        let value = -0.5082563016279674;
        let alpha = 2.6666666666666665;
        let delta = 0.19059611311048785;

        let ipopt_order = ipopt_blas_axpy_value(value, alpha, delta);
        let separate = value + alpha * delta;

        assert_eq!(ipopt_order.to_bits(), 1.5682327834694952e-16_f64.to_bits());
        assert_ne!(ipopt_order.to_bits(), separate.to_bits());
        assert_eq!(ipopt_blas_axpy_value(value, 0.0, f64::INFINITY), value);
    }

    #[test]
    fn ipopt_order_bound_residual_contracts_add_two_vectors_term() {
        let slack = 1.0;
        let dz = -7.582200803883872e-13;
        let z = 1.0;
        let dx = -3.346096292797418e-13;
        let rhs_z = 4.4296881516653666e-13;

        let ipopt_order = ipopt_lower_bound_residual_z(slack, dz, z, dx, rhs_z);
        let left_associative = slack * dz + z * dx - rhs_z;

        assert_eq!(
            ipopt_order.to_bits(),
            (-1.5357985248346656e-12_f64).to_bits()
        );
        assert_ne!(ipopt_order.to_bits(), left_associative.to_bits());
    }

    #[test]
    fn bound_multiplier_correction_clamps_complementarity_band() {
        let slack = vec![2.0, 4.0];
        let z = vec![100.0, 1e-6];
        let mu = 1.0;
        let kappa_sigma = 10.0;

        let (corrected_z, max_correction) =
            correct_bound_multiplier_estimate(&z, &slack, mu, kappa_sigma);

        assert!(max_correction > 0.0);
        for (slack_i, z_i) in slack.iter().zip(corrected_z.iter()) {
            let compl = slack_i * z_i;
            assert!(compl <= kappa_sigma * mu + 1e-12);
            assert!(compl >= mu / kappa_sigma - 1e-12);
        }
    }

    #[test]
    fn bound_multiplier_correction_keeps_ipopt_step_order() {
        let mu = 1.7646745086707415e-7;
        let kappa_sigma = 5.918795724267679;
        let slack = vec![0.2958312539029896];
        let z = vec![278.59313097706615];

        let (corrected_z, _) = correct_bound_multiplier_estimate(&z, &slack, mu, kappa_sigma);
        let direct_endpoint = (kappa_sigma * mu) / slack[0];

        assert_eq!(corrected_z[0].to_bits(), 0x3ecd_9dff_f800_0000);
        assert_eq!(direct_endpoint.to_bits(), 0x3ecd_9dff_fa07_9d96);
    }

    #[test]
    fn restoration_bound_multiplier_step_matches_ipopt_formula() {
        let mut expected: f64 = 5.0;
        expected -= 3.0;
        expected *= 2.0;
        expected += 0.1;
        expected /= 5.0;
        expected -= 2.0;

        let step = ipopt_restoration_bound_multiplier_step(2.0, 5.0, 3.0, 0.1);

        assert_eq!(step.to_bits(), expected.to_bits());
    }

    #[test]
    fn restoration_bound_multiplier_update_uses_dual_fraction_and_reset_threshold() {
        let bounds = BoundConstraints {
            lower_indices: vec![0],
            lower_values: vec![0.0],
            upper_indices: vec![1],
            upper_values: vec![10.0],
        };
        let (z_lower, z_upper, z, alpha_dual, reset) = ipopt_restoration_bound_multiplier_update(
            &[2.0, 8.0],
            &[3.0, 7.0],
            &bounds,
            &[4.0],
            &[2.0],
            &[2.0],
            &[3.0],
            &[5.0],
            0.1,
            0.99,
        );
        let expected_dz_lower = ipopt_restoration_bound_multiplier_step(2.0, 2.0, 3.0, 0.1);
        let expected_dz_upper = ipopt_restoration_bound_multiplier_step(3.0, 2.0, 3.0, 0.1);
        let expected_dz = ipopt_restoration_bound_multiplier_step(5.0, 4.0, 2.0, 0.1);
        let expected_alpha = ipopt_dual_fraction_to_boundary_with_limiter(
            &[2.0],
            &[expected_dz_lower],
            &[3.0],
            &[expected_dz_upper],
            &[5.0],
            &[expected_dz],
            0.99,
        )
        .0;

        assert!(!reset);
        assert_eq!(alpha_dual.to_bits(), expected_alpha.to_bits());
        assert_eq!(
            z_lower[0].to_bits(),
            ipopt_dense_current_plus_step(2.0, expected_alpha, expected_dz_lower).to_bits()
        );
        assert_eq!(
            z_upper[0].to_bits(),
            ipopt_dense_current_plus_step(3.0, expected_alpha, expected_dz_upper).to_bits()
        );
        assert_eq!(
            z[0].to_bits(),
            ipopt_dense_current_plus_step(5.0, expected_alpha, expected_dz).to_bits()
        );

        let (_, _, reset_z, _, reset) = ipopt_restoration_bound_multiplier_update(
            &[],
            &[],
            &BoundConstraints::default(),
            &[1.0],
            &[0.5],
            &[],
            &[],
            &[1.5e3],
            1.5e3,
            0.99,
        );
        assert!(reset);
        assert_eq!(reset_z, vec![1.0]);
    }

