    #[test]
    fn wrong_inertia_max_hessian_fallback_matches_ipopt_delta_c_retry() {
        let config = IpoptPerturbationRetryConfig {
            max_regularization: 2.0,
            ..test_perturbation_config(false)
        };

        // IpPDPerturbationHandler::PerturbForWrongInertia retries with
        // delta_c/delta_d and resets delta_x/delta_s when Hessian growth
        // alone exceeds max_hessian_perturbation.
        let retry = ipopt_perturb_for_wrong_inertia(
            1.0,
            0.0,
            IpoptPerturbationTestStatus::NoTest,
            true,
            config,
        )
        .expect("delta-c fallback after max Hessian perturbation");
        assert_perturbation_retry(retry, 1.0e-4, 1.0e-9, IpoptPerturbationTestStatus::NoTest);

        assert!(
            ipopt_perturb_for_wrong_inertia(
                1.0,
                0.0,
                IpoptPerturbationTestStatus::NoTest,
                false,
                config,
            )
            .is_none(),
            "IPOPT only applies the delta-c fallback when constraints are present"
        );
    }

    #[test]
    fn hessian_perturbation_growth_matches_ipopt_max_check() {
        fn assert_close(actual: Option<f64>, expected: f64) {
            let actual = actual.expect("expected a perturbation value");
            assert!(
                (actual - expected).abs() <= expected.abs().max(1.0) * 1.0e-15,
                "actual={actual:.17e} expected={expected:.17e}"
            );
        }

        // IpPDPerturbationHandler::get_deltas_for_wrong_inertia starts with
        // first_hessian_perturbation when there is no current or previous
        // successful perturbation, and then rejects that trial if it exceeds
        // max_hessian_perturbation. The caller must not widen the max to the
        // first trial value.
        assert_close(
            next_ipopt_hessian_perturbation(0.0, None, 1.0e-4, 100.0, 8.0, 1.0 / 3.0, 1.0e-3),
            1.0e-4,
        );
        assert_eq!(
            next_ipopt_hessian_perturbation(0.0, None, 1.0e-4, 100.0, 8.0, 1.0 / 3.0, 1.0e-5),
            None
        );

        // After a successful perturbation on an earlier system, IPOPT decays
        // from that last value for the next fresh matrix. Repeated failures use
        // the special first growth factor only while current is still far above
        // the last successful value; otherwise they use perturb_inc_fact.
        assert_close(
            next_ipopt_hessian_perturbation(0.0, Some(9.0e-3), 1.0e-4, 100.0, 8.0, 1.0 / 3.0, 1.0),
            3.0e-3,
        );
        assert_close(
            next_ipopt_hessian_perturbation(
                2.0e-2,
                Some(1.0e-9),
                1.0e-4,
                100.0,
                8.0,
                1.0 / 3.0,
                10.0,
            ),
            2.0,
        );
        assert_close(
            next_ipopt_hessian_perturbation(
                2.0e-2,
                Some(1.0e-2),
                1.0e-4,
                100.0,
                8.0,
                1.0 / 3.0,
                10.0,
            ),
            1.6e-1,
        );
    }

    #[test]
    fn full_space_refinement_loop_matches_ipopt_option_thresholds() {
        let options = IpoptLinearRefinementOptions {
            min_refinement_steps: 2,
            max_refinement_steps: 3,
            residual_ratio_max: 1.0e-8,
            residual_ratio_singular: 1.0e-5,
            residual_improvement_factor: 0.5,
        };

        // IpPDFullSpaceSolver::Solve refines while either the minimum step count
        // has not been reached or the residual ratio remains above the target.
        assert!(ipopt_refinement_should_continue(0, 0.0, options));
        assert!(ipopt_refinement_should_continue(1, 0.0, options));
        assert!(!ipopt_refinement_should_continue(2, 1.0e-9, options));
        assert!(ipopt_refinement_should_continue(2, 2.0e-8, options));

        // The source uses `num_iter_ref > min_refinement_steps_` and
        // `num_iter_ref > max_refinement_steps_`, so equality with either bound
        // is still allowed to continue.
        assert!(!ipopt_refinement_failed_after_step(
            2, 2.0e-8, 1.0e-7, options
        ));
        assert!(ipopt_refinement_failed_after_step(
            3, 6.0e-8, 1.0e-7, options
        ));
        assert!(!ipopt_refinement_failed_after_step(
            3, 4.0e-8, 1.0e-7, options
        ));
        assert!(ipopt_refinement_failed_after_step(
            4,
            1.0e-8 + f64::EPSILON,
            1.0e-7,
            options
        ));
    }

    #[test]
    fn full_space_refinement_failure_decision_matches_ipopt_branch_order() {
        let options = IpoptLinearRefinementOptions {
            min_refinement_steps: 1,
            max_refinement_steps: 1,
            residual_ratio_max: 1.0e-8,
            residual_ratio_singular: 1.0e-5,
            residual_improvement_factor: 1.0,
        };

        // IpPDFullSpaceSolver first asks the augmented solver to improve
        // quality, if that has not already happened for this system.
        assert_eq!(
            ipopt_refinement_failure_decision(1.0e-3, options, false, true, false),
            IpoptRefinementFailureDecision::RetryWithHigherQuality
        );

        // If quality was already increased, a bad residual asks SolveOnce to
        // pretend the system is singular.
        assert_eq!(
            ipopt_refinement_failure_decision(1.0e-3, options, true, true, false),
            IpoptRefinementFailureDecision::PretendSingular
        );

        // The source accepts a failed refinement when the residual is below
        // residual_ratio_singular_, appending the uppercase S marker.
        assert_eq!(
            ipopt_refinement_failure_decision(1.0e-6, options, true, false, false),
            IpoptRefinementFailureDecision::AcceptCurrentSolution {
                after_pretend_singular_retry: false
            }
        );

        // After one pretend-singular retry, the source resets the flag and
        // accepts the current solution even when the residual remains large.
        assert_eq!(
            ipopt_refinement_failure_decision(1.0e-3, options, true, false, true),
            IpoptRefinementFailureDecision::AcceptCurrentSolution {
                after_pretend_singular_retry: true
            }
        );
    }

    #[test]
    fn full_space_refinement_failure_uses_strict_singular_threshold() {
        let options = IpoptLinearRefinementOptions {
            min_refinement_steps: 1,
            max_refinement_steps: 1,
            residual_ratio_max: 1.0e-8,
            residual_ratio_singular: 1.0e-5,
            residual_improvement_factor: 1.0,
        };

        // IpPDFullSpaceSolver::Solve uses `< residual_ratio_singular_`, not
        // `<=`, when deciding whether to accept the current failed-refinement
        // solution with the uppercase S marker.
        assert_eq!(
            ipopt_refinement_failure_decision(1.0e-5, options, true, false, false),
            IpoptRefinementFailureDecision::PretendSingular
        );
        assert_eq!(
            ipopt_refinement_failure_decision(
                f64::from_bits(1.0e-5_f64.to_bits() - 1),
                options,
                true,
                false,
                false
            ),
            IpoptRefinementFailureDecision::AcceptCurrentSolution {
                after_pretend_singular_retry: false
            }
        );

        // If quality cannot be improved, IPOPT goes directly to the same
        // singular/accept-current split even before any quality retry.
        assert_eq!(
            ipopt_refinement_failure_decision(1.0e-3, options, false, false, false),
            IpoptRefinementFailureDecision::PretendSingular
        );
    }

    #[test]
    fn full_space_refinement_failure_markers_match_ipopt_source() {
        let options = IpoptLinearRefinementOptions {
            min_refinement_steps: 1,
            max_refinement_steps: 1,
            residual_ratio_max: 1.0e-8,
            residual_ratio_singular: 1.0e-5,
            residual_improvement_factor: 1.0,
        };

        let retry_quality = ipopt_refinement_failure_decision(1.0e-3, options, false, true, false);
        let pretend_singular =
            ipopt_refinement_failure_decision(1.0e-3, options, true, true, false);
        let accept_current = ipopt_refinement_failure_decision(1.0e-6, options, true, false, false);
        let accept_after_pretend =
            ipopt_refinement_failure_decision(1.0e-3, options, true, false, true);

        // IpPDFullSpaceSolver::Solve appends q when IncreaseQuality()
        // succeeds, lowercase s when it retries pretending singular, and
        // uppercase S when residual_ratio_singular_ says the current solution
        // is good enough. The final accept-after-pretend retry appends no
        // source info marker.
        assert_eq!(
            ipopt_refinement_failure_info_marker(retry_quality),
            Some('q')
        );
        assert_eq!(
            ipopt_refinement_failure_detail(retry_quality),
            "spral_quality_retry_requested"
        );
        assert_eq!(
            ipopt_refinement_failure_info_marker(pretend_singular),
            Some('s')
        );
        assert_eq!(
            ipopt_refinement_failure_detail(pretend_singular),
            "ipopt_pretend_singular_after_refinement_failure"
        );
        assert_eq!(
            ipopt_refinement_failure_info_marker(accept_current),
            Some('S')
        );
        assert_eq!(
            ipopt_refinement_failure_detail(accept_current),
            "ipopt_accept_current_solution_after_refinement_failure"
        );
        assert_eq!(
            ipopt_refinement_failure_info_marker(accept_after_pretend),
            None
        );
        assert_eq!(
            ipopt_refinement_failure_detail(accept_after_pretend),
            "ipopt_accept_current_solution_after_pretend_singular_refinement_failure"
        );
    }

