    #[test]
    fn adaptive_mu_restore_previous_iterate_uses_stored_fixed_mode_point() {
        let options = InteriorPointOptions {
            mu_strategy: InteriorPointMuStrategy::Adaptive,
            adaptive_mu_oracle: InteriorPointAdaptiveMuOracle::Loqo,
            adaptive_mu_globalization: InteriorPointAdaptiveMuGlobalization::KktError,
            adaptive_mu_restore_previous_iterate: true,
            adaptive_mu_kkt_error_red_iters: 1,
            adaptive_mu_kkt_error_red_fact: 0.5,
            ..InteriorPointOptions::default()
        };
        let mut state = AdaptiveMuUpdateState {
            kkt_error_refs: vec![1.0],
            accepted_iterate: Some(AdaptiveMuAcceptedIterate {
                x: vec![0.25],
                lambda_eq: vec![2.0],
                lambda_ineq: vec![3.0, 0.5],
                slack: vec![2.0, 4.0],
                slack_barrier: vec![2.0, 4.0],
                z: vec![3.0, 0.5],
                z_lower: Vec::new(),
                z_upper: Vec::new(),
                r_dual: vec![0.125],
                r_eq: vec![0.25],
                r_ineq: vec![0.5, 0.625],
                r_slack_stationarity: vec![0.75, 0.875],
            }),
            ..AdaptiveMuUpdateState::default()
        };
        let bounds = BoundConstraints::default();
        let current_slack_barrier = [1.0, 1.0];
        let current_z = [1.0, 1.0];
        let current_dual_residual = [1.0];
        let current_constraint_residual = [1.0, 1.0];

        let fixed = adaptive_loqo_update(
            10.0,
            10.0,
            10.0,
            10.0,
            1.0,
            0.0,
            false,
            false,
            &current_slack_barrier,
            &current_z,
            &[0.0],
            &bounds,
            &[],
            &[],
            &current_dual_residual,
            &[],
            &current_constraint_residual,
            &current_constraint_residual,
            None,
            &mut state,
            &options,
        );
        let expected_mu = adaptive_fixed_mu_from_current_complementarity(
            adaptive_mu_min(&options).max(options.mu_target),
            options.mu_max_fact,
            complementarity_product_stats(&[2.0, 4.0], &[3.0, 0.5], &[0.25], &bounds, &[], &[]),
            0.0,
            &options,
        );

        assert!(!state.free_mu_mode);
        assert!(fixed.reset_line_search);
        assert!((fixed.mu - expected_mu).abs() <= f64::EPSILON);
        let restored = fixed
            .restored_iterate
            .expect("free-to-fixed switch should restore the accepted iterate");
        assert_eq!(restored.x, vec![0.25]);
        assert_eq!(restored.lambda_eq, vec![2.0]);
        assert_eq!(restored.lambda_ineq, vec![3.0, 0.5]);
        assert_eq!(restored.slack, vec![2.0, 4.0]);
        assert_eq!(restored.z, vec![3.0, 0.5]);
    }

    #[test]
    fn monotone_mu_tiny_step_forces_only_one_drop() {
        let options = InteriorPointOptions::default();

        // IPOPT IpMonotoneMuUpdate::UpdateBarrierParameter consumes
        // tiny_step_flag after the first loop pass. A large barrier error
        // therefore stops after the forced one-step update.
        let next = next_barrier_parameter(1e-1, true, true, &options, |_| 1e6);

        assert!(!next.stop_at_tiny_step);
        assert!((next.barrier_parameter - 2e-2).abs() <= f64::EPSILON);
    }

    #[test]
    fn monotone_mu_tiny_step_at_floor_requests_best_possible_stop() {
        let options = InteriorPointOptions {
            mu_target: 1e-1,
            ..InteriorPointOptions::default()
        };

        // IPOPT IpMonotoneMuUpdate::UpdateBarrierParameter throws
        // TINY_STEP_DETECTED when tiny_step_flag is set but CalcNewMuAndTau
        // leaves mu unchanged.
        let next = next_barrier_parameter(1e-1, true, true, &options, |_| 1e6);

        assert!(next.stop_at_tiny_step);
        assert_eq!(next.barrier_parameter.to_bits(), 1e-1f64.to_bits());
    }

    #[test]
    fn monotone_mu_first_call_can_fast_decrease_even_when_disabled() {
        let options = InteriorPointOptions {
            overall_tol: 1e-12,
            complementarity_tol: 1e-12,
            mu_allow_fast_monotone_decrease: false,
            ..InteriorPointOptions::default()
        };

        // IPOPT keeps initialized_=false until the end of the first
        // UpdateBarrierParameter call, so the first call can still take the
        // fast monotone loop even when later calls would stop after one drop.
        let first_call = next_barrier_parameter(1e-1, false, false, &options, |_| 0.0);
        let later_call = next_barrier_parameter(1e-1, false, true, &options, |_| 0.0);

        assert!(!first_call.stop_at_tiny_step);
        assert!(!later_call.stop_at_tiny_step);
        assert!((first_call.barrier_parameter - 1e-12 / 11.0).abs() <= f64::EPSILON);
        assert!((later_call.barrier_parameter - 2e-2).abs() <= f64::EPSILON);
    }

    #[test]
    fn monotone_mu_skips_first_restoration_update() {
        // IPOPT sets MonotoneMuUpdate::first_iter_resto_ for algorithms
        // initialized with the "resto." prefix. The first call marks the
        // update initialized but does not enter the mu reduction loop.
        assert!(skip_first_restoration_barrier_update(1, false));
        assert!(!skip_first_restoration_barrier_update(1, true));
        assert!(!skip_first_restoration_barrier_update(0, false));
    }

    #[test]
    fn monotone_mu_change_detection_has_no_local_tolerance() {
        let options = InteriorPointOptions {
            overall_tol: 1e-12,
            complementarity_tol: 1e-12,
            ..InteriorPointOptions::default()
        };
        let floor = minimum_monotone_barrier_parameter(&options);
        let just_above_floor = f64::from_bits(floor.to_bits() + 1);

        // IPOPT IpMonotoneMuUpdate::UpdateBarrierParameter tests
        // `mu != new_mu` exactly before accepting a barrier update and
        // resetting the line search. Even a one-ulp drop to the monotone floor
        // is therefore source-visible.
        let next = next_barrier_parameter(just_above_floor, false, true, &options, |_| 0.0);

        assert!(!next.stop_at_tiny_step);
        assert_eq!(next.barrier_parameter.to_bits(), floor.to_bits());
    }

    #[test]
    fn push_scalar_to_bounds_interior_keeps_ipopt_tiny_margin_order() {
        let lower = 0.0;
        let upper = 1.0e-305;
        let bound_push = 1.0;
        let bound_frac = 0.5;
        let tiny_double = 100.0 * f64::MIN_POSITIVE;

        let pushed_from_lower =
            push_scalar_to_bounds_interior(lower, Some(lower), Some(upper), bound_push, bound_frac);
        let pushed_from_upper =
            push_scalar_to_bounds_interior(upper, Some(lower), Some(upper), bound_push, bound_frac);

        // Ipopt::DefaultIterateInitializer::push_variables subtracts
        // tiny_double from the lower-side fraction margin, then adds it back
        // only for the upper-side margin.
        assert_eq!(
            pushed_from_lower.to_bits(),
            (bound_frac * (upper - lower) - tiny_double).to_bits()
        );
        assert_eq!(
            pushed_from_upper.to_bits(),
            (upper - bound_frac * (upper - lower)).to_bits()
        );
    }

    #[test]
    fn push_scalar_to_bounds_interior_snaps_before_pushing() {
        let pushed = push_scalar_to_bounds_interior(-10.0, Some(2.0), Some(8.0), 1.0e-1, 1.0e-1);

        assert_eq!(pushed, 2.2);
    }

    #[test]
    fn push_scalar_to_bounds_interior_without_bound_frac_only_snaps() {
        let pushed = push_scalar_to_bounds_interior(-10.0, Some(2.0), Some(8.0), 1.0e-1, 0.0);

        assert_eq!(pushed, 2.0);
    }

    struct RestorationMockProblem;

    impl CompiledNlpProblem for RestorationMockProblem {
        fn dimension(&self) -> Index {
            2
        }

        fn parameter_count(&self) -> Index {
            0
        }

        fn parameter_ccs(&self, _parameter_index: Index) -> &CCS {
            static EMPTY: std::sync::OnceLock<CCS> = std::sync::OnceLock::new();
            EMPTY.get_or_init(|| CCS::empty(0, 0))
        }

        fn equality_count(&self) -> Index {
            1
        }

        fn inequality_count(&self) -> Index {
            1
        }

        fn objective_value(&self, x: &[f64], _parameters: &[ParameterMatrix<'_>]) -> f64 {
            if x[0] < 0.0 {
                return f64::NAN;
            }
            x[0] * x[0] + 3.0 * x[1] * x[1]
        }

        fn objective_gradient(
            &self,
            x: &[f64],
            _parameters: &[ParameterMatrix<'_>],
            out: &mut [f64],
        ) {
            out[0] = 2.0 * x[0];
            out[1] = 6.0 * x[1];
        }

        fn equality_jacobian_ccs(&self) -> &CCS {
            static JAC: std::sync::OnceLock<CCS> = std::sync::OnceLock::new();
            JAC.get_or_init(|| CCS::new(1, 2, vec![0, 1, 2], vec![0, 0]))
        }

        fn equality_values(&self, x: &[f64], _parameters: &[ParameterMatrix<'_>], out: &mut [f64]) {
            out[0] = x[0] + 2.0 * x[1] - 3.0;
        }

        fn equality_jacobian_values(
            &self,
            _x: &[f64],
            _parameters: &[ParameterMatrix<'_>],
            out: &mut [f64],
        ) {
            out.copy_from_slice(&[1.0, 2.0]);
        }

        fn inequality_jacobian_ccs(&self) -> &CCS {
            static JAC: std::sync::OnceLock<CCS> = std::sync::OnceLock::new();
            JAC.get_or_init(|| CCS::new(1, 2, vec![0, 1, 2], vec![0, 0]))
        }

        fn inequality_values(
            &self,
            x: &[f64],
            _parameters: &[ParameterMatrix<'_>],
            out: &mut [f64],
        ) {
            out[0] = x[0] - x[1] + 1.0;
        }

        fn inequality_jacobian_values(
            &self,
            _x: &[f64],
            _parameters: &[ParameterMatrix<'_>],
            out: &mut [f64],
        ) {
            out.copy_from_slice(&[1.0, -1.0]);
        }

        fn lagrangian_hessian_ccs(&self) -> &CCS {
            static HESSIAN: std::sync::OnceLock<CCS> = std::sync::OnceLock::new();
            HESSIAN.get_or_init(|| CCS::lower_triangular_dense(2))
        }

        fn lagrangian_hessian_values(
            &self,
            _x: &[f64],
            _parameters: &[ParameterMatrix<'_>],
            _equality_multipliers: &[f64],
            _inequality_multipliers: &[f64],
            out: &mut [f64],
        ) {
            out.copy_from_slice(&[2.0, 0.0, 6.0]);
        }
    }

    #[test]
    fn equality_restoration_initial_guess_matches_ipopt_quadratic_initializer() {
        let x = [4.0, -2.0];
        let equality_values = [-3.0, 0.0, 2.0];
        let inequality_residuals = [1.5, -0.25];
        let restoration_mu = 0.2;
        let rho = 1.0e3;
        let guess = equality_restoration_initial_guess(
            &x,
            &equality_values,
            &inequality_residuals,
            restoration_mu,
            rho,
        );

        assert_eq!(&guess[..x.len()], x.as_slice());
        let shift = restoration_mu / (2.0 * rho);
        let assert_residual_pair =
            |guess: &[f64], residuals: &[f64], negative_offset: usize, positive_offset: usize| {
                for (row, &constraint_value) in residuals.iter().enumerate() {
                    let a = shift - 0.5 * constraint_value;
                    let b = constraint_value * shift;
                    let expected_negative = a.mul_add(a, b).sqrt() + a;
                    let negative = guess[negative_offset + row];
                    let positive = guess[positive_offset + row];

                    assert_eq!(negative.to_bits(), expected_negative.to_bits());
                    assert_eq!(
                        positive.to_bits(),
                        (constraint_value + expected_negative).to_bits()
                    );
                    assert!((constraint_value + negative - positive).abs() <= f64::EPSILON);
                    assert!(negative > 0.0);
                    assert!(positive > 0.0);
                }
            };
        assert_residual_pair(
            &guess,
            &equality_values,
            x.len(),
            x.len() + equality_values.len(),
        );
        assert_residual_pair(
            &guess,
            &inequality_residuals,
            x.len() + 2 * equality_values.len(),
            x.len() + 2 * equality_values.len() + inequality_residuals.len(),
        );
    }

    #[test]
    fn restoration_initial_barrier_uses_current_mu_and_absolute_residuals() {
        let value =
            ipopt_restoration_initial_barrier_parameter(1.0e-4, &[-0.03, 0.02], &[0.04, -0.7]);
        assert_eq!(value, 0.7);

        let value = ipopt_restoration_initial_barrier_parameter(0.25, &[0.03], &[0.04]);
        assert_eq!(value, 0.25);
    }

    fn source_aug_resto_sigma_tilde_inv(
        sigma: Option<&[f64]>,
        delta_x: f64,
        prototype_len: usize,
    ) -> Option<Vec<f64>> {
        if sigma.is_none() && delta_x == 0.0 {
            return None;
        }
        Some(match sigma {
            Some(values) if delta_x != 0.0 => values
                .iter()
                .map(|value| {
                    let mut value = *value;
                    value += delta_x;
                    value.recip()
                })
                .collect(),
            Some(values) => values.iter().map(|value| value.recip()).collect(),
            None => vec![1.0 / delta_x; prototype_len],
        })
    }

    fn source_aug_resto_neg_omega_c_plus_d_c(
        sigma_n_inv: Option<&[f64]>,
        sigma_p_inv: Option<&[f64]>,
        d_c: Option<&[f64]>,
        prototype: &[f64],
    ) -> Option<Vec<f64>> {
        if sigma_n_inv.is_none() && sigma_p_inv.is_none() && d_c.is_none() {
            return None;
        }
        let mut result = vec![0.0; prototype.len()];
        if let Some(values) = sigma_n_inv {
            for (slot, value) in result.iter_mut().zip(values.iter()) {
                *slot -= value;
            }
        }
        if let Some(values) = sigma_p_inv {
            for (slot, value) in result.iter_mut().zip(values.iter()) {
                *slot -= value;
            }
        }
        if let Some(values) = d_c {
            for (slot, value) in result.iter_mut().zip(values.iter()) {
                *slot += value;
            }
        }
        Some(result)
    }

    fn source_aug_resto_rhs_c(
        rhs_c: &[f64],
        sigma_n_inv: Option<&[f64]>,
        rhs_n_c: &[f64],
        sigma_p_inv: Option<&[f64]>,
        rhs_p_c: &[f64],
    ) -> Vec<f64> {
        let mut result = rhs_c.to_vec();
        if let Some(values) = sigma_n_inv {
            for ((slot, sigma), rhs) in result.iter_mut().zip(values.iter()).zip(rhs_n_c.iter()) {
                let product = sigma * rhs;
                *slot -= product;
            }
        }
        if let Some(values) = sigma_p_inv {
            for ((slot, sigma), rhs) in result.iter_mut().zip(values.iter()).zip(rhs_p_c.iter()) {
                let product = sigma * rhs;
                *slot += product;
            }
        }
        result
    }

    fn source_aug_resto_dx_plus_wr_d(cd_x0: Option<&[f64]>, factor: f64, wr_d: &[f64]) -> Vec<f64> {
        let mut result = vec![0.0; wr_d.len()];
        match cd_x0 {
            Some(values) => {
                for ((slot, wr), value) in result.iter_mut().zip(wr_d.iter()).zip(values.iter()) {
                    *slot = factor.mul_add(*wr, *value);
                }
            }
            None => {
                for (slot, wr) in result.iter_mut().zip(wr_d.iter()) {
                    *slot = factor * wr;
                }
            }
        }
        result
    }

    fn source_aug_resto_back_out_equality_steps(
        sigma_n_inv: Option<&[f64]>,
        rhs_n_c: &[f64],
        sigma_p_inv: Option<&[f64]>,
        rhs_p_c: &[f64],
        sol_c: &[f64],
    ) -> (Vec<f64>, Vec<f64>) {
        let mut sol_n = vec![0.0; sol_c.len()];
        if let Some(values) = sigma_n_inv {
            for (((slot, rhs), sol), sigma) in sol_n
                .iter_mut()
                .zip(rhs_n_c.iter())
                .zip(sol_c.iter())
                .zip(values.iter())
            {
                let mut value = *rhs;
                value -= sol;
                *slot = value * sigma;
            }
        }
        let mut sol_p = vec![0.0; sol_c.len()];
        if let Some(values) = sigma_p_inv {
            for (((slot, rhs), sol), sigma) in sol_p
                .iter_mut()
                .zip(rhs_p_c.iter())
                .zip(sol_c.iter())
                .zip(values.iter())
            {
                let mut value = *rhs;
                value += sol;
                *slot = value * sigma;
            }
        }
        (sol_n, sol_p)
    }

    fn source_aug_resto_neg_omega_d_plus_d_d(
        sigma_n_inv: Option<&[f64]>,
        pd_l: &[(usize, f64)],
        sigma_p_inv: Option<&[f64]>,
        neg_pd_u: &[(usize, f64)],
        d_d: Option<&[f64]>,
        prototype_len: usize,
    ) -> Option<Vec<f64>> {
        if sigma_n_inv.is_none() && sigma_p_inv.is_none() && d_d.is_none() {
            return None;
        }
        let mut result = vec![0.0; prototype_len];
        if let Some(values) = sigma_n_inv {
            for (&sigma, &(row, coefficient)) in values.iter().zip(pd_l.iter()) {
                result[row] -= coefficient * sigma;
            }
        }
        if let Some(values) = sigma_p_inv {
            for (&sigma, &(row, coefficient)) in values.iter().zip(neg_pd_u.iter()) {
                result[row] += coefficient * sigma;
            }
        }
        if let Some(values) = d_d {
            // Mirrors IpAugRestoSystemSolver::Neg_Omega_d_plus_D_d exactly:
            // after accumulating Pd_L / neg_Pd_U contributions, source IPOPT
            // calls Copy(*D_d), replacing rather than Axpy-ing the diagonal.
            result.copy_from_slice(values);
        }
        Some(result)
    }

    fn source_aug_resto_rhs_d(
        rhs_d: &[f64],
        sigma_n_inv: Option<&[f64]>,
        rhs_n_d: &[f64],
        pd_l: &[(usize, f64)],
        sigma_p_inv: Option<&[f64]>,
        rhs_p_d: &[f64],
        neg_pd_u: &[(usize, f64)],
    ) -> Vec<f64> {
        let mut result = rhs_d.to_vec();
        if let Some(values) = sigma_n_inv {
            for ((&sigma, &rhs), &(row, coefficient)) in
                values.iter().zip(rhs_n_d.iter()).zip(pd_l.iter())
            {
                result[row] -= coefficient * sigma * rhs;
            }
        }
        if let Some(values) = sigma_p_inv {
            for ((&sigma, &rhs), &(row, coefficient)) in
                values.iter().zip(rhs_p_d.iter()).zip(neg_pd_u.iter())
            {
                result[row] -= coefficient * sigma * rhs;
            }
        }
        result
    }

    fn source_aug_resto_back_out_inequality_steps(
        sigma_n_inv: Option<&[f64]>,
        rhs_n_d: &[f64],
        pd_l: &[(usize, f64)],
        sigma_p_inv: Option<&[f64]>,
        rhs_p_d: &[f64],
        neg_pd_u: &[(usize, f64)],
        sol_d: &[f64],
    ) -> (Vec<f64>, Vec<f64>) {
        let mut sol_n = vec![0.0; pd_l.len()];
        if let Some(values) = sigma_n_inv {
            for (((slot, &rhs), &(row, coefficient)), &sigma) in sol_n
                .iter_mut()
                .zip(rhs_n_d.iter())
                .zip(pd_l.iter())
                .zip(values.iter())
            {
                let mut value = rhs;
                value -= coefficient * sol_d[row];
                *slot = value * sigma;
            }
        }
        let mut sol_p = vec![0.0; neg_pd_u.len()];
        if let Some(values) = sigma_p_inv {
            for (((slot, &rhs), &(row, coefficient)), &sigma) in sol_p
                .iter_mut()
                .zip(rhs_p_d.iter())
                .zip(neg_pd_u.iter())
                .zip(values.iter())
            {
                let mut value = rhs;
                value -= coefficient * sol_d[row];
                *slot = value * sigma;
            }
        }
        (sol_n, sol_p)
    }

    #[test]
    fn aug_resto_sigma_tilde_inv_mirrors_ipopt_source_cases() {
        let with_sigma = source_aug_resto_sigma_tilde_inv(Some(&[0.25, 0.5]), 0.125, 2).unwrap();
        assert_eq!(with_sigma[0].to_bits(), (1.0_f64 / 0.375).to_bits());
        assert_eq!(with_sigma[1].to_bits(), (1.0_f64 / 0.625).to_bits());

        let homogenous = source_aug_resto_sigma_tilde_inv(Some(&[0.25, 0.5]), 0.0, 2).unwrap();
        assert_eq!(homogenous[0].to_bits(), 4.0_f64.to_bits());
        assert_eq!(homogenous[1].to_bits(), 2.0_f64.to_bits());

        let delta_only = source_aug_resto_sigma_tilde_inv(None, 0.125, 3).unwrap();
        assert_eq!(delta_only, vec![8.0, 8.0, 8.0]);

        assert!(source_aug_resto_sigma_tilde_inv(None, 0.0, 3).is_none());
    }

    #[test]
    fn aug_resto_equality_reduction_mirrors_ipopt_source_order() {
        let sigma_n_inv = [2.0, 0.5];
        let sigma_p_inv = [0.25, 4.0];
        let d_c = [0.125, -0.75];
        let rhs_c = [1.0, -2.0];
        let rhs_n_c = [0.375, 8.0];
        let rhs_p_c = [-4.0, 0.0625];
        let sol_c = [0.2, -0.3];

        let diag = source_aug_resto_neg_omega_c_plus_d_c(
            Some(&sigma_n_inv),
            Some(&sigma_p_inv),
            Some(&d_c),
            &rhs_c,
        )
        .unwrap();
        assert_eq!(diag[0].to_bits(), (-2.0_f64 - 0.25 + 0.125).to_bits());
        assert_eq!(diag[1].to_bits(), (-0.5_f64 - 4.0 - 0.75).to_bits());

        let rhs = source_aug_resto_rhs_c(
            &rhs_c,
            Some(&sigma_n_inv),
            &rhs_n_c,
            Some(&sigma_p_inv),
            &rhs_p_c,
        );
        assert_eq!(
            rhs[0].to_bits(),
            (1.0_f64 - 2.0 * 0.375 + 0.25 * -4.0).to_bits()
        );
        assert_eq!(
            rhs[1].to_bits(),
            (-2.0_f64 - 0.5 * 8.0 + 4.0 * 0.0625).to_bits()
        );

        let (sol_n, sol_p) = source_aug_resto_back_out_equality_steps(
            Some(&sigma_n_inv),
            &rhs_n_c,
            Some(&sigma_p_inv),
            &rhs_p_c,
            &sol_c,
        );
        assert_eq!(sol_n[0].to_bits(), ((0.375_f64 - 0.2) * 2.0).to_bits());
        assert_eq!(sol_n[1].to_bits(), ((8.0_f64 + 0.3) * 0.5).to_bits());
        assert_eq!(sol_p[0].to_bits(), ((-4.0_f64 + 0.2) * 0.25).to_bits());
        assert_eq!(sol_p[1].to_bits(), ((0.0625_f64 - 0.3) * 4.0).to_bits());
    }

    #[test]
    fn aug_resto_inequality_reduction_mirrors_ipopt_source_order() {
        let sigma_n_inv = [2.0, 0.5];
        let sigma_p_inv = [0.25, 4.0];
        let pd_l = [(0, 1.0), (2, 1.0)];
        let neg_pd_u = [(1, -1.0), (2, -1.0)];
        let d_d = [0.125, -0.75, 9.0];
        let rhs_d = [1.0, -2.0, 3.0];
        let rhs_n_d = [0.375, 8.0];
        let rhs_p_d = [-4.0, 0.0625];
        let sol_d = [0.2, -0.3, 0.125];

        let diag_without_d = source_aug_resto_neg_omega_d_plus_d_d(
            Some(&sigma_n_inv),
            &pd_l,
            Some(&sigma_p_inv),
            &neg_pd_u,
            None,
            rhs_d.len(),
        )
        .unwrap();
        assert_eq!(diag_without_d[0].to_bits(), (-2.0_f64).to_bits());
        assert_eq!(diag_without_d[1].to_bits(), (-0.25_f64).to_bits());
        assert_eq!(diag_without_d[2].to_bits(), (-0.5_f64 - 4.0).to_bits());

        let diag_with_d = source_aug_resto_neg_omega_d_plus_d_d(
            Some(&sigma_n_inv),
            &pd_l,
            Some(&sigma_p_inv),
            &neg_pd_u,
            Some(&d_d),
            rhs_d.len(),
        )
        .unwrap();
        assert_eq!(diag_with_d, d_d);

        let rhs = source_aug_resto_rhs_d(
            &rhs_d,
            Some(&sigma_n_inv),
            &rhs_n_d,
            &pd_l,
            Some(&sigma_p_inv),
            &rhs_p_d,
            &neg_pd_u,
        );
        assert_eq!(rhs[0].to_bits(), (1.0_f64 - 2.0 * 0.375).to_bits());
        assert_eq!(rhs[1].to_bits(), (-2.0_f64 - 1.0).to_bits());
        assert_eq!(rhs[2].to_bits(), (3.0_f64 - 0.5 * 8.0 + 0.25).to_bits());

        let (sol_n, sol_p) = source_aug_resto_back_out_inequality_steps(
            Some(&sigma_n_inv),
            &rhs_n_d,
            &pd_l,
            Some(&sigma_p_inv),
            &rhs_p_d,
            &neg_pd_u,
            &sol_d,
        );
        assert_eq!(sol_n[0].to_bits(), ((0.375_f64 - 0.2) * 2.0).to_bits());
        assert_eq!(sol_n[1].to_bits(), ((8.0_f64 - 0.125) * 0.5).to_bits());
        assert_eq!(sol_p[0].to_bits(), ((-4.0_f64 - 0.3) * 0.25).to_bits());
        assert_eq!(sol_p[1].to_bits(), ((0.0625_f64 + 0.125) * 4.0).to_bits());
    }

    #[test]
    fn aug_resto_dx_plus_wr_d_mirrors_ipopt_source_order() {
        let wr_d = [0.25, -8.0, 3.0];
        let d_x = [1.0, 2.0, -5.0];
        let with_d = source_aug_resto_dx_plus_wr_d(Some(&d_x), 0.125, &wr_d);
        assert_eq!(with_d[0].to_bits(), 0.125_f64.mul_add(0.25, 1.0).to_bits());
        assert_eq!(with_d[1].to_bits(), 0.125_f64.mul_add(-8.0, 2.0).to_bits());
        assert_eq!(with_d[2].to_bits(), 0.125_f64.mul_add(3.0, -5.0).to_bits());

        let no_d = source_aug_resto_dx_plus_wr_d(None, 0.125, &wr_d);
        assert_eq!(no_d[0].to_bits(), (0.125_f64 * 0.25).to_bits());
        assert_eq!(no_d[1].to_bits(), (0.125_f64 * -8.0).to_bits());
        assert_eq!(no_d[2].to_bits(), (0.125_f64 * 3.0).to_bits());
    }

    #[test]
    fn restoration_nlp_includes_inequality_residual_blocks() {
        let problem = RestorationMockProblem;
        let nlp = EqualityRestorationNlp::new(&problem, &[2.0, -4.0], 1.0e3, 0.25).unwrap();

        assert_eq!(nlp.dimension(), 6);
        assert_eq!(nlp.equality_count(), 1);
        assert_eq!(nlp.inequality_count(), 1);
        assert_eq!(
            nlp.equality_jacobian_ccs(),
            &CCS::new(1, 6, vec![0, 1, 2, 3, 4, 4, 4], vec![0, 0, 0, 0])
        );
        assert_eq!(
            nlp.inequality_jacobian_ccs(),
            &CCS::new(1, 6, vec![0, 1, 2, 2, 2, 3, 4], vec![0, 0, 0, 0])
        );

        let x = [1.0, 2.0, 0.3, 0.4, 0.5, 0.6];
        let mut equality_values = vec![0.0; nlp.equality_count()];
        let mut inequality_values = vec![0.0; nlp.inequality_count()];
        let mut equality_jacobian_values = vec![0.0; nlp.equality_jacobian_ccs().nnz()];
        let mut inequality_jacobian_values = vec![0.0; nlp.inequality_jacobian_ccs().nnz()];
        let mut hessian_values = vec![0.0; nlp.lagrangian_hessian_ccs().nnz()];

        nlp.equality_values(&x, &[], &mut equality_values);
        nlp.inequality_values(&x, &[], &mut inequality_values);
        nlp.equality_jacobian_values(&x, &[], &mut equality_jacobian_values);
        nlp.inequality_jacobian_values(&x, &[], &mut inequality_jacobian_values);
        nlp.lagrangian_hessian_values(&x, &[], &[7.0], &[11.0], &mut hessian_values);

        assert!((equality_values[0] - 1.9).abs() <= f64::EPSILON);
        assert!((inequality_values[0] + 0.1).abs() <= f64::EPSILON);
        assert_eq!(equality_jacobian_values, [1.0, 2.0, 1.0, -1.0]);
        assert_eq!(inequality_jacobian_values, [1.0, -1.0, 1.0, -1.0]);

        let objective = nlp.objective_value(&x, &[]);
        assert!((objective - 1800.3125).abs() <= 1.0e-12);

        let mut gradient = vec![0.0; nlp.dimension()];
        nlp.objective_gradient(&x, &[], &mut gradient);
        assert_eq!(
            gradient,
            [
                -(0.25 * 0.25),
                0.25 * (1.0 / 16.0) * 6.0,
                1.0e3,
                1.0e3,
                1.0e3,
                1.0e3
            ]
        );

        assert_eq!(hessian_values, [0.25 * 0.25, 0.0, 0.25 * (1.0 / 16.0)]);

        nlp.lagrangian_hessian_values_with_objective_factor(
            &x,
            &[],
            0.5,
            &[7.0],
            &[11.0],
            &mut hessian_values,
        );
        assert_eq!(
            hessian_values,
            [0.5 * 0.25 * 0.25, 0.0, 0.5 * 0.25 * (1.0 / 16.0)]
        );
    }

    #[test]
    fn restoration_nlp_keeps_split_bounds_unrelaxed_like_ipopt() {
        let problem = RestorationMockProblem;
        let relaxed_original_bounds = BoundConstraints {
            lower_indices: vec![0],
            lower_values: vec![-1.0e-8],
            upper_indices: vec![1],
            upper_values: vec![8.0 + 1.0e-8],
        };
        let nlp = EqualityRestorationNlp::new_with_relaxed_original_bounds(
            &problem,
            &[2.0, -4.0],
            1.0e3,
            0.25,
            &relaxed_original_bounds,
        )
        .unwrap();
        let bounds = nlp.variable_bounds().unwrap();
        let lower = bounds.lower.as_ref().unwrap();
        let upper = bounds.upper.as_ref().unwrap();

        assert_eq!(lower[0], Some(-1.0e-8));
        assert_eq!(upper[1], Some(8.0 + 1.0e-8));
        assert_eq!(&lower[2..], &[Some(0.0), Some(0.0), Some(0.0), Some(0.0)]);

        let options = InteriorPointOptions::default();
        let (collected_bounds, _) =
            collect_interior_point_bounds_and_fixed(&nlp, &options).unwrap();
        let original_lower_position = collected_bounds
            .lower_indices
            .iter()
            .position(|index| *index == 0)
            .expect("restoration original lower bound collected");
        assert_eq!(
            collected_bounds.lower_values[original_lower_position].to_bits(),
            (-1.0e-8_f64).to_bits()
        );
        let original_upper_position = collected_bounds
            .upper_indices
            .iter()
            .position(|index| *index == 1)
            .expect("restoration original upper bound collected");
        assert_eq!(
            collected_bounds.upper_values[original_upper_position].to_bits(),
            (8.0 + 1.0e-8_f64).to_bits()
        );
        for split_index in 2..6 {
            let position = collected_bounds
                .lower_indices
                .iter()
                .position(|index| *index == split_index)
                .expect("restoration split lower bound collected");
            assert_eq!(
                collected_bounds.lower_values[position].to_bits(),
                0.0_f64.to_bits()
            );
        }
    }

    #[test]
    fn restoration_second_level_trial_recomputes_only_split_variables() {
        let problem = RestorationMockProblem;
        let nlp = EqualityRestorationNlp::new(&problem, &[2.0, -4.0], 1.0e3, 0.25).unwrap();
        let current_x = [1.0, 2.0, 9.0, 10.0, 11.0, 12.0];
        let slack = [0.2];
        let trial_x = nlp
            .second_level_restoration_trial_x(&current_x, &slack, 0.25, &[])
            .unwrap();

        assert_eq!(&trial_x[..2], &[1.0, 2.0]);
        let expected =
            equality_restoration_initial_guess(&[1.0, 2.0], &[2.0], &[-0.2], 0.25, 1.0e3);
        assert_eq!(trial_x, expected);
    }

    #[test]
    fn restoration_nlp_updates_proximity_weight_from_barrier_parameter() {
        let problem = RestorationMockProblem;
        let nlp = EqualityRestorationNlp::new(&problem, &[2.0, -4.0], 1.0e3, 2.0).unwrap();
        let x = [1.0, 2.0, 0.3, 0.4, 0.5, 0.6];

        assert!((nlp.objective_value(&x, &[]) - 1802.5).abs() <= 1.0e-12);

        nlp.interior_point_set_barrier_parameter(0.25);

        let objective = nlp.objective_value(&x, &[]);
        assert!((objective - 1800.625).abs() <= 1.0e-12);

        let mut gradient = vec![0.0; nlp.dimension()];
        nlp.objective_gradient(&x, &[], &mut gradient);
        assert_eq!(gradient[0], -0.5 * 0.25);
        assert_eq!(gradient[1], 0.5 * (1.0 / 16.0) * 6.0);

        let mut hessian_values = vec![0.0; nlp.lagrangian_hessian_ccs().nnz()];
        nlp.lagrangian_hessian_values(&x, &[], &[7.0], &[11.0], &mut hessian_values);
        assert_eq!(hessian_values, [0.5 * 0.25, 0.0, 0.5 * (1.0 / 16.0)]);
    }

